def port_trace_size_error(n_events: int, capacity: int = TRACE_CAPACITY) -> Optional[str]:
    """Pure size gate for port_trace length (validator + append share this)."""
    if type(n_events) is not int or type(capacity) is not int:
        return "trace size types"
    if n_events < 0:
        return "trace length negative"
    if n_events > capacity:
        return f"trace length {n_events} > TRACE_CAPACITY ({capacity})"
    if n_events > UINT32_MAX:
        return "trace length > UINT32_MAX"
    return None

