def _load_d3s1():
    spec = importlib.util.spec_from_file_location("d3s1_gen", D3S1_GEN)
    m = importlib.util.module_from_spec(spec)
    assert spec.loader
    spec.loader.exec_module(m)
    return m

d3s1 = _load_d3s1()

def load_d1():
    raw = D1_PATH.read_bytes()
    if hashlib.sha256(raw).hexdigest() != D1_SHA:
        raise SystemExit("D1 sha pin mismatch")
    doc = json.loads(raw)
    if doc.get("format") != D1_FORMAT or len(doc["vectors"]) != D1_COUNT:
        raise SystemExit("D1 format/count pin")
    return {v["id"]: v for v in doc["vectors"] if "key_hex" in v}

D1 = load_d1()

def gkey(vid: str) -> bytes:
    return bytes.fromhex(D1[vid]["key_hex"])

def gval(vid: str) -> bytes:
    return bytes.fromhex(D1[vid]["value_hex"])

def hex_of(b: bytes) -> str:
    return b.hex()

def body_of(val: bytes) -> bytes:
    return val[108:-4]

def patch_at(val: bytes, off: int, data: bytes) -> bytes:
    b = bytearray(val)
    b[off : off + len(data)] = data
    b[-4:] = d3s1.be32(d3s1.crc32c(bytes(b[:-4])))
    return bytes(b)

def set_payload_blob_dig(val: bytes, dig: bytes) -> bytes:
    """TRANSACTION_ANCHOR: payload_blob_key_digest is last 32 of body."""
    body = body_of(val)
    return patch_at(val, 108 + len(body) - 32, dig)

def set_dlv_payload_blob_dig(val: bytes, dig: bytes) -> bytes:
    """DELIVERY: payload dig is third-from-end (pay32 + result_cache32 + reservation32)."""
    body = body_of(val)
    return patch_at(val, 108 + len(body) - 96, dig)

def set_ingress_blob_digs(val: bytes, pay: bytes, evi: bytes, sem: Optional[bytes] = None) -> bytes:
    """ORDERED_INGRESS tail: semantic, payload, evidence digests before state+reservation."""
    body = bytearray(body_of(val))
    if len(body) < 168:
        raise ValueError("ingress body too short")
    if sem is not None:
        body[-132:-100] = sem
    body[-100:-68] = pay
    body[-68:-36] = evi
    return d3s1.enc_env_full(
        6, 0x27, 0, 1, val[24:40], val[40:72], val[72:104], bytes(body)
    )

def msd_ingress(ing_body: bytes, payload: bytes, evidence: bytes) -> bytes:
    """Independent message_semantic_digest matching production docs17 §5.1.

    Prefix fields are the contiguous ORDERED_INGRESS encoding from message_kind
    through evidence_trust (body[20 : len-168]); controller/reserved1/digests
    are excluded. Then payload_length || payload || evidence_length || evidence.
    """
    if len(ing_body) < 168:
        raise ValueError("ingress body short")
    prefix = ing_body[20 : len(ing_body) - 168]
    h = hashlib.sha256()
    h.update(b"NINLIL-BEARER-MESSAGE-V1")
    h.update(prefix)
    h.update(struct.pack(">I", len(payload)))
    h.update(payload)
    h.update(struct.pack(">I", len(evidence)))
    h.update(evidence)
    return h.digest()

def msd_parts(
    kind: int,
    flags: int,
    transaction_id: bytes,
    attempt_id: bytes,
    event_id: bytes,
    party: bytes,
    target: bytes,
    service_enc: bytes,
    content_digest: bytes,
    generation: int,
    deadline_epoch: bytes,
    abs_deadline_ms: int,
    evidence_grace_ms: int,
    required_evidence: int,
    receipt_stage: int,
    disposition: int,
    effect_certainty: int,
    retry_guidance: int,
    cancel_kind: int,
    retry_delay_ms: int,
    evidence_epoch: bytes,
    evidence_now_ms: int,
    evidence_trust: int,
    payload: bytes,
    evidence: bytes,
) -> bytes:
    h = hashlib.sha256()
    h.update(b"NINLIL-BEARER-MESSAGE-V1")
    h.update(struct.pack(">I", kind & 0xFFFFFFFF))
    h.update(struct.pack(">I", flags & 0xFFFFFFFF))
    h.update(transaction_id)
    h.update(attempt_id)
    h.update(event_id)
    h.update(party)
    h.update(target)
    h.update(service_enc)
    h.update(content_digest)
    h.update(struct.pack(">Q", generation & 0xFFFFFFFFFFFFFFFF))
    h.update(deadline_epoch)
    h.update(struct.pack(">Q", abs_deadline_ms & 0xFFFFFFFFFFFFFFFF))
    h.update(struct.pack(">Q", evidence_grace_ms & 0xFFFFFFFFFFFFFFFF))
    h.update(struct.pack(">I", required_evidence & 0xFFFFFFFF))
    h.update(struct.pack(">I", receipt_stage & 0xFFFFFFFF))
    h.update(struct.pack(">I", disposition & 0xFFFFFFFF))
    h.update(struct.pack(">I", effect_certainty & 0xFFFFFFFF))
    h.update(struct.pack(">I", retry_guidance & 0xFFFFFFFF))
    h.update(struct.pack(">I", cancel_kind & 0xFFFFFFFF))
    h.update(struct.pack(">Q", retry_delay_ms & 0xFFFFFFFFFFFFFFFF))
    h.update(evidence_epoch)
    h.update(struct.pack(">Q", evidence_now_ms & 0xFFFFFFFFFFFFFFFF))
    h.update(struct.pack(">I", evidence_trust & 0xFFFFFFFF))
    h.update(struct.pack(">I", len(payload)))
    h.update(payload)
    h.update(struct.pack(">I", len(evidence)))
    h.update(evidence)
    return h.digest()

def dlv_msd_fields(dlv_body: bytes):
    """Extract Mode30 semantic-binding fields from DELIVERY body."""
    # raw16 + creation_kind2 + reserved2 + sched8 + tx16 + event16 + party100 + target100 + svc + tail172
    o = 2 + 80 + 2 + 2 + 8
    tx = dlv_body[o : o + 16]
    o += 16
    event = dlv_body[o : o + 16]
    o += 16
    party = dlv_body[o : o + 100]
    o += 100
    target = dlv_body[o : o + 100]
    o += 100
    tail = 32 + 8 + 16 + 8 + 8 + 4 + 32 + 32 + 32  # 172
    svc = dlv_body[o : len(dlv_body) - tail]
    o = len(dlv_body) - tail
    content = dlv_body[o : o + 32]
    o += 32
    gen = struct.unpack(">Q", dlv_body[o : o + 8])[0]
    o += 8
    deadline_epoch = dlv_body[o : o + 16]
    o += 16
    abs_ms = struct.unpack(">Q", dlv_body[o : o + 8])[0]
    o += 8
    grace = struct.unpack(">Q", dlv_body[o : o + 8])[0]
    o += 8
    req = struct.unpack(">I", dlv_body[o : o + 4])[0]
    return tx, event, party, target, svc, content, gen, deadline_epoch, abs_ms, grace, req

def rr_attempt_and_semantic_off(rr_body: bytes) -> Tuple[bytes, int, int]:
    """Return (attempt_id, semantic_off_in_body, body_blob_off_in_body)."""
    rl = struct.unpack(">H", rr_body[0:2])[0]
    o = 2 + rl
    dl = struct.unpack(">H", rr_body[o : o + 2])[0]
    o = o + 2 + dl  # start of fixed tail after delivery raw
    # txn16 + kind4 + semantic32 + body_blob32 + state4 + gen8 + inv8 + exh4 + res4 + attempt16 + ...
    sem_off = o + 16 + 4
    blob_off = sem_off + 32
    att_off = blob_off + 32 + 4 + 8 + 8 + 4 + 4
    return rr_body[att_off : att_off + 16], sem_off, blob_off

def rc_evidence_stage(rc_body: bytes) -> int:
    # raw16(82) + dig32 + txn16 + count8 + seen4 + attempt4 + state4 + reply4 + tok16+8+16+8
    # + started16+8 + complete8 + cb8 + rec_inv8 + rec_gen8 + nbf16+8 + app_kind4 + stage4
    o = 2 + 80 + 32 + 16 + 8 + 4 + 4 + 4 + 4 + 16 + 8 + 16 + 8 + 16 + 8 + 8 + 8 + 8 + 8 + 16 + 8 + 4
    return struct.unpack(">I", rc_body[o : o + 4])[0]

def man_body_offsets(body: bytes) -> Tuple[int, int, bytes]:
    rl = struct.unpack(">H", body[36:38])[0]
    return rl, 38 + rl + 32, body[:32]

def blob_id_digest(
    owner_kind: int, owner_raw: bytes, blob_kind: int, content_digest: bytes, total: int
) -> bytes:
    return d3s1.sha256(
        b"NINLIL-DOMAIN-BLOB-ID-V1"
        + struct.pack(">H", owner_kind)
        + struct.pack(">H", len(owner_raw))
        + owner_raw
        + struct.pack(">H", blob_kind)
        + content_digest
        + struct.pack(">Q", total)
    )

def blob_owner_pkd(owner_kind: int, owner_raw: bytes) -> bytes:
    if owner_kind == 1:  # TX → ANCHOR id128
        return d3s1.key_digest(d3s1.bkey(6, 0x20, 2, owner_raw))
    if owner_kind == 2:  # INGRESS u64
        return d3s1.key_digest(d3s1.bkey(6, 0x27, 3, owner_raw))
    if owner_kind == 3:  # DELIVERY composite raw16
        return d3s1.key_digest(
            d3s1.bkey(6, 0x40, 5, d3s1.composite(0x40, struct.pack(">H", len(owner_raw)) + owner_raw))
        )
    raise ValueError("owner_kind")


def blob_owner_primary_id(owner_kind: int, owner_raw: bytes) -> bytes:
    """Common primary_id hint from BLOB owner (docs/17 §4 / production typed).

    TRANSACTION: owner_raw[16]; INGRESS: left-pad u64; DELIVERY: composite
    identity first 16 of COMPOSITE(0x40, raw16(owner_raw)).
    """
    if owner_kind == 1:
        if len(owner_raw) != 16:
            raise ValueError("tx owner_raw")
        return owner_raw
    if owner_kind == 2:
        if len(owner_raw) != 8:
            raise ValueError("ingress owner_raw")
        return bytes(8) + owner_raw
    if owner_kind == 3:
        if len(owner_raw) != 80:
            raise ValueError("delivery owner_raw")
        return d3s1.composite(0x40, d3s1.raw16(owner_raw))[:16]
    raise ValueError("owner_kind")


def chunk_count_for_total(total: int) -> int:
    if total == 0:
        return 0
    return (total + 3071) // 3072

def rebuild_manifest(
    owner_kind: int,
    owner_raw: bytes,
    blob_kind: int,
    stream: bytes,
    primary_id: bytes,
    pvd: bytes,
    head: Optional[bytes] = None,
) -> Tuple[bytes, bytes]:
    """Build (man_key, man_value) with D1-valid blob_id/key for stream bytes.

    R20: common primary_id is always derived from owner_kind/owner_raw (caller
    primary_id arg is ignored when it disagrees; kept for call-site compatibility).
    """
    total = len(stream)
    cd = d3s1.sha256(stream)
    count = chunk_count_for_total(total)
    bid = blob_id_digest(owner_kind, owner_raw, blob_kind, cd, total)
    opkd = blob_owner_pkd(owner_kind, owner_raw)
    pid = blob_owner_primary_id(owner_kind, owner_raw)
    # Accept legacy callers that pass a correct pid; always encode derived.
    _ = primary_id
    body = (
        bid
        + struct.pack(">H", owner_kind)
        + struct.pack(">H", blob_kind)
        + struct.pack(">H", len(owner_raw))
        + owner_raw
        + opkd
        + struct.pack(">Q", total)
        + struct.pack(">I", count)
        + cd
    )
    man_k = d3s1.bkey(6, 0x30, 5, d3s1.composite(0x30, bytes([1]) + bid))
    # BLOB man: head witness + primary_value_digest must be non-zero (D1 same-record).
    if head is None:
        head = D1_NONZERO_HEAD
    if pvd == D1_ZERO32:
        # Callers that later patch_pvd may pass zero temporarily; keep explicit non-zero default
        # only when head was defaulted and pvd left as pure zero placeholder is caller-owned.
        pass
    man_v = d3s1.enc_env_full(6, 0x30, 1, 1, pid, head, pvd, body)
    return man_k, man_v

def set_man_total_count_cd(val: bytes, total: int, count: int, cd: bytes) -> bytes:
    """Legacy in-place patch — invalid if blob_id must change. Prefer rebuild_manifest."""
    body = bytearray(body_of(val))
    _, base, _ = man_body_offsets(bytes(body))
    body[base : base + 8] = struct.pack(">Q", total)
    body[base + 8 : base + 12] = struct.pack(">I", count)
    body[base + 12 : base + 44] = cd
    return d3s1.enc_env_full(
        6, 0x30, 1, 1, val[24:40], val[40:72], val[72:104], bytes(body)
    )

def rebuild_chunk(man_k: bytes, man_v: bytes, data: bytes, index: int = 0):
    body = body_of(man_v)
    _, base, blob_id = man_body_offsets(body)
    total = struct.unpack(">Q", body[base : base + 8])[0]
    count = struct.unpack(">I", body[base + 8 : base + 12])[0]
    cd = body[base + 12 : base + 44]
    mkd = d3s1.key_digest(man_k)
    chk_key = d3s1.bkey(
        6, 0x30, 5, d3s1.composite(0x30, bytes([2]) + blob_id + struct.pack(">I", index))
    )
    cbody = (
        blob_id + mkd + struct.pack(">I", index) + struct.pack(">I", count)
        + struct.pack(">Q", total) + cd + struct.pack(">I", len(data)) + data
    )
    return chk_key, d3s1.enc_env_full(
        6, 0x30, 2, 1, man_k[13:29], D1_NONZERO_HEAD, d3s1.value_digest(man_v), cbody
    )


def rebuild_chunk_foreign_headers(
    blob_id: bytes,
    data: bytes,
    *,
    index: int,
    total: int,
    content_digest: Optional[bytes] = None,
    man_value_digest: Optional[bytes] = None,
    head: Optional[bytes] = None,
) -> Tuple[bytes, bytes]:
    """D1-valid chunk that may disagree cross-row with a man that shares blob_id.

    Chunk same-record does **not** recompute blob_id from total/content_digest (man does).
    Local D1 rules: count=ceil(total/3072), index<count, length shape, single-chunk cd,
    manifest_key_digest = KEY_DIGEST(man complete key for blob_id), key formula.
    Cross-row BIND_CHUNK / FOCUS detects count/total/content disagreement with man.
    """
    count = chunk_count_for_total(total)
    if count < 1 or index >= count or total < 1:
        raise ValueError("foreign chunk shape not D1-constructible")
    if content_digest is None:
        if count == 1:
            content_digest = d3s1.sha256(data)
        else:
            # multi-chunk stream digest is D3; local non-zero only
            content_digest = d3s1.sha256(data if data else b"\x01")
    if content_digest == D1_ZERO32:
        raise ValueError("foreign chunk content_digest zero")
    man_k = d3s1.bkey(6, 0x30, 5, d3s1.composite(0x30, bytes([1]) + blob_id))
    mkd = d3s1.key_digest(man_k)
    chk_key = d3s1.bkey(
        6, 0x30, 5, d3s1.composite(0x30, bytes([2]) + blob_id + struct.pack(">I", index))
    )
    if man_value_digest is None:
        man_value_digest = D1_NONZERO_PVD
    if head is None:
        head = D1_NONZERO_HEAD
    cbody = (
        blob_id
        + mkd
        + struct.pack(">I", index)
        + struct.pack(">I", count)
        + struct.pack(">Q", total)
        + content_digest
        + struct.pack(">I", len(data))
        + data
    )
    return chk_key, d3s1.enc_env_full(
        6, 0x30, 2, 1, man_k[13:29], head, man_value_digest, cbody
    )


