def _d1_nlr1_framing(value: bytes) -> Optional[str]:
    if not isinstance(value, (bytes, bytearray)) or len(value) < 16:
        return "value_short"
    v = bytes(value)
    if v[:4] != b"NLR1":
        return "not_nlr1"
    rver = int.from_bytes(v[6:8], "big")
    plen = int.from_bytes(v[8:12], "big")
    if rver != 1:
        return "record_version"
    if plen > 4096 or len(v) != 12 + plen + 4:
        return "envelope_len"
    try:
        if d3s1.crc32c(v[:-4]) != struct.unpack(">I", v[-4:])[0]:
            return "crc"
    except Exception:
        return "crc"
    return None


def _d1_profile_key_ok(key: bytes) -> Optional[str]:
    if not (8 <= len(key) <= 255):
        return "profile_key_len"
    if key[:8] != DOMAIN_KEY_ROOT:
        return "root"
    if key[8] not in (1, 2, 3, 4):
        return "profile_family"
    return None


def _d1_domain_key_ok(key: bytes) -> Optional[str]:
    if not (13 <= len(key) <= 45):
        return "domain_key_len"
    if key[:8] != DOMAIN_KEY_ROOT:
        return "root"
    fam, _st, kf, ik, il = key[8], key[9], key[10], key[11], key[12]
    if kf != 1:
        return "key_format"
    if 13 + il != len(key):
        return "identity_len_field"
    if fam not in (5, 6):
        return "domain_family"
    want = {1: 0, 2: 16, 3: 8, 4: 32, 5: 32}.get(ik)
    if want is None or il != want:
        return "identity_kind_len"
    return None


def _d1_domain_envelope_ok(
    value: bytes,
    *,
    expect_subtype: int,
    expect_flags: int,
    expect_record_type: Optional[int] = None,
) -> Optional[str]:
    """Common domain envelope. family6 business rows require record_type exact 6."""
    err = _d1_nlr1_framing(value)
    if err is not None:
        return err
    rtype = int.from_bytes(value[4:6], "big")
    plen = int.from_bytes(value[8:12], "big")
    if expect_record_type is not None:
        if rtype != expect_record_type:
            return "record_type"
    elif rtype not in (5, 6):
        return "record_type"
    if plen < 96:
        return "payload_lt_common"
    if int.from_bytes(value[12:14], "big") != 1:
        return "domain_format"
    if value[14] != (expect_subtype & 0xFF):
        return "subtype_mismatch"
    if value[15] != (expect_flags & 0xFF):
        return "flags_mismatch"
    body_len = int.from_bytes(value[104:108], "big")
    if body_len != plen - 96 or 108 + body_len + 4 != len(value):
        return "body_framing"
    if int.from_bytes(value[16:24], "big") < 1:
        return "revision0"
    return None


def _d1_blob_owner_pair_ok(owner_kind: int, blob_kind: int) -> bool:
    return (owner_kind, blob_kind) in {
        (1, 1), (1, 2), (2, 3), (2, 4), (3, 1), (3, 2), (3, 5),
    }


def _d1_blob_owner_raw_ok(owner_kind: int, owner_raw: bytes) -> bool:
    """BLOB owner_key_raw canonical identity (docs/17 §8.4) — not length-only.

    TRANSACTION: exact 16-byte nonzero transaction ID.
    INGRESS: exact 8-byte big-endian ordered_sequence > 0.
    DELIVERY: exact 80-byte canonical delivery key; each of five 16-byte IDs nonzero.
    Other owner kinds are not in the BLOB owner enum (fail closed).
    """
    if owner_kind == 1:  # TRANSACTION
        return len(owner_raw) == 16 and owner_raw != D1_ZERO32[:16]
    if owner_kind == 2:  # INGRESS
        if len(owner_raw) != 8:
            return False
        return struct.unpack(">Q", owner_raw)[0] >= 1
    if owner_kind == 3:  # DELIVERY
        if len(owner_raw) != 80:
            return False
        for i in range(5):
            if owner_raw[i * 16 : (i + 1) * 16] == bytes(16):
                return False
        return True
    return False


def _d1_blob_manifest_row_ok(key: bytes, value: bytes) -> Optional[str]:
    err = _d1_domain_envelope_ok(
        value, expect_subtype=0x30, expect_flags=1, expect_record_type=6
    )
    if err is not None:
        return f"man_env:{err}"
    body = body_of(value)
    if len(body) < 44:
        return "man_body_short"
    bid = body[0:32]
    owner_kind = struct.unpack(">H", body[32:34])[0]
    blob_kind = struct.unpack(">H", body[34:36])[0]
    rl = struct.unpack(">H", body[36:38])[0]
    if 38 + rl + 32 + 8 + 4 + 32 != len(body):
        return "man_body_exact"
    owner_raw = body[38 : 38 + rl]
    opkd = body[38 + rl : 38 + rl + 32]
    base = 38 + rl + 32
    total = struct.unpack(">Q", body[base : base + 8])[0]
    count = struct.unpack(">I", body[base + 8 : base + 12])[0]
    cd = body[base + 12 : base + 44]
    if bid == D1_ZERO32 or cd == D1_ZERO32:
        return "man_zero_digest"
    if not _d1_blob_owner_pair_ok(owner_kind, blob_kind):
        return "man_owner_pair"
    if not _d1_blob_owner_raw_ok(owner_kind, owner_raw):
        return "man_owner_raw"
    try:
        if opkd != blob_owner_pkd(owner_kind, owner_raw):
            return "man_opkd"
        if bid != blob_id_digest(owner_kind, owner_raw, blob_kind, cd, total):
            return "man_blob_id"
    except ValueError:
        return "man_owner_derive"
    if count != chunk_count_for_total(total):
        return "man_count_vs_total"
    if total == 0 and cd != d3s1.sha256(b""):
        return "man_zero_cd"
    if value[40:72] == D1_ZERO32 or value[72:104] == D1_ZERO32:
        return "man_head_or_pvd_zero"
    if int.from_bytes(value[16:24], "big") != 1:
        return "man_revision"
    want_k = d3s1.bkey(6, 0x30, 5, d3s1.composite(0x30, bytes([1]) + bid))
    if key != want_k:
        return "man_key_formula"
    try:
        want_pid = blob_owner_primary_id(owner_kind, owner_raw)
    except ValueError:
        return "man_primary_id_owner"
    if value[24:40] != want_pid:
        return "man_primary_id"
    return None


def _d1_blob_chunk_row_ok(key: bytes, value: bytes) -> Optional[str]:
    err = _d1_domain_envelope_ok(
        value, expect_subtype=0x30, expect_flags=2, expect_record_type=6
    )
    if err is not None:
        return f"chk_env:{err}"
    body = body_of(value)
    if len(body) < 116:
        return "chk_body_short"
    bid = body[0:32]
    mkd = body[32:64]
    index = struct.unpack(">I", body[64:68])[0]
    count = struct.unpack(">I", body[68:72])[0]
    total = struct.unpack(">Q", body[72:80])[0]
    cd = body[80:112]
    dlen = struct.unpack(">I", body[112:116])[0]
    if 116 + dlen != len(body):
        return "chk_body_exact"
    data = body[116 : 116 + dlen]
    if bid == D1_ZERO32 or mkd == D1_ZERO32 or cd == D1_ZERO32:
        return "chk_zero_digest"
    if count == 0 or index >= count or total == 0 or dlen == 0 or dlen > BLOB_CHUNK_DATA_MAX:
        return "chk_local_shape"
    if count != chunk_count_for_total(total):
        return "chk_count_vs_total"
    if index + 1 < count:
        if dlen != BLOB_CHUNK_DATA_MAX:
            return "chk_nonfinal_len"
    else:
        prior = (count - 1) * BLOB_CHUNK_DATA_MAX
        if total <= prior:
            return "chk_final_total"
        final_len = total - prior
        if final_len < 1 or final_len > BLOB_CHUNK_DATA_MAX or final_len != dlen:
            return "chk_final_len"
    man_k = d3s1.bkey(6, 0x30, 5, d3s1.composite(0x30, bytes([1]) + bid))
    if mkd != d3s1.key_digest(man_k):
        return "chk_manifest_key_digest"
    if count == 1 and cd != d3s1.sha256(data):
        return "chk_single_content_digest"
    want_k = d3s1.bkey(
        6, 0x30, 5, d3s1.composite(0x30, bytes([2]) + bid + struct.pack(">I", index))
    )
    if key != want_k:
        return "chk_key_formula"
    if value[40:72] == D1_ZERO32 or value[72:104] == D1_ZERO32:
        return "chk_head_or_pvd_zero"
    if int.from_bytes(value[16:24], "big") != 1:
        return "chk_revision"
    if value[24:40] != man_k[13:29]:
        return "chk_primary_id"
    return None


