_D1_REASON_FAILED = frozenset({
    22,  # TARGET_UNAUTHORIZED
    _D1_R_RETRY_BUDGET_EXHAUSTED,  # 70
    _D1_R_OPERATOR_DISCARDED,  # 80
    128,  # APPLICATION_FAILED
})
# AWAITING (public TXN_AWAITING_EVIDENCE ← AWAITING_RECEIPT/EVIDENCE/GRACE):
#   0 NONE after accepted-send reset
#   68 EFFECT_POSSIBLE_EVIDENCE_PENDING after EFFECT_DEADLINE with effect possible
#   83 CANCEL_AFTER_EFFECT_POSSIBLE after TOO_LATE cancel result (still AWAITING)
#   86 CANCEL_PENDING_REMOTE_FENCE while remote cancel outstanding
#   128/129 EFFECT_POSSIBLE + RETRY_OPERATOR_ACTION Disposition (AWAITING only;
#   automatic retry 0; terminalize later via evidence close 69 / clock 20)
_D1_REASON_AWAITING = frozenset({
    0,
    _D1_R_EFFECT_PENDING,  # 68
    _D1_R_CANCEL_AFTER_EFFECT,  # 83
    _D1_R_CANCEL_PENDING_REMOTE,  # 86
    128,  # APPLICATION_FAILED (effect-possible Disposition)
    129,  # OUTCOME_UNKNOWN (effect-possible Disposition; not terminal)
})
# WAITING (public TXN_WAITING_WINDOW ← RETRY_WAIT/RECONCILE_WAIT): only reasons that
# actually open a retry window (docs/13). Terminal-only / AWAITING-only reasons RED.
_D1_REASON_WAITING = frozenset({
    11,  # CAPACITY_EXHAUSTED (NO_EFFECT + RETRY_SAME_AFTER)
    _D1_R_TRANSPORT_RETRY,  # 85 TX_GATE TEMPORARY / Bearer WOULD_BLOCK|UNAVAILABLE
    128,  # APPLICATION_FAILED (APPLY_FAILED NO_EFFECT + RETRY_SAME_AFTER)
    130,  # RECEIVER_UNAVAILABLE (APPLICATION_BUSY)
    132,  # RECONCILE_RETRY_LATER (RETRY_LATER)
})
# EventFact AWAITING closed set = {NONE(0)} only (docs/13 §964/§1061/§1149,
# docs/12 §1758). EventFact has no deadline and no cancel; operator-action
# Disposition parks (PARKED_RETRY), and the normal accepted-send AWAITING commit
# resets reason to NONE. So 68 (deadline-after evidence wait, DS deadline),
# 83/86 (cancel-family, DS-only), 128/129 (operator-action Disposition → EF parks)
# are all EF-illegal in AWAITING.
_D1_REASON_AWAITING_EF = frozenset({0})
# EventFact WAITING: DesiredState WAITING set minus CAPACITY_EXHAUSTED(11). For
# EventFact, CAPACITY_EXHAUSTED/NO_EFFECT_PROVEN parks immediately (PARKED_RETRY +
# CAPACITY_UNAVAILABLE), never a retry window (docs/13 §964/§999).
_D1_REASON_WAITING_EF = _D1_REASON_WAITING - frozenset({
    11,  # CAPACITY_EXHAUSTED
})
# EventFact terminal Outcomes: Receipt → SATISFIED; audited discard → FAILED only
# (docs/12: EF stays OUTCOME_NONE until terminal Receipt or explicit discard).
_D1_EF_TERMINAL_OUTCOMES = frozenset({_D1_OUT_SATISFIED, _D1_OUT_FAILED})
_D1_M1A_ATTEMPTS_PER_CYCLE = 8
_D1_STATE_BODY_LEN = 224
_D1_TEXT_ID_MAX = 63
_D1_PRESENCE_DEVICE = 1
_D1_PRESENCE_INSTALLATION = 2
_D1_PRESENCE_SITE = 4
_D1_PRESENCE_ALLOWED = 7
# CANCEL_STATE closed public bijection + gates (docs/17 §8.4).
_D1_CS_NONE, _D1_CS_PEND, _D1_CS_FENCED, _D1_CS_TOO_LATE = 1, 2, 3, 4
_D1_CK_NONE, _D1_CK_FENCED, _D1_CK_PEND, _D1_CK_TOO_LATE = 0, 1, 2, 3
_D1_GATE_NEVER, _D1_GATE_RETRY, _D1_GATE_CLOSED = 1, 2, 3
_D1_R_PEND, _D1_R_FENCED, _D1_R_TOO_LATE = 86, 82, 83
_D1_E_NONE, _D1_E_NO_EFFECT, _D1_E_POSSIBLE = 0, 1, 2
_D1_CS_OWNER_TX, _D1_CS_OWNER_DLV = 1, 2
# EVENT_SPOOL
_D1_ES_ACTIVE, _D1_ES_PARKED, _D1_ES_RELEASED, _D1_ES_DISCARDED = 1, 2, 3, 4
_D1_ES_RESUME_MAX = 8
# REVERSE_REPLY send states (docs/17 §8.5 D1-B3j)
_D1_RR_PENDING, _D1_RR_WAIT, _D1_RR_CLOSED_SENT, _D1_RR_CLOSED_DENY, _D1_RR_EXHAUSTED = (
    1, 2, 3, 4, 5,
)
# ORDERED_INGRESS
_D1_ING_STATE_PENDING = 1
_D1_BIND_EXISTING_TX, _D1_BIND_EXISTING_DLV, _D1_BIND_NEW_DLV = 1, 2, 3
_D1_CLOCK_TRUST = frozenset({1, 2})  # TRUSTED / UNCERTAIN (production)
# Disposition / effect / retry_guidance closed (docs/12 §7.2 + version.h).
_D1_DISP_NONE = 0
_D1_DISP_RETRY_LATER = 1
_D1_DISP_INVALID_PAYLOAD = 2
_D1_DISP_UNSUPPORTED_SCHEMA = 3
_D1_DISP_UNAUTHORIZED_SERVICE = 4
_D1_DISP_STALE_NOT_APPLIED = 5
_D1_DISP_APPLICATION_BUSY = 6
_D1_DISP_APPLY_FAILED = 7
_D1_DISP_VERIFY_FAILED = 8
_D1_DISP_CAPACITY_EXHAUSTED = 9
_D1_DISP_OUTCOME_UNKNOWN = 10
_D1_EFF_NONE = 0
_D1_EFF_NO_EFFECT = 1
_D1_EFF_POSSIBLE = 2
_D1_RG_NEVER = 0
_D1_RG_SAME_AFTER = 1
_D1_RG_MODIFIED = 2
_D1_RG_OPERATOR = 3
_D1_MAX_RETRY_DELAY_MS = 600000
# E_REC public reasons (docs/17 §8.5 / docs/12 reason registry).
_D1_R_CALLBACK_CONTRACT = 23
_D1_R_COUNTER_EXHAUSTED = 76
_D1_R_APPLICATION_FAILED = 128
_D1_R_OUTCOME_UNKNOWN = 129
_D1_R_RECEIVER_UNAVAILABLE = 130
_D1_R_APP_COMPLETION_TIMEOUT = 131
_D1_R_RECONCILE_RETRY_LATER = 132
_D1_R_TARGET_UNAUTHORIZED = 22
_D1_R_CAPACITY_EXHAUSTED = 11
# Used family6 subtypes in D3-S3 suffix / independent gate.
_D1_USED_FAMILY6 = frozenset({0x20, 0x22, 0x27, 0x30, 0x32, 0x33, 0x40, 0x41, 0x42, 0x50})
# Immutable primary subtypes: common record_revision exact 1 (docs/17 §4 / §8).
_D1_IMMUTABLE_REV1 = frozenset({0x20, 0x27, 0x40})  # ANCHOR / ORDERED_INGRESS / DELIVERY
# BLOB man+chunk also immutable rev1 (enforced in blob validators).
# RESULT_CACHE token_state (docs/17 §8.5) — defined early for E_REC helpers.
_D1_TOK_NONE = 1
_D1_TOK_ACTIVE = 2
_D1_TOK_CONSUMED = 3
_D1_TOK_EXPIRED = 4
_D1_TOK_RECOVERY_TOMB = 5
_D1_TOK_RETAINED = frozenset({_D1_TOK_CONSUMED, _D1_TOK_EXPIRED, _D1_TOK_RECOVERY_TOMB})


def _d1_id_zero(b: bytes) -> bool:
    return b == bytes(len(b))


def _d1_reason_public_ok(reason: int) -> bool:
    """docs/12 / production public reason ranges (not C oracle)."""
    if reason == 0:
        return True
    if 1 <= reason <= 24:
        return True
    if 64 <= reason <= 66:
        return True
    if 68 <= reason <= 86:
        return True
    if 128 <= reason <= 132:
        return True
    if reason in (4096, 4097):
        return True
    return False


def _d1_ascii_lower_or_digit(b: int) -> bool:
    return (ord("a") <= b <= ord("z")) or (ord("0") <= b <= ord("9"))


def _d1_text_id_wire_ok(buf: bytes, o: int, *, namespace_grammar: bool) -> Optional[int]:
    """Parse one TEXT_ID; return new offset or None."""
    if o >= len(buf):
        return None
    n = buf[o]
    if n < 1 or n > _D1_TEXT_ID_MAX or o + 1 + n > len(buf):
        return None
    data = buf[o + 1 : o + 1 + n]
    if not _d1_ascii_lower_or_digit(data[0]):
        return None
    for ch in data[1:]:
        if _d1_ascii_lower_or_digit(ch):
            continue
        if ch in (ord("."), ord("-")):
            continue
        if not namespace_grammar and ch == ord("_"):
            continue
        return None
    return o + 1 + n


def _d1_presence_ok(
    flags: int,
    device: bytes,
    installation: bytes,
    site: bytes,
    binding_epoch: int,
    membership_epoch: int,
) -> bool:
    if flags & ~_D1_PRESENCE_ALLOWED:
        return False
    has_d = (flags & _D1_PRESENCE_DEVICE) != 0
    has_i = (flags & _D1_PRESENCE_INSTALLATION) != 0
    has_s = (flags & _D1_PRESENCE_SITE) != 0
    if _d1_id_zero(device) == has_d:
        return False
    if _d1_id_zero(installation) == has_i:
        return False
    if _d1_id_zero(site) == has_s:
        return False
    if (binding_epoch != 0) != (has_d or has_i):
        return False
    if (membership_epoch != 0) != has_s:
        return False
    return True


def _d1_party_ok(party: bytes) -> bool:
    if len(party) != d3s1.PARTY_LEN:
        return False
    rt, app = party[0:16], party[16:32]
    if _d1_id_zero(rt) or _d1_id_zero(app):
        return False
    flags = struct.unpack(">I", party[32:36])[0]
    device, installation, site = party[36:52], party[52:68], party[68:84]
    be = struct.unpack(">Q", party[84:92])[0]
    me = struct.unpack(">Q", party[92:100])[0]
    return _d1_presence_ok(flags, device, installation, site, be, me)


def _d1_party_all_zero(party: bytes) -> bool:
    return len(party) == d3s1.PARTY_LEN and party == bytes(d3s1.PARTY_LEN)


def _d1_target_ok(target: bytes) -> bool:
    if len(target) != d3s1.TARGET_LEN:
        return False
    flags = struct.unpack(">I", target[0:4])[0]
    trt, tapp = target[4:20], target[20:36]
    if _d1_id_zero(trt) or _d1_id_zero(tapp):
        return False
    device, installation, site = target[36:52], target[52:68], target[68:84]
    be = struct.unpack(">Q", target[84:92])[0]
    me = struct.unpack(">Q", target[92:100])[0]
    return _d1_presence_ok(flags, device, installation, site, be, me)


def _d1_service_identity_ok(si: bytes) -> Optional[Tuple[int, int]]:
    """Return (family, end_offset_in_si) or None if invalid. si is the full SI blob."""
    o = 0
    for ns_gram in (True, False, False):
        o2 = _d1_text_id_wire_ok(si, o, namespace_grammar=ns_gram)
        if o2 is None:
            return None
        o = o2
    if o + 8 + 32 + 2 + 2 + 4 != len(si):
        return None
    rev = struct.unpack(">Q", si[o : o + 8])[0]
    o += 8
    dig = si[o : o + 32]
    o += 32
    o += 2 + 2  # major/minor
    family = struct.unpack(">I", si[o : o + 4])[0]
    if rev == 0 or dig == D1_ZERO32 or family not in _D1_FAMILY_M1A:
        return None
    return family, len(si)


def _d1_parse_service_at(buf: bytes, o: int) -> Optional[Tuple[bytes, int, int]]:
    """Parse SERVICE_IDENTITY at offset; return (si_bytes, family, new_off) or None."""
    start = o
    for ns_gram in (True, False, False):
        o2 = _d1_text_id_wire_ok(buf, o, namespace_grammar=ns_gram)
        if o2 is None:
            return None
        o = o2
    if o + 8 + 32 + 2 + 2 + 4 > len(buf):
        return None
    rev = struct.unpack(">Q", buf[o : o + 8])[0]
    dig = buf[o + 8 : o + 40]
    family = struct.unpack(">I", buf[o + 44 : o + 48])[0]
    end = o + 48
    if rev == 0 or dig == D1_ZERO32 or family not in _D1_FAMILY_M1A:
        return None
    return buf[start:end], family, end


def _d1_scope_raw_from_party_si(party: bytes, si: bytes) -> Optional[bytes]:
    """scope = application_instance_id || namespace TEXT_ID wire || service TEXT_ID wire."""
    if len(party) != d3s1.PARTY_LEN:
        return None
    app = party[16:32]
    o = 0
    o2 = _d1_text_id_wire_ok(si, o, namespace_grammar=True)
    if o2 is None:
        return None
    ns_wire = si[o:o2]
    o = o2
    o3 = _d1_text_id_wire_ok(si, o, namespace_grammar=False)
    if o3 is None:
        return None
    svc_wire = si[o:o3]
    return app + ns_wire + svc_wire


def _d1_raw16(raw: bytes) -> bytes:
    return struct.pack(">H", len(raw)) + raw


def _d1_common_business(
    value: bytes, st: int, *, primary_zero_pvd: bool
) -> Optional[str]:
    err = _d1_domain_envelope_ok(
        value, expect_subtype=st, expect_flags=0, expect_record_type=6
    )
    if err is not None:
        return f"env:{err}"
    if value[40:72] == D1_ZERO32:
        return "head_zero"
    pvd = value[72:104]
    if primary_zero_pvd:
        if pvd != D1_ZERO32:
            return "pvd_must_zero"
    elif pvd == D1_ZERO32:
        return "pvd_zero"
    # Immutable primary: record_revision exact 1 (docs/17). Mutable: >=1 (envelope).
    if st in _D1_IMMUTABLE_REV1:
        if int.from_bytes(value[16:24], "big") != 1:
            return "revision_ne1"
    return None


def _d1_disposition_tuple_ok(
    disposition: int, effect: int, guidance: int, retry_delay: int
) -> bool:
    """docs/12 §7.2 disposition closed product (Bearer DISPOSITION + RESULT E_DISP)."""
    if disposition == _D1_DISP_RETRY_LATER:
        return (
            effect == _D1_EFF_NO_EFFECT
            and guidance == _D1_RG_SAME_AFTER
            and 0 <= retry_delay <= _D1_MAX_RETRY_DELAY_MS
        )
    if disposition in (_D1_DISP_INVALID_PAYLOAD, _D1_DISP_UNSUPPORTED_SCHEMA):
        return (
            effect == _D1_EFF_NO_EFFECT
            and guidance == _D1_RG_MODIFIED
            and retry_delay == 0
        )
    if disposition == _D1_DISP_UNAUTHORIZED_SERVICE:
        return (
            effect == _D1_EFF_NO_EFFECT
            and guidance == _D1_RG_MODIFIED
            and retry_delay == 0
        )
    if disposition == _D1_DISP_STALE_NOT_APPLIED:
        return (
            effect == _D1_EFF_NO_EFFECT
            and guidance == _D1_RG_NEVER
            and retry_delay == 0
        )
    if disposition in (_D1_DISP_APPLICATION_BUSY, _D1_DISP_CAPACITY_EXHAUSTED):
        return (
            effect == _D1_EFF_NO_EFFECT
            and guidance == _D1_RG_SAME_AFTER
            and 0 <= retry_delay <= _D1_MAX_RETRY_DELAY_MS
        )
    if disposition == _D1_DISP_APPLY_FAILED:
        if (
            effect == _D1_EFF_NO_EFFECT
            and guidance == _D1_RG_SAME_AFTER
            and 0 <= retry_delay <= _D1_MAX_RETRY_DELAY_MS
        ):
            return True
        return (
            effect == _D1_EFF_POSSIBLE
            and guidance == _D1_RG_OPERATOR
            and retry_delay == 0
        )
    if disposition in (_D1_DISP_VERIFY_FAILED, _D1_DISP_OUTCOME_UNKNOWN):
        return (
            effect == _D1_EFF_POSSIBLE
            and guidance == _D1_RG_OPERATOR
            and retry_delay == 0
        )
    return False


def _d1_disp_reason_ok(disposition: int, reason: int, effect: int) -> bool:
    """RESULT_CACHE E_DISP reason mapping (docs/12 §7.2 → reason registry)."""
    if disposition == _D1_DISP_RETRY_LATER:
        return reason == _D1_R_RECONCILE_RETRY_LATER
    if disposition in (
        _D1_DISP_INVALID_PAYLOAD,
        _D1_DISP_UNSUPPORTED_SCHEMA,
        _D1_DISP_STALE_NOT_APPLIED,
        _D1_DISP_APPLY_FAILED,
        _D1_DISP_VERIFY_FAILED,
    ):
        return reason == _D1_R_APPLICATION_FAILED
    if disposition == _D1_DISP_UNAUTHORIZED_SERVICE:
        return reason == _D1_R_TARGET_UNAUTHORIZED
    if disposition == _D1_DISP_APPLICATION_BUSY:
        return reason == _D1_R_RECEIVER_UNAVAILABLE
    if disposition == _D1_DISP_CAPACITY_EXHAUSTED:
        return reason == _D1_R_CAPACITY_EXHAUSTED
    if disposition == _D1_DISP_OUTCOME_UNKNOWN:
        return reason == _D1_R_OUTCOME_UNKNOWN and effect == _D1_EFF_POSSIBLE
    return False


def _d1_e_rec_reason_guidance_ok(reason: int, guidance: int) -> bool:
    if reason in (
        _D1_R_APPLICATION_FAILED,
        _D1_R_CALLBACK_CONTRACT,
        _D1_R_COUNTER_EXHAUSTED,
        _D1_R_OUTCOME_UNKNOWN,
    ):
        return guidance == _D1_RG_OPERATOR
    if reason == _D1_R_APP_COMPLETION_TIMEOUT:
        return guidance == _D1_RG_SAME_AFTER
    return False


def _d1_e_rec_token_pair_ok(reason: int, token_state: int, n: int) -> bool:
    """docs/17 §8.5 E_REC reason × token_state for physical state 6/7."""
    retained = token_state in _D1_TOK_RETAINED
    if reason == _D1_R_APP_COMPLETION_TIMEOUT:
        return n >= 1 and token_state == _D1_TOK_EXPIRED
    if reason == _D1_R_APPLICATION_FAILED:
        return n >= 1 and token_state == _D1_TOK_RECOVERY_TOMB
    if reason == _D1_R_CALLBACK_CONTRACT:
        return n >= 1 and retained
    if reason == _D1_R_OUTCOME_UNKNOWN:
        return n >= 1 and token_state in (_D1_TOK_EXPIRED, _D1_TOK_RECOVERY_TOMB)
    if reason == _D1_R_COUNTER_EXHAUSTED:
        return n == UINT64_MAX and retained
    return False


def _d1_zero_disposition_tuple_ok(
    disposition: int, effect: int, guidance: int, retry_delay: int
) -> bool:
    return (
        disposition == _D1_DISP_NONE
        and effect == _D1_EFF_NONE
        and guidance == _D1_RG_NEVER
        and retry_delay == 0
    )


def _d1_service_slot_ok(svc_slot: bytes) -> Optional[int]:
    """Return SI family if fixed 240-byte service_slot is material-encoded; else None."""
    if len(svc_slot) != 240:
        return None
    for end in range(54, 241):
        cand = svc_slot[:end]
        if _d1_service_identity_ok(cand) is not None and svc_slot[end:] == bytes(240 - end):
            si_ok = _d1_service_identity_ok(cand)
            assert si_ok is not None
            return si_ok[0]
    return None


def _d1_parse_raw16_at(buf: bytes, o: int) -> Tuple[Optional[bytes], int]:
    if o + 2 > len(buf):
        return None, o
    n = struct.unpack(">H", buf[o : o + 2])[0]
    o += 2
    if o + n > len(buf):
        return None, o
    return buf[o : o + n], o + n


def _d1_skip_service_identity(buf: bytes, o: int) -> Optional[int]:
    try:
        return d3s1.skip_service_identity(buf, o)
    except Exception:
        return None


def _d1_res_kd_tx(tx: bytes) -> bytes:
    return d3s1.complete_key_digest_composite(
        0x23, struct.pack(">H", 2) + d3s1.raw16(tx)
    )


def _d1_anchor_row_ok(key: bytes, value: bytes) -> Optional[str]:
    """TRANSACTION_ANCHOR (0x20): complete Normative same-record (docs/17 §8.2)."""
    err = _d1_common_business(value, 0x20, primary_zero_pvd=True)
    if err is not None:
        return err
    body = body_of(value)
    o = 0
    if len(body) < 48:
        return "anchor_body_len"
    tx = body[0:16]
    o = 16
    if tx == bytes(16):
        return "anchor_tx_zero"
    if key != d3s1.bkey(6, 0x20, 2, tx):
        return "anchor_key"
    if value[24:40] != tx:
        return "anchor_primary_id"
    txn_seq = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    if txn_seq < 1:
        return "anchor_txn_seq"
    sched_owner_seq = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    if sched_owner_seq < 1:
        return "anchor_sched_seq"
    family = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    if family not in _D1_FAMILY_M1A:
        return "anchor_family"
    if o + d3s1.PARTY_LEN > len(body):
        return "anchor_body_len"
    party = body[o : o + d3s1.PARTY_LEN]
    o += d3s1.PARTY_LEN
    if not _d1_party_ok(party):
        return "anchor_party"
    parsed = _d1_parse_service_at(body, o)
    if parsed is None:
        return "anchor_service"
    si, si_family, o = parsed
    if si_family != family:
        return "anchor_service_family"
    if o + 32 + 32 + 16 + 8 > len(body):
        return "anchor_body_len"
    content = body[o : o + 32]
    o += 32
    canon = body[o : o + 32]
    o += 32
    if content == D1_ZERO32 or canon == D1_ZERO32:
        return "anchor_content_canon"
    event_id = body[o : o + 16]
    o += 16
    generation = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    if o + 16 + 8 + 16 + 8 + 8 + 4 + 4 + d3s1.TARGET_LEN > len(body):
        return "anchor_body_len"
    adm_ep = body[o : o + 16]
    o += 16
    _adm_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    ddl_ep = body[o : o + 16]
    o += 16
    abs_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    grace = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    if _d1_id_zero(adm_ep):
        return "anchor_adm_epoch"
    req = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    if req not in _D1_EVIDENCE_REQ:
        return "anchor_required_evidence"
    target_count = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    if target_count != 1:
        return "anchor_target_count"
    target = body[o : o + d3s1.TARGET_LEN]
    o += d3s1.TARGET_LEN
    if not _d1_target_ok(target):
        return "anchor_target"
    scope, o = _d1_parse_raw16_at(body, o)
    if scope is None or len(scope) == 0 or len(scope) > 255:
        return "anchor_scope"
    want_scope = _d1_scope_raw_from_party_si(party, si)
    if want_scope is None or scope != want_scope:
        return "anchor_scope_identity"
    ikey, o = _d1_parse_raw16_at(body, o)
    if ikey is None or len(ikey) == 0 or len(ikey) > 64:
        return "anchor_ikey"
    if o + 32 * 4 + 8 + 32 != len(body):
        return "anchor_body_len"
    seq_kd = body[o : o + 32]
    o += 32
    im_kd = body[o : o + 32]
    o += 32
    event_map = body[o : o + 32]
    o += 32
    res_kd = body[o : o + 32]
    o += 32
    sched_key_seq = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    payload_dig = body[o : o + 32]
    if payload_dig == D1_ZERO32:
        return "anchor_payload_dig_zero"
    if sched_key_seq != sched_owner_seq:
        return "anchor_sched_key_seq"
    want_seq = d3s1.complete_key_digest_u64(0x21, struct.pack(">Q", txn_seq))
    if seq_kd != want_seq:
        return "anchor_seq_kd"
    want_im = d3s1.complete_key_digest_composite(
        0x24, d3s1.raw16(scope) + d3s1.raw16(ikey)
    )
    if im_kd != want_im:
        return "anchor_im_kd"
    want_res = _d1_res_kd_tx(tx)
    if res_kd != want_res:
        return "anchor_res_kd"
    is_event = family == 1
    if is_event:
        if event_id == bytes(16):
            return "anchor_ef_event_zero"
        if generation != 0:
            return "anchor_ef_generation"
        if not _d1_id_zero(ddl_ep):
            return "anchor_ef_deadline_epoch"
        if abs_ms != UINT64_MAX:
            return "anchor_ef_abs_deadline"
        if grace != 0:
            return "anchor_ef_grace"
        want_em = d3s1.complete_key_digest_composite(
            0x25, d3s1.raw16(scope) + event_id
        )
        if event_map != want_em:
            return "anchor_event_map_kd"
    else:
        if event_id != bytes(16):
            return "anchor_ds_event_nz"
        if event_map != D1_ZERO32:
            return "anchor_ds_event_map_nz"
        if generation == 0:
            return "anchor_ds_generation"
        if _d1_id_zero(ddl_ep) or abs_ms == UINT64_MAX:
            return "anchor_ds_deadline"
        if ddl_ep != adm_ep:
            return "anchor_ds_deadline_epoch_pair"
    return None


def _d1_state_row_ok(key: bytes, value: bytes) -> Optional[str]:
    """TRANSACTION_STATE (0x22): closed family×state×outcome×deadline×reason×evidence×dep.

    Authority: docs/12 public snapshot + docs/13 Normative reducers + Disposition matrix
    + clock-uncertainty recovery (not production C). Family by deadline_verdict:
      EventFact ⇒ deadline always NOT_APPLICABLE; DesiredState ⇒ never NA.
    R27 closed product (re-extracted; closes R26 Root QA residual NO-GO holes):
    - nonterminal ⇒ outcome NONE; TERMINAL ⇒ five reachable Outcomes only
    - READY/DISPATCHING ⇒ reason NONE + park NONE; DS deadline PENDING only
    - AWAITING ⇒ reason ∈ {0, 68, 83, 86, 128, 129} (effect-possible Disposition)
    - PARKED ⇒ EventFact only; reason EVENT_RETRY_CYCLE_PARKED; park∈1..5
    - WAITING ⇒ reason ∈ {11, 85, 128, 130, 132} only (retry-window creators)
    - TERMINAL outcome↔reason exclusive (docs/13):
        SATISFIED={64}; EXPIRED={65,66,20}; UNKNOWN={69,20} only
          (evidence close 69; clock uncertainty effect-possible 20;
           Disposition reason 129 is AWAITING-only — not terminal);
        CANCELLED={82}; FAILED={22,70,80,128}
      20 CLOCK_UNCERTAIN is legal for EXPIRED and UNKNOWN only (shared);
      65 is EXPIRED not SATISFIED; 83/86/129 are AWAITING-only;
      EF forbids EXPIRED/CANCELLED (Receipt or discard only)
    - discard bijection OPERATOR_DISCARDED ⇔ discarded=1 ⇔ TERMINAL+FAILED (EF)
    - DS counters retry/attempt/es_rev all 0; EF es_rev≥1 and retry≥1
    - cumulative_attempts ≥ attempt_in_cycle; has_late=1 ⇒ latest∈1..4;
      TERMINAL+SATISFIED ⇒ latest∈1..4; TERMINAL+EXPIRED+65 ⇒ latest∈1..4
    - target_* mirrors exact
    """
    err = _d1_common_business(value, 0x22, primary_zero_pvd=False)
    if err is not None:
        return err
    body = body_of(value)
    if len(body) != _D1_STATE_BODY_LEN:
        return "state_body_len"
    tx = body[0:16]
    if tx == bytes(16):
        return "state_tx_zero"
    if key != d3s1.bkey(6, 0x22, 2, tx):
        return "state_key"
    if value[24:40] != tx:
        return "state_primary_id"
    o = 16
    avd = body[o : o + 32]
    o += 32
    if avd == D1_ZERO32:
        return "state_anchor_vd"
    state = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    outcome = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    ddl_v = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    latest = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    reason = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    park = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    retry = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    attempt_in = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    cumul = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    es_rev = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    has_late = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    discarded = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    target = body[o : o + d3s1.TARGET_LEN]
    o += d3s1.TARGET_LEN
    if o + 16 > len(body):
        return "state_body_len"
    t_state = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    t_outcome = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    t_reason = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    t_latest = struct.unpack(">I", body[o : o + 4])[0]
    if state not in _D1_TXN_STATES:
        return "state_enum"
    if outcome not in _D1_OUTCOMES:
        return "state_outcome"
    if ddl_v not in _D1_DEADLINE_VERDICTS:
        return "state_deadline_verdict"
    if latest not in _D1_EVIDENCE_STAGES:
        return "state_latest_evidence"
    if not _d1_reason_public_ok(reason):
        return "state_reason"
    if reason in _D1_GENERATED_ZERO_REASONS:
        return "state_reason_generated_zero"
    if park not in _D1_PARK_CAUSES:
        return "state_park"
    if attempt_in > _D1_M1A_ATTEMPTS_PER_CYCLE:
        return "state_attempt_in_cycle"
    if has_late not in (0, 1):
        return "state_has_late"
    if discarded not in (0, 1):
        return "state_discarded"
    if not _d1_target_ok(target):
        return "state_target"
    if t_state != state or t_outcome != outcome or t_reason != reason or t_latest != latest:
        return "state_target_mirror"

    # ---- family discrimination (docs/12 family table: EF deadline always NA) ----
    is_ef = ddl_v == _D1_DDL_NA
    if is_ef:
        if retry < 1:
            return "state_retry_cycle"
        if es_rev < 1:
            return "state_es_revision"
    else:
        # DesiredState: park always NONE; discarded always 0; EF counters zero
        if park != _D1_PARK_NONE:
            return "state_park_family"
        if discarded != 0:
            return "state_discarded_family"
        if retry != 0:
            return "state_retry_cycle"
        if attempt_in != 0:
            return "state_attempt_in_cycle"
        if es_rev != 0:
            return "state_es_revision"

    # ---- dependent counters / evidence flags ----
    # cumulative_attempts is lifetime committed attempts ≥ current cycle attempts used
    if cumul < attempt_in:
        return "state_cumulative_attempts"
    # has_late_evidence=1 requires a non-NONE latest stage (late observation of something)
    if has_late == 1 and latest == 0:
        return "state_has_late_evidence"

    # ---- closed state × outcome pair ----
    if state in _D1_TXN_NONTERMINAL:
        if outcome != _D1_OUT_NONE:
            return "state_outcome_pair"
    elif state == _D1_TXN_TERMINAL:
        if outcome == _D1_OUT_SUPERSEDED_RESERVED:
            return "state_outcome_reserved"
        if outcome not in _D1_OUT_TERMINAL_REACHABLE:
            return "state_outcome_pair"
        # EventFact: only Receipt (SATISFIED) or audited discard (FAILED)
        if is_ef and outcome not in _D1_EF_TERMINAL_OUTCOMES:
            return "state_outcome_family"
    else:
        return "state_enum"

    # PARKED is EventFact-only (docs/12: Command does not generate PARKED_RETRY)
    if state == _D1_TXN_PARKED and not is_ef:
        return "state_parked_family"

    # ---- state-dependent reason / park / discard ----
    # NOTE (R28 r3): this D1 constructibility gate applies the shared reason sets
    # to both families. The Mode27 EventFact state-dependent reason closure
    # (EF AWAITING={0}; EF WAITING excludes CAPACITY_EXHAUSTED; EF DISPATCHING
    # consumes ≥1 attempt) is a Mode27 *adoption* rule enforced in the oracle
    # classifier (o1a_mode27_cross_row_ok) and production run_select_setup_mode27,
    # not here — so EF-shaped rows stay D1-constructible and the adoption guard is
    # independently regression-testable.
    if state in (_D1_TXN_READY, _D1_TXN_DISPATCHING):
        if reason != 0:
            return "state_reason_shape"
        if park != _D1_PARK_NONE:
            return "state_park_shape"
        if discarded != 0:
            return "state_discarded_shape"
    elif state == _D1_TXN_AWAITING:
        if park != _D1_PARK_NONE:
            return "state_park_shape"
        if discarded != 0:
            return "state_discarded_shape"
        # closed AWAITING reason product (64 REQUIRED_EVIDENCE_MET is terminal-only)
        if reason not in _D1_REASON_AWAITING:
            return "state_reason_shape"
    elif state == _D1_TXN_PARKED:
        if reason != _D1_R_EVENT_RETRY_CYCLE_PARKED:
            return "state_reason_shape"
        if park not in _D1_PARK_ACTIVE:
            return "state_park_shape"
        if discarded != 0:
            return "state_discarded_shape"
    elif state == _D1_TXN_WAITING:
        # WAITING: exact retry-window reason set only (docs/13 RETRY_WAIT creators)
        if reason not in _D1_REASON_WAITING:
            return "state_reason_shape"
        if park != _D1_PARK_NONE:
            return "state_park_shape"
        if discarded != 0:
            return "state_discarded_shape"
    elif state == _D1_TXN_TERMINAL:
        if park != _D1_PARK_NONE:
            return "state_park_shape"
        if reason == 0:
            return "state_reason_shape"
        # discard bijection: discarded=1 ⇔ OPERATOR_DISCARDED ⇔ TERMINAL+FAILED (EF only)
        if discarded == 1:
            if not is_ef:
                return "state_discarded_family"
            if outcome != _D1_OUT_FAILED or reason != _D1_R_OPERATOR_DISCARDED:
                return "state_discarded_shape"
        if reason == _D1_R_OPERATOR_DISCARDED and discarded != 1:
            return "state_discarded_shape"
        # EventFact terminal reason closed: Receipt or audited discard only
        if is_ef:
            if outcome == _D1_OUT_SATISFIED:
                # no deadline ⇒ only on-time required evidence (not LATE/EXPIRED)
                if reason != _D1_R_REQUIRED_EVIDENCE_MET:
                    return "state_outcome_reason"
            elif outcome == _D1_OUT_FAILED:
                if reason != _D1_R_OPERATOR_DISCARDED or discarded != 1:
                    return "state_outcome_reason"
        # outcome → reason closed product (docs/13 reducers; clock 20 shared exp/unk)
        if outcome == _D1_OUT_SATISFIED:
            if reason not in _D1_REASON_SATISFIED:
                return "state_outcome_reason"
            # required evidence terminal ⇒ latest stage known non-zero
            if latest == 0:
                return "state_latest_evidence"
        elif outcome == _D1_OUT_EXPIRED:
            if reason not in _D1_REASON_EXPIRED:
                return "state_outcome_reason"
            # late required evidence ⇒ latest stage known non-zero
            if reason == _D1_R_REQUIRED_EVIDENCE_LATE and latest == 0:
                return "state_latest_evidence"
        elif outcome == _D1_OUT_UNKNOWN:
            if reason not in _D1_REASON_UNKNOWN:
                return "state_outcome_reason"
        elif outcome == _D1_OUT_CANCELLED:
            if reason not in _D1_REASON_CANCELLED:
                return "state_outcome_reason"
        elif outcome == _D1_OUT_FAILED:
            if reason not in _D1_REASON_FAILED:
                return "state_outcome_reason"
        # exclusive reverse (clock 20 is shared EXPIRED|UNKNOWN — not exclusive either way)
        if reason in _D1_REASON_SATISFIED and outcome != _D1_OUT_SATISFIED:
            return "state_outcome_reason"
        if reason in (_D1_R_REQUIRED_EVIDENCE_LATE, _D1_R_DEADLINE_ELAPSED) and (
            outcome != _D1_OUT_EXPIRED
        ):
            return "state_outcome_reason"
        if reason == _D1_R_EFFECT_MISSING and outcome != _D1_OUT_UNKNOWN:
            return "state_outcome_reason"
        if reason in _D1_REASON_CANCELLED and outcome != _D1_OUT_CANCELLED:
            return "state_outcome_reason"
        if reason == _D1_R_CLOCK_UNCERTAIN and outcome not in (
            _D1_OUT_EXPIRED, _D1_OUT_UNKNOWN,
        ):
            return "state_outcome_reason"
        # FAILED-only exclusive reasons (22/70/80); 128 may also be AWAITING/WAITING
        # but at TERMINAL it must pair with FAILED
        if reason in (22, _D1_R_RETRY_BUDGET_EXHAUSTED, _D1_R_OPERATOR_DISCARDED) and (
            outcome != _D1_OUT_FAILED
        ):
            return "state_outcome_reason"
        if reason == 128 and outcome != _D1_OUT_FAILED:
            return "state_outcome_reason"
        if reason == _D1_R_EVENT_RETRY_CYCLE_PARKED:
            return "state_reason_shape"
        # AWAITING-only reasons never terminal (incl. Disposition OUTCOME_UNKNOWN=129)
        if reason in (
            _D1_R_CANCEL_PENDING_REMOTE, _D1_R_CANCEL_AFTER_EFFECT,
            _D1_R_EFFECT_PENDING, 129,
        ):
            return "state_reason_shape"

    # park reason exclusivity
    if reason == _D1_R_EVENT_RETRY_CYCLE_PARKED and state != _D1_TXN_PARKED:
        return "state_reason_shape"
    # 64 is terminal SATISFIED only
    if reason == _D1_R_REQUIRED_EVIDENCE_MET and (
        state != _D1_TXN_TERMINAL or outcome != _D1_OUT_SATISFIED
    ):
        return "state_reason_shape"
    # 65 is terminal EXPIRED only (not SATISFIED)
    if reason == _D1_R_REQUIRED_EVIDENCE_LATE and (
        state != _D1_TXN_TERMINAL or outcome != _D1_OUT_EXPIRED
    ):
        return "state_reason_shape"
    # 83 is AWAITING-only (too-late cancel; not terminal CANCELLED)
    if reason == _D1_R_CANCEL_AFTER_EFFECT and state != _D1_TXN_AWAITING:
        return "state_reason_shape"
    # 86 is AWAITING-only
    if reason == _D1_R_CANCEL_PENDING_REMOTE and state != _D1_TXN_AWAITING:
        return "state_reason_shape"
    # 68 is AWAITING-only (deadline-after evidence pending; not WAITING)
    if reason == _D1_R_EFFECT_PENDING and state != _D1_TXN_AWAITING:
        return "state_reason_shape"
    # 129 is AWAITING-only (Disposition matrix exact reason; terminal is 69/20)
    if reason == 129 and state != _D1_TXN_AWAITING:
        return "state_reason_shape"
    # 82 is terminal CANCELLED only
    if reason == _D1_R_CANCEL_FENCED and (
        state != _D1_TXN_TERMINAL or outcome != _D1_OUT_CANCELLED
    ):
        return "state_reason_shape"
    # 20 is terminal EXPIRED|UNKNOWN only
    if reason == _D1_R_CLOCK_UNCERTAIN and (
        state != _D1_TXN_TERMINAL
        or outcome not in (_D1_OUT_EXPIRED, _D1_OUT_UNKNOWN)
    ):
        return "state_reason_shape"

    # ---- family × state × outcome × deadline closed product (docs/12 table) ----
    if is_ef:
        # EventFact: always NOT_APPLICABLE (already enforced by is_ef)
        if ddl_v != _D1_DDL_NA:
            return "state_deadline_shape"
    else:
        # DesiredState
        if state in (_D1_TXN_READY, _D1_TXN_DISPATCHING):
            # active before deadline
            if ddl_v != _D1_DDL_PENDING:
                return "state_deadline_shape"
        elif state in (_D1_TXN_AWAITING, _D1_TXN_WAITING):
            # before deadline PENDING; unresolved after deadline INDETERMINATE
            if ddl_v not in (_D1_DDL_PENDING, _D1_DDL_INDETERMINATE):
                return "state_deadline_shape"
        elif state == _D1_TXN_TERMINAL:
            if outcome == _D1_OUT_SATISFIED:
                # proven in-time only (late evidence is EXPIRED+65, not SATISFIED)
                if ddl_v != _D1_DDL_MET:
                    return "state_deadline_shape"
                if reason != _D1_R_REQUIRED_EVIDENCE_MET:
                    return "state_deadline_shape"
            elif outcome == _D1_OUT_EXPIRED:
                if reason == _D1_R_CLOCK_UNCERTAIN:
                    # docs/13: clock uncertainty ⇒ deadline_verdict INDETERMINATE
                    if ddl_v != _D1_DDL_INDETERMINATE:
                        return "state_deadline_shape"
                else:
                    # 65 late evidence or 66 pre-dispatch elapsed ⇒ MISSED
                    if ddl_v != _D1_DDL_MISSED:
                        return "state_deadline_shape"
            elif outcome in (_D1_OUT_CANCELLED, _D1_OUT_FAILED):
                # before deadline proof PENDING; may already have MET/MISSED proof
                if ddl_v not in (_D1_DDL_PENDING, _D1_DDL_MET, _D1_DDL_MISSED):
                    return "state_deadline_shape"
            elif outcome == _D1_OUT_UNKNOWN:
                # unresolved after deadline / clock uncertainty: INDETERMINATE
                if ddl_v != _D1_DDL_INDETERMINATE:
                    return "state_deadline_shape"

    return None


def _d1_ingress_row_ok(key: bytes, value: bytes) -> Optional[str]:
    """ORDERED_INGRESS (0x27): complete same-record (docs/17 §8.3)."""
    err = _d1_common_business(value, 0x27, primary_zero_pvd=True)
    if err is not None:
        return err
    body = body_of(value)
    if len(body) < 168:
        return "ingress_body_len"
    oseq = body[0:8]
    if oseq == bytes(8) or struct.unpack(">Q", oseq)[0] < 1:
        return "ingress_seq_zero"
    if key != d3s1.bkey(6, 0x27, 3, oseq):
        return "ingress_key"
    if value[24:40] != (bytes(8) + oseq):
        return "ingress_primary_id"
    owner_seq = struct.unpack(">Q", body[8:16])[0]
    if owner_seq < 1:
        return "ingress_owner_seq"
    bind = struct.unpack(">H", body[16:18])[0]
    if body[18:20] != b"\x00\x00":
        return "ingress_reserved0"
    kind = struct.unpack(">I", body[20:24])[0]
    flags = struct.unpack(">I", body[24:28])[0]
    if flags != 0:
        return "ingress_msg_flags"
    if kind not in _D1_BEARER_KINDS:
        return "ingress_kind"
    # binding: APP(1)/CANCEL_REQ(4) → EXISTING_DLV(2)/NEW_DLV(3);
    # RECEIPT(2)/DISPOSITION(3)/CUSTODY(5)/CANCEL_RESULT(6) → EXISTING_TX(1)
    # (docs/17 §8.3; docs/12 bearer kinds — CANCEL_REQUEST is 4 not 5)
    if kind in (1, 4):  # APPLICATION, CANCEL_REQUEST
        if bind not in (_D1_BIND_EXISTING_DLV, _D1_BIND_NEW_DLV):
            return "ingress_binding"
    else:
        if bind != _D1_BIND_EXISTING_TX:
            return "ingress_binding"
    tx = body[28:44]
    attempt = body[44:60]
    event_id = body[60:76]
    if tx == bytes(16) or attempt == bytes(16):
        return "ingress_id_zero"
    party = body[76 : 76 + d3s1.PARTY_LEN]
    target = body[76 + d3s1.PARTY_LEN : 76 + d3s1.PARTY_LEN + d3s1.TARGET_LEN]
    if not _d1_party_ok(party):
        return "ingress_party"
    if not _d1_target_ok(target):
        return "ingress_target"
    o = 76 + d3s1.PARTY_LEN + d3s1.TARGET_LEN
    parsed = _d1_parse_service_at(body, o)
    if parsed is None:
        return "ingress_service"
    si, si_family, o = parsed
    # Fixed tail after SI: content32+gen8+ddl_ep16+abs8+grace8+req4+receipt4+disp4+
    # effect4+rg4+cancel4+retry_delay8+evi_ep16+evi_ms8+evi_trust4+res4+
    # ctrl_ep16+ctrl_ms8+ctrl_trust4+res4+msd32+pay32+evi32+ingress_state4+res32
    # = 32+8+16+8+8+4 + 4*5 + 8 + 16+8+4+4 + 16+8+4+4 + 32*3 + 4 + 32 = 300
    if o + 300 != len(body):
        return "ingress_body_len"
    content = body[o : o + 32]
    o += 32
    gen = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    ddl_ep = body[o : o + 16]
    o += 16
    abs_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    grace = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    req = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    receipt = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    disp = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    effect = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    rg = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    cancel_k = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    retry_delay = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    evi_ep = body[o : o + 16]
    o += 16
    evi_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    evi_trust = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    res1 = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    ctrl_ep = body[o : o + 16]
    o += 16
    ctrl_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    ctrl_trust = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    res2 = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    msd = body[o : o + 32]
    o += 32
    pay = body[o : o + 32]
    o += 32
    evi_blob = body[o : o + 32]
    o += 32
    ing_state = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    res_kd = body[o : o + 32]
    if content == D1_ZERO32:
        return "ingress_content_zero"
    if req not in _D1_EVIDENCE_REQ:
        return "ingress_required_evidence"
    if res1 != 0 or res2 != 0:
        return "ingress_reserved1"
    if ing_state != _D1_ING_STATE_PENDING:
        return "ingress_state"
    is_event = si_family == 1
    if is_event:
        if event_id == bytes(16) or gen != 0 or not _d1_id_zero(ddl_ep) or abs_ms != UINT64_MAX or grace != 0:
            return "ingress_ef_deadline"
    else:
        if event_id != bytes(16) or gen == 0 or _d1_id_zero(ddl_ep) or abs_ms == UINT64_MAX:
            return "ingress_ds_deadline"
    # CANCEL_REQUEST(4) / CANCEL_RESULT(6) are DesiredState only (docs/12 §5.4 /
    # docs/17 §8.3). CUSTODY_ACCEPTED(5) is NOT cancel — EventFact CUSTODY is legal.
    if kind in (4, 6) and is_event:
        return "ingress_cancel_on_ef"
    zero_disp = _d1_zero_disposition_tuple_ok(disp, effect, rg, retry_delay)
    if kind == 1:  # APPLICATION
        if receipt != 0 or not zero_disp or cancel_k != 0:
            return "ingress_app_enums"
        if not _d1_id_zero(evi_ep) or evi_ms != 0 or evi_trust != 0:
            return "ingress_app_evi_time"
        if not _d1_id_zero(ctrl_ep) or ctrl_ms != 0 or ctrl_trust != 0:
            return "ingress_app_ctrl"
        if evi_blob != D1_ZERO32:
            return "ingress_app_evidence_nonzero"
        # Empty payload: content_digest must be SHA-256(empty) (docs/17 §8.3).
        if pay == D1_ZERO32 and content != d3s1.sha256(b""):
            return "ingress_app_empty_content"
    elif kind == 2:  # RECEIPT
        if receipt == 0 or receipt not in _D1_EVIDENCE_REQ:
            return "ingress_receipt_stage"
        if not zero_disp or cancel_k != 0:
            return "ingress_receipt_disp"
        if _d1_id_zero(evi_ep) or evi_trust not in _D1_CLOCK_TRUST:
            return "ingress_receipt_evi"
        if _d1_id_zero(ctrl_ep) or ctrl_trust not in _D1_CLOCK_TRUST:
            return "ingress_receipt_ctrl"
        if pay != D1_ZERO32:
            return "ingress_receipt_payload_nonzero"
    elif kind == 3:  # DISPOSITION — closed disposition/effect/guidance/delay
        if receipt != 0 or cancel_k != 0:
            return "ingress_disp_enums"
        if not _d1_disposition_tuple_ok(disp, effect, rg, retry_delay):
            return "ingress_disp_tuple"
        if not _d1_id_zero(evi_ep) or evi_ms != 0 or evi_trust != 0:
            return "ingress_disp_evi"
        if not _d1_id_zero(ctrl_ep) or ctrl_ms != 0 or ctrl_trust != 0:
            return "ingress_disp_ctrl"
        if pay != D1_ZERO32 or evi_blob != D1_ZERO32:
            return "ingress_other_view_nonzero"
    elif kind == 6:  # CANCEL_RESULT
        if receipt != 0 or not zero_disp:
            return "ingress_cancel_res_disp"
        if cancel_k not in (1, 3):
            return "ingress_cancel_kind"
        if not _d1_id_zero(evi_ep) or evi_ms != 0 or evi_trust != 0:
            return "ingress_cancel_res_evi"
        if not _d1_id_zero(ctrl_ep) or ctrl_ms != 0 or ctrl_trust != 0:
            return "ingress_cancel_res_ctrl"
        if pay != D1_ZERO32 or evi_blob != D1_ZERO32:
            return "ingress_other_view_nonzero"
    else:  # CANCEL_REQUEST / CUSTODY
        if receipt != 0 or not zero_disp or cancel_k != 0:
            return "ingress_other_enums"
        if not _d1_id_zero(evi_ep) or evi_ms != 0 or evi_trust != 0:
            return "ingress_other_evi"
        if not _d1_id_zero(ctrl_ep) or ctrl_ms != 0 or ctrl_trust != 0:
            return "ingress_other_ctrl"
        if pay != D1_ZERO32 or evi_blob != D1_ZERO32:
            return "ingress_other_view_nonzero"
    want_res = d3s1.complete_key_digest_composite(
        0x23, struct.pack(">H", 3) + d3s1.raw16(oseq)
    )
    if res_kd != want_res:
        return "ingress_reservation_kd"
    za = pay == D1_ZERO32
    zb = evi_blob == D1_ZERO32
    if za and zb:
        if msd != msd_ingress(body, b"", b""):
            return "ingress_msd_empty"
    elif msd == D1_ZERO32:
        return "ingress_sem_zero_with_blob"
    return None


def _d1_delivery_row_ok(key: bytes, value: bytes) -> Optional[str]:
    err = _d1_common_business(value, 0x40, primary_zero_pvd=True)
    if err is not None:
        return err
    body = body_of(value)
    # Pre-length before any struct.unpack/from_bytes that needs a minimum (R24).
    if len(body) < 2:
        return "delivery_body_len"
    rl = struct.unpack(">H", body[0:2])[0]
    if 2 + rl + 2 + 2 + 8 + 16 + 16 + d3s1.PARTY_LEN + d3s1.TARGET_LEN > len(body):
        return "delivery_body_len"
    raw = body[2 : 2 + rl]
    if rl != 80:
        return "delivery_raw80"
    o = 2 + rl
    creation = struct.unpack(">H", body[o : o + 2])[0]
    o += 2
    if body[o : o + 2] != b"\x00\x00":
        return "delivery_reserved"
    o += 2
    sched = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    if sched < 1:
        return "delivery_sched_seq"
    tx = body[o : o + 16]
    o += 16
    event = body[o : o + 16]
    o += 16
    party = body[o : o + d3s1.PARTY_LEN]
    o += d3s1.PARTY_LEN
    target = body[o : o + d3s1.TARGET_LEN]
    o += d3s1.TARGET_LEN
    if tx == bytes(16):
        return "delivery_tx_zero"
    if not _d1_party_ok(party):
        return "delivery_party"
    if not _d1_target_ok(target):
        return "delivery_target"
    # five raw components non-zero + bijection raw[32:48]==tx
    for i in range(5):
        if raw[i * 16 : (i + 1) * 16] == bytes(16):
            return "delivery_raw_component"
    if raw[32:48] != tx:
        return "delivery_raw_tx"
    # raw bijection: source.rt||source.app||tx||target.rt||target.app
    src_rt, src_app = party[0:16], party[16:32]
    tgt_rt, tgt_app = target[4:20], target[20:36]
    if raw != src_rt + src_app + tx + tgt_rt + tgt_app:
        return "delivery_raw_bijection"
    parsed = _d1_parse_service_at(body, o)
    if parsed is None:
        return "delivery_service"
    si, si_family, o = parsed
    if o + 172 != len(body):
        return "delivery_body_len"
    content = body[o : o + 32]
    o += 32
    gen = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    dep = body[o : o + 16]
    o += 16
    abs_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    grace = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    req = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    pay = body[o : o + 32]
    o += 32
    rc_kd = body[o : o + 32]
    o += 32
    res_kd = body[o : o + 32]
    if content == D1_ZERO32:
        return "delivery_content_zero"
    if creation not in _D1_DELIVERY_CREATION:
        return "delivery_creation"
    if req not in _D1_EVIDENCE_REQ:
        return "delivery_required_evidence"
    is_event = si_family == 1
    is_cancel = creation == 2
    if is_cancel and is_event:
        return "delivery_cancel_on_ef"
    if is_event:
        if event == bytes(16) or gen != 0 or not _d1_id_zero(dep) or abs_ms != UINT64_MAX or grace != 0:
            return "delivery_ef_deadline"
    else:
        if event != bytes(16) or gen == 0 or _d1_id_zero(dep) or abs_ms == UINT64_MAX:
            return "delivery_ds_deadline"
    if is_cancel:
        if pay != D1_ZERO32:
            return "delivery_cancel_payload_nz"
    elif pay == D1_ZERO32:
        return "delivery_app_payload_zero"
    want = d3s1.bkey(6, 0x40, 5, d3s1.composite(0x40, _d1_raw16(raw)))
    if key != want:
        return "delivery_key"
    if value[24:40] != d3s1.composite(0x40, d3s1.raw16(raw))[:16]:
        return "delivery_primary_id"
    rc_k = d3s1.bkey(6, 0x41, 5, d3s1.composite(0x41, _d1_raw16(raw)))
    if rc_kd != d3s1.key_digest(rc_k):
        return "delivery_rc_kd"
    want_res = d3s1.complete_key_digest_composite(
        0x23, struct.pack(">H", 4) + d3s1.raw16(raw)
    )
    if res_kd != want_res:
        return "delivery_reservation_kd"
    return None


# RESULT_CACHE application_result_kind / cancel_result_kind.
_D1_APPK_NONE = 0
_D1_APPK_POS = 1
_D1_APPK_DISP = 2
_D1_CANCEL_FENCED = 1
_D1_CANCEL_TOO_LATE = 3


def _d1_rc_parse(body: bytes) -> Optional[Dict[str, Any]]:
    if len(body) != 378:
        return None
    o = 0
    rl = struct.unpack(">H", body[o : o + 2])[0]
    o += 2
    if rl != 80:
        return None
    raw = body[o : o + 80]
    o += 80
    dkd = body[o : o + 32]
    o += 32
    tx = body[o : o + 16]
    o += 16
    n = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    seen = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    att = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    st = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    reply = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    tok_ctx = body[o : o + 16]
    o += 16
    tok_gen = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    tok_ep = body[o : o + 16]
    o += 16
    tok_exp = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    start_ep = body[o : o + 16]
    o += 16
    start_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    comp_exp = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    cb = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    ri = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    g = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    nb_ep = body[o : o + 16]
    o += 16
    nb_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    appk = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    evi = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    disp = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    reason = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    effect = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    rg = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    rd = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    ecell = body[o : o + 32]
    o += 32
    tok = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    cancel = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    done_ep = body[o : o + 16]
    o += 16
    done_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    if o != 378:
        return None
    return {
        "raw": raw, "dkd": dkd, "tx": tx, "n": n, "seen": seen, "att": att,
        "st": st, "reply": reply, "tok_ctx": tok_ctx, "tok_gen": tok_gen,
        "tok_ep": tok_ep, "tok_exp": tok_exp, "start_ep": start_ep,
        "start_ms": start_ms, "comp_exp": comp_exp, "cb": cb, "ri": ri, "g": g,
        "nb_ep": nb_ep, "nb_ms": nb_ms, "appk": appk, "evi": evi, "disp": disp,
        "reason": reason, "effect": effect, "rg": rg, "rd": rd, "ecell": ecell,
        "tok": tok, "cancel": cancel, "done_ep": done_ep, "done_ms": done_ms,
    }


def _d1_rc_product_ok(rc: Dict[str, Any]) -> Optional[str]:
    """Closed physical delivery_state × A/N/token/D/E/F product (docs/17 §8.5)."""
    n, st, ts, f = rc["n"], rc["st"], rc["tok"], rc["cancel"]
    if st == 3 or st not in _D1_DELIVERY_STATES:
        return "rc_delivery_state"
    if rc["reply"] > 4:
        return "rc_reply_count"
    if ts == _D1_TOK_NONE:
        if not (n == 0 and rc["tok_ctx"] == bytes(16) and rc["tok_gen"] == 0
                and rc["tok_ep"] == bytes(16) and rc["tok_exp"] == 0
                and rc["start_ep"] == bytes(16) and rc["start_ms"] == 0
                and rc["comp_exp"] == 0):
            return "rc_token_none"
    elif ts in (_D1_TOK_ACTIVE, _D1_TOK_CONSUMED, _D1_TOK_EXPIRED, _D1_TOK_RECOVERY_TOMB):
        if n < 1 or rc["tok_ctx"] != rc["tx"] or rc["tx"] == bytes(16):
            return "rc_token_ctx"
        if rc["tok_ep"] == bytes(16) or rc["start_ep"] == bytes(16):
            return "rc_token_timer_ep"
        if rc["tok_ep"] != rc["start_ep"]:
            return "rc_token_timer_ep_pair"
        if rc["tok_exp"] == 0 or rc["comp_exp"] == 0 or rc["tok_exp"] != rc["comp_exp"]:
            return "rc_token_timer_exp"
        if rc["comp_exp"] <= rc["start_ms"]:
            return "rc_token_timer_order"
    else:
        return "rc_token_state"
    if rc["cb"] != n or rc["tok_gen"] != n:
        if ts != _D1_TOK_NONE or rc["cb"] != 0 or rc["tok_gen"] != 0:
            return "rc_token_counters"

    ecell0 = rc["ecell"] == D1_ZERO32
    a_app = rc["seen"] == 1 and rc["att"] >= 1 and not ecell0
    a_cancel = rc["seen"] == 0 and rc["att"] == 0 and n == 0 and ecell0
    if a_app:
        want_ec = d3s1.complete_key_digest_composite(
            0x32,
            struct.pack(">H", 2) + d3s1.raw16(rc["raw"]) + struct.pack(">I", 0),
        )
        if rc["ecell"] != want_ec:
            return "rc_ecell_kd"

    done0 = rc["done_ep"] == bytes(16) and rc["done_ms"] == 0
    done_nz = rc["done_ep"] != bytes(16) and rc["done_ms"] != 0
    e_zero = (
        rc["appk"] == _D1_APPK_NONE and rc["evi"] == 0 and rc["disp"] == 0
        and rc["reason"] == 0 and rc["effect"] == 0 and rc["rg"] == _D1_RG_NEVER
        and rc["rd"] == 0 and done0
    )
    e_pos = (
        rc["appk"] == _D1_APPK_POS
        and rc["evi"] in _D1_EVIDENCE_REQ
        and rc["disp"] == 0
        and rc["reason"] == 0 and rc["effect"] == 0 and rc["rg"] == _D1_RG_NEVER
        and rc["rd"] == 0 and done_nz
    )
    # E_DISP: exact disposition closed product + reason mapping (docs/17 574-630).
    e_disp = (
        rc["appk"] == _D1_APPK_DISP
        and rc["evi"] == 0
        and _d1_disposition_tuple_ok(rc["disp"], rc["effect"], rc["rg"], rc["rd"])
        and _d1_disp_reason_ok(rc["disp"], rc["reason"], rc["effect"])
        and done_nz
    )
    # E_REC: exact reason set + default guidance; completed (0,0) mandatory.
    e_rec = (
        rc["appk"] == _D1_APPK_NONE and rc["evi"] == 0 and rc["disp"] == 0
        and rc["effect"] == _D1_EFF_POSSIBLE
        and rc["rd"] == 0 and done0
        and _d1_e_rec_reason_guidance_ok(rc["reason"], rc["rg"])
    )

    d_idle = rc["g"] == 0 and rc["ri"] == 0 and rc["nb_ep"] == bytes(16) and rc["nb_ms"] == 0
    d_open = (
        rc["g"] >= 1
        and (rc["ri"] == (1 << 64) - 1 or rc["g"] <= rc["ri"] + 1)
        and rc["nb_ep"] == bytes(16) and rc["nb_ms"] == 0
    )
    d_wait = (
        rc["g"] >= 1
        and (rc["ri"] == (1 << 64) - 1 or rc["g"] <= rc["ri"] + 1)
        and rc["nb_ep"] != bytes(16) and rc["nb_ms"] != 0
    )
    d_held = (
        rc["g"] >= 1 and rc["ri"] >= 1 and rc["ri"] >= rc["g"]
        and rc["nb_ep"] == bytes(16) and rc["nb_ms"] == 0
    )
    tomb = ts in _D1_TOK_RETAINED

    if f == _D1_CANCEL_FENCED:
        if n != 0 or ts != _D1_TOK_NONE or st not in (1, 8):
            return "rc_f_fenced"
    elif f == _D1_CANCEL_TOO_LATE:
        if st == 8 or n == 0:
            return "rc_f_late"
    elif f != 0:
        return "rc_f_unknown"

    if st == 1:
        if not a_app or not e_zero:
            return "rc_product_inbox"
        if n == 0:
            if not (ts == _D1_TOK_NONE and d_idle and f in (0, _D1_CANCEL_FENCED)):
                return "rc_product_inbox"
        elif not (tomb and d_held and f in (0, _D1_CANCEL_TOO_LATE)):
            return "rc_product_inbox"
        return None
    if st == 2:
        if not (a_app and n >= 1 and ts == _D1_TOK_ACTIVE and e_zero
                and (d_idle or d_held) and f in (0, _D1_CANCEL_TOO_LATE) and done0):
            return "rc_product_started"
        return None
    if st == 4:
        if not (a_app and n >= 1 and ts == _D1_TOK_CONSUMED and e_pos
                and (d_idle or d_held) and f in (0, _D1_CANCEL_TOO_LATE)):
            return "rc_product_result"
        return None
    if st == 5:
        if not a_app or not e_disp:
            return "rc_product_disp"
        if n == 0:
            if not (ts == _D1_TOK_NONE and d_idle and f == 0):
                return "rc_product_disp"
        elif not (ts == _D1_TOK_CONSUMED and (d_idle or d_held)
                  and f in (0, _D1_CANCEL_TOO_LATE)):
            return "rc_product_disp"
        return None
    if st == 6:
        if not (a_app and e_rec and d_open and f in (0, _D1_CANCEL_TOO_LATE)):
            return "rc_product_recovery"
        if not _d1_e_rec_token_pair_ok(rc["reason"], ts, n):
            return "rc_e_rec_token"
        return None
    if st == 7:
        if not (a_app and e_rec and d_wait and f in (0, _D1_CANCEL_TOO_LATE)):
            return "rc_product_reconcile"
        if not _d1_e_rec_token_pair_ok(rc["reason"], ts, n):
            return "rc_e_rec_token"
        return None
    if st == 8:
        if not (a_cancel and n == 0 and ts == _D1_TOK_NONE and d_idle and e_zero
                and f == _D1_CANCEL_FENCED and done0):
            return "rc_product_cancel_tomb"
        return None
    return "rc_product"


def _d1_result_cache_row_ok(key: bytes, value: bytes) -> Optional[str]:
    err = _d1_common_business(value, 0x41, primary_zero_pvd=False)
    if err is not None:
        return err
    body = body_of(value)
    if len(body) != 378:
        return "rc_body_len"
    rc = _d1_rc_parse(body)
    if rc is None:
        return "rc_body_len"
    raw = rc["raw"]
    want = d3s1.bkey(6, 0x41, 5, d3s1.composite(0x41, _d1_raw16(raw)))
    if key != want:
        return "rc_key"
    if value[24:40] != d3s1.composite(0x40, d3s1.raw16(raw))[:16]:
        return "rc_primary_id"
    dlv_k = d3s1.bkey(6, 0x40, 5, d3s1.composite(0x40, _d1_raw16(raw)))
    if rc["dkd"] != d3s1.key_digest(dlv_k):
        return "rc_delivery_kd"
    if rc["tx"] == bytes(16):
        return "rc_tx_zero"
    if raw[32:48] != rc["tx"]:
        return "rc_raw_tx"
    for i in range(5):
        if raw[i * 16 : (i + 1) * 16] == bytes(16):
            return "rc_raw_component"
    if rc["seen"] > 1:
        return "rc_seen"
    if (rc["nb_ep"] == bytes(16)) != (rc["nb_ms"] == 0):
        return "rc_nb_mixed"
    if rc["g"] == 0:
        if rc["ri"] != 0 or rc["nb_ep"] != bytes(16) or rc["nb_ms"] != 0:
            return "rc_g0"
    elif rc["ri"] != (1 << 64) - 1 and rc["g"] > rc["ri"] + 1:
        return "rc_g_ri"
    # disposition/reason/effect/guidance enum surface (product also binds shapes)
    if rc["evi"] not in _D1_EVIDENCE_STAGES:
        return "rc_evidence_stage"
    # disposition closed 0..10 (docs/12 disposition enum)
    if rc["disp"] > 10:
        return "rc_disposition"
    if rc["reason"] != 0 and not _d1_reason_public_ok(rc["reason"]):
        return "rc_reason"
    if rc["effect"] not in (_D1_EFF_NONE, _D1_EFF_NO_EFFECT, _D1_EFF_POSSIBLE):
        return "rc_effect"
    if rc["appk"] not in (0, 1, 2):
        return "rc_appk"
    if rc["rg"] not in (
        _D1_RG_NEVER, _D1_RG_SAME_AFTER, _D1_RG_MODIFIED, _D1_RG_OPERATOR
    ):
        return "rc_retry_guidance"
    return _d1_rc_product_ok(rc)


def _d1_reverse_reply_row_ok(key: bytes, value: bytes) -> Optional[str]:
    """REVERSE_REPLY (0x42): full raw/tx/reply/send-state matrix (docs/17 §8.5)."""
    err = _d1_common_business(value, 0x42, primary_zero_pvd=False)
    if err is not None:
        return err
    body = body_of(value)
    if len(body) != 330:
        return "rr_body_len"
    rl = struct.unpack(">H", body[0:2])[0]
    o = 2
    reply_raw = body[o : o + rl]
    o += rl
    dl = struct.unpack(">H", body[o : o + 2])[0]
    o += 2
    delivery_raw = body[o : o + dl]
    o += dl
    if dl != 80:
        return "rr_raw80"
    tx = body[o : o + 16]
    o += 16
    reply_kind = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    semantic = body[o : o + 32]
    o += 32
    body_blob = body[o : o + 32]
    o += 32
    send_state = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    gen = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    inv = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    exhausted = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    reserved = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    attempt = body[o : o + 16]
    o += 16
    avail = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    retry_ep = body[o : o + 16]
    o += 16
    retry_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    if o != 330:
        return "rr_body_len"
    if reply_kind not in _D1_REPLY_KINDS:
        return "rr_kind"
    if tx == bytes(16) or attempt == bytes(16):
        return "rr_id_zero"
    if semantic == D1_ZERO32 or body_blob == D1_ZERO32:
        return "rr_dig_zero"
    if delivery_raw[32:48] != tx:
        return "rr_raw_tx"
    for i in range(5):
        if delivery_raw[i * 16 : (i + 1) * 16] == bytes(16):
            return "rr_raw_component"
    if reserved != 0:
        return "rr_reserved"
    # reply_key_raw = delivery_key_raw:RAW16 (2+80) || reply_kind:u32 (docs/17 §8.5)
    if rl != 86:
        return "rr_reply_raw_len"
    expect_reply = struct.pack(">H", 80) + delivery_raw + struct.pack(">I", reply_kind)
    if reply_raw != expect_reply:
        return "rr_reply_raw"
    want = d3s1.bkey(6, 0x42, 5, d3s1.composite(0x42, _d1_raw16(reply_raw)))
    if key != want:
        return "rr_key"
    if value[24:40] != d3s1.composite(0x40, d3s1.raw16(delivery_raw))[:16]:
        return "rr_primary_id"
    # timer pair
    if _d1_id_zero(retry_ep):
        if retry_ms != 0:
            return "rr_timer"
    elif retry_ms == 0:
        return "rr_timer"
    # I/avail coupling
    if inv > gen:
        return "rr_counters"
    if inv == 0:
        if avail != 0:
            return "rr_avail"
    elif avail == 0:
        return "rr_avail"
    if exhausted not in (0, 1):
        return "rr_exhausted"
    at_max = gen == UINT64_MAX or inv == UINT64_MAX
    not_max = not at_max
    timer_zero = _d1_id_zero(retry_ep) and retry_ms == 0
    timer_nz = not _d1_id_zero(retry_ep) and retry_ms != 0
    if send_state == _D1_RR_PENDING:
        if gen == 0:
            if not (inv == 0 and avail == 0 and exhausted == 0 and timer_zero):
                return "rr_send_matrix"
        elif not (not_max and exhausted == 0 and timer_zero):
            return "rr_send_matrix"
    elif send_state == _D1_RR_WAIT:
        if not (gen >= 1 and not_max and exhausted == 0 and timer_nz):
            return "rr_send_matrix"
    elif send_state == _D1_RR_CLOSED_SENT:
        if not (gen >= 1 and not_max and inv >= 1 and exhausted == 0 and timer_zero):
            return "rr_send_matrix"
    elif send_state == _D1_RR_CLOSED_DENY:
        if not (gen >= 1 and not_max and exhausted == 0 and timer_zero):
            return "rr_send_matrix"
    elif send_state == _D1_RR_EXHAUSTED:
        if not (at_max and exhausted == 1 and timer_zero):
            return "rr_send_matrix"
    else:
        return "rr_send_state"
    return None


def _d1_evidence_cell_row_ok(key: bytes, value: bytes) -> Optional[str]:
    """EVIDENCE_CELL: primary digest/target/issuer/stage/trust/family-gen/RAW."""
    err = _d1_common_business(value, 0x32, primary_zero_pvd=False)
    if err is not None:
        return err
    body = body_of(value)
    # Pre-length before any struct.unpack/from_bytes that needs a minimum (R24).
    if len(body) < 6:
        return "cell_body_len"
    owner_kind = struct.unpack(">H", body[0:2])[0]
    cell_kind = struct.unpack(">H", body[2:4])[0]
    if owner_kind not in (1, 2):
        return "cell_owner_kind"
    if cell_kind not in (1, 2):
        return "cell_kind"
    rl = struct.unpack(">H", body[4:6])[0]
    if 6 + rl > len(body):
        return "cell_raw_trunc"
    raw = body[6 : 6 + rl]
    if owner_kind == 2 and rl != 80:
        return "cell_raw80"
    if owner_kind == 1 and rl != 16:
        return "cell_raw16"
    if len(body) != 718 + rl:
        return "cell_body_len"
    # TRANSACTION owner_raw must be a nonzero 16-byte transaction ID (docs/17 §8.4).
    # Length-only acceptance of all-zero was R22 Sol high false-green.
    if owner_kind == 1 and raw == bytes(16):
        return "cell_txn_raw_zero"
    matched_slot = None
    for slot in range(0, 16):
        want = d3s1.bkey(
            6, 0x32, 5,
            d3s1.composite(
                0x32,
                struct.pack(">H", owner_kind) + _d1_raw16(raw) + struct.pack(">I", slot),
            ),
        )
        if key == want:
            matched_slot = slot
            break
    if matched_slot is None:
        return "cell_key"
    if cell_kind == 1 and matched_slot != 0:
        return "cell_summary_slot"
    if cell_kind == 2 and (matched_slot < 1 or matched_slot > 8):
        return "cell_raw_slot"
    if owner_kind == 1:
        want_pid = raw[:16]
        want_pkd = d3s1.complete_key_digest_id128(0x20, raw)
    else:
        want_pid = d3s1.composite(0x40, d3s1.raw16(raw))[:16]
        want_pkd = d3s1.complete_key_digest_composite(0x40, d3s1.raw16(raw))
        for i in range(5):
            if raw[i * 16 : (i + 1) * 16] == bytes(16):
                return "cell_raw_component"
    if value[24:40] != want_pid:
        return "cell_primary_id"
    o = 6 + rl
    pkd = body[o : o + 32]
    o += 32
    target_dig = body[o : o + 32]
    o += 32
    if pkd != want_pkd:
        return "cell_primary_kd"
    if target_dig == D1_ZERO32:
        return "cell_target_digest"
    slot_wire = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    if slot_wire != matched_slot:
        return "cell_slot_wire"
    cell_state = struct.unpack(">H", body[o : o + 2])[0]
    o += 2
    reserved0 = struct.unpack(">H", body[o : o + 2])[0]
    o += 2
    if reserved0 != 0:
        return "cell_reserved"
    highest, latest, material = struct.unpack(">III", body[o : o + 12])
    o += 12
    disp, effect, late = struct.unpack(">III", body[o : o + 12])
    o += 12
    issuer = body[o : o + 100]
    o += 100
    svc_slot = body[o : o + 240]
    o += 240
    content = body[o : o + 32]
    o += 32
    generation = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    durable = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    epoch = body[o : o + 16]
    o += 16
    at_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    trust = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    sat = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    dig = body[o : o + 32]
    o += 32
    elen = struct.unpack(">H", body[o : o + 2])[0]
    o += 2
    res2 = struct.unpack(">H", body[o : o + 2])[0]
    o += 2
    ebytes_full = body[o : o + 128]
    o += 128
    valid_m = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    exact_dup = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    raw_ovf = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    late_cnt = struct.unpack(">Q", body[o : o + 8])[0]
    if res2 != 0 or elen > 128:
        return "cell_evi_len"
    ebytes = ebytes_full[:elen]
    if ebytes_full[elen:] != bytes(128 - elen):
        return "cell_evi_pad"
    _CS_UNUSED, _CS_MAT = 1, 2
    if cell_state not in (_CS_UNUSED, _CS_MAT):
        return "cell_state"
    # disposition/effect always 0 on every legal shape (docs/17 §8.4 EVIDENCE_CELL).
    if disp != 0 or effect != 0:
        return "cell_disp_effect"
    empty_fields = (
        highest == 0 and latest == 0 and material == 0 and disp == 0 and effect == 0
        and late == 0 and content == D1_ZERO32 and generation == 0 and durable == 0
        and epoch == bytes(16) and at_ms == 0 and trust == 0 and sat == 0
        and dig == D1_ZERO32 and elen == 0 and valid_m == 0 and exact_dup == 0
        and raw_ovf == 0 and late_cnt == 0
        and _d1_party_all_zero(issuer) and svc_slot == bytes(240)
    )

    def material_core_ok(*, is_summary: bool) -> Optional[str]:
        if late not in (0, 1):
            return "cell_late"
        if not _d1_party_ok(issuer):
            return "cell_issuer"
        si_fam = _d1_service_slot_ok(svc_slot)
        if si_fam is None:
            return "cell_service_slot"
        if content == D1_ZERO32 or durable == 0 or epoch == bytes(16):
            return "cell_material_core"
        # Known trust only: TRUSTED(1)/UNCERTAIN(2). Unknown nonzero (e.g. 99) is RED.
        if trust not in _D1_CLOCK_TRUST:
            return "cell_trust"
        if dig != d3s1.sha256(ebytes):
            return "cell_evi_digest"
        if si_fam == 1:
            if generation != 0:
                return "cell_family_generation"
        elif generation < 1:
            return "cell_family_generation"
        if is_summary:
            # known material/source/receipt stage 1..4 and three stages equal
            if (
                highest not in _D1_EVIDENCE_REQ
                or highest != latest
                or highest != material
            ):
                return "cell_stage_triple"
            if late != (1 if late_cnt > 0 else 0):
                return "cell_late_coherence"
            if valid_m < 1:
                return "cell_valid_count"
            if raw_ovf > valid_m or late_cnt > valid_m:
                return "cell_counter_bound"
            if exact_dup > 0 and valid_m < 1:
                return "cell_counter_bound"
            if sat not in (0, 1):
                return "cell_sat"
            if sat == 0:
                if any(x == UINT64_MAX for x in (valid_m, exact_dup, raw_ovf, late_cnt)):
                    return "cell_sat_coherence"
            else:
                if not any(
                    x == UINT64_MAX for x in (valid_m, exact_dup, raw_ovf, late_cnt)
                ):
                    return "cell_sat_coherence"
        else:
            # RAW MATERIALIZED: aggregate stages 0; material stage known 1..4;
            # counters/sat always 0; late is material late bit 0/1 only.
            if highest != 0 or latest != 0:
                return "cell_raw_stages"
            if material not in _D1_EVIDENCE_REQ:
                return "cell_raw_material_stage"
            if valid_m != 0 or exact_dup != 0 or raw_ovf != 0 or late_cnt != 0 or sat != 0:
                return "cell_raw_counters"
        return None

    if cell_kind == 1:
        if cell_state != _CS_MAT:
            return "cell_summary_state"
        # SUMMARY empty: identity only; all material fields zero.
        if valid_m == 0:
            if not empty_fields:
                return "cell_summary_empty"
            return None
        return material_core_ok(is_summary=True)
    # RAW
    if cell_state == _CS_UNUSED:
        if not empty_fields:
            return "cell_raw_unused"
        return None
    if cell_state != _CS_MAT:
        return "cell_state"
    return material_core_ok(is_summary=False)


def _d1_cs_bijection_ok(state: int, kind: int, reason: int, effect: int) -> bool:
    if state == _D1_CS_NONE:
        return kind == _D1_CK_NONE and reason == 0 and effect == _D1_E_NONE
    if state == _D1_CS_PEND:
        return kind == _D1_CK_PEND and reason == _D1_R_PEND and effect == _D1_E_NONE
    if state == _D1_CS_FENCED:
        return (
            kind == _D1_CK_FENCED
            and reason == _D1_R_FENCED
            and effect == _D1_E_NO_EFFECT
        )
    if state == _D1_CS_TOO_LATE:
        return (
            kind == _D1_CK_TOO_LATE
            and reason == _D1_R_TOO_LATE
            and effect == _D1_E_POSSIBLE
        )
    return False


def _d1_cancel_state_row_ok(key: bytes, value: bytes) -> Optional[str]:
    """CANCEL_STATE (0x33): owner/key/pkd + closed 7-shape matrix (docs/17 §8.4)."""
    err = _d1_common_business(value, 0x33, primary_zero_pvd=False)
    if err is not None:
        return err
    body = body_of(value)
    # Pre-length before any struct.unpack/from_bytes that needs a minimum (R24).
    if len(body) < 6:
        return "cs_body_len"
    owner_kind = struct.unpack(">H", body[0:2])[0]
    if body[2:4] != b"\x00\x00":
        return "cs_reserved"
    rl = struct.unpack(">H", body[4:6])[0]
    if 6 + rl > len(body):
        return "cs_trunc"
    raw = body[6 : 6 + rl]
    if owner_kind not in (_D1_CS_OWNER_TX, _D1_CS_OWNER_DLV):
        return "cs_owner_kind"
    if owner_kind == _D1_CS_OWNER_DLV and rl != 80:
        return "cs_raw80"
    if owner_kind == _D1_CS_OWNER_TX and rl != 16:
        return "cs_raw16"
    if len(body) != 146 + rl:
        return "cs_body_len"
    o = 6 + rl
    pkd = body[o : o + 32]
    o += 32
    tx = body[o : o + 16]
    o += 16
    attempt = body[o : o + 16]
    o += 16
    state = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    kind = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    reason = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    effect = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    gate = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    semantic = body[o : o + 32]
    o += 32
    t_ep = body[o : o + 16]
    o += 16
    t_ms = struct.unpack(">Q", body[o : o + 8])[0]
    if tx == bytes(16) or pkd == D1_ZERO32:
        return "cs_tx_or_pkd"
    if owner_kind == _D1_CS_OWNER_TX:
        if raw != tx or _d1_id_zero(raw):
            return "cs_owner_raw"
        want_pkd = d3s1.complete_key_digest_id128(0x20, tx)
        want_pid = tx
    else:
        if raw[32:48] != tx:
            return "cs_owner_raw"
        for i in range(5):
            if raw[i * 16 : (i + 1) * 16] == bytes(16):
                return "cs_owner_raw"
        want_pkd = d3s1.complete_key_digest_composite(0x40, d3s1.raw16(raw))
        want_pid = d3s1.composite(0x40, d3s1.raw16(raw))[:16]
    if pkd != want_pkd:
        return "cs_primary_kd"
    want = d3s1.bkey(
        6, 0x33, 5, d3s1.composite(0x33, struct.pack(">H", owner_kind) + _d1_raw16(raw))
    )
    if key != want:
        return "cs_key"
    if value[24:40] != want_pid:
        return "cs_primary_id"
    if not _d1_cs_bijection_ok(state, kind, reason, effect):
        return "cs_bijection"
    if gate not in (_D1_GATE_NEVER, _D1_GATE_RETRY, _D1_GATE_CLOSED):
        return "cs_gate"
    att0 = _d1_id_zero(attempt)
    dig0 = semantic == D1_ZERO32
    if att0 != dig0:
        return "cs_attempt_digest_pair"
    if _d1_id_zero(t_ep):
        if t_ms != 0:
            return "cs_timeout"
    elif t_ms == 0:
        return "cs_timeout"
    t_cleared = _d1_id_zero(t_ep) and t_ms == 0
    g_never = gate == _D1_GATE_NEVER
    g_retry = gate == _D1_GATE_RETRY
    g_closed = gate == _D1_GATE_CLOSED
    if state == _D1_CS_NONE:
        if not (att0 and g_never and t_cleared):
            return "cs_matrix"
        return None
    if owner_kind == _D1_CS_OWNER_TX:
        if state == _D1_CS_PEND:
            if att0:
                return "cs_matrix"
            if g_never or g_retry:
                return None if t_cleared else "cs_matrix"
            if g_closed:
                return None
            return "cs_matrix"
        if state == _D1_CS_FENCED:
            if att0:
                return None if (g_never and t_cleared) else "cs_matrix"
            return None if (g_closed and t_cleared) else "cs_matrix"
        if state == _D1_CS_TOO_LATE:
            return None if (not att0 and g_closed and t_cleared) else "cs_matrix"
        return "cs_matrix"
    # DELIVERY
    if state == _D1_CS_PEND:
        return "cs_matrix"
    if not g_never:
        return "cs_matrix"
    if state == _D1_CS_FENCED:
        return None if (not att0 and t_cleared) else "cs_matrix"
    if state == _D1_CS_TOO_LATE:
        return None if (not att0 and t_cleared) else "cs_matrix"
    return "cs_matrix"


def _d1_event_spool_row_ok(key: bytes, value: bytes) -> Optional[str]:
    """EVENT_SPOOL (0x50): state/cause/revision/event/retry/blob/reservation."""
    err = _d1_common_business(value, 0x50, primary_zero_pvd=False)
    if err is not None:
        return err
    body = body_of(value)
    if len(body) != 300:
        return "es_body_len"
    tx = body[0:16]
    event = body[16:32]
    rev = struct.unpack(">Q", body[32:40])[0]
    st = struct.unpack(">I", body[40:44])[0]
    cause = struct.unpack(">I", body[44:48])[0]
    retry = struct.unpack(">Q", body[48:56])[0]
    pay = body[56:88]
    # skip provider/decision/grant block to resume/discard/reservation
    # layout after pay32: provider16+rev8+decision32+grant16+grant_rev8+
    # dec_ep16+eval8+from8+exp8+retry_delay8+glimits... = total 300
    # successful_resume at fixed end: last 4+4+32 = resume, discard, res_kd
    resume = struct.unpack(">I", body[300 - 40 : 300 - 36])[0]
    discard = struct.unpack(">I", body[300 - 36 : 300 - 32])[0]
    res_kd = body[300 - 32 : 300]
    if tx == bytes(16):
        return "es_tx_zero"
    if event == bytes(16):
        return "es_event_zero"
    if key != d3s1.bkey(6, 0x50, 2, tx):
        return "es_key"
    if value[24:40] != tx:
        return "es_primary_id"
    if rev < 1:
        return "es_revision"
    # common record_revision must equal body spool_revision (docs/17 §8.5 / D1-B3k).
    common_rev = int.from_bytes(value[16:24], "big")
    if common_rev != rev:
        return "es_rev_mismatch"
    if st not in (_D1_ES_ACTIVE, _D1_ES_PARKED, _D1_ES_RELEASED, _D1_ES_DISCARDED):
        return "es_state"
    if cause not in _D1_PARK_CAUSES:
        return "es_cause"
    if st == _D1_ES_PARKED:
        if cause < 1 or cause > 5:
            return "es_state_cause"
    elif cause != 0:
        return "es_state_cause"
    if retry < 1:
        return "es_retry_cycle"
    if pay == D1_ZERO32:
        return "es_payload_dig"
    if resume > _D1_ES_RESUME_MAX:
        return "es_resume"
    if discard not in (0, 1):
        return "es_discard"
    if (discard == 1) != (st == _D1_ES_DISCARDED):
        return "es_discard_state"
    if res_kd != _d1_res_kd_tx(tx):
        return "es_reservation_kd"
    return None


_D1_FAMILY6_VALIDATORS = {
    0x20: _d1_anchor_row_ok,
    0x22: _d1_state_row_ok,
    0x27: _d1_ingress_row_ok,
    0x30: None,  # BLOB handled separately (flags branch)
    0x32: _d1_evidence_cell_row_ok,
    0x33: _d1_cancel_state_row_ok,
    0x40: _d1_delivery_row_ok,
    0x41: _d1_result_cache_row_ok,
    0x42: _d1_reverse_reply_row_ok,
    0x50: _d1_event_spool_row_ok,
}


def _d1_profile_catalog_pairs() -> frozenset:
    """Exact family1–4 catalog rows from independent encode (not arbitrary NLR1)."""
    rows = d3s1.encode_all_profile_rows(d3s1.default_binding_fields())
    return frozenset((r["key_hex"], r["value_hex"]) for r in rows)


_D1_PROFILE_CATALOG: Optional[frozenset] = None


def _d1_profile_row_ok(key: bytes, value: bytes) -> Optional[str]:
    err = _d1_profile_key_ok(key)
    if err is not None:
        return f"key:{err}"
    err = _d1_nlr1_framing(value)
    if err is not None:
        return err
    global _D1_PROFILE_CATALOG
    if _D1_PROFILE_CATALOG is None:
        _D1_PROFILE_CATALOG = _d1_profile_catalog_pairs()
    pair = (hex_of(key), hex_of(value))
    if pair not in _D1_PROFILE_CATALOG:
        return "profile_not_canonical_catalog"
    return None


def d1_independent_row_legality(key: bytes, value: bytes) -> Optional[str]:
    """Return None if row is locally D1-legal; else a short reason code.

    Independent of production C. Enforces complete Normative D1 for every used
    family6 subtype (R21/R22); profile catalog exact; family5 envelope.
    """
    if not isinstance(key, (bytes, bytearray)) or not isinstance(value, (bytes, bytearray)):
        return "type"
    k = bytes(key)
    v = bytes(value)
    if len(k) >= 9 and k[8] in (1, 2, 3, 4):
        return _d1_profile_row_ok(k, v)
    err = _d1_domain_key_ok(k)
    if err is not None:
        return f"key:{err}"
    fam, st = k[8], k[9]
    if fam == 5:
        return _d1_domain_envelope_ok(
            v, expect_subtype=st, expect_flags=0, expect_record_type=5
        )
    if fam != 6:
        return "family"
    if len(v) < 16:
        return "value_short"
    fl = v[15]
    if st == 0x30:
        if fl == 1:
            return _d1_blob_manifest_row_ok(k, v)
        if fl == 2:
            return _d1_blob_chunk_row_ok(k, v)
        return "blob_flags"
    fn = _D1_FAMILY6_VALIDATORS.get(st)
    if fn is None:
        return f"subtype_unvalidated_0x{st:02x}"
    return fn(k, v)


def d1_rows_legality_gate(rows: Sequence[Dict[str, str]]) -> Optional[str]:
    """Gate every fixture row. formal_precheck may duplicate keys; each row still D1."""
    if not isinstance(rows, (list, tuple)):
        return "rows_not_list"
    for i, r in enumerate(rows):
        if not isinstance(r, dict):
            return f"row[{i}] not object"
        try:
            k = d3s1.from_hex(r.get("key_hex", ""))
            v = d3s1.from_hex(r.get("value_hex", ""))
        except (TypeError, ValueError) as e:
            return f"row[{i}] hex:{e}"
        err = d1_independent_row_legality(k, v)
        if err is not None:
            return f"row[{i}]:{err}"
    return None



def man_owner_raw(man_v: bytes) -> Tuple[int, int, bytes]:
    body = body_of(man_v)
    ok = struct.unpack(">H", body[32:34])[0]
    bk = struct.unpack(">H", body[34:36])[0]
    rl = struct.unpack(">H", body[36:38])[0]
    return ok, bk, body[38 : 38 + rl]

def link_rr_body_blob(rr_v: bytes, man_k: bytes) -> bytes:
    body = body_of(rr_v)
    rl = struct.unpack(">H", body[0:2])[0]
    o = 2 + rl
    dl = struct.unpack(">H", body[o : o + 2])[0]
    o = o + 2 + dl + 16 + 4 + 32
    return patch_at(rr_v, 108 + o, d3s1.key_digest(man_k))

def profile_rows():
    return d3s1.encode_all_profile_rows(d3s1.default_binding_fields())

def sort_rows(rows):
    return sorted(rows, key=lambda r: d3s1.from_hex(r["key_hex"]))

def mkrow(k, v):
    return {"key_hex": hex_of(k), "value_hex": hex_of(v)}

def one_byte_for_cd(cd: bytes) -> bytes:
    for x in range(256):
        if d3s1.sha256(bytes([x])) == cd:
            return bytes([x])
    raise ValueError("no single-byte preimage for content_digest")

def drop_subtype(rows, subtype: int):
    out = []
    for r in rows:
        k = d3s1.from_hex(r["key_hex"])
        if len(k) >= 10 and k[8] == 6 and k[9] == subtype:
            continue
        out.append(r)
    return out

# ---------- materials ----------

def _sync_state_avd_pvd_to_anchor(anc_v: bytes, st_v: bytes) -> bytes:
    """Mode27 D3-S3: STATE body avd + common PVD + body tx = ANCHOR complete digest/tx."""
    tx = body_of(anc_v)[:16]
    avd = d3s1.value_digest(anc_v)
    body = bytearray(body_of(st_v))
    if len(body) < 48:
        raise ValueError("state body short for avd sync")
    body[0:16] = tx
    body[16:48] = avd
    return d3s1.enc_env_full(
        6, 0x22, 0, max(1, int.from_bytes(st_v[16:24], "big")),
        tx, st_v[40:72], avd, bytes(body),
    )


def mat27_chunked():
    anc_k, anc_v = gkey("DSB2_ANCHOR_TYPED"), gval("DSB2_ANCHOR_TYPED")
    st_k, st_v = gkey("DSB2_STATE_TYPED"), gval("DSB2_STATE_TYPED")
    man_k, man_v = gkey("DSB3_BLOB_MAN_TX_CMD_TYPED"), gval("DSB3_BLOB_MAN_TX_CMD_TYPED")
    chk_k, chk_v = gkey("DSB3_BLOB_CHK_SINGLE_TYPED"), gval("DSB3_BLOB_CHK_SINGLE_TYPED")
    anc_v = set_payload_blob_dig(anc_v, d3s1.key_digest(man_k))
    st_v = _sync_state_avd_pvd_to_anchor(anc_v, st_v)
    man_v = d3s1.patch_pvd(man_v, d3s1.value_digest(anc_v))
    chk_v = d3s1.patch_pvd(chk_v, d3s1.value_digest(man_v))
    return sort_rows(profile_rows() + [mkrow(anc_k, anc_v), mkrow(st_k, st_v), mkrow(man_k, man_v), mkrow(chk_k, chk_v)])

def mat27_zero():
    anc_k, anc_v = gkey("DSB2_ANCHOR_TYPED"), gval("DSB2_ANCHOR_TYPED")
    st_k, st_v = gkey("DSB2_STATE_TYPED"), gval("DSB2_STATE_TYPED")
    man_k, man_v = gkey("DSB3_BLOB_MAN_ZERO_TYPED"), gval("DSB3_BLOB_MAN_ZERO_TYPED")
    anc_v = set_payload_blob_dig(anc_v, d3s1.key_digest(man_k))
    st_v = _sync_state_avd_pvd_to_anchor(anc_v, st_v)
    man_v = d3s1.patch_pvd(man_v, d3s1.value_digest(anc_v))
    return sort_rows(profile_rows() + [mkrow(anc_k, anc_v), mkrow(st_k, st_v), mkrow(man_k, man_v)])

def mat27_missing():
    return drop_subtype(mat27_chunked(), 0x30)

def mat27_owner_pvd_bad():
    rows = []
    for r in mat27_zero():
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30:
            v = d3s1.patch_pvd(v, bytes([0x11]) * 32)
        rows.append(mkrow(k, v))
    return sort_rows(rows)

def mat27_chunk_pvd_bad():
    rows = []
    for r in mat27_chunked():
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 2:  # chunk flags
            v = d3s1.patch_pvd(v, bytes([0x22]) * 32)
        rows.append(mkrow(k, v))
    return sort_rows(rows)

def mat27_content_dig_bad():
    """Cross-row content_digest field disagree: D1-valid man + D1-valid foreign chunk.

    Man keeps original content_digest/blob_id. Chunk is rebuilt with different
    data (single-chunk ⇒ different content_digest) but same blob_id (chunk does
    not recompute blob_id). FOCUS header compare man.cd≠chunk.cd → CORRUPT.
    (In-place man.cd mutate breaks blob_id and is D1-illegal.)
    """
    rows = []
    man_k = man_v = None
    for r in mat27_chunked():
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_k, man_v = k, v
            rows.append(mkrow(k, v))
            continue
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 2:
            continue
        rows.append(mkrow(k, v))
    if man_k is None or man_v is None:
        raise RuntimeError("mat27_content_dig_bad: no man")
    bid = body_of(man_v)[:32]
    # different single-byte preimage than man stream
    data = b"\xfe"
    ck, cv = rebuild_chunk_foreign_headers(
        bid, data, index=0, total=1, man_value_digest=d3s1.value_digest(man_v)
    )
    return sort_rows(rows + [mkrow(ck, cv)])

def mat27_hist():
    """Historical BLOB after DesiredState terminal release: man absent + dig retained.

    R25: Mode27 HISTORICAL is terminal/released with manifest absent (docs/17 Mode27
    table) — not the discard-bit alone. DesiredState legal TERMINAL+EXPIRED+MISSED
    with explicitly_discarded=0 is D1-legal (docs/12 family table). Event discard
    HISTORICAL is a separate EF fixture with RELEASED/DISCARDED spool.
    """
    anc_k, anc_v = gkey("DSB2_ANCHOR_TYPED"), gval("DSB2_ANCHOR_TYPED")
    st_k, st_v = gkey("DSB2_STATE_TYPED"), gval("DSB2_STATE_TYPED")
    man_k = gkey("DSB3_BLOB_MAN_ZERO_TYPED")
    anc_v = set_payload_blob_dig(anc_v, d3s1.key_digest(man_k))
    st_v = _sync_state_avd_pvd_to_anchor(anc_v, st_v)
    sb = bytearray(body_of(st_v))
    # TERMINAL + EXPIRED + MISSED + DEADLINE_ELAPSED; discarded=0; DS counters 0
    sb[48:52] = struct.pack(">I", _D1_TXN_TERMINAL)
    sb[52:56] = struct.pack(">I", _D1_OUT_EXPIRED)
    sb[56:60] = struct.pack(">I", _D1_DDL_MISSED)
    sb[64:68] = struct.pack(">I", _D1_R_DEADLINE_ELAPSED)
    sb[68:72] = struct.pack(">I", _D1_PARK_NONE)
    sb[72:80] = struct.pack(">Q", 0)  # retry_cycle_id
    sb[80:84] = struct.pack(">I", 0)  # attempt_in_cycle
    sb[92:100] = struct.pack(">Q", 0)  # event_spool_revision
    sb[104:108] = struct.pack(">I", 0)  # explicitly_discarded
    t_off = 108 + d3s1.TARGET_LEN
    sb[t_off : t_off + 4] = struct.pack(">I", _D1_TXN_TERMINAL)
    sb[t_off + 4 : t_off + 8] = struct.pack(">I", _D1_OUT_EXPIRED)
    sb[t_off + 8 : t_off + 12] = struct.pack(">I", _D1_R_DEADLINE_ELAPSED)
    avd = d3s1.value_digest(anc_v)
    st_v = d3s1.enc_env_full(6, 0x22, 0, 1, body_of(anc_v)[:16], st_v[40:72], avd, bytes(sb))
    return sort_rows(profile_rows() + [mkrow(anc_k, anc_v), mkrow(st_k, st_v)])

def mat27_orphan():
    man_k = gkey("DSB3_BLOB_MAN_TX_CMD_TYPED")
    return [r for r in mat27_chunked() if d3s1.from_hex(r["key_hex"]) != man_k]


def _promote_anchor_to_eventfact(anc_v: bytes, event_id: Optional[bytes] = None) -> bytes:
    """R20/R21: DesiredState → EventFact with full EF closures + derived event_map.

    EventFact Normative (docs/17 §8.2): event_id non-zero, generation 0,
    deadline_clock_epoch zero, absolute_effect_deadline_ms = NINLIL_NO_DEADLINE
    (UINT64_MAX), evidence_grace_ms 0, event_map = KEY_DIGEST(EVENT_ID_MAP).
    """
    body = bytearray(body_of(anc_v))
    # family at offset 16+8+8 = 32
    body[32:36] = struct.pack(">I", 1)  # EventFact
    # SERVICE_IDENTITY.family must match body.family (docs/17 §8.2).
    o = 16 + 8 + 8 + 4 + d3s1.PARTY_LEN
    si_start = o
    for _ in range(3):
        if o >= len(body):
            raise ValueError("anchor SI text")
        o = o + 1 + body[o]
    # rev8 + dig32 + major2 + minor2 + family4
    fam_off = o + 8 + 32 + 2 + 2
    if fam_off + 4 > len(body):
        raise ValueError("anchor SI family")
    body[fam_off : fam_off + 4] = struct.pack(">I", 1)
    o = fam_off + 4
    o += 32 + 32  # content + canon
    if event_id is None:
        event_id = bytes([0x81] + [0] * 14 + [0x42])
    if len(event_id) != 16 or event_id == bytes(16):
        raise ValueError("event_id")
    body[o : o + 16] = event_id
    o += 16
    body[o : o + 8] = struct.pack(">Q", 0)  # generation 0 for EventFact
    o += 8
    # admission_clock_epoch16 + admitted_at_ms u64 — leave as-is (non-zero epoch)
    o += 16 + 8
    # R21: EventFact deadline epoch zero, abs = UINT64_MAX, grace 0
    body[o : o + 16] = bytes(16)
    o += 16
    body[o : o + 8] = struct.pack(">Q", UINT64_MAX)
    o += 8
    body[o : o + 8] = struct.pack(">Q", 0)
    o += 8
    o += 4 + 4 + d3s1.TARGET_LEN  # required + target_count + target
    scope, o = _d1_parse_raw16_at(bytes(body), o)
    ikey, o = _d1_parse_raw16_at(bytes(body), o)
    if scope is None or ikey is None:
        raise ValueError("anchor scope/ikey")
    # digests: seq, im, event_map, res — only rewrite event_map; keep seq/im/res
    em_off = o + 32 + 32
    want_em = d3s1.complete_key_digest_composite(0x25, d3s1.raw16(scope) + event_id)
    body[em_off : em_off + 32] = want_em
    return d3s1.enc_env_full(
        6, 0x20, 0, 1, anc_v[24:40], anc_v[40:72], anc_v[72:104], bytes(body)
    )


def _ef_event_id_from_anchor(anc_v: bytes) -> bytes:
    """Extract EventFact event_id[16] from ANCHOR body (docs/17 §8.2 layout)."""
    body = body_of(anc_v)
    o = 16 + 8 + 8 + 4 + d3s1.PARTY_LEN
    for _ in range(3):
        if o >= len(body):
            raise ValueError("anchor SI text")
        o = o + 1 + body[o]
    o = o + 8 + 32 + 2 + 2 + 4  # SI rev/dig/major/minor/family
    o += 32 + 32  # content + canon
    if o + 16 > len(body):
        raise ValueError("anchor event_id")
    eid = body[o : o + 16]
    if eid == bytes(16):
        raise ValueError("event_id zero")
    return eid


def _rebuild_state_for_anchor(
    anc_v: bytes,
    st_template: bytes,
    *,
    state: int,
    outcome: int = 0,
    reason: int = 0,
    park: int = 0,
    ddl: int = _D1_DDL_NA,
    latest: int = 0,
    retry: int = 1,
    attempt: int = 0,
    cumul: int = 0,
    es_rev: int = 1,
    has_late: int = 0,
    discarded: int = 0,
    head: Optional[bytes] = None,
) -> Tuple[bytes, bytes]:
    """Rebuild TRANSACTION_STATE with family fields + matching avd and common PVD.

    anchor_value_digest and common primary_value_digest both equal complete ANCHOR
    value digest (docs/17 secondary PVD / STATE body avd).
    """
    tx = body_of(anc_v)[:16]
    avd = d3s1.value_digest(anc_v)
    body = _d1_state_apply_fields(
        body_of(st_template),
        state=state,
        outcome=outcome,
        ddl=ddl,
        latest=latest,
        reason=reason,
        park=park,
        retry=retry,
        attempt=attempt,
        cumul=cumul,
        es_rev=es_rev,
        has_late=has_late,
        discarded=discarded,
        mirror=True,
    )
    body = bytearray(body)
    body[0:16] = tx
    body[16:48] = avd
    if head is None:
        head = st_template[40:72]
        if head == D1_ZERO32:
            head = D1_NONZERO_HEAD
    st_k = o1a_state_key(tx)
    st_v = d3s1.enc_env_full(
        6, 0x22, 0, max(1, int.from_bytes(st_template[16:24], "big")),
        tx, head, avd, bytes(body),
    )
    return st_k, st_v


def _rebuild_spool_for_anchor(
    anc_v: bytes,
    es_template: bytes,
    *,
    spool_state: int,
    park_cause: int = 0,
    rev: int = 1,
    retry: int = 1,
    discard_flag: int = 0,
    payload_dig: Optional[bytes] = None,
    head: Optional[bytes] = None,
) -> Tuple[bytes, bytes]:
    """Rebuild EVENT_SPOOL bound to ANCHOR tx/event with matching revision/shape."""
    tx = body_of(anc_v)[:16]
    event = _ef_event_id_from_anchor(anc_v)
    es_body = bytearray(body_of(es_template))
    if len(es_body) != 300:
        raise ValueError("es template body")
    es_body[0:16] = tx
    es_body[16:32] = event
    es_body[32:40] = struct.pack(">Q", rev)
    es_body[40:44] = struct.pack(">I", spool_state)
    es_body[44:48] = struct.pack(">I", park_cause)
    es_body[48:56] = struct.pack(">Q", retry)
    if payload_dig is None:
        payload_dig = es_body[56:88]
        if payload_dig == D1_ZERO32:
            payload_dig = bytes([0xA5]) * 32
    es_body[56:88] = payload_dig
    # discard flag at body[300-36:300-32]; bijection with DISCARDED state
    es_body[300 - 36 : 300 - 32] = struct.pack(">I", 1 if discard_flag else 0)
    # reservation key digest last 32
    es_body[300 - 32 : 300] = _d1_res_kd_tx(tx)
    if head is None:
        head = es_template[40:72]
        if head == D1_ZERO32:
            head = D1_NONZERO_HEAD
    pvd = d3s1.value_digest(anc_v)
    es_k = o1a_spool_key(tx)
    es_v = d3s1.enc_env_full(6, 0x50, 0, rev, tx, head, pvd, bytes(es_body))
    return es_k, es_v


def mat27_eventfact_chunked():
    """Mode27 EventFact LIVE: family-correct STATE + ACTIVE spool + man/chunk.

    R26: full rebuild (not ANCHOR-only promote). STATE is EF READY with ddl=NA,
    retry/es_rev≥1, matching anchor_value_digest and common PVD; EVENT_SPOOL is
    ACTIVE with matching tx/event/revision/spool body.
    """
    anc_k, anc_v = gkey("DSB2_ANCHOR_TYPED"), gval("DSB2_ANCHOR_TYPED")
    st_tmpl = gval("DSB2_STATE_TYPED")
    man_k, man_v = gkey("DSB3_BLOB_MAN_TX_CMD_TYPED"), gval("DSB3_BLOB_MAN_TX_CMD_TYPED")
    chk_k, chk_v = gkey("DSB3_BLOB_CHK_SINGLE_TYPED"), gval("DSB3_BLOB_CHK_SINGLE_TYPED")
    anc_v = _promote_anchor_to_eventfact(anc_v)
    anc_v = set_payload_blob_dig(anc_v, d3s1.key_digest(man_k))
    st_k, st_v = _rebuild_state_for_anchor(
        anc_v, st_tmpl,
        state=_D1_TXN_READY, outcome=0, reason=0, park=0,
        ddl=_D1_DDL_NA, latest=0, retry=1, attempt=0, cumul=0, es_rev=1,
        has_late=0, discarded=0,
    )
    es_k, es_v = _rebuild_spool_for_anchor(
        anc_v, gval("DSB3_ES_ACTIVE_TYPED"),
        spool_state=_D1_ES_ACTIVE, park_cause=0, rev=1, retry=1, discard_flag=0,
    )
    man_v = d3s1.patch_pvd(man_v, d3s1.value_digest(anc_v))
    chk_v = d3s1.patch_pvd(chk_v, d3s1.value_digest(man_v))
    return sort_rows(profile_rows() + [
        mkrow(anc_k, anc_v), mkrow(st_k, st_v), mkrow(es_k, es_v),
        mkrow(man_k, man_v), mkrow(chk_k, chk_v),
    ])


def mat27_ef_hist_receipt():
    """Mode27 EventFact HISTORICAL: terminal Receipt + RELEASED spool, man absent.

    TERMINAL+SATISFIED+REQUIRED_EVIDENCE_MET+discarded=0; spool RELEASED;
    retained non-zero payload dig on ANCHOR; manifest absent.
    """
    anc_k, anc_v = gkey("DSB2_ANCHOR_TYPED"), gval("DSB2_ANCHOR_TYPED")
    st_tmpl = gval("DSB2_STATE_TYPED")
    man_k = gkey("DSB3_BLOB_MAN_ZERO_TYPED")
    anc_v = _promote_anchor_to_eventfact(anc_v)
    anc_v = set_payload_blob_dig(anc_v, d3s1.key_digest(man_k))
    st_k, st_v = _rebuild_state_for_anchor(
        anc_v, st_tmpl,
        state=_D1_TXN_TERMINAL, outcome=_D1_OUT_SATISFIED,
        reason=_D1_R_REQUIRED_EVIDENCE_MET, park=0, ddl=_D1_DDL_NA,
        latest=1, retry=1, attempt=0, cumul=1, es_rev=2,
        has_late=0, discarded=0,
    )
    es_k, es_v = _rebuild_spool_for_anchor(
        anc_v, gval("DSB3_ES_RELEASED_TYPED"),
        spool_state=_D1_ES_RELEASED, park_cause=0, rev=2, retry=1, discard_flag=0,
    )
    return sort_rows(profile_rows() + [
        mkrow(anc_k, anc_v), mkrow(st_k, st_v), mkrow(es_k, es_v),
    ])


def mat27_ef_hist_discard():
    """Mode27 EventFact HISTORICAL: audited discard + DISCARDED spool, man absent.

    TERMINAL+FAILED+OPERATOR_DISCARDED+discarded=1; spool DISCARDED; dig retained.
    """
    anc_k, anc_v = gkey("DSB2_ANCHOR_TYPED"), gval("DSB2_ANCHOR_TYPED")
    st_tmpl = gval("DSB2_STATE_TYPED")
    man_k = gkey("DSB3_BLOB_MAN_ZERO_TYPED")
