def mat30_missing_dlv():
    return drop_subtype(mat30_receipt_empty(), 0x40)

def mat30_missing_rc():
    return drop_subtype(mat30_receipt_empty(), 0x41)

def mat30_missing_cell():
    rows = []
    for r in mat30_receipt_empty():
        k = d3s1.from_hex(r["key_hex"])
        if len(k) >= 10 and k[9] == 0x32:
            continue
        rows.append(r)
    return sort_rows(rows)

def mat30_mixup():
    """body_blob points at COMMAND man (blob_kind != REPLY) → CORRUPT."""
    rr_k, rr_v = gkey("DSB3_RR_KIND_RECEIPT_TYPED"), gval("DSB3_RR_KIND_RECEIPT_TYPED")
    dlv_k, dlv_v = gkey("DSB3_DLV_APP_DS_TYPED"), gval("DSB3_DLV_APP_DS_TYPED")
    rc_k, rc_v = gkey("DSB3_RC_RESULT_POS_TYPED"), gval("DSB3_RC_RESULT_POS_TYPED")
    man_k, man_v = gkey("DSB3_BLOB_MAN_DLV_CMD_TYPED"), gval("DSB3_BLOB_MAN_DLV_CMD_TYPED")
    man_v = d3s1.patch_pvd(man_v, d3s1.value_digest(dlv_v))
    # fake non-zero semantic so setup reaches man kind check
    rr_v = _patch_rr_semantic_and_blob(rr_v, man_k, bytes([0x51]) * 32)
    return sort_rows(profile_rows() + [
        mkrow(rr_k, rr_v), mkrow(dlv_k, dlv_v), mkrow(rc_k, rc_v), mkrow(man_k, man_v),
    ])

def mat30_stage_mismatch():
    """R20: cell locally D1-valid; RC.evidence_stage disagrees (cross-row)."""
    rows = []
    for r in mat30_receipt_1byte():
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x41:
            body = bytearray(body_of(v))
            # evidence_stage sits just after application_result_kind
            o = 2 + 80 + 32 + 16 + 8 + 4 + 4 + 4 + 4 + 16 + 8 + 16 + 8 + 16 + 8 + 8 + 8 + 8 + 8 + 16 + 8
            o += 4  # app_kind
            cur = struct.unpack(">I", body[o : o + 4])[0]
            body[o : o + 4] = struct.pack(">I", cur ^ 0x2 if cur else 2)
            # keep closed product: RESULT_COMMITTED requires e_pos with non-zero evi
            if struct.unpack(">I", body[o : o + 4])[0] == 0:
                body[o : o + 4] = struct.pack(">I", 2)
            v = d3s1.enc_env_full(6, 0x41, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        rows.append(mkrow(k, v))
    return sort_rows(rows)

def mat30_digest_mismatch():
    """R20: cell dig matches cell bytes; man/chunk stream differs (cross-row)."""
    base = mat30_receipt_1byte()
    # Rebuild man/chunk with alternate 1-byte stream; leave cell as original evidence.
    alt = b"\xa5"
    out = []
    man_k = man_v = None
    for r in base:
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            ok, bk, owner_raw = man_owner_raw(v)
            dlv_v = None
            for r2 in base:
                k2 = d3s1.from_hex(r2["key_hex"]); v2 = d3s1.from_hex(r2["value_hex"])
                if len(k2) >= 10 and k2[9] == 0x40:
                    dlv_v = v2
                    break
            man_k, man_v = rebuild_manifest(
                ok, owner_raw, bk, alt, v[24:40],
                d3s1.value_digest(dlv_v) if dlv_v else D1_NONZERO_PVD, v[40:72],
            )
            out.append(mkrow(man_k, man_v))
            continue
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 2:
            continue  # drop old chunk; rebuild below
        if len(k) >= 10 and k[9] == 0x42 and man_k is not None:
            # retarget RR blob dig after man rebuild — handled in second pass
            out.append(mkrow(k, v))
            continue
        out.append(mkrow(k, v))
    if man_k is None or man_v is None:
        raise RuntimeError("digest_mismatch: no man")
    ck, cv = rebuild_chunk(man_k, man_v, alt, 0)
    final = []
    for r in out:
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x42:
            v = _patch_rr_semantic_and_blob(v, man_k, o1a_dec_rr(v)["semantic_digest"])
            # keep original semantic; only blob dig retarget
            body = bytearray(body_of(v))
            _, _, blob_off = rr_attempt_and_semantic_off(bytes(body))
            body[blob_off : blob_off + 32] = d3s1.key_digest(man_k)
            v = d3s1.enc_env_full(6, 0x42, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        final.append(mkrow(k, v))
    final.append(mkrow(ck, cv))
    return sort_rows(final)

def mat30_orphan_chunk():
    """Orphan BLOB chunk under Mode30 BIND (RR-band SCAN)."""
    return mat27_orphan()

def _rr_with_kind_key(rr_v: bytes, reply_kind: int) -> Tuple[bytes, bytes]:
    """Rebuild RR complete key from reply_key_raw with patched reply_kind."""
    body = bytearray(body_of(rr_v))
    rl = struct.unpack(">H", body[0:2])[0]
    raw = bytearray(body[2 : 2 + rl])
    # reply raw = raw16(delivery80) + reply_kind u32
    if len(raw) < 6:
        raise ValueError("reply raw short")
    raw[-4:] = struct.pack(">I", reply_kind)
    body[2 : 2 + rl] = raw
    # also body fixed reply_kind after delivery_key_raw section
    o = 2 + rl
    dl = struct.unpack(">H", body[o : o + 2])[0]
    kind_off = o + 2 + dl + 16
    body[kind_off : kind_off + 4] = struct.pack(">I", reply_kind)
    new_v = d3s1.enc_env_full(
        6, 0x42, 0, 1, rr_v[24:40], rr_v[40:72], rr_v[72:104], bytes(body)
    )
    comp = struct.pack(">H", rl) + bytes(raw)
    dig = d3s1.composite(0x42, comp)
    new_k = d3s1.bkey(6, 0x42, 5, dig)
    return new_k, new_v

def mat30_two_rr_shared():
    """Same-delivery 2 live RR kinds sharing one REPLY man digest.

    §18.14.2 / AFP #7: distinct reply_kind on the same delivery may share
    KEY_DIGEST. Both must be LIVE (state 1..4, not HISTORICAL state5).
    RECEIPT + CUSTODY share POS RESULT (CUSTODY matrix allows non-DISP shape;
    same RESULT cannot be E_POS and E_DISP simultaneously).
    """
    base = mat30_receipt_empty()
    man_k = None
    for r in base:
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_k = k
            break
    if man_k is None:
        raise RuntimeError("two_rr: missing man")
    # Second live RR: CUSTODY (kind=3); empty REPLY; same POS RESULT companion.
    rr_k2, rr_v2 = _rr_with_kind_key(gval("DSB3_RR_KIND_RECEIPT_TYPED"), 3)
    dlv_v = gval("DSB3_DLV_APP_DS_TYPED")
    dlv_b = body_of(dlv_v)
    tx, event, party, target, svc, content, gen, dep, abs_ms, grace, req = dlv_msd_fields(dlv_b)
    attempt, _, _ = rr_attempt_and_semantic_off(body_of(rr_v2))
    sem = msd_parts(
        5, 0, tx, attempt, event, party, target, svc, content, gen, dep, abs_ms, grace, req,
        0, 0, 0, 0, 0, 0, bytes(16), 0, 0, b"", b"",
    )
    rr_v2 = _patch_rr_semantic_and_blob(rr_v2, man_k, sem)
    return sort_rows(list(base) + [mkrow(rr_k2, rr_v2)])

def _cs_cancel_kind(cs_v: bytes) -> int:
    b = body_of(cs_v)
    o = 4
    orl = struct.unpack(">H", b[o : o + 2])[0]
    o += 2 + orl + 32 + 16 + 16 + 4  # past state
    return struct.unpack(">I", b[o : o + 4])[0]

def mat30_cancel_empty():
    """Mode30 CANCEL_RESULT empty REPLY man + CANCEL_STATE companion (#10).

    RESULT.cancel_result_kind must bijection-match CANCEL_STATE.cancel_kind
    (§18.14.7.3). POS RESULT (cancel_rk=0) with cancel_kind=1 is illegal.
    """
    rr_k, rr_v = _rr_with_kind_key(gval("DSB3_RR_KIND_RECEIPT_TYPED"), 4)
    dlv_k, dlv_v = gkey("DSB3_DLV_APP_DS_TYPED"), gval("DSB3_DLV_APP_DS_TYPED")
    # CANCEL_FIRST RESULT has cancel_result_kind=1 (FENCED_BEFORE_DISPATCH).
    rc_k, rc_v = gkey("DSB3_RC_CANCEL_FIRST_TYPED"), gval("DSB3_RC_CANCEL_FIRST_TYPED")
    cs_k, cs_v = gkey("DSB3_CS_DLV_FENCED_TYPED"), gval("DSB3_CS_DLV_FENCED_TYPED")
    base_man_v = gval("DSB3_BLOB_MAN_DLV_RPL_TYPED")
    ok, bk, owner_raw = man_owner_raw(base_man_v)
    man_k, man_v = rebuild_manifest(
        ok, owner_raw, bk, b"", base_man_v[24:40], d3s1.value_digest(dlv_v), base_man_v[40:72]
    )
    dlv_b = body_of(dlv_v)
    tx, event, party, target, svc, content, gen, dep, abs_ms, grace, req = dlv_msd_fields(dlv_b)
    attempt, _, _ = rr_attempt_and_semantic_off(body_of(rr_v))
    ck = _cs_cancel_kind(cs_v)
    if ck not in (1, 3):
        raise ValueError(f"cancel_kind {ck}")
    # Ensure RESULT cancel_result_kind matches CANCEL_STATE (patch if needed).
    rc_b = bytearray(body_of(rc_v))
    # cancel_result_kind sits after token_state u32 following evidence_cell dig32
    # layout after application_result block: ... retry_delay + dig32 + token_state + cancel_result_kind
    o = 2 + 80 + 32 + 16 + 8 + 4 + 4 + 4 + 4 + 16 + 8 + 16 + 8 + 16 + 8 + 8 + 8 + 8 + 8 + 16 + 8
    o += 4 + 4 + 4 + 4 + 4 + 4 + 8 + 32 + 4  # app..token_state
    rc_b[o : o + 4] = struct.pack(">I", ck)
    rc_v = d3s1.enc_env_full(
        6, 0x41, 0, 1, rc_v[24:40], rc_v[40:72], rc_v[72:104], bytes(rc_b)
    )
    sem = msd_parts(
        6, 0, tx, attempt, event, party, target, svc, content, gen, dep, abs_ms, grace, req,
        0, 0, 0, 0, ck, 0, bytes(16), 0, 0, b"", b"",
    )
    rr_v = _patch_rr_semantic_and_blob(rr_v, man_k, sem)
    return sort_rows(profile_rows() + [
        mkrow(rr_k, rr_v), mkrow(dlv_k, dlv_v), mkrow(rc_k, rc_v),
        mkrow(man_k, man_v), mkrow(cs_k, cs_v),
    ])

def mat30_missing_cancel():
    return drop_subtype(mat30_cancel_empty(), 0x33)

def mat30_receipt_128():
    """Mode30 RECEIPT exact 128-byte boundary (single chunk; #15/#16)."""
    rr_k, rr_v = gkey("DSB3_RR_KIND_RECEIPT_TYPED"), gval("DSB3_RR_KIND_RECEIPT_TYPED")
    dlv_k, dlv_v = gkey("DSB3_DLV_APP_DS_TYPED"), gval("DSB3_DLV_APP_DS_TYPED")
    rc_k, rc_v = gkey("DSB3_RC_RESULT_POS_TYPED"), gval("DSB3_RC_RESULT_POS_TYPED")
    base_man_v = gval("DSB3_BLOB_MAN_DLV_RPL_TYPED")
    cell_k, cell_v = gkey("DSB3_EV_DLV_SUM_EMPTY_TYPED"), gval("DSB3_EV_DLV_SUM_EMPTY_TYPED")
    evidence = bytes([(i * 17 + 3) & 0xFF for i in range(128)])
    ok, bk, owner_raw = man_owner_raw(base_man_v)
    man_k, man_v = rebuild_manifest(
        ok, owner_raw, bk, evidence, base_man_v[24:40], d3s1.value_digest(dlv_v), base_man_v[40:72]
    )
    ck, cv = rebuild_chunk(man_k, man_v, evidence, 0)
    stage = rc_evidence_stage(body_of(rc_v))
    dlv_b = body_of(dlv_v)
    content = dlv_msd_fields(dlv_b)[5]
    epoch = bytes([0xE2]) + bytes(15)
    cell_v = _patch_cell_summary_material(
        cell_v, stage, evidence,
        _party_from_dlv(dlv_b), _service_from_dlv(dlv_b),
        content, 1, epoch, 9, 1,
    )
    tx, event, party, target, svc, content, gen, dep, abs_ms, grace, req = dlv_msd_fields(dlv_b)
    attempt, _, _ = rr_attempt_and_semantic_off(body_of(rr_v))
    sem = msd_parts(
        2, 0, tx, attempt, event, party, target, svc, content, gen, dep, abs_ms, grace, req,
        stage, 0, 0, 0, 0, 0, epoch, 9, 1, b"", evidence,
    )
    rr_v = _patch_rr_semantic_and_blob(rr_v, man_k, sem)
    return sort_rows(profile_rows() + [
        mkrow(rr_k, rr_v), mkrow(dlv_k, dlv_v), mkrow(rc_k, rc_v),
        mkrow(man_k, man_v), mkrow(ck, cv), mkrow(cell_k, cell_v),
    ])

def mat30_cell_len_mismatch():
    """R20: cell locally valid (len=1); man total=0 empty (cross-row length)."""
    base = mat30_receipt_1byte()
    out = []
    man_k = man_v = None
    for r in base:
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            ok, bk, owner_raw = man_owner_raw(v)
            dlv_v = None
            for r2 in base:
                k2 = d3s1.from_hex(r2["key_hex"]); v2 = d3s1.from_hex(r2["value_hex"])
                if len(k2) >= 10 and k2[9] == 0x40:
                    dlv_v = v2
                    break
            man_k, man_v = rebuild_manifest(
                ok, owner_raw, bk, b"", v[24:40],
                d3s1.value_digest(dlv_v) if dlv_v else D1_NONZERO_PVD, v[40:72],
            )
            out.append(mkrow(man_k, man_v))
            continue
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 2:
            continue  # empty man → no chunk
        out.append(mkrow(k, v))
    if man_k is None:
        raise RuntimeError("cell_len: no man")
    final = []
    for r in out:
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x42:
            body = bytearray(body_of(v))
            _, _, blob_off = rr_attempt_and_semantic_off(bytes(body))
            body[blob_off : blob_off + 32] = d3s1.key_digest(man_k)
            v = d3s1.enc_env_full(6, 0x42, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        final.append(mkrow(k, v))
    return sort_rows(final)

def mat30_cell_byte_mismatch():
    """R20: cell locally valid with bytes X; man/chunk stream Y (cross-row bytes)."""
    # Same construct as digest mismatch: alternate stream vs cell evidence.
    return mat30_digest_mismatch()

def mat30_cross_delivery():
    """Shared dig man belongs to different delivery raw than RR → #14 CORRUPT."""
    rows = mat30_receipt_empty()
    # Flip owner raw inside man while keeping key/digest identity via body patch —
    # better: rebuild man with alternate owner raw so KEY_DIGEST changes, then
    # point RR body_blob at original man key dig while man owner is foreign.
    # Construct: keep RR dig = KEY_DIGEST(man_k) but man owner_raw != RR delivery raw.
    rr_k = gkey("DSB3_RR_KIND_RECEIPT_TYPED")
    # foreign delivery raw: flip one byte of APP delivery contents
    dlv_v = gval("DSB3_DLV_APP_DS_TYPED")
    dlv_b = body_of(dlv_v)
    dl = struct.unpack(">H", dlv_b[0:2])[0]
    foreign = bytearray(dlv_b[2 : 2 + dl])
    foreign[0] ^= 0x01
    out = []
    for r in rows:
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            ok, bk, _ = man_owner_raw(v)
            # rebuild man with foreign owner; keep stream empty; pin dig from original key?
            # For SCAN match: RR points at KEY_DIGEST(this key). owner raw wrong vs RR.
            man_k, man_v = rebuild_manifest(
                ok, bytes(foreign), bk, b"", v[24:40], d3s1.value_digest(dlv_v), v[40:72]
            )
            # re-link RR dig to new man key
            out.append(mkrow(man_k, man_v))
            # patch RR in second pass
            rr_new_k = None
            rr_new_v = None
            for r2 in rows:
                k2 = d3s1.from_hex(r2["key_hex"]); v2 = d3s1.from_hex(r2["value_hex"])
                if len(k2) >= 10 and k2[9] == 0x42:
                    # keep semantic; only retarget blob dig
                    body = bytearray(body_of(v2))
                    _, sem_off, blob_off = rr_attempt_and_semantic_off(bytes(body))
                    body[blob_off : blob_off + 32] = d3s1.key_digest(man_k)
                    v2 = d3s1.enc_env_full(
                        6, 0x42, 0, 1, v2[24:40], v2[40:72], v2[72:104], bytes(body)
                    )
                    rr_new_k, rr_new_v = k2, v2
            rebuilt = [r2 for r2 in rows if not (
                len(d3s1.from_hex(r2["key_hex"])) >= 10 and d3s1.from_hex(r2["key_hex"])[9] in (0x30, 0x42)
            )]
            rebuilt.append(mkrow(man_k, man_v))
            rebuilt.append(mkrow(rr_new_k, rr_new_v))
            return sort_rows(rebuilt)
        out.append(mkrow(k, v))
    raise RuntimeError("cross_delivery rebuild failed")

def mat30_orphan_man_0rr():
    """REPLY man present with 0 RR referrer → BIND orphan CORRUPT."""
    rows = []
    for r in mat30_receipt_empty():
        k = d3s1.from_hex(r["key_hex"])
        if len(k) >= 10 and k[9] == 0x42:
            continue  # drop all RR
        rows.append(r)
    return sort_rows(rows)

def mat30_disp_nonempty():
    """DISPOSITION with non-zero REPLY total_length → #15 CORRUPT."""
    rr_k, rr_v = _rr_with_kind_key(gval("DSB3_RR_KIND_RECEIPT_TYPED"), 2)
    dlv_k, dlv_v = gkey("DSB3_DLV_APP_DS_TYPED"), gval("DSB3_DLV_APP_DS_TYPED")
    rc_k, rc_v = gkey("DSB3_RC_DISP_PRE_TYPED"), gval("DSB3_RC_DISP_PRE_TYPED")
    base_man_v = gval("DSB3_BLOB_MAN_DLV_RPL_TYPED")
    ok, bk, owner_raw = man_owner_raw(base_man_v)
    stream = b"\xab"
    man_k, man_v = rebuild_manifest(
        ok, owner_raw, bk, stream, base_man_v[24:40], d3s1.value_digest(dlv_v), base_man_v[40:72]
    )
    ck, cv = rebuild_chunk(man_k, man_v, stream, 0)
    # non-zero dig so SCAN installs and #15 fires
    rr_v = _patch_rr_semantic_and_blob(rr_v, man_k, bytes([0x51]) * 32)
    return sort_rows(profile_rows() + [
        mkrow(rr_k, rr_v), mkrow(dlv_k, dlv_v), mkrow(rc_k, rc_v),
        mkrow(man_k, man_v), mkrow(ck, cv),
    ])

def mat30_disp_extra_chunk():
    """DISPOSITION empty man + D1-valid foreign-header chunk sharing blob_id.

    Empty man is D1-valid (total0/count0). Extra chunk is D1-valid under its own
    total/count/content (blob_id not recomputed on chunk). BIND_CHUNK step4
    count/total/content equality fails. Not index>=count (D1-illegal).
    """
    rows = mat30_disposition_empty()
    man_k = man_v = None
    for r in rows:
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_k, man_v = k, v
            break
    if man_k is None:
        raise RuntimeError("no man")
    bid = body_of(man_v)[:32]
    data = b"\x01"
    ck, cv = rebuild_chunk_foreign_headers(
        bid, data, index=0, total=1, man_value_digest=d3s1.value_digest(man_v)
    )
    return sort_rows(rows + [mkrow(ck, cv)])

def mat27_total_mismatch():
    """Cross-row: D1-valid man total_length != D1-valid chunk total_length (same bid).

    Man body total is not mutated in place (would break blob_id / count ceil).
    Replace the sole chunk with a foreign-header D1-valid chunk (total=2).
    """
    rows = []
    man_v = man_k = None
    for r in mat27_chunked():
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_k, man_v = k, v
            rows.append(mkrow(k, v))
            continue
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 2:
            continue  # drop matching chunk; replace below
        rows.append(mkrow(k, v))
    if man_k is None or man_v is None:
        raise RuntimeError("mat27_total_mismatch: no man")
    bid = body_of(man_v)[:32]
    data = b"\x02\x03"  # total=2 single-chunk D1-legal
    ck, cv = rebuild_chunk_foreign_headers(
        bid, data, index=0, total=2, man_value_digest=d3s1.value_digest(man_v)
    )
    return sort_rows(rows + [mkrow(ck, cv)])

def mat27_count_mismatch():
    """Cross-row: D1-valid man count=1 vs D1-valid chunk declaring count=2 (same bid).

    Not man.count=2 with total for 1 (D1 count≠ceil(total)). Foreign chunk uses
    total=3073 so ceil→2; index=0 non-final length exact 3072.
    """
    rows = []
    man_v = man_k = None
    for r in mat27_chunked():
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_k, man_v = k, v
            rows.append(mkrow(k, v))
            continue
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 2:
            continue
        rows.append(mkrow(k, v))
    if man_k is None or man_v is None:
        raise RuntimeError("mat27_count_mismatch: no man")
    bid = body_of(man_v)[:32]
    data = bytes([0x41]) * BLOB_CHUNK_DATA_MAX  # non-final of count=2
    ck, cv = rebuild_chunk_foreign_headers(
        bid, data, index=0, total=BLOB_CHUNK_DATA_MAX + 1,
        man_value_digest=d3s1.value_digest(man_v),
    )
    return sort_rows(rows + [mkrow(ck, cv)])

def mat27_missing_chunk():
    """LIVE man count>=1 with chunk row dropped."""
    return sort_rows([
        r for r in mat27_chunked()
        if not (
            len(d3s1.from_hex(r["key_hex"])) >= 10
            and d3s1.from_hex(r["key_hex"])[9] == 0x30
            and d3s1.from_hex(r["value_hex"])[15] == 2
        )
    ])

def mat28_orphan():
    return mat27_orphan()

def mat29_orphan():
    return mat27_orphan()

def mat27_multi():
    """Non-empty multi-chunk positive: non-final 3072 + final 1 (D1 length rules)."""
    anc_k, anc_v = gkey("DSB2_ANCHOR_TYPED"), gval("DSB2_ANCHOR_TYPED")
    st_k, st_v = gkey("DSB2_STATE_TYPED"), gval("DSB2_STATE_TYPED")
    base_man_v = gval("DSB3_BLOB_MAN_TX_CMD_TYPED")
    ok, bk, owner_raw = man_owner_raw(base_man_v)
    data0 = bytes([0x41]) * 3072
    data1 = bytes([0x42])
    stream = data0 + data1
    # provisional man with zero PVD then patch after ANCHOR dig linked
    man_k, man_v = rebuild_manifest(
        ok, owner_raw, bk, stream, base_man_v[24:40], bytes(32), base_man_v[40:72]
    )
    anc_v = set_payload_blob_dig(anc_v, d3s1.key_digest(man_k))
    st_v = _sync_state_avd_pvd_to_anchor(anc_v, st_v)
    man_v = d3s1.patch_pvd(man_v, d3s1.value_digest(anc_v))
    c0k, c0v = rebuild_chunk(man_k, man_v, data0, 0)
    c1k, c1v = rebuild_chunk(man_k, man_v, data1, 1)
    return sort_rows(profile_rows() + [
        mkrow(anc_k, anc_v), mkrow(st_k, st_v), mkrow(man_k, man_v),
        mkrow(c0k, c0v), mkrow(c1k, c1v),
    ])

def mat27_duplicate_match():
    """Multiset complete-key man row (same key twice).

    REP1-v1 formal inputs forbid multiset complete keys (§18.14.19.1).
    The product vector is therefore zero-Port FAILED at the pre-generation gate
    (not a mid-FOCUS MATCH_DUPLICATE walk). Kept as an AFP case-11 negative
    with BLOB man rows present.
    """
    rows = mat27_zero()
    man_k = gkey("DSB3_BLOB_MAN_ZERO_TYPED")
    man_rows = [r for r in rows if d3s1.from_hex(r["key_hex"]) == man_k]
    return sort_rows(rows + man_rows)

def mat27_extra_chunk():
    """Extra D1-valid foreign-header chunk sharing man blob_id (cross-row D3).

    Not index>=count (D1-illegal; step5 index-only is non-constructible given
    D1 + BIND_CHUNK step4 equality). Foreign chunk: same bid, total/count/cd
    disagree with man; BIND_CHUNK step4 CORRUPT. FOCUS known-index path remains
    green on the matching index-0 chunk.
    """
    rows = mat27_chunked()
    man_k = man_v = None
    for r in rows:
        k = d3s1.from_hex(r["key_hex"]); v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_k, man_v = k, v
            break
    if man_k is None or man_v is None:
        raise RuntimeError("mat27_extra_chunk: no man")
    bid = body_of(man_v)[:32]
    # index=1 requires count>=2; total in 3073..6144 so ceil=2; final length=1
    data = b"\x99"
    ck, cv = rebuild_chunk_foreign_headers(
        bid,
        data,
        index=1,
        total=BLOB_CHUNK_DATA_MAX + 1,
        man_value_digest=d3s1.value_digest(man_v),
    )
    return sort_rows(rows + [mkrow(ck, cv)])

def mat29_terminal_hist():
    """APPLICATION_FIRST + terminal RESULT_CACHE → HISTORICAL_ABSENT OK."""
    dlv_k, dlv_v = gkey("DSB3_DLV_APP_DS_TYPED"), gval("DSB3_DLV_APP_DS_TYPED")
    rc_k, rc_v = gkey("DSB3_RC_RESULT_POS_TYPED"), gval("DSB3_RC_RESULT_POS_TYPED")
    man_k = gkey("DSB3_BLOB_MAN_DLV_CMD_TYPED")
    # keep non-zero dig so historical path (terminal) may leave man present or absent;
    # setup marks HISTORICAL_ABSENT when RC terminal — man may be present or not.
    dlv_v = set_dlv_payload_blob_dig(dlv_v, d3s1.key_digest(man_k))
    return sort_rows(profile_rows() + [mkrow(dlv_k, dlv_v), mkrow(rc_k, rc_v)])



