LC_NONE = 0
LC_LIVE_REQUIRED = 1
LC_HISTORICAL_ABSENT = 2
LC_ILLEGAL = 3

# Mode-scoped owner×blob_kind (D1 BLOB pairs + §18.14 BIND)
# 27 TX×COMMAND/EVENT; 28 ING×INGRESS_PAYLOAD/EVIDENCE;
# 29 DLV×COMMAND/EVENT; 30 DLV×REPLY (+ RR-band)
O1A_MODE_OWNER = {27: 1, 28: 2, 29: 3, 30: 3}
O1A_MODE_BLOB = {27: {1, 2}, 28: {3, 4}, 29: {1, 2}, 30: {5}}

O1A_ZERO32 = bytes(32)
O1A_MSD_LABEL = b"NINLIL-BEARER-MESSAGE-V1"
O1A_NLR1_HDR = 108  # domain NLR1 fixed header before body
O1A_NLR1_CRC = 4


# ---- independent D1 framing / hash (distinct from fixture helpers) ----

def o1a_empty_sha() -> bytes:
    return hashlib.sha256(b"").digest()


def o1a_body(val: bytes) -> bytes:
    """NLR1 domain value → typed body (header 108, trailing CRC32C 4)."""
    if len(val) < O1A_NLR1_HDR + O1A_NLR1_CRC:
        raise ValueError("o1a_body: value short")
    return val[O1A_NLR1_HDR : len(val) - O1A_NLR1_CRC]


def o1a_pvd(val: bytes) -> bytes:
    """Common header primary_value_digest at [72:104]."""
    if len(val) < 104:
        raise ValueError("o1a_pvd short")
    return val[72:104]


def o1a_flags(val: bytes) -> int:
    return val[15] if len(val) > 15 else 0


def o1a_value_typed_current(
    value: Optional[bytes],
    *,
    expect_subtype: int,
    expect_flags: int,
) -> Optional[str]:
    """Strict returned-value D1 domain CURRENT envelope on actual response bytes.

    Never consults request key. Complete CURRENT framing requires:
      NLR1 magic; family=6; record_version=1;
      outer payload length plen with total len == 12+plen+4 and plen >= 96;
      complete value length >= 112 (fixed domain header 108 + CRC 4 floor);
      domain_format at value[12:14] / payload[0:2] exactly 1;
      subtype/flags at value[14]/value[15];
      inner body_length at value[104:108] exactly plen-96 and exact body framing;
      CRC32C over all bytes except trailer.
    expect_flags required: non-BLOB 0; BLOB MAN 1; BLOB CHUNK 2.
    """
    if value is None or not isinstance(value, (bytes, bytearray)):
        return "absent_value"
    v = bytes(value)
    if len(v) < 16 or v[:4] != b"NLR1":
        return "not_nlr1"
    rtype = int.from_bytes(v[4:6], "big")
    rver = int.from_bytes(v[6:8], "big")
    plen = int.from_bytes(v[8:12], "big")
    if rtype != 6:
        return "family"
    if rver != 1:
        return "version"
    if plen < 96 or plen > VALUE_CAPACITY:
        return "payload_len"
    if len(v) != 12 + plen + 4:
        return "envelope_len"
    if len(v) < 112:
        return "short_domain"
    # CRC32C over all bytes except trailer (before other field trusts)
    try:
        got_crc = struct.unpack(">I", v[-4:])[0]
        want_crc = d3s1.crc32c(v[:-4])
    except Exception:
        return "crc"
    if got_crc != want_crc:
        return "crc"
    # domain_format u16be at payload start (value[12:14]) must be 1
    domain_format = int.from_bytes(v[12:14], "big")
    if domain_format != 1:
        return "domain_format"
    st = v[14]
    fl = v[15]
    if st != (expect_subtype & 0xFF):
        return "subtype"
    if fl != (expect_flags & 0xFF):
        return "flags"
    # fixed domain header is 108 bytes before body: NLR1(12)+envelope payload starts at 12;
    # common fixed fields occupy 96 bytes of payload before body; body starts at offset 108.
    # value[104:108] = body_length (inside payload: offset 12+92=104).
    body_len = int.from_bytes(v[104:108], "big")
    if body_len != plen - 96:
        return "body_len"
    # body occupies [108 : 108+body_len], trailer CRC at end; exact framing
    if 108 + body_len + 4 != len(v):
        return "body_framing"
    return None





# ---- REP1 product-path fixed memory model (maps to §18.14.12 754 layout) ----
# Concurrent product SHA contexts allowed: exactly 1 (sha_state/bitcount/block bank).
# No heap stream buffers; no multi complete-value retention across GETs/drives.
_PRODUCT_SHA_LIVE = 0
_PRODUCT_SHA_MAX = 1


class FixedSha256Product:
    """Conceptual fixed SHA-256 state for product path.

    Maps to context fields sha_state[32] + sha_bitcount[8] + sha_block[64] +
    sha_block_len[1] (105 bytes of the 754 layout). Python hashlib object is only
    a stand-in for that fixed bank — not an extra unbounded buffer.
    At most one live instance product-wide.
    """

    __slots__ = ("_h", "_closed")

    def __init__(self) -> None:
        global _PRODUCT_SHA_LIVE
        if _PRODUCT_SHA_LIVE >= _PRODUCT_SHA_MAX:
            raise RuntimeError("product SHA bank already live (max 1)")
        self._h = hashlib.sha256()
        self._closed = False
        _PRODUCT_SHA_LIVE += 1

    def update(self, data: bytes) -> None:
        if self._closed:
            raise RuntimeError("SHA context closed")
        if not isinstance(data, (bytes, bytearray)):
            raise TypeError("sha update requires bytes")
        self._h.update(bytes(data))

    def digest_finalize(self) -> bytes:
        """Finalize and release the single product SHA bank."""
        global _PRODUCT_SHA_LIVE
        if self._closed:
            raise RuntimeError("SHA already finalized")
        dig = self._h.digest()
        self._closed = True
        _PRODUCT_SHA_LIVE = max(0, _PRODUCT_SHA_LIVE - 1)
        return dig

    def abandon(self) -> None:
        global _PRODUCT_SHA_LIVE
        if not self._closed:
            self._closed = True
            _PRODUCT_SHA_LIVE = max(0, _PRODUCT_SHA_LIVE - 1)


