def layout_754_range(slot: str) -> Tuple[int, int]:
    """Return [start, end) byte range for a layout slot; end exclusive."""
    off, sz = LAYOUT_754_SLOTS[slot]
    return off, off + sz


def _layout_754_validate_static() -> None:
    """Fail-closed: slots pack to Σ=754 with no gaps/overlaps."""
    items = sorted(((n, o, s) for n, (o, s) in LAYOUT_754_SLOTS.items()), key=lambda t: t[1])
    cur = 0
    for name, off, sz in items:
        if off != cur:
            raise AssertionError(f"layout gap/overlap at {cur} before {name}@{off}")
        if sz < 1:
            raise AssertionError(f"layout empty {name}")
        cur = off + sz
    if cur != 754:
        raise AssertionError(f"layout sum {cur} != 754")
    for k, slot in PRODUCT_PATH_PIN_SLOT.items():
        if slot not in LAYOUT_754_SLOTS:
            raise AssertionError(f"pin map bad slot {k}->{slot}")
    for k, slot in PRODUCT_PATH_MAN_SLOT.items():
        if slot not in LAYOUT_754_SLOTS:
            raise AssertionError(f"man map bad slot {k}->{slot}")


_layout_754_validate_static()

