def o1a_man_product_pins(man: Dict[str, Any]) -> Dict[str, Any]:
    """Strip complete key/value; retain only 754-mappable man pin bank fields."""
    return {k: man[k] for k in PRODUCT_PATH_MAN_ALLOWLIST if k in man}


def product_pins_keep(pins: Dict[str, Any]) -> Dict[str, Any]:
    """Allowlist filter for call-spanning active_pins (R7)."""
    out: Dict[str, Any] = {}
    for k, v in pins.items():
        if k in PRODUCT_PATH_FORBIDDEN_PIN_KEYS:
            continue
        if k not in PRODUCT_PATH_PIN_ALLOWLIST:
            continue
        out[k] = v
    return out


def o1a_row_key(r: Dict[str, str]) -> bytes:
    return d3s1.from_hex(r["key_hex"])


def o1a_row_val(r: Dict[str, str]) -> bytes:
    return d3s1.from_hex(r["value_hex"])


def o1a_subtype(k: bytes) -> int:
    return k[9] if len(k) >= 10 else -1


def o1a_index(rows: List[Dict[str, str]]) -> Dict[bytes, bytes]:
    """Last-wins key map for exact_get-style lookups (not uniqueness)."""
    return {o1a_row_key(r): o1a_row_val(r) for r in rows}


def o1a_pairs(rows: List[Dict[str, str]]) -> List[Tuple[bytes, bytes]]:
    """Full multiset of (key, value) rows — preserves duplicates for uniqueness proofs."""
    return [(o1a_row_key(r), o1a_row_val(r)) for r in rows]


def o1a_carriers(mode: int, rows: List[Dict[str, str]]) -> List[bytes]:
    st = {27: 0x20, 28: 0x27, 29: 0x40, 30: 0x42}[mode]
    return sorted(k for k in (o1a_row_key(r) for r in rows) if o1a_subtype(k) == st)


def o1a_all_mans(rows: List[Dict[str, str]]) -> List[Tuple[bytes, bytes]]:
    out = []
    for r in rows:
        k, v = o1a_row_key(r), o1a_row_val(r)
        if o1a_subtype(k) == 0x30 and o1a_flags(v) == 1:
            out.append((k, v))
    return out


def o1a_all_chunks(rows: List[Dict[str, str]]) -> List[Tuple[bytes, bytes]]:
    out = []
    for r in rows:
        k, v = o1a_row_key(r), o1a_row_val(r)
        if o1a_subtype(k) == 0x30 and o1a_flags(v) == 2:
            out.append((k, v))
    return out


def o1a_dec_man(man_k: bytes, man_v: bytes) -> Dict[str, Any]:
    """BLOB manifest decode (offline/test helper).

    Returns complete key/value for offline helpers only. Product path must install
    via o1a_man_product_pins() (no key/value; single fixed pin bank).
    """
    if o1a_flags(man_v) != 1:
        raise ValueError("not manifest")
    body = o1a_body(man_v)
    if len(body) < 44:
        raise ValueError("man short")
    bid = body[0:32]
    owner_kind = struct.unpack(">H", body[32:34])[0]
    blob_kind = struct.unpack(">H", body[34:36])[0]
    rl = struct.unpack(">H", body[36:38])[0]
    if 38 + rl + 32 + 8 + 4 + 32 > len(body):
        raise ValueError("man trunc")
    owner_raw = body[38 : 38 + rl]
    opkd = body[38 + rl : 38 + rl + 32]
    base = 38 + rl + 32
    total = struct.unpack(">Q", body[base : base + 8])[0]
    count = struct.unpack(">I", body[base + 8 : base + 12])[0]
    cd = body[base + 12 : base + 44]
    return {
        "key": man_k,
        "value": man_v,
        "key_digest": d3s1.key_digest(man_k),
        "blob_id": bid,
        "owner_kind": owner_kind,
        "blob_kind": blob_kind,
        "owner_raw": owner_raw,
        "owner_primary_key_digest": opkd,
        "total_length": total,
        "chunk_count": count,
        "content_digest": cd,
        "expected_owner_pvd": o1a_pvd(man_v),
        "expected_manifest_value_digest": d3s1.value_digest(man_v),
    }


def o1a_dec_chunk(chk_k: bytes, chk_v: bytes) -> Dict[str, Any]:
    """Chunk: bid32 + man_kd32 + index u32 + count u32 + total u64 + cd32 + len u32 + data."""
    if o1a_flags(chk_v) != 2:
        raise ValueError("not chunk")
    body = o1a_body(chk_v)
    if len(body) < 116:
        raise ValueError("chunk short")
    bid = body[0:32]
    mkd = body[32:64]
    index = struct.unpack(">I", body[64:68])[0]
    count = struct.unpack(">I", body[68:72])[0]
    total = struct.unpack(">Q", body[72:80])[0]
    cd = body[80:112]
    dlen = struct.unpack(">I", body[112:116])[0]
    if 116 + dlen > len(body):
        raise ValueError("chunk data trunc")
    return {
        "key": chk_k,
        "value": chk_v,
        "blob_id": bid,
        "manifest_key_digest": mkd,
        "index": index,
        "chunk_count": count,
        "total_length": total,
        "content_digest": cd,
        "data": body[116 : 116 + dlen],
        "primary_value_digest": o1a_pvd(chk_v),
    }


def o1a_mode_scoped_mans(mode: int, rows: List[Dict[str, str]]) -> List[Tuple[bytes, Dict[str, Any]]]:
    """Filter manifests to exact mode BIND/FOCUS kind set BEFORE adjudication."""
    want_ok = O1A_MODE_OWNER[mode]
    want_bk = O1A_MODE_BLOB[mode]
    out: List[Tuple[bytes, Dict[str, Any]]] = []
    for mk, mv in o1a_all_mans(rows):
        try:
            man = o1a_dec_man(mk, mv)
        except ValueError:
            continue
        if man["owner_kind"] == want_ok and man["blob_kind"] in want_bk:
            out.append((mk, man))
    return out


def o1a_mode_kind_ok(mode: int, man: Dict[str, Any]) -> bool:
    return (
        man["owner_kind"] == O1A_MODE_OWNER[mode]
        and man["blob_kind"] in O1A_MODE_BLOB[mode]
    )


def o1a_dec_anchor_payload_dig(anc_v: bytes) -> bytes:
    """TRANSACTION_ANCHOR.payload_blob_key_digest = last 32 of body."""
    body = o1a_body(anc_v)
    if len(body) < 32:
        raise ValueError("anchor short")
    return body[-32:]


def o1a_mode28_view_pair_legal(message_kind: int, view_a: bytes, view_b: bytes) -> bool:
    """D1 §8.3: APPLICATION(1) payload-only; RECEIPT(2) evidence-only; else both zero."""
    za = view_a == O1A_ZERO32
    zb = view_b == O1A_ZERO32
    if message_kind == 1:  # APPLICATION
        return zb  # evidence digest must be zero
    if message_kind == 2:  # RECEIPT
        return za  # payload digest must be zero
    return za and zb


def o1a_dec_ingress_tail(ing_v: bytes) -> Dict[str, Any]:
    """ORDERED_INGRESS tail digests + semantic (D1 §8.3).

    Tail (from end): reservation32 + state u32 + evi_blob32 + pay_blob32 + sem32.
    Semantic prefix for MSD is body[20 : len-168] (message_kind..evidence_trust),
    excluding controller/reserved1/digest fields (normative §5.1 / §8.3).
    """
    body = o1a_body(ing_v)
    if len(body) < 168:
        raise ValueError("ingress short")
    return {
        "body": body,
        "semantic_stored": body[-132:-100],
        "view_a": body[-100:-68],
        "view_b": body[-68:-36],
        "msd_prefix": body[20 : len(body) - 168],
    }


def o1a_dec_dlv(dlv_v: bytes) -> Dict[str, Any]:
    """DELIVERY body (D1 §8.5): raw16 + creation_kind u16 + reserved u16 + sched u64
    + tx16 + event16 + party100 + target100 + service + content32 + gen u64
    + deadline_epoch16 + abs_ms u64 + grace u64 + required u32
    + payload_blob32 + result_cache32 + reservation32.
    """
    body = o1a_body(dlv_v)
    rl = struct.unpack(">H", body[0:2])[0]
    if 2 + rl + 2 + 2 + 8 > len(body):
        raise ValueError("dlv raw short")
    owner_raw = body[2 : 2 + rl]
    o = 2 + rl
    creation_kind = struct.unpack(">H", body[o : o + 2])[0]
    o += 2 + 2 + 8  # reserved + sched
    tx = body[o : o + 16]
    o += 16
    event = body[o : o + 16]
    o += 16
    party = body[o : o + 100]
    o += 100
    target = body[o : o + 100]
    o += 100
    tail = 32 + 8 + 16 + 8 + 8 + 4 + 32 + 32 + 32  # 172
    if o + tail > len(body):
        raise ValueError("dlv tail short")
    svc = body[o : len(body) - tail]
    o = len(body) - tail
    content = body[o : o + 32]
    o += 32
    gen = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    dep = body[o : o + 16]
    o += 16
    abs_ms = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    grace = struct.unpack(">Q", body[o : o + 8])[0]
    o += 8
    req = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    payload_blob = body[o : o + 32]
    o += 32
    result_cache_key_digest = body[o : o + 32]
    return {
        "owner_raw": owner_raw,
        "creation_kind": creation_kind,
        "transaction_id": tx,
        "event_id": event,
        "party": party,
        "target": target,
        "service": svc,
        "content_digest": content,
        "generation": gen,
        "deadline_epoch": dep,
        "abs_deadline_ms": abs_ms,
        "evidence_grace_ms": grace,
        "required_evidence": req,
        "payload_blob_key_digest": payload_blob,
        "result_cache_key_digest": result_cache_key_digest,
    }


def o1a_dec_state_discarded(st_v: bytes) -> int:
    """TRANSACTION_STATE.explicitly_discarded u32 at body offset 104."""
    body = o1a_body(st_v)
    if len(body) < 108:
        raise ValueError("state short")
    return struct.unpack(">I", body[104:108])[0]


def o1a_dec_state_fields(st_v: bytes) -> Dict[str, Any]:
    """TRANSACTION_STATE public lifecycle + Mode27 cross-row fields (docs/17 body)."""
    body = o1a_body(st_v)
    if len(body) < 108:
        raise ValueError("state short")
    return {
        "tx": body[0:16],
        "avd": body[16:48],
        "state": struct.unpack(">I", body[48:52])[0],
        "outcome": struct.unpack(">I", body[52:56])[0],
        "deadline_verdict": struct.unpack(">I", body[56:60])[0],
        "latest": struct.unpack(">I", body[60:64])[0],
        "reason": struct.unpack(">I", body[64:68])[0],
        "park": struct.unpack(">I", body[68:72])[0],
        "retry": struct.unpack(">Q", body[72:80])[0],
        "attempt": struct.unpack(">I", body[80:84])[0],
        "cumul": struct.unpack(">Q", body[84:92])[0],
        "es_rev": struct.unpack(">Q", body[92:100])[0],
        "has_late": struct.unpack(">I", body[100:104])[0],
        "discarded": struct.unpack(">I", body[104:108])[0],
        "common_pvd": st_v[72:104],
        "common_rev": int.from_bytes(st_v[16:24], "big"),
    }


def o1a_dec_spool_state(sp_v: bytes) -> int:
    """EVENT_SPOOL.spool_state u32 at body offset 40 (tx16+event16+rev8)."""
    return o1a_dec_spool_fields(sp_v)["spool_state"]


def o1a_dec_spool_fields(sp_v: bytes) -> Dict[str, Any]:
    """EVENT_SPOOL Mode27 cross-row fields (docs/17 D1-B3k body + common)."""
    body = o1a_body(sp_v)
    if len(body) < 48:
        raise ValueError("spool short")
    return {
        "tx": body[0:16],
        "event": body[16:32],
        "spool_revision": struct.unpack(">Q", body[32:40])[0],
        "spool_state": struct.unpack(">I", body[40:44])[0],
        "park_cause": struct.unpack(">I", body[44:48])[0],
        "common_pvd": sp_v[72:104],
        "common_rev": int.from_bytes(sp_v[16:24], "big"),
    }


def _o1a_ef_state_reason_ok(stf: Dict[str, Any]) -> Optional[str]:
    """R28 r3: Mode27 EventFact state-dependent reason closure (Mode27 adoption rule).

    docs/13 §964/§1061/§1149 + §995/§1143, docs/12 §1758. EventFact has no deadline
    and no cancel; operator-action Disposition parks. EF AWAITING={NONE(0)}; EF
    WAITING excludes CAPACITY_EXHAUSTED(11) (parks); EF DISPATCHING ← ATTEMPT_PREPARED
    consumes ≥1 attempt. This is the Mode27 adoption guard, independent of the D1
    constructibility gate (which keeps EF rows constructible for regression test).
    """
    st = stf["state"]
    reason = stf["reason"]
    if st == _D1_TXN_AWAITING:
        if reason not in _D1_REASON_AWAITING_EF:
            return "m27_ef_awaiting_reason"
    elif st == _D1_TXN_WAITING:
        if reason not in _D1_REASON_WAITING_EF:
            return "m27_ef_waiting_reason"
    elif st == _D1_TXN_DISPATCHING:
        if stf["attempt"] < 1:
            return "m27_ef_dispatching_attempt"
    return None


def o1a_mode27_cross_row_ok(
    st_v: bytes,
    sp_v: Optional[bytes],
    *,
    is_ef: bool,
    want_avd: bytes,
    want_tx: Optional[bytes] = None,
) -> Optional[str]:
    """D3-S3 Mode27 exact cross-row (beyond independent D1 same-record).

    docs/17 defers live PVD/cardinality to D3; this classifier/RefSession path is the
    D3-S3 constructibility gate. Returns sticky CORRUPT reason string or None if OK.

    ``want_avd`` is complete ANCHOR value digest (pinned at SELECT; no offline idx).
    """
    try:
        stf = o1a_dec_state_fields(st_v)
    except ValueError:
        return "m27_state_decode"
    # (1) family: EF anchor ⇔ STATE deadline_verdict NA; DS ⇔ not NA
    st_is_ef = stf["deadline_verdict"] == _D1_DDL_NA
    if is_ef != st_is_ef:
        return "m27_family_mismatch"
    # (2) STATE anchor_value_digest + common PVD == complete ANCHOR value digest
    if stf["avd"] != want_avd:
        return "m27_state_avd"
    if stf["common_pvd"] != want_avd:
        return "m27_state_pvd"
    # body tx must match ANCHOR tx when provided
    if want_tx is not None and stf["tx"] != want_tx:
        return "m27_state_tx"
    if not is_ef:
        # DesiredState: no EVENT_SPOOL in Mode27 lifecycle
        if sp_v is not None:
            return "m27_ds_spool_present"
        return None
    if sp_v is None:
        return "m27_ef_spool_absent"
    try:
        spf = o1a_dec_spool_fields(sp_v)
    except ValueError:
        return "m27_spool_decode"
    # (3) spool common PVD == complete ANCHOR value digest
    if spf["common_pvd"] != want_avd:
        return "m27_spool_pvd"
    if spf["tx"] != stf["tx"]:
        return "m27_spool_tx"
    # (4) STATE es_rev == body spool_revision == common record_revision
    if stf["es_rev"] != spf["spool_revision"]:
        return "m27_rev_mismatch"
    if spf["common_rev"] != spf["spool_revision"]:
        return "m27_spool_common_rev"
    # (5) STATE ↔ spool state / park-cause closed product (Mode27 EventFact)
    st = stf["state"]
    ss = spf["spool_state"]
    terminal = st == _D1_TXN_TERMINAL
    is_receipt = (
        terminal
        and stf["outcome"] == _D1_OUT_SATISFIED
        and stf["reason"] == _D1_R_REQUIRED_EVIDENCE_MET
        and stf["discarded"] == 0
    )
    is_discard = (
        terminal
        and stf["outcome"] == _D1_OUT_FAILED
        and stf["reason"] == _D1_R_OPERATOR_DISCARDED
        and stf["discarded"] == 1
    )
    if st == _D1_TXN_PARKED:
        # PARKED TX requires PARKED spool + exact park cause match
        if ss != _D1_ES_PARKED:
            return "m27_parked_spool"
        if stf["park"] != spf["park_cause"]:
            return "m27_park_cause"
        if stf["park"] not in _D1_PARK_ACTIVE:
            return "m27_park_cause"
    elif not terminal:
        # live non-PARKED nonterminal requires ACTIVE spool (READY+PARKED RED)
        if ss != _D1_ES_ACTIVE:
            return "m27_live_spool"
        if stf["park"] != _D1_PARK_NONE or spf["park_cause"] != 0:
            return "m27_live_park"
    elif is_receipt:
        if ss != _D1_ES_RELEASED:
            return "m27_receipt_spool"
        if stf["park"] != _D1_PARK_NONE or spf["park_cause"] != 0:
            return "m27_receipt_park"
    elif is_discard:
        if ss != _D1_ES_DISCARDED:
            return "m27_discard_spool"
        if stf["park"] != _D1_PARK_NONE or spf["park_cause"] != 0:
            return "m27_discard_park"
    else:
        # other terminal shapes are not EventFact-legal owners
        return "m27_ef_terminal_shape"
    # (6) R28 r3: EventFact state-dependent reason closure (Mode27 adoption guard;
    # family + cross-row above already passed, so RED here is the reason gate only).
    ef_reason_err = _o1a_ef_state_reason_ok(stf)
    if ef_reason_err is not None:
        return ef_reason_err
    return None


def o1a_dec_rc(rc_v: bytes) -> Dict[str, Any]:
    """RESULT_CACHE selected fields (D1 B3i layout)."""
    body = o1a_body(rc_v)
    o = 2 + 80 + 32 + 16 + 8 + 4 + 4
    if o + 4 > len(body):
        raise ValueError("rc short")
    delivery_state = struct.unpack(">I", body[o : o + 4])[0]
    # app_kind after token/timer block
    o_app = (
        2 + 80 + 32 + 16 + 8 + 4 + 4 + 4 + 4
        + 16 + 8 + 16 + 8 + 16 + 8 + 8 + 8 + 8 + 8 + 16 + 8
    )
    if o_app + 8 > len(body):
        raise ValueError("rc app short")
    app_kind = struct.unpack(">I", body[o_app : o_app + 4])[0]
    stage = struct.unpack(">I", body[o_app + 4 : o_app + 8])[0]
    # disposition tuple after stage: disp@+0 of stage block already used;
    # stage_off = o_app+4; disp = stage_off+4, effect = stage_off+12, ...
    stage_off = o_app + 4
    disp = struct.unpack(">I", body[stage_off + 4 : stage_off + 8])[0]
    effect = struct.unpack(">I", body[stage_off + 12 : stage_off + 16])[0]
    retry_g = struct.unpack(">I", body[stage_off + 16 : stage_off + 20])[0]
    retry_d = struct.unpack(">Q", body[stage_off + 20 : stage_off + 28])[0]
    # cancel_result_kind after token_state
    o_ck = o_app + 4 + 4 + 4 + 4 + 4 + 4 + 8 + 32 + 4
    cancel_rk = struct.unpack(">I", body[o_ck : o_ck + 4])[0] if o_ck + 4 <= len(body) else 0
    return {
        "delivery_state": delivery_state,
        "app_kind": app_kind,
        "evidence_stage": stage,
        "disposition": disp,
        "effect_certainty": effect,
        "retry_guidance": retry_g,
        "retry_delay_ms": retry_d,
        "cancel_result_kind": cancel_rk,
    }


def o1a_dec_rr(rr_v: bytes) -> Dict[str, Any]:
    """REVERSE_REPLY exact 330-byte body (D1 B3j)."""
    body = o1a_body(rr_v)
    rl = struct.unpack(">H", body[0:2])[0]
    o = 2 + rl
    dl = struct.unpack(">H", body[o : o + 2])[0]
    o += 2
    delivery_raw = body[o : o + dl]
    o += dl
    tx = body[o : o + 16]
    o += 16
    reply_kind = struct.unpack(">I", body[o : o + 4])[0]
    o += 4
    semantic = body[o : o + 32]
    o += 32
    body_blob = body[o : o + 32]
    o += 32
    send_state = struct.unpack(">I", body[o : o + 4])[0]
    o += 4 + 8 + 8 + 4 + 4
    attempt = body[o : o + 16]
    return {
        "delivery_raw": delivery_raw,
        "transaction_id": tx,
        "reply_kind": reply_kind,
        "semantic_digest": semantic,
        "body_blob_key_digest": body_blob,
        "send_state": send_state,
        "attempt_id": attempt,
    }


def o1a_dec_cell(cell_v: bytes) -> Dict[str, Any]:
    """EVIDENCE_CELL SUMMARY material fields for Mode30 #16."""
    body = o1a_body(cell_v)
    st_off = 6 + 80 + 64 + 4 + 2 + 2
    if st_off + 12 > len(body):
        raise ValueError("cell stages")
    stages = struct.unpack(">III", body[st_off : st_off + 12])
    material_receipt_stage = stages[2]
    dig_off = len(body) - 32 - 128 - 2 - 2 - 32
    if dig_off < 0:
        raise ValueError("cell evi")
    evidence_digest = body[dig_off : dig_off + 32]
    len_off = dig_off + 32
    evidence_length = struct.unpack(">H", body[len_off : len_off + 2])[0]
    bytes_off = len_off + 2 + 2
    evidence_bytes = body[bytes_off : bytes_off + evidence_length]
    pre = dig_off
    trust = struct.unpack(">I", body[pre - 8 : pre - 4])[0]
    at_ms = struct.unpack(">Q", body[pre - 16 : pre - 8])[0]
    epoch = body[pre - 32 : pre - 16]
    return {
        "material_receipt_stage": material_receipt_stage,
        "evidence_digest": evidence_digest,
        "evidence_length": evidence_length,
        "evidence_bytes": evidence_bytes,
        "evidence_epoch": epoch,
        "evidence_at_ms": at_ms,
        "evidence_trust": trust,
    }


def o1a_dec_cancel_kind(cs_v: bytes) -> int:
    """CANCEL_STATE.cancel_kind (D1): after owner RAW16 + pkd32 + tx16 + att16 + state u32."""
    b = o1a_body(cs_v)
    o = 4  # owner_kind u16 + reserved u16
    orl = struct.unpack(">H", b[o : o + 2])[0]
    o += 2 + orl + 32 + 16 + 16 + 4  # past state
    return struct.unpack(">I", b[o : o + 4])[0]


def o1a_msd_parts(
    kind: int,
    flags: int,
    transaction_id: bytes,
    attempt_id: bytes,
    event_id: bytes,
    party: bytes,
    target: bytes,
    service_enc: bytes,
    content_digest: bytes,
    generation: int,
    deadline_epoch: bytes,
    abs_deadline_ms: int,
    evidence_grace_ms: int,
    required_evidence: int,
    receipt_stage: int,
    disposition: int,
    effect_certainty: int,
    retry_guidance: int,
    cancel_kind: int,
    retry_delay_ms: int,
    evidence_epoch: bytes,
    evidence_now_ms: int,
    evidence_trust: int,
    payload: bytes,
    evidence: bytes,
) -> bytes:
    """Independent Bearer message_semantic_digest (docs/17 §5.1 exact preimage)."""
    h = hashlib.sha256()
    h.update(O1A_MSD_LABEL)
    h.update(struct.pack(">I", kind & 0xFFFFFFFF))
    h.update(struct.pack(">I", flags & 0xFFFFFFFF))
    h.update(transaction_id)
    h.update(attempt_id)
    h.update(event_id)
    h.update(party)
    h.update(target)
    h.update(service_enc)
    h.update(content_digest)
    h.update(struct.pack(">Q", generation & 0xFFFFFFFFFFFFFFFF))
    h.update(deadline_epoch)
    h.update(struct.pack(">Q", abs_deadline_ms & 0xFFFFFFFFFFFFFFFF))
    h.update(struct.pack(">Q", evidence_grace_ms & 0xFFFFFFFFFFFFFFFF))
    h.update(struct.pack(">I", required_evidence & 0xFFFFFFFF))
    h.update(struct.pack(">I", receipt_stage & 0xFFFFFFFF))
    h.update(struct.pack(">I", disposition & 0xFFFFFFFF))
    h.update(struct.pack(">I", effect_certainty & 0xFFFFFFFF))
    h.update(struct.pack(">I", retry_guidance & 0xFFFFFFFF))
    h.update(struct.pack(">I", cancel_kind & 0xFFFFFFFF))
    h.update(struct.pack(">Q", retry_delay_ms & 0xFFFFFFFFFFFFFFFF))
    h.update(evidence_epoch)
    h.update(struct.pack(">Q", evidence_now_ms & 0xFFFFFFFFFFFFFFFF))
    h.update(struct.pack(">I", evidence_trust & 0xFFFFFFFF))
    h.update(struct.pack(">I", len(payload) & 0xFFFFFFFF))
    h.update(payload)
    h.update(struct.pack(">I", len(evidence) & 0xFFFFFFFF))
    h.update(evidence)
    return h.digest()


def o1a_msd_ingress(ing_body_prefix: bytes, payload: bytes, evidence: bytes) -> bytes:
    """Mode28 MSD from already-extracted ingress semantic prefix + streams.

    Length fields follow stream byte lengths (O1a L1 convenience). REP1-L2 Mode28
    semantic must use o1a_msd_ingress_pinned with pin-derived lengths.
    """
    return o1a_msd_ingress_pinned(
        ing_body_prefix, payload, evidence, len(payload), len(evidence)
    )


def o1a_msd_ingress_pinned(
    ing_body_prefix: bytes,
    payload: bytes,
    evidence: bytes,
    payload_length: int,
    evidence_length: int,
) -> bytes:
    """Mode28 MSD using exact u32 length fields (no mask / wrap / len()-recompute)."""
    if type(payload_length) is not int or type(evidence_length) is not int:
        raise TypeError("Mode28 pin lengths must be int")
    if payload_length < 0 or payload_length > UINT32_MAX:
        raise ValueError("payload_length not u32")
    if evidence_length < 0 or evidence_length > UINT32_MAX:
        raise ValueError("evidence_length not u32")
    h = hashlib.sha256()
    h.update(O1A_MSD_LABEL)
    h.update(ing_body_prefix)
    h.update(struct.pack(">I", payload_length))
    h.update(payload)
    h.update(struct.pack(">I", evidence_length))
    h.update(evidence)
    return h.digest()


def o1a_chunk_count_for_total(total: int) -> int:
    if total == 0:
        return 0
    return (total + 3071) // 3072



def o1a_raw16(raw: bytes) -> bytes:
    return struct.pack(">H", len(raw)) + raw


def o1a_bkey_id128(subtype: int, id16: bytes) -> bytes:
    return d3s1.bkey(6, subtype, 2, id16)


def o1a_bkey_composite(subtype: int, identity: bytes) -> bytes:
    return d3s1.bkey(6, subtype, 5, d3s1.composite(subtype, identity))


def o1a_rc_key(raw80: bytes) -> bytes:
    """RESULT_CACHE key = COMPOSITE(41, delivery_key_raw:RAW16)."""
    return o1a_bkey_composite(0x41, o1a_raw16(raw80))


def o1a_dlv_key(raw80: bytes) -> bytes:
    return o1a_bkey_composite(0x40, o1a_raw16(raw80))


def o1a_cell_key(raw80: bytes, slot: int = 0) -> bytes:
    """EVIDENCE_CELL COMPOSITE(32, owner_kind=DELIVERY(2) || raw:RAW16 || slot u32)."""
    return o1a_bkey_composite(
        0x32, struct.pack(">H", 2) + o1a_raw16(raw80) + struct.pack(">I", slot & 0xFFFFFFFF)
    )


def o1a_cs_key(raw80: bytes) -> bytes:
    """CANCEL_STATE COMPOSITE(33, owner_kind=DELIVERY(2) || raw:RAW16)."""
    return o1a_bkey_composite(0x33, struct.pack(">H", 2) + o1a_raw16(raw80))


def o1a_state_key(tx16: bytes) -> bytes:
    return o1a_bkey_id128(0x22, tx16)


def o1a_spool_key(tx16: bytes) -> bytes:
    """EVENT_SPOOL key = ID128(transaction_id) (D1-B3k)."""
    return o1a_bkey_id128(0x50, tx16)


def o1a_man_key_from_blob_id(blob_id: bytes) -> bytes:
    """Manifest complete key: COMPOSITE(0x30, u8=1 || blob_id)."""
    return o1a_bkey_composite(0x30, bytes([1]) + blob_id)


def o1a_chk_key_from_blob_index(blob_id: bytes, index: int) -> bytes:
    """Chunk complete key: COMPOSITE(0x30, u8=2 || blob_id || index:u32 BE)."""
    return o1a_bkey_composite(
        0x30, bytes([2]) + blob_id + struct.pack(">I", index & 0xFFFFFFFF)
    )


def o1a_unique_body_then_key(
    matches: List[Tuple[bytes, bytes]], expect_k: bytes
) -> Tuple[Optional[Tuple[bytes, bytes]], Optional[str]]:
    """Require exactly one body match, then that row's complete key == expect_k.

    Multiple body matches are always duplicate — even if only one key matches.
    """
    if not matches:
        return None, "absent"
    if len(matches) != 1:
        return None, "duplicate"
    k, v = matches[0]
    if k != expect_k:
        return None, "key_mismatch"
    return (k, v), None


def o1a_anchor_is_event_fact(anc_v: bytes) -> bool:
    """DesiredState: event_map_key_digest zero; EventFact: non-zero (D1 §8.2)."""
    body = o1a_body(anc_v)
    if len(body) < 168:
        return False
    # tail: seq_idx32 + idemp_map32 + event_map32 + res32 + sched_seq8 + payload32
    event_map = body[-104:-72]
    return event_map != O1A_ZERO32


def o1a_setup_gets(
    mode: int, carrier_k: bytes, carrier_v: bytes, idx: Dict[bytes, bytes]
) -> int:
    if mode == 27:
        # DesiredState: STATE only; EventFact: STATE + EVENT_SPOOL for this tx
        return 2 if o1a_anchor_is_event_fact(carrier_v) else 1
    if mode == 29:
        return 1 if o1a_dec_dlv(carrier_v)["creation_kind"] == 1 else 0
    return 0


def o1a_resolve_state_for_anchor(
    pairs: List[Tuple[bytes, bytes]], anc_k: bytes, anc_v: bytes
) -> Tuple[Optional[bytes], Optional[str]]:
    """Exact TRANSACTION_STATE for this ANCHOR tx (no first-global fallback)."""
    tx = o1a_body(anc_v)[:16]
    expect_k = o1a_state_key(tx)
    matches = []
    for k, v in pairs:
        if o1a_subtype(k) != 0x22:
            continue
        try:
            if o1a_body(v)[:16] != tx:
                continue
        except ValueError:
            continue
        matches.append((k, v))
    hit, err = o1a_unique_body_then_key(matches, expect_k)
    if hit is None:
        return None, err
    return hit[1], None


def o1a_resolve_spool_for_anchor(
    pairs: List[Tuple[bytes, bytes]], anc_v: bytes
) -> Tuple[Optional[bytes], Optional[str]]:
    """EventFact only: exact one EVENT_SPOOL for ANCHOR.tx via ID128 key + body tx."""
    tx = o1a_body(anc_v)[:16]
    expect_k = o1a_spool_key(tx)
    matches = []
    for k, v in pairs:
        if o1a_subtype(k) != 0x50:
            continue
        try:
            if o1a_body(v)[:16] != tx:
                continue
        except ValueError:
            continue
        matches.append((k, v))
    hit, err = o1a_unique_body_then_key(matches, expect_k)
    if hit is None:
        return None, err
    return hit[1], None


def o1a_resolve_rc_for_delivery(
    pairs: List[Tuple[bytes, bytes]], dlv_k: bytes, dlv_v: bytes
) -> Tuple[Optional[bytes], Optional[str]]:
    """Unique RESULT_CACHE for this DELIVERY via COMPOSITE(41, raw) + dig cross-check."""
    d = o1a_dec_dlv(dlv_v)
    raw = d["owner_raw"]
    if len(raw) != 80:
        return None, "raw_len"
    expect_k = o1a_rc_key(raw)
    expect_dig = d3s1.key_digest(expect_k)
    if d["result_cache_key_digest"] != expect_dig:
        return None, "rc_dig_field"
    matches = []
    for k, v in pairs:
        if o1a_subtype(k) != 0x41:
            continue
        try:
            body = o1a_body(v)
            rl = struct.unpack(">H", body[0:2])[0]
            if body[2 : 2 + rl] != raw:
                continue
        except (ValueError, struct.error):
            continue
        matches.append((k, v))
    hit, err = o1a_unique_body_then_key(matches, expect_k)
    if hit is None:
        return None, err
    k, v = hit
    body = o1a_body(v)
    rl = struct.unpack(">H", body[0:2])[0]
    dig_off = 2 + rl
    if body[dig_off : dig_off + 32] != d3s1.key_digest(dlv_k):
        return None, "dlv_dig_mismatch"
    return v, None


def o1a_resolve_dlv_for_raw(
    pairs: List[Tuple[bytes, bytes]], raw80: bytes
) -> Tuple[Optional[Tuple[bytes, bytes]], Optional[str]]:
    if len(raw80) != 80:
        return None, "raw_len"
    expect_k = o1a_dlv_key(raw80)
    matches = []
    for k, v in pairs:
        if o1a_subtype(k) != 0x40:
            continue
        try:
            if o1a_dec_dlv(v)["owner_raw"] != raw80:
                continue
        except ValueError:
            continue
        matches.append((k, v))
    return o1a_unique_body_then_key(matches, expect_k)


def o1a_resolve_cell_for_delivery(
    pairs: List[Tuple[bytes, bytes]], raw80: bytes
) -> Tuple[Optional[bytes], Optional[str]]:
    expect_k = o1a_cell_key(raw80, 0)
    matches = []
    for k, v in pairs:
        if o1a_subtype(k) != 0x32:
            continue
        try:
            body = o1a_body(v)
            okind = struct.unpack(">H", body[0:2])[0]
            o = 4
            rl = struct.unpack(">H", body[o : o + 2])[0]
            oraw = body[o + 2 : o + 2 + rl]
            slot_off = o + 2 + rl + 32 + 32
            slot = struct.unpack(">I", body[slot_off : slot_off + 4])[0]
        except (ValueError, struct.error):
            continue
        if okind == 2 and oraw == raw80 and slot == 0:
            matches.append((k, v))
    hit, err = o1a_unique_body_then_key(matches, expect_k)
    if hit is None:
        return None, err
    return hit[1], None


def o1a_resolve_cs_for_delivery(
    pairs: List[Tuple[bytes, bytes]], raw80: bytes
) -> Tuple[Optional[bytes], Optional[str]]:
    expect_k = o1a_cs_key(raw80)
    matches = []
    for k, v in pairs:
        if o1a_subtype(k) != 0x33:
            continue
        try:
            body = o1a_body(v)
            okind = struct.unpack(">H", body[0:2])[0]
            o = 4
            rl = struct.unpack(">H", body[o : o + 2])[0]
            oraw = body[o + 2 : o + 2 + rl]
        except (ValueError, struct.error):
            continue
        if okind == 2 and oraw == raw80:
            matches.append((k, v))
    hit, err = o1a_unique_body_then_key(matches, expect_k)
    if hit is None:
        return None, err
    return hit[1], None


def o1a_classify(
    mode: int, carrier_k: bytes, carrier_v: bytes, idx: Dict[bytes, bytes], rows: List[Dict[str, str]]
) -> Tuple[int, Optional[str], Dict[str, Any]]:
    pins: Dict[str, Any] = {"carrier_key": carrier_k, "carrier_value": carrier_v}
    pairs = o1a_pairs(rows)
    if mode == 27:
        dig = o1a_dec_anchor_payload_dig(carrier_v)
        pins["focus_dig"] = dig
        st_v, err = o1a_resolve_state_for_anchor(pairs, carrier_k, carrier_v)
        if st_v is None:
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        pins["state_value"] = st_v
        try:
            stf = o1a_dec_state_fields(st_v)
        except ValueError:
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        is_ef = o1a_anchor_is_event_fact(carrier_v)
        # EventFact: exact EVENT_SPOOL required; DesiredState never uses spool lifecycle
        sp_v = None
        if is_ef:
            sp_v, err = o1a_resolve_spool_for_anchor(pairs, carrier_v)
            if sp_v is None:
                return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
            pins["spool_value"] = sp_v
            try:
                spool_state = o1a_dec_spool_state(sp_v)
            except ValueError:
                return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
            pins["spool_state"] = spool_state
        # R27-Sol: exact cross-row (family / avd / PVD / rev / state×park) before lifecycle
        xerr = o1a_mode27_cross_row_ok(
            st_v, sp_v,
            is_ef=is_ef,
            want_avd=d3s1.value_digest(carrier_v),
            want_tx=o1a_body(carrier_v)[:16],
        )
        if xerr is not None:
            pins["cross_row_err"] = xerr
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        if is_ef:
            # lifecycle after cross-row closed product:
            #   non-PARKED nonterminal + ACTIVE → LIVE
            #   PARKED TX + PARKED spool (cause match) → LIVE
            #   terminal receipt + RELEASED → HISTORICAL
            #   terminal audited discard + DISCARDED → HISTORICAL
            #   else CORRUPT
            spool_state = int(pins["spool_state"])
            terminal_tx = stf["state"] == _D1_TXN_TERMINAL
            is_receipt = (
                terminal_tx
                and stf["outcome"] == _D1_OUT_SATISFIED
                and stf["reason"] == _D1_R_REQUIRED_EVIDENCE_MET
                and stf["discarded"] == 0
            )
            is_audited_discard = (
                terminal_tx
                and stf["outcome"] == _D1_OUT_FAILED
                and stf["reason"] == _D1_R_OPERATOR_DISCARDED
                and stf["discarded"] == 1
            )
            if not terminal_tx:
                if stf["state"] == _D1_TXN_PARKED:
                    if spool_state != _D1_ES_PARKED:
                        return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
                else:
                    if spool_state != _D1_ES_ACTIVE:
                        return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
                if stf["discarded"] != 0:
                    return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
                if dig == O1A_ZERO32:
                    return LC_NONE, None, pins
                return LC_LIVE_REQUIRED, None, pins
            if is_receipt and spool_state == _D1_ES_RELEASED:
                if dig == O1A_ZERO32:
                    return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
                return LC_HISTORICAL_ABSENT, None, pins
            if is_audited_discard and spool_state == _D1_ES_DISCARDED:
                if dig == O1A_ZERO32:
                    return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
                return LC_HISTORICAL_ABSENT, None, pins
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        # DesiredState: TERMINAL ⇒ HISTORICAL (man absent); nonterminal active ⇒ LIVE
        if stf["discarded"] != 0:
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        if stf["state"] == _D1_TXN_TERMINAL:
            if dig == O1A_ZERO32:
                return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
            return LC_HISTORICAL_ABSENT, None, pins
        if dig == O1A_ZERO32:
            return LC_NONE, None, pins
        return LC_LIVE_REQUIRED, None, pins

    if mode == 28:
        tail = o1a_dec_ingress_tail(carrier_v)
        pins.update(tail)
        return LC_LIVE_REQUIRED, None, pins

    if mode == 29:
        dlv = o1a_dec_dlv(carrier_v)
        dig = dlv["payload_blob_key_digest"]
        pins["focus_dig"] = dig
        pins["creation_kind"] = dlv["creation_kind"]
        pins["dlv"] = dlv
        if dlv["creation_kind"] == 2:
            if dig != O1A_ZERO32:
                return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
            return LC_NONE, None, pins
        if dlv["creation_kind"] != 1:
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        rc_v, err = o1a_resolve_rc_for_delivery(pairs, carrier_k, carrier_v)
        if rc_v is None:
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        rc = o1a_dec_rc(rc_v)
        pins["rc"] = rc
        pins["rc_value"] = rc_v
        if rc["delivery_state"] >= 4:
            # terminal APP_FIRST HISTORICAL requires retained non-zero payload dig
            if dig == O1A_ZERO32:
                return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
            return LC_HISTORICAL_ABSENT, None, pins
        if dig == O1A_ZERO32:
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        return LC_LIVE_REQUIRED, None, pins

    if mode == 30:
        rr = o1a_dec_rr(carrier_v)
        pins.update(rr)
        pins["focus_dig"] = rr["body_blob_key_digest"]
        pins["focus_raw80"] = rr["delivery_raw"]
        if rr["send_state"] == 5:
            if rr["body_blob_key_digest"] == O1A_ZERO32:
                return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
            return LC_HISTORICAL_ABSENT, None, pins
        if rr["send_state"] not in (1, 2, 3, 4):
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        if rr["body_blob_key_digest"] == O1A_ZERO32:
            return LC_ILLEGAL, STAGE_SELECT_SETUP, pins
        return LC_LIVE_REQUIRED, None, pins

    return LC_ILLEGAL, STAGE_SELECT_SETUP, pins


def o1a_digest_match_scan(
    rows: List[Dict[str, str]], focus_dig: bytes
) -> Tuple[int, Optional[Dict[str, Any]]]:
    if focus_dig == O1A_ZERO32:
        return 0, None
    match_count = 0
    installed = None
    for mk, mv in o1a_all_mans(rows):
        if d3s1.key_digest(mk) != focus_dig:
            continue
        if match_count == 0:
            match_count = 1
            installed = o1a_dec_man(mk, mv)
        else:
            match_count = 2
    return match_count, installed


def o1a_chunk_map(rows: List[Dict[str, str]]) -> Dict[Tuple[bytes, int], Dict[str, Any]]:
    out: Dict[Tuple[bytes, int], Dict[str, Any]] = {}
    for ck, cv in o1a_all_chunks(rows):
        ch = o1a_dec_chunk(ck, cv)
        key = (ch["blob_id"], ch["index"])
        if key in out:
            # duplicate index for same blob_id
            out[key] = None  # type: ignore
        else:
            out[key] = ch
    return out


def o1a_verify_chunks(man: Dict[str, Any], rows: List[Dict[str, str]]) -> Optional[str]:
    cmap = o1a_chunk_map(rows)
    total = man["total_length"]
    count = man["chunk_count"]
    if count != o1a_chunk_count_for_total(total):
        return "count_vs_total"
    stream = bytearray()
    length_sum = 0
    for i in range(count):
        ch = cmap.get((man["blob_id"], i))
        if ch is None:
            return "missing_or_dup_chunk"
        if ch["chunk_count"] != count or ch["total_length"] != total:
            return "chunk_header_tuple"
        if ch["content_digest"] != man["content_digest"] or ch["blob_id"] != man["blob_id"]:
            return "chunk_tuple"
        if ch["manifest_key_digest"] != man["key_digest"]:
            return "chunk_mkd"
        if ch["primary_value_digest"] != man["expected_manifest_value_digest"]:
            return "chunk_pvd"
        stream.extend(ch["data"])
        length_sum += len(ch["data"])
    if length_sum != total:
        return "length_sum"
    if hashlib.sha256(bytes(stream)).digest() != man["content_digest"]:
        return "content_digest"
    if total == 0 and (count != 0 or man["content_digest"] != o1a_empty_sha()):
        return "zero_shape"
    return None


def o1a_stream_bytes(man: Dict[str, Any], rows: List[Dict[str, str]]) -> bytes:
    cmap = o1a_chunk_map(rows)
    parts = []
    for i in range(man["chunk_count"]):
        ch = cmap.get((man["blob_id"], i))
        if ch is None:
            return b""
        parts.append(ch["data"])
    return b"".join(parts)


def o1a_verify_owner_pvd(
    mode: int, man: Dict[str, Any], pins: Dict[str, Any], idx: Dict[bytes, bytes]
) -> bool:
    if mode in (27, 28, 29):
        ov = pins.get("carrier_value")
        if ov is None:
            return False
        return d3s1.value_digest(ov) == man["expected_owner_pvd"]
    found, err = o1a_resolve_dlv_for_raw(list(idx.items()), man["owner_raw"])
    if found is None:
        return False
    return d3s1.value_digest(found[1]) == man["expected_owner_pvd"]


def o1a_mode30_h14(man: Dict[str, Any], pins: Dict[str, Any]) -> Optional[str]:
    if man["owner_kind"] != 3 or man["blob_kind"] != 5:
        return "kind"
    if man["owner_raw"] != pins["focus_raw80"] or len(man["owner_raw"]) != 80:
        return "raw"
    return None


def o1a_mode30_h15(reply_kind: int, man: Dict[str, Any]) -> Optional[str]:
    if reply_kind == 1:
        return "receipt_len" if man["total_length"] > 128 else None
    if man["total_length"] != 0 or man["chunk_count"] != 0:
        return "non_receipt_nonempty"
    if man["content_digest"] != o1a_empty_sha():
        return "non_receipt_cd"
    return None


def o1a_semantic_mode28_streams(
    pins: Dict[str, Any],
    pay_stream: bytes,
    evi_stream: bytes,
    *,
    payload_length: int,
    evidence_length: int,
) -> bool:
    """Mode28 semantic using exact returned/accumulated streams only (no rows/idx)."""
    pay = bytes(pay_stream) if pay_stream is not None else b""
    evi = bytes(evi_stream) if evi_stream is not None else b""
    if pins.get("view_a", O1A_ZERO32) == O1A_ZERO32:
        pay = b""
    if pins.get("view_b", O1A_ZERO32) == O1A_ZERO32:
        evi = b""
    if type(payload_length) is not int or type(evidence_length) is not int:
        return False
    if payload_length < 0 or payload_length > UINT32_MAX:
        return False
    if evidence_length < 0 or evidence_length > UINT32_MAX:
        return False
    if len(pay) != payload_length or len(evi) != evidence_length:
        return False
    return (
        o1a_msd_ingress_pinned(
            pins["msd_prefix"], pay, evi, payload_length, evidence_length
        )
        == pins["semantic_stored"]
    )


def o1a_semantic_mode28(
    pins: Dict[str, Any],
    man_a: Optional[Dict],
    man_b: Optional[Dict],
    rows,
    *,
    payload_length: Optional[int] = None,
    evidence_length: Optional[int] = None,
) -> bool:
    """Offline/self-test helper: rebuild streams from rows then compare.

    Product-path Mode28 must call o1a_semantic_mode28_streams with Port-returned
    chunk bytes only — never this rows-backed path.
    """
    pay = o1a_stream_bytes(man_a, rows) if man_a else b""
    evi = o1a_stream_bytes(man_b, rows) if man_b else b""
    if payload_length is None:
        payload_length = len(pay)
    if evidence_length is None:
        evidence_length = len(evi)
    return o1a_semantic_mode28_streams(
        pins, pay, evi, payload_length=payload_length, evidence_length=evidence_length
    )


def o1a_semantic_mode30_returned(
    pins: Dict[str, Any],
    man: Dict[str, Any],
    reply_stream: bytes,
) -> bool:
    """Mode30 semantic from Port-returned companion pins + returned chunk stream only.

    Required pins (filled by SELECT_SETUP/PREFIX product GETs):
      dlv_value, rc_value, and for rk==1 cell_value / rk==4 cs_value;
      focus_raw80, transaction_id, attempt_id, semantic_digest, reply_kind.
    reply_stream is the exact concatenation of returned chunk payloads (may be empty).
    """
    rk = int(pins.get("reply_kind") or 0)
    dlv_v = pins.get("dlv_value")
    rc_v = pins.get("rc_value")
    if not isinstance(dlv_v, (bytes, bytearray)) or not isinstance(rc_v, (bytes, bytearray)):
        return False
    try:
        d = o1a_dec_dlv(bytes(dlv_v))
        rc = o1a_dec_rc(bytes(rc_v))
    except (ValueError, struct.error):
        return False
    if d["owner_raw"] != pins.get("focus_raw80"):
        return False
    if d["transaction_id"] != pins.get("transaction_id"):
        return False
    if d3s1.value_digest(bytes(dlv_v)) != man.get("expected_owner_pvd"):
        return False
    stream = bytes(reply_stream or b"")
    attempt = pins.get("attempt_id") or bytes(16)

    def msd(kind, stage, disp, effect, rg, ck, delay, epoch, now, trust, pay, evi):
        return o1a_msd_parts(
            kind, 0, d["transaction_id"], attempt, d["event_id"], d["party"], d["target"],
            d["service"], d["content_digest"], d["generation"], d["deadline_epoch"],
            d["abs_deadline_ms"], d["evidence_grace_ms"], d["required_evidence"],
            stage, disp, effect, rg, ck, delay, epoch, now, trust, pay, evi,
        )

    if rk == 1:
        if rc["app_kind"] != 1:
            return False
        cell_v = pins.get("cell_value")
        if not isinstance(cell_v, (bytes, bytearray)):
            return False
        try:
            cm = o1a_dec_cell(bytes(cell_v))
        except ValueError:
            return False
        if cm["material_receipt_stage"] != rc["evidence_stage"]:
            return False
        if cm["evidence_length"] != man["total_length"]:
            return False
        if cm["evidence_digest"] != man["content_digest"]:
            return False
        if cm["evidence_bytes"] != stream or len(stream) != man["total_length"]:
            return False
        sem = msd(
            2, rc["evidence_stage"], 0, 0, 0, 0, 0,
            cm["evidence_epoch"], cm["evidence_at_ms"], cm["evidence_trust"], b"", stream,
        )
        return sem == pins.get("semantic_digest")

    if rk == 2:
        if rc["app_kind"] != 2:
            return False
        sem = msd(
            3, 0, rc["disposition"], rc["effect_certainty"], rc["retry_guidance"], 0,
            rc["retry_delay_ms"], bytes(16), 0, 0, b"", b"",
        )
        return sem == pins.get("semantic_digest")

    if rk == 3:
        if rc["app_kind"] == 2:
            return False
        sem = msd(5, 0, 0, 0, 0, 0, 0, bytes(16), 0, 0, b"", b"")
        return sem == pins.get("semantic_digest")

    if rk == 4:
        cs_v = pins.get("cs_value")
        if not isinstance(cs_v, (bytes, bytearray)):
            return False
        try:
            ck = o1a_dec_cancel_kind(bytes(cs_v))
        except (ValueError, struct.error):
            return False
        if ck not in (1, 3):
            return False
        if rc["cancel_result_kind"] != ck:
            return False
        sem = msd(6, 0, 0, 0, 0, ck, 0, bytes(16), 0, 0, b"", b"")
        return sem == pins.get("semantic_digest")

    return False


def o1a_semantic_mode30(
    pins: Dict[str, Any], man: Dict[str, Any], rows: List[Dict[str, str]], idx: Dict[bytes, bytes]
) -> Tuple[bool, int]:
    """Offline/self-test helper only. Product path must use o1a_semantic_mode30_returned."""
    rk = pins["reply_kind"]
    gets = 0
    pairs = o1a_pairs(rows)
    found, err = o1a_resolve_dlv_for_raw(pairs, pins["focus_raw80"])
    if found is None:
        return False, gets
    gets += 1
    dlv_k, dlv_v = found
    d = o1a_dec_dlv(dlv_v)
    if d["owner_raw"] != pins["focus_raw80"]:
        return False, gets
    if d["transaction_id"] != pins["transaction_id"]:
        return False, gets
    if d3s1.value_digest(dlv_v) != man["expected_owner_pvd"]:
        return False, gets

    rc_v, err = o1a_resolve_rc_for_delivery(pairs, dlv_k, dlv_v)
    if rc_v is None:
        return False, gets
    gets += 1
    rc = o1a_dec_rc(rc_v)
    stream = o1a_stream_bytes(man, rows)
    attempt = pins["attempt_id"]

    def msd(kind, stage, disp, effect, rg, ck, delay, epoch, now, trust, pay, evi):
        return o1a_msd_parts(
            kind, 0, d["transaction_id"], attempt, d["event_id"], d["party"], d["target"],
            d["service"], d["content_digest"], d["generation"], d["deadline_epoch"],
            d["abs_deadline_ms"], d["evidence_grace_ms"], d["required_evidence"],
            stage, disp, effect, rg, ck, delay, epoch, now, trust, pay, evi,
        )

    if rk == 1:
        if rc["app_kind"] != 1:
            return False, gets
        cell_v, err = o1a_resolve_cell_for_delivery(pairs, pins["focus_raw80"])
        if cell_v is None:
            return False, gets
        gets += 1
        try:
            cm = o1a_dec_cell(cell_v)
        except ValueError:
            return False, gets
        if cm["material_receipt_stage"] != rc["evidence_stage"]:
            return False, gets
        if cm["evidence_length"] != man["total_length"]:
            return False, gets
        if cm["evidence_digest"] != man["content_digest"]:
            return False, gets
        if cm["evidence_bytes"] != stream or len(stream) != man["total_length"]:
            return False, gets
        gets += man["chunk_count"]
        sem = msd(
            2, rc["evidence_stage"], 0, 0, 0, 0, 0,
            cm["evidence_epoch"], cm["evidence_at_ms"], cm["evidence_trust"], b"", stream,
        )
        return sem == pins["semantic_digest"], gets

    if rk == 2:
        if rc["app_kind"] != 2:
            return False, gets
        sem = msd(
            3, 0, rc["disposition"], rc["effect_certainty"], rc["retry_guidance"], 0,
            rc["retry_delay_ms"], bytes(16), 0, 0, b"", b"",
        )
        return sem == pins["semantic_digest"], gets

    if rk == 3:
        if rc["app_kind"] == 2:
            return False, gets
        sem = msd(5, 0, 0, 0, 0, 0, 0, bytes(16), 0, 0, b"", b"")
        return sem == pins["semantic_digest"], gets

    if rk == 4:
        cs_v, err = o1a_resolve_cs_for_delivery(pairs, pins["focus_raw80"])
        if cs_v is None:
            return False, gets
        gets += 1
        ck = o1a_dec_cancel_kind(cs_v)
        if ck not in (1, 3):
            return False, gets
        if rc["cancel_result_kind"] != ck:
            return False, gets
        sem = msd(6, 0, 0, 0, 0, ck, 0, bytes(16), 0, 0, b"", b"")
        return sem == pins["semantic_digest"], gets

    return False, gets


def o1a_referrer_digs(mode: int, owner_v: bytes) -> List[bytes]:
    if mode == 27:
        return [o1a_dec_anchor_payload_dig(owner_v)]
    if mode == 28:
        t = o1a_dec_ingress_tail(owner_v)
        return [t["view_a"], t["view_b"]]
    if mode == 29:
        return [o1a_dec_dlv(owner_v)["payload_blob_key_digest"]]
    return []


def o1a_owner_complete_key(owner_kind: int, owner_raw: bytes) -> bytes:
    """D1 pure forward rebuild of owner complete key (no digest→key reverse)."""
    if owner_kind == 1:
        if len(owner_raw) != 16:
            raise ValueError("tx owner_raw length")
        return d3s1.bkey(6, 0x20, 2, owner_raw)
    if owner_kind == 2:
        if len(owner_raw) != 8:
            raise ValueError("ingress owner_raw length")
        return d3s1.bkey(6, 0x27, 3, owner_raw)
    if owner_kind == 3:
        if len(owner_raw) != 80:
            raise ValueError("delivery owner_raw length")
        return o1a_dlv_key(owner_raw)
    raise ValueError("owner_kind")


def o1a_bind_man_eligible(mode: int, k: bytes, v: bytes) -> bool:
    """§18.14.9.2 / .3 eligible current typed man (visit-only else GET 0)."""
    if o1a_subtype(k) != 0x30 or o1a_flags(v) != 1:
        return False
    try:
        man = o1a_dec_man(k, v)
    except ValueError:
        return False
    if mode == 30:
        return man["owner_kind"] == 3 and man["blob_kind"] == 5
    return o1a_mode_kind_ok(mode, man)


def o1a_owner_referrer_digest(mode: int, blob_kind: int, owner_v: bytes) -> bytes:
    """Exact mode-scoped referrer digest from returned owner value-only."""
    if mode == 27:
        return o1a_dec_anchor_payload_dig(owner_v)
    if mode == 28:
        t = o1a_dec_ingress_tail(owner_v)
        if blob_kind == 3:
            return t["view_a"]
        if blob_kind == 4:
            return t["view_b"]
        raise ValueError("mode28 blob_kind")
    if mode == 29:
        return o1a_dec_dlv(owner_v)["payload_blob_key_digest"]
    raise ValueError("mode")


def o1a_owner_raw_identity(mode: int, owner_v: bytes) -> bytes:
    """Returned owner raw identity for BIND_MAN post-get compare."""
    if mode == 27:
        return o1a_body(owner_v)[:16]
    if mode == 28:
        return o1a_body(owner_v)[:8]
    if mode == 29:
        return o1a_dec_dlv(owner_v)["owner_raw"]
    raise ValueError("mode")


def o1a_bind_manifest_ok(
    mode: int, scoped: List[Tuple[bytes, Dict[str, Any]]], idx: Dict[bytes, bytes]
) -> bool:
    """OFFLINE-ONLY helper retained for anti-false-pass self-tests.

    Must not be consulted by formal BIND execution (Port-only WG / Mode30 W).
    """
    if mode == 30:
        rrs = [(k, o1a_dec_rr(v)) for k, v in idx.items() if o1a_subtype(k) == 0x42]
        for _mk, man in scoped:
            ok = False
            for _rk, rr in rrs:
                if rr["body_blob_key_digest"] != man["key_digest"]:
                    continue
                if rr["delivery_raw"] != man["owner_raw"]:
                    continue
                if rr["send_state"] not in (1, 2, 3, 4):
                    continue
                ok = True
                break
            if not ok:
                return False
        return True

    for _mk, man in scoped:
        owner_v = None
        if mode == 27:
            for k, v in idx.items():
                if o1a_subtype(k) == 0x20 and o1a_body(v)[:16] == man["owner_raw"]:
                    owner_v = v
                    break
        elif mode == 28:
            for k, v in idx.items():
                if o1a_subtype(k) == 0x27 and o1a_body(v)[:8] == man["owner_raw"]:
                    owner_v = v
                    break
        elif mode == 29:
            found, _err = o1a_resolve_dlv_for_raw(list(idx.items()), man["owner_raw"])
            owner_v = found[1] if found else None
        if owner_v is None:
            return False
        try:
            want = o1a_owner_referrer_digest(mode, int(man["blob_kind"]), owner_v)
        except ValueError:
            return False
        if man["key_digest"] != want:
            return False
    return True


def o1a_bind_chunk_ok(rows: List[Dict[str, str]]) -> bool:
    """OFFLINE-ONLY helper retained for anti-false-pass self-tests.

    Must not be consulted by formal BIND_CHUNK WG execution.
    Forward keys (D1 BLOB):
      man  = COMPOSITE(0x30, u8=1 || blob_id)
      chunk = COMPOSITE(0x30, u8=2 || blob_id || index:u32 BE)
    """
    by_bid: Dict[bytes, List[Tuple[bytes, Dict[str, Any]]]] = {}
    for mk, mv in o1a_all_mans(rows):
        try:
            man = o1a_dec_man(mk, mv)
        except ValueError:
            return False
        by_bid.setdefault(man["blob_id"], []).append((mk, man))

    seen_idx: Dict[Tuple[bytes, int], int] = {}
    for ck, cv in o1a_all_chunks(rows):
        try:
            ch = o1a_dec_chunk(ck, cv)
        except ValueError:
            return False
        mans = by_bid.get(ch["blob_id"])
        if not mans:
            return False  # untyped orphan
        if len(mans) != 1:
            return False  # duplicate/conflicting manifest body for blob_id
        mk, man = mans[0]
        # exact reconstructed complete keys
        if mk != o1a_man_key_from_blob_id(man["blob_id"]):
            return False
        if ck != o1a_chk_key_from_blob_index(ch["blob_id"], ch["index"]):
            return False
        ik = (ch["blob_id"], ch["index"])
        if ik in seen_idx:
            return False  # duplicate index
        seen_idx[ik] = 1
        if ch["index"] >= man["chunk_count"]:
            return False
        if ch["chunk_count"] != man["chunk_count"]:
            return False
        if ch["total_length"] != man["total_length"]:
            return False
        if ch["content_digest"] != man["content_digest"]:
            return False
        if ch["manifest_key_digest"] != man["key_digest"]:
            return False
        if ch["manifest_key_digest"] != d3s1.key_digest(mk):
            return False
        if ch["primary_value_digest"] != man["expected_manifest_value_digest"]:
            return False
        if ch["primary_value_digest"] != d3s1.value_digest(man["value"]):
            return False
    return True


def o1a_walk(
    rows: List[Dict[str, str]], after_key_gets: Optional[Dict[bytes, int]] = None
) -> Tuple[List[str], int]:
    after_key_gets = after_key_gets or {}
    ops: List[str] = ["iter_open:prefix0"]
    peer = 0
    for r in rows:
        k = o1a_row_key(r)
        ops.append("iter_next")
        nget = int(after_key_gets.get(k, 0))
        if nget:
            ops.extend(["get"] * nget)
            peer += nget
    ops.append("iter_next")
    ops.append("iter_close")
    return ops, peer


# ---- §18.14.19.1 formal pre-generation gate (pure; zero Port on fail) ----

FORMAL_MODES = frozenset({27, 28, 29, 30})
FORMAL_ROW_KEYS = frozenset({"key_hex", "value_hex"})
# Full multipass Port-event / on_call / peer representability is closed by
# rep1_schedule_plan_check() (count-only dry-run of the same RefSession schedule).
# N / row_budget arithmetic remains in rep1_representability_gate().


def rep1_catalog_profile_keys() -> List[bytes]:
    """Fixed D2 family1–4 catalog keys (exactly 17) in catalog order."""
    pref = d3s1.encode_all_profile_rows(d3s1.default_binding_fields())
    return [d3s1.from_hex(r["key_hex"]) for r in pref]


def rep1_checked_u32(v: int, *, name: str = "value") -> Optional[str]:
    if type(v) is not int or isinstance(v, bool):
        return f"{name} not strict int"
    if v < 0 or v > UINT32_MAX:
        return f"{name} not representable as u32"
    return None


def rep1_checked_u64(v: int, *, name: str = "value") -> Optional[str]:
    if type(v) is not int or isinstance(v, bool):
        return f"{name} not strict int"
    if v < 0 or v > UINT64_MAX:
        return f"{name} not representable as u64"
    return None


def rep1_representability_gate(
    n: int, formal_class: str = FORMAL_CLASS_ORDINARY
) -> Optional[str]:
    """§18.14.19.1 representability for N and ordinary row_budget=N+1.

    Closed and exact: ``0 ≤ N ≤ UINT32_MAX-1`` so ``row_budget=N+1`` is u32;
    B5 also requires ``N≥1`` and budget ``N`` as u32.
    Complete multipass counters are checked by ``rep1_schedule_plan_check``.
    """
    if type(n) is not int or isinstance(n, bool):
        return "N not strict int"
    if n < 0:
        return "N negative"
    # 0 ≤ N ≤ UINT32_MAX-1 so row_budget=N+1 is exact u32
    if n > UINT32_MAX - 1:
        return "N > UINT32_MAX-1 (row_budget=N+1 not u32)"
    err = rep1_checked_u32(n, name="N")
    if err:
        return err
    err = rep1_checked_u32(n + 1, name="row_budget_N+1")
    if err:
        return err
    err = rep1_checked_u64(n, name="N_u64")
    if err:
        return err
    if formal_class == FORMAL_CLASS_B5_BASELINE:
        if n < 1:
            return "B5 requires N>=1"
        err = rep1_checked_u32(n, name="row_budget_B5_N")
        if err:
            return err
    return None


# Schedule totals keys compared exact between count-only planner and real pack.
REP1_SCHEDULE_TOTAL_KEYS = (
    "formal_call_count",
    "total_port_events",
    "get_count",
    "iter_next_count",
    "iter_open_count",
    "iter_close_count",
    "begin_count",
    "rollback_count",
    "close_count",
    "reopen_attempt_count",
    "reopen_success_count",
    "event_end",
    "trace_count",
    "api_call_index_max",
    "d3_peer_get_count",
    "ok_row_count",
    "current_domain_key_count",
    "family14_row_count",
    "mutation_calls",
    "trace_overflow",
)


def rep1_check_schedule_totals(totals: Dict[str, int]) -> Optional[str]:
    """Validate derived schedule counters as u32/u64 without wrap.

    u32: call/event/op/reopen/window/api index, family14_row_count, mutation_calls.
    u64: peer, ok_row_count, current_domain_key_count.
    Masks/flags are closed by checkpoint validators (0..255 flag forms / mask bits),
    not re-checked here as schedule-length counters.
    """
    u32_keys = (
        "formal_call_count", "total_port_events", "get_count", "iter_next_count",
        "iter_open_count", "iter_close_count", "begin_count", "rollback_count",
        "close_count", "reopen_attempt_count", "reopen_success_count",
        "event_end", "trace_count", "api_call_index_max",
        "family14_row_count", "mutation_calls",
    )
    for k in u32_keys:
        if k not in totals:
            return f"schedule totals missing {k}"
        err = rep1_checked_u32(int(totals[k]), name=k)
        if err:
            return err
    for k in ("d3_peer_get_count", "ok_row_count", "current_domain_key_count"):
        if k not in totals:
            return f"schedule totals missing {k}"
        err = rep1_checked_u64(int(totals[k]), name=k)
        if err:
            return err
    # peer formula when begin profile succeeded (get_count >= 17)
    gc = int(totals.get("get_count", 0))
    peer = int(totals.get("d3_peer_get_count", 0))
    if gc >= 17 and peer != gc - 17:
        return f"d3_peer_get_count {peer} != get_count-17 ({gc}-17)"
    if int(totals.get("trace_overflow", 0)) != 0:
        return "trace_overflow must be 0"
    return None


def rep1_schedule_plan_totals(
    mode: int,
    rows: Any,
    *,
    formal_class: str = FORMAL_CLASS_ORDINARY,
    faults: Optional[List] = None,
) -> Tuple[Optional[Dict[str, int]], Optional[str]]:
    """Count-only dry-run → derived totals dict (no retained Port bodies).

    Authority for event/window counts is ``_schedule_event_count`` (not
    ``len(port_trace)``, which stays 0 under count-only). Returns
    ``(totals, None)`` on success or ``(None, reason)`` if precheck failed
    (no multipass) or a plan error string.
    """
    rs = RefSession(mode, rows)
    rs._schedule_count_only = True
    rs._schedule_event_count = 0
    try:
        pack = rs.run(faults=faults, formal_class=formal_class)
    except ValueError:
        raise
    except (RuntimeError, TypeError) as e:
        return None, f"schedule plan error: {e}"
    if getattr(rs, "_precheck_failed", False):
        return None, None  # structural zero-Port: no multipass schedule
    # Do not read checkpoint port.event_* under count-only (they mirror empty trace).
    n_ev = int(getattr(rs, "_schedule_event_count", 0))
    totals = {
        "formal_call_count": len(pack.get("_calls") or []),
        "total_port_events": n_ev,
        "get_count": int(rs.op_counts.get("get", 0)),
        "iter_next_count": int(rs.op_counts.get("iter_next", 0)),
        "iter_open_count": int(rs.op_counts.get("iter_open", 0)),
        "iter_close_count": int(rs.op_counts.get("iter_close", 0)),
        "begin_count": int(rs.op_counts.get("begin", 0)),
        "rollback_count": int(rs.op_counts.get("rollback", 0)),
        "close_count": int(rs.op_counts.get("close", 0)),
        "reopen_attempt_count": int(rs.reopen_attempt_count),
        "reopen_success_count": int(rs.reopen_success_count),
        "event_end": n_ev,
        "trace_count": n_ev,
        "api_call_index_max": max(0, int(rs.api_call_index) - 1) if rs.api_call_index else 0,
        "d3_peer_get_count": int(rs.peer),
        "ok_row_count": int(rs.ok_row_count),
        "current_domain_key_count": int(rs.current_domain_key_count),
        "family14_row_count": int(rs.family14_row_count),
        "mutation_calls": int(rs.op_counts.get("mutation", 0)),
        "trace_overflow": 0,
    }
    return totals, None


def rep1_schedule_plan_check(
    mode: int,
    rows: Any,
    *,
    formal_class: str = FORMAL_CLASS_ORDINARY,
    faults: Optional[List] = None,
) -> Optional[str]:
    """Representability gate via count-only planner totals."""
    totals, err = rep1_schedule_plan_totals(
        mode, rows, formal_class=formal_class, faults=faults,
    )
    if err is not None:
        return err
    if totals is None:
        return None  # structural precheck zero-Port path
    return rep1_check_schedule_totals(totals)


def rep1_schedule_totals_from_pack(pack: Dict[str, Any]) -> Dict[str, int]:
    """Extract derived schedule totals from a real production pack.

    ok_row_count / current_domain_key_count come from final session checkpoint
    (not port block). Event windows from final port block when present.
    """
    ptrace = pack.get("port_trace") or []
    calls = pack.get("_calls") or []
    fin_cp: Dict[str, Any] = {}
    fin_port: Dict[str, Any] = {}
    fin_sess: Dict[str, Any] = {}
    if calls:
        fin_cp = calls[-1].get("checkpoint") or {}
        fin_port = fin_cp.get("port") or {}
        fin_sess = fin_cp.get("session") or {}
    return {
        "formal_call_count": len(calls),
        "total_port_events": len(ptrace),
        "get_count": int(fin_port.get("get_count", sum(1 for e in ptrace if e.get("op") == "get"))),
        "iter_next_count": int(
            fin_port.get("iter_next_count", sum(1 for e in ptrace if e.get("op") == "iter_next"))
        ),
        "iter_open_count": int(
            fin_port.get("iter_open_count", sum(1 for e in ptrace if e.get("op") == "iter_open"))
        ),
        "iter_close_count": int(
            fin_port.get("iter_close_count", sum(1 for e in ptrace if e.get("op") == "iter_close"))
        ),
        "begin_count": int(
            fin_port.get("begin_count", sum(1 for e in ptrace if e.get("op") == "begin"))
        ),
        "rollback_count": int(
            fin_port.get("rollback_count", sum(1 for e in ptrace if e.get("op") == "rollback"))
        ),
        "close_count": int(
            fin_port.get("close_count", sum(1 for e in ptrace if e.get("op") == "close"))
        ),
        "reopen_attempt_count": int(fin_port.get("reopen_attempt_count", 0)),
        "reopen_success_count": int(fin_port.get("reopen_success_count", 0)),
        "event_end": int(fin_port.get("event_end", len(ptrace))),
        "trace_count": int(fin_port.get("trace_count", len(ptrace))),
        "api_call_index_max": max(
            (int(e.get("api_call_index", 0)) for e in ptrace), default=0
        ),
        "d3_peer_get_count": int(
            pack.get("d3_peer_get_count", fin_port.get("d3_peer_get_count", 0))
        ),
        "ok_row_count": int(fin_sess.get("ok_row_count", 0)),
        "current_domain_key_count": int(fin_sess.get("current_domain_key_count", 0)),
        "family14_row_count": int(
            fin_sess.get("family14_row_count", pack.get("family14_row_count", 0))
        ),
        "mutation_calls": int(
            fin_port.get("mutation_calls", pack.get("mutation_calls", 0))
        ),
        "trace_overflow": int(fin_port.get("trace_overflow", 0)),
    }


def rep1_precheck_formal_inputs(
    mode: Any,
    rows: Any,
    *,
    formal_class: str = FORMAL_CLASS_ORDINARY,
    faults: Optional[List] = None,
) -> Optional[str]:
    """§18.14.19.1 formal pre-generation gate. Pure; no Port events.

    Returns None on accept, else a stable reason string. Production
    ``RefSession.run`` and unit RED harnesses share this function.
    The ``rows`` argument is the exact formal input object (no coerce).
    """
    if formal_class not in FORMAL_VECTOR_CLASSES:
        return f"formal_class closed set; got {formal_class!r}"
    if type(mode) is not int or isinstance(mode, bool) or mode not in FORMAL_MODES:
        return f"mode not in formal closed set {{27,28,29,30}}; got {mode!r}"
    if type(rows) is not list:
        return "rows must be a list"
    n = len(rows)
    # B5 N<1 is ill-formed formal input → same precheck path (not ValueError).
    if formal_class == FORMAL_CLASS_B5_BASELINE and n < 1:
        return "B5 requires N>=1"
    # exact row schema + hex type
    keys_seen: Dict[bytes, int] = {}
    for i, r in enumerate(rows):
        if type(r) is not dict:
            return f"rows[{i}] not object"
        # exact keys {key_hex, value_hex} — surplus rejected
        try:
            got_keys = set(r.keys())
        except TypeError:
            return f"rows[{i}] keys unhashable"
        if got_keys != FORMAL_ROW_KEYS:
            missing = sorted(FORMAL_ROW_KEYS - got_keys)
            extra = sorted(got_keys - FORMAL_ROW_KEYS)
            if missing:
                return f"rows[{i}] missing key_hex/value_hex"
            return f"rows[{i}] surplus keys {extra}"
        kh, vh = r["key_hex"], r["value_hex"]
        if type(kh) is not str or type(vh) is not str:
            return f"rows[{i}] key_hex/value_hex must be str"
        if len(kh) % 2 != 0 or len(vh) % 2 != 0:
            return f"rows[{i}] hex length not even"
        if not all(c in "0123456789abcdefABCDEF" for c in kh):
            return f"rows[{i}] key_hex not hex"
        if not all(c in "0123456789abcdefABCDEF" for c in vh):
            return f"rows[{i}] value_hex not hex"
        if len(kh) == 0:
            return f"rows[{i}] empty complete key"
        try:
            kb = bytes.fromhex(kh)
        except ValueError:
            return f"rows[{i}] key_hex decode"
        keys_seen[kb] = keys_seen.get(kb, 0) + 1
    # complete-key uniqueness (REP1-v1: not multiset-stable)
    for kb, c in keys_seen.items():
        if c != 1:
            return "duplicate complete key"
    n = len(rows)
    # profile: fixed 17 catalog keys exactly once; no surplus family1–4 profile keys
    try:
        catalog = rep1_catalog_profile_keys()
    except Exception as e:
        return f"profile catalog unavailable: {e}"
    if len(catalog) != 17:
        return f"profile catalog length {len(catalog)} != 17"
    catalog_set = set(catalog)
    if len(catalog_set) != 17:
        return "profile catalog internal duplicate"
    for ck in catalog:
        cnt = keys_seen.get(ck, 0)
        if cnt == 0:
            return "profile key missing"
        if cnt != 1:
            return "profile key duplicate"
    # surplus family1–4 current-root keys not in catalog
    ninlil_prefix = bytes.fromhex("4e494e4c494c00")
    for kb in keys_seen:
        if len(kb) < 9:
            continue
        if not kb.startswith(ninlil_prefix):
            continue
        fam = kb[8]
        if fam in (1, 2, 3, 4) and kb not in catalog_set:
            return "surplus profile key"
    # representability of N + full derived schedule counters
    err = rep1_representability_gate(n, formal_class)
    if err is not None:
        return err
    # fault schedule length already validated later; length 0|1 only here
    if faults is not None:
        if type(faults) is not list:
            return "faults must be list or omitted"
        if len(faults) > 1:
            return "faults length must be 0 or 1"
    return None


class RefSession:
    """§18.14 independent multipass oracle (O1a semantics + O1b-B REP1 schedule).

    Derives final_status from rows/faults only (no outcome inject).
    Emits §18.14.19.7 Port events, §18.14.19.8 control tuples, §18.14.19.9 checkpoints.
    One drive = exactly one of W / G / WG (REP1-v1 closed micro-step kinds).
    B0 begin includes I1; no close at W end. SELECT pure W; SELECT_SETUP G; BIND uses WG where required.
    """

    def __init__(self, mode: int, rows: Any):
        self.mode = mode
        # Exact formal input object (no coerce). run() prechecks this identity.
        self._formal_rows: Any = rows
        # Working list materialised only after precheck accept.
        self.rows: List[Dict[str, str]] = []
        self._precheck_failed = False
        self._precheck_reason = ""
        # Port event log (structured)
        self.port_trace: List[Dict[str, Any]] = []
        # Per-op absolute counters (1-based on_call for faults)
        self.op_counts: Dict[str, int] = {
            "begin": 0, "get": 0, "iter_open": 0, "iter_next": 0,
            "iter_close": 0, "rollback": 0, "close": 0, "mutation": 0,
        }
        self.peer = 0  # post-profile GET attempts (OK/NOT_FOUND/fault)
        self._get_response_overrides: Dict[bytes, bytes] = {}
        self._product_gets = False  # False during 17 profile GETs; True after begin profile
        self.opens = 0
        self.session_state = SS_IDLE
        self.phase = PHASE_IDLE
        self.pass_kind = PASS_BASELINE
        self.focus_sub = 0
        self.semantic_pass = 0
        self.flags = 0
        self.count_mask = 0
        self.bind_mask = 0
        self.sticky = ""
        self.has_sticky = 0
        self.adopted = 0
        self.final_status = OUT_OK
        self.terminal_stage = STAGE_COMPLETE
        self.last_carrier_key = b""
        self.reopen_required = 0
        self.fence_pending = 0
        self.cleanup_status: Optional[str] = None
        self.profile_exact_active = 0
        self.profile_mismatch = 0
        self.future_profile_candidate = 0
        self.recognizable_future_seen = 0
        self.family14_row_count = 0
        self.family14_iter_seen_mask = 0
        self.profile_get_present_mask = 0
        self.ok_row_count = 0
        self.current_domain_key_count = 0
        self.has_previous = 0
        self.previous_key = b""
        self.lifecycle_class = 0
        self.expected_live = 0
        self.observed_live = 0
        self.reply_kind = 0
        self.focus_id16 = bytes(16)
        self.txn_live = 0
        self.iter_live = 0
        self.storage_handle_id: Optional[str] = "H1"
        self.txn_handle_id: Optional[str] = None
        self.iter_handle_id: Optional[str] = None
        self.reopen_attempt_count = 0
        self.reopen_success_count = 0
        self.api_call_index = 0
        self.handle = 0
        self.iter_handle = 0
        self.faults: List = []
        self.fault_used = 0
        self.calls: List[Dict[str, Any]] = []
        self._call_events_start = 0
        self._terminal = False  # first COMPLETE/FAILED reached
        self._failed = False
        self._finalize_done = False
        self.idx: Dict[bytes, bytes] = {}
        self.pairs: List[Tuple[bytes, bytes]] = []
        self.sorted_rows: List[Dict[str, str]] = []
        self.n_rows = 0
        self.row_budget = 0
        self._rows_materialized = False
        # Eager materialize only when the *exact* formal rows already pass ordinary gate.
        if (
            rep1_precheck_formal_inputs(
                mode, self._formal_rows, formal_class=FORMAL_CLASS_ORDINARY
            )
            is None
        ):
            self.rows = list(self._formal_rows)
            self._materialize_rows()

    def _materialize_rows(self) -> None:
        """Build idx/pairs/sorted_rows after precheck accept (self.rows is list)."""
        if self._rows_materialized:
            return
        if type(self.rows) is not list:
            raise RuntimeError("materialize requires list rows after precheck")
        self.idx = o1a_index(self.rows)
        self.pairs = o1a_pairs(self.rows)
        self.sorted_rows = sorted(self.rows, key=lambda r: o1a_row_key(r))
        self.n_rows = len(self.sorted_rows)
        self.row_budget = self.n_rows + 1
        self._rows_materialized = True

    def _zero_port_failed(self, reason: str) -> Dict[str, Any]:
        """R18 formal pre-generation gate: no Port, no production call column.

        Production is not invoked. Product packaging (``vec``) places this on
        ``execution_scope=formal_precheck`` with a closed ``precheck_error``.
        Does **not** synthesize begin/finalize Runtime checkpoints or sticky.
        """
        self._precheck_failed = True
        self._precheck_reason = reason
        if self.port_trace:
            raise RuntimeError("precheck failure must not emit Port events")
        return {
            "_precheck_failed": True,
            "_precheck_reason": reason,
            "_calls": [],
            "_positive": 0,
            "port_trace": [],
        }

    # ---- Port emission (§18.14.19.7 exact keys) ----
    def _append_port_event(self, e: Dict[str, Any]) -> Dict[str, Any]:
        """Append one Port event. Rejects unknown keys; fills seq/api_call_index internally.

        Emitted dict key order is exactly PORT_EVENT_KEYS (stable under PYTHONHASHSEED).
        When ``_schedule_count_only`` is set, counters advance but no event body is retained.
        """
        if not isinstance(e, dict):
            raise TypeError("port event must be dict")
        # Membership only — never iterate a set to build the serialized event.
        allowed_in = set(PORT_EVENT_KEYS) - {"seq", "api_call_index"}
        unknown = sorted(set(e.keys()) - allowed_in)
        if unknown:
            raise ValueError(f"port event unknown keys: {unknown}")
        if "seq" in e or "api_call_index" in e:
            raise ValueError("seq/api_call_index are filled internally")
        count_only = bool(getattr(self, "_schedule_count_only", False))
        if count_only:
            seq = int(getattr(self, "_schedule_event_count", 0))
        else:
            seq = len(self.port_trace)
        # next length after append would be seq+1; reject at boundary before write
        size_err = port_trace_size_error(seq + 1, TRACE_CAPACITY)
        if size_err is not None:
            raise RuntimeError(size_err)
        if seq > UINT32_MAX:
            raise RuntimeError("port event seq exceeds UINT32_MAX")
        api_idx = int(self.api_call_index)
        if api_idx < 0 or api_idx > UINT32_MAX:
            raise RuntimeError("api_call_index not representable as u32")
        # require all allowed fields present (callers pass complete op payloads)
        missing = sorted(allowed_in - set(e.keys()))
        if missing:
            raise ValueError(f"port event missing keys: {missing}")
        # Stable insertion order = PORT_EVENT_KEYS tuple (not set iteration).
        full: Dict[str, Any] = {}
        for k in PORT_EVENT_KEYS:
            if k == "seq":
                full[k] = seq
            elif k == "api_call_index":
                full[k] = api_idx
            else:
                full[k] = e[k]
        # u32 representability for numeric descriptor fields
        for nk in (
            "on_call", "prefix_length", "request_key_length",
            "key_capacity", "key_length", "value_capacity", "value_length",
        ):
            v = full[nk]
            if type(v) is bool or type(v) is not int:
                raise TypeError(f"port event {nk} must be int (not bool)")
            if v < 0 or v > UINT32_MAX:
                raise ValueError(f"port event {nk} not representable as u32: {v}")
        if count_only:
            self._schedule_event_count = seq + 1
            return full
        self.port_trace.append(full)
        return full

    def _ev(
        self,
        op: str,
        storage_status: Optional[str],
        *,
        input_handle_id: Optional[str] = None,
        output_handle_id: Optional[str] = None,
        mode: Optional[str] = None,
        prefix_hex: str = "",
        prefix_length: int = 0,
        request_key_hex: str = "",
        request_key_length: int = 0,
        key_hex: str = "",
        key_capacity: int = 0,
        key_length: int = 0,
        value_capacity: int = 0,
        value_length: int = 0,
    ) -> Dict[str, Any]:
        self.op_counts[op] = self.op_counts.get(op, 0) + 1
        return self._append_port_event({
            "op": op,
            "on_call": self.op_counts[op],
            "storage_status": storage_status,
            "input_handle_id": input_handle_id,
            "output_handle_id": output_handle_id,
            "mode": mode,
            "prefix_hex": prefix_hex,
            "prefix_length": int(prefix_length),
            "request_key_hex": request_key_hex,
            "request_key_length": int(request_key_length),
            "key_hex": key_hex,
            "key_capacity": int(key_capacity),
            "key_length": int(key_length),
            "value_capacity": int(value_capacity),
            "value_length": int(value_length),
        })

    def _map_returned(self, status: str) -> str:
        """Map call expected_status to Runtime returned_status symbol."""
        if status == "OK":
            return OUT_OK
        return status

    def _checkpoint(self, returned_status: str, *, finalize: bool = False) -> Dict[str, Any]:
        """§18.14.19.9 nested checkpoint; no peer_key scratch fields."""
        sticky = "" if not self.has_sticky else self.sticky
        event_start = int(self._call_events_start)
        event_end = len(self.port_trace)
        port_block = {
            "event_start": event_start,
            "event_end": event_end,
            "trace_count": event_end,
            "begin_count": int(self.op_counts.get("begin", 0)),
            "get_count": int(self.op_counts.get("get", 0)),
            "iter_open_count": int(self.op_counts.get("iter_open", 0)),
            "iter_next_count": int(self.op_counts.get("iter_next", 0)),
            "iter_close_count": int(self.op_counts.get("iter_close", 0)),
            "rollback_count": int(self.op_counts.get("rollback", 0)),
            "close_count": int(self.op_counts.get("close", 0)),
            "d3_peer_get_count": int(self.peer),
            "reopen_attempt_count": int(self.reopen_attempt_count),
            "reopen_success_count": int(self.reopen_success_count),
            "mutation_calls": int(self.op_counts.get("mutation", 0)),
            "trace_overflow": 0,
            "storage_handle_id": self.storage_handle_id,
            "txn_handle_id": self.txn_handle_id if self.txn_live else None,
            "iter_handle_id": self.iter_handle_id if self.iter_live else None,
        }
        session_block = {
            "state": self.session_state,
            "txn_live": int(self.txn_live),
            "iter_live": int(self.iter_live),
            "has_sticky_primary": int(self.has_sticky),
            "sticky_primary": sticky,
            "cleanup_status": self.cleanup_status,
            "reopen_required": int(self.reopen_required),
            "fence_pending": int(self.fence_pending),
            "profile_exact_active": int(self.profile_exact_active),
            "profile_mismatch": int(self.profile_mismatch),
            "future_profile_candidate": int(self.future_profile_candidate),
            "recognizable_future_seen": int(self.recognizable_future_seen),
            "family14_row_count": int(self.family14_row_count),
            "family14_iter_seen_mask": int(self.family14_iter_seen_mask),
            "profile_get_present_mask": int(self.profile_get_present_mask),
            "ok_row_count": int(self.ok_row_count),
            "current_domain_key_count": int(self.current_domain_key_count),
            "has_previous": int(self.has_previous),
            "previous_key_hex": self.previous_key.hex() if self.previous_key else "",
            "previous_key_length": int(len(self.previous_key)),
        }
        d3s3_block = {
            "phase": int(self.phase),
            "pass_kind": int(self.pass_kind),
            "focus_mode": int(self.mode),
            "focus_sub": int(self.focus_sub),
            "semantic_pass": int(self.semantic_pass),
            "lifecycle_class": int(self.lifecycle_class),
            "expected_live": int(self.expected_live),
            "observed_live": int(self.observed_live),
            "reply_kind": int(self.reply_kind),
            "flags": int(self.flags),
            "count_complete_mask": int(self.count_mask),
            "binding_complete_mask": int(self.bind_mask),
            "last_carrier_key_hex": (
                self.last_carrier_key.hex() if self.last_carrier_key else ""
            ),
            "last_carrier_key_len": int(len(self.last_carrier_key)),
            "focus_id16_hex": self.focus_id16.hex(),
        }
        result_block: Any = None
        if finalize:
            rs = self._map_returned(returned_status)
            result_block = {
                "status": rs,
                "adopted": int(self.adopted),
                "state_after": SS_DONE,
                "has_sticky_primary": int(self.has_sticky),
                "sticky_primary": sticky,
                "reopen_required": int(self.reopen_required),
                "cleanup_status": self.cleanup_status,
                "mutation_calls": int(self.op_counts.get("mutation", 0)),
                "profile_exact_active": int(self.profile_exact_active),
                "profile_mismatch": int(self.profile_mismatch),
                "future_profile_candidate": int(self.future_profile_candidate),
                "recognizable_future_seen": int(self.recognizable_future_seen),
                "family14_row_count": int(self.family14_row_count),
                "family14_iter_seen_mask": int(self.family14_iter_seen_mask),
                "profile_get_present_mask": int(self.profile_get_present_mask),
                "ok_row_count": int(self.ok_row_count),
                "current_domain_key_count": int(self.current_domain_key_count),
                "d3_peer_get_count": int(self.peer),
            }
        return {
            "returned_status": self._map_returned(returned_status),
            "session": session_block,
            "d3s3": d3s3_block,
            "port": port_block,
            "result": result_block,
        }

    def _end_call(self, op: str, expected_status: str, **extra) -> None:
        # O1b-C: finalize must not repair profile_* fields; publish live session state.
        finalize = op == "finalize"
        cp = self._checkpoint(expected_status, finalize=finalize)
        call: Dict[str, Any] = {
            "op": op,
            "expected_status": expected_status,
            "checkpoint": cp,
            "trace_begin": self._call_events_start,
            "trace_end": len(self.port_trace),
        }
        if op == "begin_profiled_d3s3":
            call["mode"] = self.mode
        if op == "d3s3_drive":
            call["row_budget"] = self.row_budget
        call.update(extra)
        self.calls.append(call)
        self._call_events_start = len(self.port_trace)
        self.api_call_index = len(self.calls)

    def _sticky_fail(self, sticky: str, stage: str) -> None:
        """First sticky only; FAILED/phase14; preserve flags/masks/substates (failure-point).

        Cleanup is finalize-only. Does not rewrite flags to BASELINE_DONE.
        Product pin/man projections and the single SHA bank are released before
        drive-end assert (R10): no live unequal slot claims after sticky.
        Normative failure-point remains flags/masks/focus_id16/last_carrier/etc.
        """
        # Release product SHA bank on failure (fixed-memory hygiene).
        sha = getattr(self, "_product_sha", None)
        if sha is not None:
            try:
                sha.abandon()
            except Exception:
                pass
            self._product_sha = None
        # Drop temporary pin/man projections (754 unique-slot rule; no FAILED exemption).
        self._release_carrier_product_workspace()
        if not self.has_sticky:
            self.sticky = sticky
            self.has_sticky = 1
            self.final_status = sticky
            self.terminal_stage = stage
        # Always enter terminal FAILED for the drive machine; keep prior sticky text.
        self.adopted = 0
        self.phase = PHASE_FAILED
        self.session_state = SS_FAILED
        self._failed = True
        self._terminal = True

    def _mark_complete_ready(self) -> None:
        self.sticky = ""
        self.has_sticky = 0
        self.final_status = OUT_OK
        self.adopted = 1
        self.phase = PHASE_COMPLETE
        self.flags = FLAG_BASELINE_DONE | FLAG_COMPLETE_READY
        self.bind_mask = MASK_BIND
        self.terminal_stage = STAGE_COMPLETE
        self._terminal = True
        self._release_carrier_product_workspace()

    # ---- fault injection (REP1-v1 NATURAL closed set) ----
    _FAULT_OPS = frozenset({"get", "iter_open", "iter_next", "rollback"})
    _FAULT_FLOORS = {"get": 18, "iter_open": 2, "iter_next": 1, "rollback": 1}
    _FAULT_KEYS = frozenset({"op", "on_call", "status", "shape"})

    def _validate_formal_faults(self, faults: Any) -> List[Dict[str, Any]]:
        """Closed formal fault schedule: built-in list length 0|1 only (no coerce)."""
        # Strict built-in list — reject list subclasses and all non-lists.
        if type(faults) is not list:
            raise ValueError(
                f"formal faults must be built-in list (no coerce); got {type(faults).__name__}"
            )
        if len(faults) not in (0, 1):
            raise ValueError("formal faults length must be 0 or 1")
        if not faults:
            return []
        f0 = faults[0]
        if type(f0) is not dict:
            raise ValueError("formal fault must be built-in dict object")
        try:
            keys = set(f0.keys())
        except TypeError as e:
            raise ValueError(f"formal fault keys unhashable/invalid: {e}") from e
        if keys != self._FAULT_KEYS:
            raise ValueError(
                f"formal fault exact keys {{op,on_call,status,shape}}; got {sorted(keys, key=str)}"
            )
        op = f0["op"]
        if type(op) is not str:
            raise ValueError(f"formal fault op must be strict str; got {type(op).__name__}")
        if op not in self._FAULT_OPS:
            raise ValueError(f"formal fault op closed set; got {op!r}")
        on = f0["on_call"]
        if type(on) is not int:
            raise ValueError("formal fault on_call must be strict int (not bool)")
        if on < 0 or on > UINT32_MAX:
            raise ValueError("formal fault on_call not u32")
        floor = self._FAULT_FLOORS[op]
        if op == "rollback":
            if on != 1:
                raise ValueError("formal fault rollback.on_call must be exactly 1")
        elif on < floor:
            raise ValueError(f"formal fault {op}.on_call floor {floor}, got {on}")
        st = f0["status"]
        if type(st) is not str:
            raise ValueError(f"formal fault status must be strict str; got {type(st).__name__}")
        if st not in STORAGE_NATURAL:
            raise ValueError(
                f"formal fault status closed natural six only; got {st!r} "
                f"(OK/NOT_FOUND/BUFFER_TOO_SMALL/unknown forbidden; no coerce)"
            )
        shape = f0["shape"]
        if type(shape) is not str:
            raise ValueError(f"formal fault shape must be strict str; got {type(shape).__name__}")
        if shape != "natural":
            raise ValueError("formal fault shape must be exactly 'natural'")
        return [{"op": op, "on_call": on, "status": st, "shape": shape}]

    def _fault_for(self, op: str) -> Optional[Dict[str, Any]]:
        if not self.faults or self.fault_used:
            return None
        f0 = self.faults[0]
        if f0.get("op") != op:
            return None
        on = f0["on_call"]  # already validated strict int
        if self.op_counts.get(op, 0) + 1 == on:
            return f0
        return None

    def _storage_status_from_fault(self, f: Dict[str, Any]) -> str:
        st = f.get("status")
        if type(st) is not str or st not in STORAGE_NATURAL:
            raise ValueError(f"illegal formal fault status (no coerce): {st!r}")
        return st

    def _port_fail(self, st: str, stage: str = STAGE_PORT) -> None:
        """Map natural Storage fault → Runtime sticky. Unknown status raises before mutation.

        docs/17 §15.11.5 / §18.14.19.10: COMMIT_UNKNOWN is a known fence status —
        map + set fence_pending at the failing drive (no in-drive cleanup).
        """
        if type(st) is not str or st not in STORAGE_NATURAL:
            raise ValueError(f"_port_fail: status not in NATURAL closed set: {st!r}")
        if st == "COMMIT_UNKNOWN":
            self.fence_pending = 1
        self._sticky_fail(STORAGE_TO_RUNTIME[st], stage)

    def _fail_get_status(self, st: str, *, stage_absent: str, stage_port: str = STAGE_PORT) -> None:
        """Classify formal GET status only: NATURAL | NOT_FOUND. Else raise before mutation."""
        if type(st) is not str:
            raise ValueError(f"_fail_get_status: status must be str; got {type(st).__name__}")
        if st in STORAGE_NATURAL:
            self._port_fail(st, stage_port)
            return
        if st == "NOT_FOUND":
            self._sticky_fail(OUT_CORRUPT, stage_absent)
            return
        raise ValueError(f"_fail_get_status: status not in closed GET set: {st!r}")

    # ---- primitives ----
    def _get(self, key: bytes, value: Optional[bytes], *, peer: bool = False) -> str:
        """Emit get. value None => ABSENT (NOT_FOUND). Returns status.

        peer=True marks a product-path GET. After profile complete, every GET
        attempt (OK/NOT_FOUND/fault) increments d3_peer_get_count regardless of
        the peer flag; profile GETs leave peer counting off.
        """
        # product-path callers pass peer=True; also count when product phase active
        count_peer = self._product_gets or peer
        f = self._fault_for("get")
        if f is not None:
            st = self._storage_status_from_fault(f)
            if count_peer:
                self.peer += 1
            self._ev(
                "get", st,
                input_handle_id=self.txn_handle_id or "T1",
                output_handle_id=None,
                mode=None,
                request_key_hex=key.hex(),
                request_key_length=len(key),
                key_hex="",
                key_capacity=0,
                key_length=0,
                value_capacity=VALUE_CAPACITY,
                value_length=0,
            )
            self.fault_used = 1
            return st
        if value is None:
            if count_peer:
                self.peer += 1
            self._ev(
                "get", "NOT_FOUND",
                input_handle_id=self.txn_handle_id or "T1",
                output_handle_id=None,
                mode=None,
                request_key_hex=key.hex(),
                request_key_length=len(key),
                key_hex="",
                key_capacity=0,
                key_length=0,
                value_capacity=VALUE_CAPACITY,
                value_length=0,
            )
            return "NOT_FOUND"
        if count_peer:
            self.peer += 1
        self._ev(
            "get", "OK",
            input_handle_id=self.txn_handle_id or "T1",
            output_handle_id=None,
            mode=None,
            request_key_hex=key.hex(),
            request_key_length=len(key),
            key_hex="",
            key_capacity=0,
            key_length=0,
            value_capacity=VALUE_CAPACITY,
            value_length=len(value),
        )
        return "OK"

    def _void_iter_close(self) -> None:
        """Void iter_close of live iterator (reopen or finalize)."""
        if not self.iter_live or self.iter_handle_id is None:
            return
        self._ev(
            "iter_close", None,
            input_handle_id=self.iter_handle_id,
            output_handle_id=None,
            mode=None,
        )
        self.iter_live = 0
        self.iter_handle_id = None

    def _iter_open_next(self, *, count_reopen: bool) -> str:
        """Open next Ik. count_reopen=True for post-I1 reopens (attempt/success)."""
        self.iter_handle += 1
        ik = f"I{self.iter_handle}"
        f = self._fault_for("iter_open")
        if f is not None:
            st = self._storage_status_from_fault(f)
            self._ev(
                "iter_open", st,
                input_handle_id=self.txn_handle_id or "T1",
                output_handle_id=None,
                mode=None,
                prefix_hex="",
                prefix_length=0,
            )
            self.fault_used = 1
            self.iter_live = 0
            self.iter_handle_id = None
            if count_reopen:
                self.reopen_attempt_count += 1
            return st
        self._ev(
            "iter_open", "OK",
            input_handle_id=self.txn_handle_id or "T1",
            output_handle_id=ik,
            mode=None,
            prefix_hex="",
            prefix_length=0,
        )
        self.opens += 1
        self.iter_live = 1
        self.iter_handle_id = ik
        self.iter_pos = 0
        if count_reopen:
            self.reopen_attempt_count += 1
            self.reopen_success_count += 1
        return "OK"

    def _entry_invalid_state(self) -> None:
        """Zero-Port INVALID_STATE before any event of this drive."""
        self._sticky_fail(OUT_INVALID_STATE, STAGE_PORT)

    def _preflight_g_entry(self) -> bool:
        """G entry: EXHAUSTED+txn1+iter1 exact; no reopen. False => sticky already set."""
        if (
            self.session_state != SS_EXHAUSTED
            or not self.txn_live
            or not self.iter_live
        ):
            self._entry_invalid_state()
            return False
        return True

    def _preflight_w_wg_entry(self) -> Optional[str]:
        """W/WG entry reopen/liveness exact. None=OK; 'INVALID_STATE'=zero-Port; else Port fault status.

        NEED=0+iter_live1: neither close nor open.
        NEED=1+iter_live1: exactly one close then one open; clear NEED before first next.
        iter_live0 (any NEED): INVALID_STATE before Port (no silent close/open, no IO_ERROR round-down).
        """
        if not self.txn_live:
            self._entry_invalid_state()
            return "INVALID_STATE"
        need = (self.flags & FLAG_NEED_REOPEN) != 0
        if not self.iter_live:
            self._entry_invalid_state()
            return "INVALID_STATE"
        if self.phase == PHASE_BASELINE:
            # BASELINE: NEED must be 0; I1 already live
            if need:
                self._entry_invalid_state()
                return "INVALID_STATE"
            return None
        if not need:
            return None
        self._void_iter_close()
        self.flags = (self.flags & ~FLAG_NEED_REOPEN) & 0xFF
        st = self._iter_open_next(count_reopen=True)
        if st != "OK":
            return st
        return None

    def _reopen_if_needed(self) -> Optional[str]:
        """Compatibility wrapper: W/WG entry preflight (returns Port fault status or None).

        INVALID_STATE is sticky-set and returns 'INVALID_STATE' so callers end the drive
        without _port_fail.
        """
        return self._preflight_w_wg_entry()

    def _fail_w_wg_entry(self, fr: Optional[str], *, row_budget: int) -> bool:
        """If fr is set, finish drive as entry failure. Returns True if failed."""
        if fr is None:
            return False
        if fr != "INVALID_STATE":
            self._port_fail(fr)
        self._drive_end(self.final_status, row_budget=row_budget)
        return True

    def _emit_iter_next(
        self, status: str, key: bytes = b"", value: bytes = b""
    ) -> str:
        if status == "OK":
            self._ev(
                "iter_next", "OK",
                input_handle_id=self.iter_handle_id,
                output_handle_id=None,
                mode=None,
                key_hex=key.hex(),
                key_capacity=KEY_CAPACITY,
                key_length=len(key),
                value_capacity=VALUE_CAPACITY,
                value_length=len(value),
            )
            return "OK"
        f = self._fault_for("iter_next")
        if f is not None and status == "CHECK_FAULT":
            st = self._storage_status_from_fault(f)
            self._ev(
                "iter_next", st,
                input_handle_id=self.iter_handle_id,
                output_handle_id=None,
                mode=None,
                key_hex="",
                key_capacity=KEY_CAPACITY,
                key_length=0,
                value_capacity=VALUE_CAPACITY,
                value_length=0,
            )
            self.fault_used = 1
            return st
        # NOT_FOUND or fault path lengths
        self._ev(
            "iter_next", status,
            input_handle_id=self.iter_handle_id,
            output_handle_id=None,
            mode=None,
            key_hex="",
            key_capacity=KEY_CAPACITY,
            key_length=0,
            value_capacity=VALUE_CAPACITY,
            value_length=0,
        )
        return status

    def _advance_w(self, budget: int, on_row=None) -> str:
        """Advance live iterator up to budget nexts. Returns OK (true exhaust), MIDWALK, or fault.

        Never opens/closes. on_row(k,v) optional; may set self._walk_abort to stop after
        the current OK row (e.g. BIND WG GET natural fault or sticky finding).

        §18.14.9.5: under PASS_INTERNAL, public ok_row_count / current_domain_key_count
        stay frozen; visit-before-hook commits only has_previous + previous_key.
        """
        if not self.iter_live:
            return "IO_ERROR"
        self._walk_abort = None  # type: Optional[str]
        advanced = 0
        while advanced < budget:
            f = self._fault_for("iter_next")
            if f is not None:
                return self._emit_iter_next("CHECK_FAULT")
            if self.iter_pos < self.n_rows:
                r = self.sorted_rows[self.iter_pos]
                k = o1a_row_key(r)
                v = o1a_row_val(r)
                self._emit_iter_next("OK", k, v)
                self.iter_pos += 1
                advanced += 1
                # Lex-only visit commit before on_row / BIND get (even under INTERNAL).
                self.has_previous = 1
                self.previous_key = k
                # Public D2 counters: BASELINE only (§18.14.9.5 INTERNAL freeze).
                if self.pass_kind == PASS_BASELINE:
                    self.ok_row_count += 1
                    self.current_domain_key_count = self.ok_row_count
                if on_row is not None:
                    on_row(k, v)
                    if self._walk_abort is not None:
                        return self._walk_abort
            else:
                self._emit_iter_next("NOT_FOUND")
                return "OK"  # true exhaustion
        return "MIDWALK"

    def _set_tuple(
        self,
        state: str,
        phase: int,
        pass_kind: int,
        focus_sub: int,
        semantic_pass: int,
        flags: int,
        count_mask: int,
        bind_mask: int,
    ) -> None:
        self.session_state = state
        self.phase = phase
        self.pass_kind = pass_kind
        self.focus_sub = focus_sub
        self.semantic_pass = semantic_pass
        self.flags = flags & 0xFF
        self.count_mask = count_mask & 0xFF
        self.bind_mask = bind_mask & 0xFF

    def _pin_mode28_totals(self, view_a: int, view_b: int) -> None:
        """Store lossless u64be pair into focus_id16 (Mode28 single authority)."""
        if type(view_a) is not int or type(view_b) is not int:
            raise TypeError("Mode28 totals must be int")
        if view_a < 0 or view_a > UINT64_MAX or view_b < 0 or view_b > UINT64_MAX:
            raise ValueError("Mode28 total not representable as u64 without wrap")
        self.focus_id16 = struct.pack(">QQ", view_a, view_b)

    def _mode28_read_pins(self) -> Tuple[int, int]:
        """Unpack focus_id16 as the sole Mode28 totals authority."""
        if not isinstance(self.focus_id16, (bytes, bytearray)) or len(self.focus_id16) != 16:
            raise ValueError("Mode28 focus_id16 must be 16 bytes")
        return struct.unpack(">QQ", bytes(self.focus_id16))

    def _reset_mode28_carrier_workspace(self) -> None:
        """New Mode28 carrier: clear single man bank + pin both halves to 0."""
        self.active_man = None
        self._pin_mode28_totals(0, 0)

    def _mode28_za_zb(self, pins: Dict[str, Any]) -> Tuple[int, int]:
        za = 1 if pins.get("view_a", O1A_ZERO32) == O1A_ZERO32 else 0
        zb = 1 if pins.get("view_b", O1A_ZERO32) == O1A_ZERO32 else 0
        return za, zb

    def _peer_gets_keys(self, keys_vals: List[Tuple[bytes, Optional[bytes]]]) -> str:
        for k, v in keys_vals:
            st = self._get(k, v, peer=True)
            if st != "OK":
                return st
        return "OK"

    def _profile_keys(self) -> List[bytes]:
        """Fixed D2 profile catalog order from fixture profile rows (17)."""
        try:
            pref = d3s1.encode_all_profile_rows(d3s1.default_binding_fields())
            order = [d3s1.from_hex(r["key_hex"]) for r in pref]
        except Exception:
            order = []
        present = {o1a_row_key(r): o1a_row_val(r) for r in self.rows}
        keys = []
        for k in order:
            if k in present:
                keys.append(k)
        if len(keys) == 17:
            return keys
        fam = sorted(
            k for k in present
            if len(k) >= 9 and k[8] in (1, 2, 3, 4)
        )
        return fam[:17]

    def _release_carrier_product_workspace(self) -> None:
        """Drop active_pins/active_man Python projections (not 754 second banks)."""
        self.active_pins = None
        self.active_man = None

    def _man_slot_name(self, man_key: str) -> str:
        """Resolve man field -> layout slot (Mode27 owner_raw -> focus_id16)."""
        if man_key == "owner_raw" and self.mode == 27:
            return "focus_id16"
        return PRODUCT_PATH_MAN_SLOT[man_key]

    def _sync_pin_to_context_754(self, pins: Dict[str, Any]) -> None:
        """Write every live pin into its unique 754 context slot."""
        if "carrier_key" in pins and isinstance(pins["carrier_key"], (bytes, bytearray)):
            # last_carrier_key advanced at SELECT; keep equal
            if pins["carrier_key"] != self.last_carrier_key:
                self.last_carrier_key = bytes(pins["carrier_key"])
        if "tx16" in pins:
            tx = pins["tx16"]
            if isinstance(tx, (bytes, bytearray)) and len(tx) == 16:
                self.focus_id16 = bytes(tx)
        if "transaction_id" in pins:
            tid = pins["transaction_id"]
            if isinstance(tid, (bytes, bytearray)) and len(tid) == 16:
                self.focus_id16 = bytes(tid)
        if "owner_raw" in pins:
            raw = pins["owner_raw"]
            if isinstance(raw, (bytes, bytearray)):
                rl = len(raw)
                if rl > 80:
                    raise ValueError("owner_raw > 80")
                self.focus_raw80 = bytes(raw) + bytes(80 - rl)
                self.focus_raw_len = rl
        if "focus_raw80" in pins:
            raw = pins["focus_raw80"]
            if isinstance(raw, (bytes, bytearray)) and len(raw) == 80:
                self.focus_raw80 = bytes(raw)
                self.focus_raw_len = 80
        if "focus_dig" in pins:
            dig = pins["focus_dig"]
            if isinstance(dig, (bytes, bytearray)) and len(dig) == 32:
                self.focus_key_digest = bytes(dig)
        if "view_a" in pins:
            va = pins["view_a"]
            if isinstance(va, (bytes, bytearray)) and len(va) == 32:
                self.view_a_key_digest = bytes(va)
        if "view_b" in pins:
            vb = pins["view_b"]
            if isinstance(vb, (bytes, bytearray)) and len(vb) == 32:
                self.view_b_key_digest = bytes(vb)
        if "semantic_stored" in pins:
            s = pins["semantic_stored"]
            if isinstance(s, (bytes, bytearray)) and len(s) == 32:
                self.expected_semantic_digest = bytes(s)
        if "semantic_digest" in pins:
            s = pins["semantic_digest"]
            if isinstance(s, (bytes, bytearray)) and len(s) == 32:
                self.expected_semantic_digest = bytes(s)
        if "reply_kind" in pins:
            self.reply_kind = int(pins["reply_kind"]) & 0xFF
        if "send_state" in pins:
            # next_chunk_index holds send_state u8 as u32 (non-checkpointed slot)
            self.next_chunk_index = int(pins["send_state"]) & 0xFFFFFFFF
        if "receipt_evidence_bytes" in pins:
            evi = pins["receipt_evidence_bytes"]
            if isinstance(evi, (bytes, bytearray)) and len(evi) == 128:
                self._receipt_evidence_bytes = bytes(evi)
        if "receipt_evidence_len" in pins:
            self._receipt_evidence_len = int(pins["receipt_evidence_len"]) & 0xFF
        if "pinned_receipt_stage" in pins:
            self._pinned_receipt_stage = int(pins["pinned_receipt_stage"]) & 0xFFFFFFFF
        if "carrier_value_digest" in pins:
            dig = pins["carrier_value_digest"]
            if isinstance(dig, (bytes, bytearray)) and len(dig) == 32:
                self.view_a_key_digest = bytes(dig)

    def _sync_man_to_context_754(self, man: Dict[str, Any]) -> None:
        """Write every live man field into its unique 754 context slot."""
        self.focus_key_digest = bytes(man["key_digest"])
        self.blob_id_digest = bytes(man["blob_id"])
        self.owner_kind = int(man["owner_kind"]) & 0xFF
        self.blob_kind = int(man["blob_kind"]) & 0xFF
        self.owner_primary_key_digest = bytes(man["owner_primary_key_digest"])
        self.total_length_pin = int(man["total_length"])
        self.chunk_count_pin = int(man["chunk_count"])
        self.content_digest_pin = bytes(man["content_digest"])
        self.expected_owner_pvd = bytes(man["expected_owner_pvd"])
        self.expected_manifest_value_digest = bytes(man["expected_manifest_value_digest"])
        raw = man["owner_raw"]
        if self.mode == 27:
            # owner_raw aliases focus_id16 (carrier tx); only write when equal/absent pin
            if not isinstance(raw, (bytes, bytearray)) or len(raw) != 16:
                raise ValueError("Mode27 man.owner_raw must be 16")
            if self.active_pins and "tx16" in self.active_pins:
                if bytes(raw) != bytes(self.active_pins["tx16"]):
                    # illegal residual: pin keeps focus_id16; man bank retains owner_raw
                    pass
                else:
                    self.focus_id16 = bytes(raw)
            else:
                self.focus_id16 = bytes(raw)
        elif self.mode in (29, 30):
            # pin owns focus_raw80; man.owner_raw must equal (h14); never overwrite pin authority
            pin_raw = None
            if self.active_pins:
                pin_raw = self.active_pins.get("focus_raw80") or self.active_pins.get("owner_raw")
            if pin_raw is not None and bytes(raw) != bytes(pin_raw):
                pass  # leave context focus_raw80 as SELECT authority
            else:
                rl = len(raw)
                if rl > 80:
                    raise ValueError("man.owner_raw > 80")
                self.focus_raw80 = bytes(raw) + bytes(80 - rl)
                self.focus_raw_len = rl
        else:
            # Mode28: man.owner_raw fills unique free focus_raw80 slot
            rl = len(raw)
            if rl > 80:
                raise ValueError("man.owner_raw > 80")
            self.focus_raw80 = bytes(raw) + bytes(80 - rl)
            self.focus_raw_len = rl

    def _context_value_for_slot(self, slot: str) -> Any:
        """Read context attribute backing a layout slot."""
        if slot == "last_carrier_key":
            return self.last_carrier_key
        if slot == "last_carrier_key_len":
            return len(self.last_carrier_key)
        if slot == "focus_raw80":
            return self.focus_raw80
        if slot == "focus_raw_len":
            return self.focus_raw_len
        if slot == "focus_id16":
            return self.focus_id16
        if slot == "focus_key_digest":
            return self.focus_key_digest
        if slot == "blob_id_digest":
            return self.blob_id_digest
        if slot == "content_digest":
            return self.content_digest_pin
        if slot == "owner_primary_key_digest":
            return self.owner_primary_key_digest
        if slot == "expected_manifest_value_digest":
            return self.expected_manifest_value_digest
        if slot == "total_length":
            return self.total_length_pin
        if slot == "chunk_count":
            return self.chunk_count_pin
        if slot == "next_chunk_index":
            return self.next_chunk_index
        if slot == "owner_kind":
            return self.owner_kind
        if slot == "blob_kind":
            return self.blob_kind
        if slot == "reply_kind":
            return self.reply_kind
        if slot == "view_a_key_digest":
            return getattr(self, "view_a_key_digest", bytes(32))
        if slot == "view_b_key_digest":
            return getattr(self, "view_b_key_digest", bytes(32))
        if slot == "expected_owner_pvd":
            return self.expected_owner_pvd
        if slot == "expected_semantic_digest":
            return getattr(self, "expected_semantic_digest", bytes(32))
        if slot == "receipt_evidence_bytes":
            return getattr(self, "_receipt_evidence_bytes", bytes(128))
        if slot == "receipt_evidence_len":
            return getattr(self, "_receipt_evidence_len", 0)
        if slot == "pinned_receipt_stage":
            return getattr(self, "_pinned_receipt_stage", 0)
        raise AssertionError(f"R9 no context reader for slot {slot}")

    def _values_equal_for_slot(self, slot: str, pin_val: Any, ctx_val: Any) -> bool:
        if slot == "last_carrier_key":
            return bytes(pin_val) == bytes(ctx_val)
        if slot == "next_chunk_index":
            return int(pin_val) == int(ctx_val)
        if slot in ("reply_kind", "receipt_evidence_len", "pinned_receipt_stage",
                    "owner_kind", "blob_kind", "chunk_count", "total_length", "focus_raw_len"):
            return int(pin_val) == int(ctx_val)
        if slot == "focus_raw80":
            # pin may be exact raw length; context is 80-byte padded
            if isinstance(pin_val, (bytes, bytearray)):
                return self.focus_raw80[: len(pin_val)] == bytes(pin_val) and (
                    self.focus_raw_len == len(pin_val) or len(pin_val) == 80
                )
            return False
        if isinstance(pin_val, (bytes, bytearray)) and isinstance(ctx_val, (bytes, bytearray)):
            return bytes(pin_val) == bytes(ctx_val)
        return pin_val == ctx_val

    def _product_state_assert_r8(self) -> None:
        """R9: 1:1 slot map + phase liveness + alias collision reject."""
        d = self.__dict__
        for bad in PRODUCT_CALL_SPANNING_FORBIDDEN_ATTRS:
            if bad in d and bad in ("carrier_queue", "carriers_seen"):
                raise AssertionError(f"R9 full-ID set attr present: {bad}")
            if bad in d and d.get(bad) not in (None, 0, False, b"", "", set(), []):
                if bad.startswith("_m28") or bad.startswith("_m30") or bad in (
                    "active_man_a", "active_man_b", "_focus_match_count",
                    "carrier_queue", "carriers_seen",
                ):
                    raise AssertionError(f"R9 forbidden product spanning attr: {bad}")
        for name, val in d.items():
            if name.startswith("__"):
                continue
            if name in PRODUCT_CALL_SPANNING_FORBIDDEN_ATTRS:
                if val not in (None, 0, False, b"", "", set(), []):
                    raise AssertionError(f"R9 forbidden attr live: {name}")
                continue
            cls = PRODUCT_CONTEXT_ATTR_CLASS.get(name)
            if cls is None:
                raise AssertionError(f"R9 unclassified product attr: {name}")

        pins = getattr(self, "active_pins", None)
        man = getattr(self, "active_man", None)
        phase = int(self.phase)
        sem = int(self.semantic_pass)
        failed = phase == PHASE_FAILED or bool(self.has_sticky)

        # Terminal / no-current-carrier surfaces: projections must be released.
        if phase in (PHASE_COMPLETE, PHASE_BIND_MANIFEST, PHASE_BIND_CHUNK, PHASE_FAILED):
            if pins is not None or man is not None:
                raise AssertionError(f"R10 stale pin/man at phase={phase} (must be released)")
        if not failed:
            if phase == PHASE_SELECT_CARRIER and sem == 0:
                if pins is not None or man is not None:
                    raise AssertionError("R10 SELECT sem0 must release pins/man")
            if phase == PHASE_SELECT_CARRIER and sem == SEM_SELECT_SETUP:
                if pins is None:
                    raise AssertionError("R10 SELECT_SETUP requires live pins")
            if phase in (
                PHASE_FOCUS_MANIFEST_SCAN, PHASE_FOCUS_MANIFEST_SCAN_B,
                PHASE_OWNER_PVD_PROOF, PHASE_OWNER_PVD_PROOF_B,
                PHASE_FOCUS_CHUNKS, PHASE_FOCUS_CHUNKS_B,
                PHASE_SEMANTIC_PREFIX_REGET, PHASE_SEMANTIC_CHUNK_REWALK,
            ):
                if pins is None and self.lifecycle_class == LC_LIVE_REQUIRED:
                    raise AssertionError(f"R10 live carrier path missing pins at phase={phase}")

        # Collect live slot claims: (start, end, source_key, value_fingerprint)
        claims: List[Tuple[int, int, str, bytes]] = []

        def _fp(v: Any) -> bytes:
            if isinstance(v, (bytes, bytearray)):
                return bytes(v)
            if isinstance(v, int):
                return struct.pack(">Q", v & 0xFFFFFFFFFFFFFFFF)
            return repr(v).encode()

        def _claim(source: str, slot: str, val: Any) -> None:
            if slot not in LAYOUT_754_SLOTS:
                raise AssertionError(f"R9 unmapped slot {slot} for {source}")
            a, b = layout_754_range(slot)
            if a < 0 or b > 754 or a >= b:
                raise AssertionError(f"R9 slot range OOB {slot} [{a},{b})")
            claims.append((a, b, source, _fp(val)))

        if pins is not None:
            for k, v in pins.items():
                if k not in PRODUCT_PATH_PIN_SLOT:
                    raise AssertionError(f"R9 pin key has no slot map: {k}")
                if k in PRODUCT_PATH_FORBIDDEN_PIN_KEYS:
                    raise AssertionError(f"R9 forbidden pin: {k}")
                slot = PRODUCT_PATH_PIN_SLOT[k]
                # context equality
                ctx = self._context_value_for_slot(slot)
                if not self._values_equal_for_slot(slot, v, ctx):
                    raise AssertionError(f"R9 pin {k} != context slot {slot}")
                _claim(f"pin:{k}", slot, v)
            # carrier_key == last_carrier_key
            if "carrier_key" in pins and pins["carrier_key"] != self.last_carrier_key:
                raise AssertionError("R9 carrier_key != last_carrier_key")

        if man is not None:
            if "key" in man or "value" in man:
                raise AssertionError("R9 man retains key/value")
            for k, v in man.items():
                if k not in PRODUCT_PATH_MAN_SLOT:
                    raise AssertionError(f"R9 man key has no slot map: {k}")
                slot = self._man_slot_name(k)
                ctx = self._context_value_for_slot(slot)
                # Every live man key claims its slot — no FAILED skip (R10).
                if k == "owner_raw":
                    pin_raw = None
                    if pins is not None:
                        if self.mode == 27:
                            pin_raw = pins.get("tx16")
                        elif self.mode == 29:
                            pin_raw = pins.get("owner_raw")
                        elif self.mode == 30:
                            pin_raw = pins.get("focus_raw80")
                    if pin_raw is not None and bytes(v) != bytes(pin_raw):
                        raise AssertionError(
                            f"R10 man.owner_raw != carrier pin (mode {self.mode})"
                        )
                    if self.mode == 27:
                        if bytes(v) != bytes(self.focus_id16):
                            raise AssertionError("R10 M27 man.owner_raw != focus_id16")
                    else:
                        if self.focus_raw80[: len(v)] != bytes(v) or self.focus_raw_len != len(v):
                            raise AssertionError(
                                f"R10 man.owner_raw != focus_raw80 (mode {self.mode})"
                            )
                elif k == "total_length":
                    if int(v) != int(self.total_length_pin):
                        raise AssertionError("R10 man.total_length != context")
                elif k == "chunk_count":
                    if int(v) != int(self.chunk_count_pin):
                        raise AssertionError("R10 man.chunk_count != context")
                elif k in ("owner_kind", "blob_kind"):
                    if int(v) != int(ctx):
                        raise AssertionError(f"R10 man.{k} != context")
                elif isinstance(v, (bytes, bytearray)):
                    if bytes(v) != bytes(ctx):
                        raise AssertionError(f"R10 man.{k} != context slot {slot}")
                _claim(f"man:{k}", slot, v)

            # Mode28: man.key_digest must equal selected view for active arm
            if self.mode == 28 and pins is not None:
                va, vb = pins.get("view_a"), pins.get("view_b")
                if man.get("key_digest") not in (va, vb):
                    raise AssertionError("R10 M28 man.key_digest != selected view digest")
                if man.get("owner_raw") is not None:
                    raw = man["owner_raw"]
                    if self.focus_raw_len != len(raw) or self.focus_raw80[: len(raw)] != raw:
                        raise AssertionError("R10 M28 man.owner_raw not in focus_raw80 slot")

            # Legal M27/M29/M30 carrier-owner identity while both live
            if self.mode == 27 and pins is not None and "tx16" in pins:
                if man.get("owner_raw") != pins["tx16"] or man.get("owner_raw") != self.focus_id16:
                    raise AssertionError("R10 M27 man.owner_raw/tx16/focus_id16 diverge")
            if self.mode == 29 and pins is not None and "owner_raw" in pins:
                if man.get("owner_raw") != pins["owner_raw"]:
                    raise AssertionError("R10 M29 man.owner_raw != pin owner_raw")
            if self.mode == 30 and pins is not None and "focus_raw80" in pins:
                if man.get("owner_raw") != pins["focus_raw80"]:
                    raise AssertionError("R10 M30 man.owner_raw != pin focus_raw80")

        # Collision: overlapping ranges with independent (unequal) values forbidden
        for i in range(len(claims)):
            a0, a1, s0, v0 = claims[i]
            for j in range(i + 1, len(claims)):
                b0, b1, s1, v1 = claims[j]
                if a0 < b1 and b0 < a1:  # overlap
                    if v0 != v1:
                        raise AssertionError(
                            f"R9 slot collision {s0}[{a0},{a1}) vs {s1}[{b0},{b1}) unequal"
                        )

        # Exhaustive coverage: every live pin/man key has exactly one mapping
        if pins is not None:
            for k in pins:
                if k not in PRODUCT_PATH_PIN_SLOT:
                    raise AssertionError(f"R9 coverage: pin {k} unmapped")
        if man is not None:
            for k in man:
                if k not in PRODUCT_PATH_MAN_SLOT:
                    raise AssertionError(f"R9 coverage: man {k} unmapped")

        if _PRODUCT_SHA_LIVE > 1:
            raise AssertionError(f"R9 SHA concurrent live={_PRODUCT_SHA_LIVE}")

    def _drive_end(self, expected_status: str, *, row_budget: int = 0) -> None:
        if not hasattr(self, "active_man"):
            self.active_man = None
        if not hasattr(self, "active_pins"):
            self.active_pins = None
        if not hasattr(self, "view_a_key_digest"):
            self.view_a_key_digest = bytes(32)
        if not hasattr(self, "view_b_key_digest"):
            self.view_b_key_digest = bytes(32)
        if not hasattr(self, "expected_semantic_digest"):
            self.expected_semantic_digest = bytes(32)
        # Release projections on terminal/no-carrier success AND on FAILED (sticky
        # already released; belt-and-suspenders if sticky was skipped).
        if self.phase in (PHASE_COMPLETE, PHASE_BIND_MANIFEST, PHASE_BIND_CHUNK, PHASE_FAILED):
            self._release_carrier_product_workspace()
        elif (
            not self.has_sticky
            and self.phase == PHASE_SELECT_CARRIER
            and int(self.semantic_pass) == 0
        ):
            self._release_carrier_product_workspace()
        # SHA must be dead after sticky/terminal failure paths.
        if self.phase == PHASE_FAILED and getattr(self, "_product_sha", None) is not None:
            try:
                self._product_sha.abandon()
            except Exception:
                pass
            self._product_sha = None
        self._product_state_assert_r8()
        self._end_call("d3s3_drive", expected_status, row_budget=row_budget)

    # ---- multipass O1b-B ----
    def run(
        self,
        faults: Optional[List] = None,
        *,
        formal_class: str = FORMAL_CLASS_ORDINARY,
    ) -> Dict[str, Any]:
        if formal_class not in FORMAL_VECTOR_CLASSES:
            raise ValueError(
                f"unknown formal_class {formal_class!r}; "
                f"closed set {sorted(FORMAL_VECTOR_CLASSES)}"
            )
        self.formal_class = formal_class
        self.b5 = formal_class == FORMAL_CLASS_B5_BASELINE
        # B5 N<1 and other ill-formed inputs: zero-Port FAILED via precheck (no raise).
        # None = API omission → empty schedule; explicit non-list never coerced to [].
        if faults is None:
            self.faults = []
        else:
            self.faults = self._validate_formal_faults(faults)
        self.fault_used = 0
        self._call_events_start = 0
        self.api_call_index = 0
        self._product_gets = False
        self.peer = 0
        self._get_response_overrides: Dict[bytes, bytes] = {}
        self.b5_done = False  # first midwalk consumed
        self.iter_pos = 0
        self.focus_id16 = bytes(16)
        self._product_sha = None  # at most one FixedSha256Product (sha_state bank)
        self.last_completed_count_mask = 0
        self.any_carrier_completed = 0
        self.active_pins: Optional[Dict[str, Any]] = None
        self.active_man: Optional[Dict[str, Any]] = None  # single fixed man pin bank
        self.bind_cb = 0  # frozen at BIND entry
        # Phase-local BIND pins (§18.14.9.2–.4); not checkpoint fields except last_carrier/observed.
        self.peer_key = b""
        self.focus_key_digest = bytes(32)
        self.focus_raw80 = bytes(80)
        self.focus_raw_len = 0
        self.view_a_key_digest = bytes(32)
        self.view_b_key_digest = bytes(32)
        self.expected_semantic_digest = bytes(32)
        self._receipt_evidence_bytes = bytes(128)
        self._receipt_evidence_len = 0
        self._pinned_receipt_stage = 0
        self.owner_kind = 0
        self.blob_kind = 0
        self.owner_primary_key_digest = bytes(32)
        self.expected_owner_pvd = bytes(32)
        self.blob_id_digest = bytes(32)
        self.next_chunk_index = 0
        self.chunk_count_pin = 0
        self.total_length_pin = 0
        self.content_digest_pin = bytes(32)
        self.expected_manifest_value_digest = bytes(32)
        self._precheck_failed = False
        self._precheck_reason = ""

        # §18.14.19.1 formal pre-generation gate — exact original formal rows, before any Port.
        pre = rep1_precheck_formal_inputs(
            self.mode,
            self._formal_rows,
            formal_class=formal_class,
            faults=self.faults,
        )
        if pre is not None:
            return self._zero_port_failed(pre)
        # Complete multipass schedule representability (count-only dry-run; Port 0 retained).
        if not getattr(self, "_schedule_count_only", False):
            plan_err = rep1_schedule_plan_check(
                self.mode,
                self._formal_rows,
                formal_class=formal_class,
                faults=self.faults if self.faults else None,
            )
            if plan_err is not None:
                return self._zero_port_failed(plan_err)
        self.rows = list(self._formal_rows)
        self._rows_materialized = False
        self._materialize_rows()
        if not self._do_begin():
            return self._finalize_pack()

        # B1 BASELINE W (or B5 midwalk)
        if not self._drive_baseline():
            return self._finalize_pack()

        while not self._terminal and self.phase not in (PHASE_COMPLETE, PHASE_FAILED):
            if self.phase == PHASE_SELECT_CARRIER and self.semantic_pass == 0:
                if not self._drive_select_w():
                    return self._finalize_pack()
            elif self.phase == PHASE_SELECT_CARRIER and self.semantic_pass == SEM_SELECT_SETUP:
                if not self._drive_select_setup_g():
                    return self._finalize_pack()
            elif self.phase == PHASE_FOCUS_MANIFEST_SCAN and self.semantic_pass == 0:
                if not self._drive_focus_scan_w(which="A"):
                    return self._finalize_pack()
            elif self.phase == PHASE_FOCUS_MANIFEST_SCAN and self.semantic_pass == 1:
                if not self._drive_mode28_rescan_w(which="A"):
                    return self._finalize_pack()
            elif self.phase == PHASE_FOCUS_MANIFEST_SCAN_B and self.semantic_pass == 0:
                if not self._drive_focus_scan_w(which="B"):
                    return self._finalize_pack()
            elif self.phase == PHASE_FOCUS_MANIFEST_SCAN_B and self.semantic_pass == 3:
                if not self._drive_mode28_rescan_w(which="B"):
                    return self._finalize_pack()
            elif self.phase == PHASE_OWNER_PVD_PROOF:
                if not self._drive_owner_g(which="A"):
                    return self._finalize_pack()
            elif self.phase == PHASE_OWNER_PVD_PROOF_B:
                if not self._drive_owner_g(which="B"):
                    return self._finalize_pack()
            elif self.phase == PHASE_FOCUS_CHUNKS:
                if not self._drive_chunks_g(which="A"):
                    return self._finalize_pack()
            elif self.phase == PHASE_FOCUS_CHUNKS_B:
                if not self._drive_chunks_g(which="B"):
                    return self._finalize_pack()
            elif self.phase == PHASE_SEMANTIC_PREFIX_REGET and self.semantic_pass == 0:
                if self.mode == 28:
                    if not self._drive_mode28_prefix_g():
                        return self._finalize_pack()
                elif self.mode == 30:
                    if not self._drive_mode30_prefix_g():
                        return self._finalize_pack()
                else:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                    self._drive_end(self.final_status)
                    return self._finalize_pack()
            elif self.phase == PHASE_SEMANTIC_CHUNK_REWALK and self.semantic_pass == 0:
                if self.mode == 30:
                    if not self._drive_mode30_sem_chunk_g():
                        return self._finalize_pack()
                else:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                    self._drive_end(self.final_status)
                    return self._finalize_pack()
            elif self.phase == PHASE_SEMANTIC_CHUNK_REWALK and self.semantic_pass == 2:
                if not self._drive_mode28_view_chunks_g(which="A"):
                    return self._finalize_pack()
            elif self.phase == PHASE_SEMANTIC_CHUNK_REWALK and self.semantic_pass == 4:
                if not self._drive_mode28_view_chunks_g(which="B"):
                    return self._finalize_pack()
            elif self.phase == PHASE_BIND_MANIFEST and self.semantic_pass == 0:
                if not self._drive_bind_man_w():
                    return self._finalize_pack()
            elif self.phase == PHASE_BIND_MANIFEST and self.semantic_pass == 5:
                if not self._drive_bind_rr_w():
                    return self._finalize_pack()
            elif self.phase == PHASE_BIND_CHUNK:
                if not self._drive_bind_chunk_w():
                    return self._finalize_pack()
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_PORT)
                self._drive_end(self.final_status)
                return self._finalize_pack()

        return self._finalize_pack()

    def _do_begin(self) -> bool:
        """B0: begin + 17 GET + iter_open→I1; exit OPEN/1/0/0/0/0x00/0/0."""
        self.handle = 1
        self.storage_handle_id = "H1"
        self._ev(
            "begin", "OK",
            input_handle_id="H1",
            output_handle_id="T1",
            mode="READ_ONLY",
        )
        self.txn_live = 1
        self.txn_handle_id = "T1"
        self.session_state = SS_OPEN
        self.phase = PHASE_BASELINE
        self.pass_kind = PASS_BASELINE
        for pk in self._profile_keys():
            pv = self.idx.get(pk)
            st = self._get(pk, pv, peer=False)
            if st != "OK":
                self._sticky_fail(OUT_STORAGE if st != "NOT_FOUND" else OUT_CORRUPT, STAGE_PORT)
                self._end_call("begin_profiled_d3s3", self.final_status)
                return False
        self._product_gets = True
        self.peer = 0
        self.family14_row_count = 17
        self.family14_iter_seen_mask = 0x1FFFF
        self.profile_get_present_mask = 0x1FFFF
        # I1 — not a reopen
        st = self._iter_open_next(count_reopen=False)
        if st != "OK":
            self._port_fail(st)
            self._end_call("begin_profiled_d3s3", self.final_status)
            return False
        # B0 tuple: flags 0x00 (BASELINE_DONE set at B1)
        self._set_tuple(SS_OPEN, PHASE_BASELINE, PASS_BASELINE, 0, 0, 0x00, 0, 0)
        self.profile_exact_active = 0
        self._end_call("begin_profiled_d3s3", "OK")
        return True

    def _drive_baseline(self) -> bool:
        """B1 true exhaustion or B5 midwalk (b5_baseline class only; N>=1)."""
        if self.b5 and not self.b5_done:
            if self.phase != PHASE_BASELINE:
                raise ValueError("B5 midwalk forbidden outside BASELINE")
            budget = self.n_rows  # N>=1 enforced at run entry
        else:
            budget = self.n_rows + 1
        # BASELINE uses I1; no reopen
        st = self._advance_w(budget)
        if st not in ("OK", "MIDWALK"):
            self._port_fail(st)
            self._drive_end(self.final_status, row_budget=budget)
            return False
        if st == "MIDWALK":
            if not self.b5 or self.b5_done or self.phase != PHASE_BASELINE:
                self._sticky_fail(OUT_CORRUPT, STAGE_PORT)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
                return False
            # B5 first stop only
            self.b5_done = True
            self._set_tuple(SS_OPEN, PHASE_BASELINE, PASS_BASELINE, 0, 0, 0x00, 0, 0)
            self._drive_end("OK", row_budget=budget)
            # resume B1 with N+1
            return self._drive_baseline()
        # true exhaustion → B1
        self._set_tuple(
            SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 0, 0, 0x11, 0, 0
        )
        self.profile_exact_active = 1
        self.profile_mismatch = 0
        self.future_profile_candidate = 0
        self._drive_end("OK", row_budget=budget)
        return True

    def _carrier_eligible_select(self, k: bytes, v: bytes) -> bool:
        """Mode-eligible SELECT carrier by key subtype only (current walk row)."""
        st = o1a_subtype(k)
        return st == {27: 0x20, 28: 0x27, 29: 0x40, 30: 0x42}.get(self.mode, -1)

    def _select_pin_from_carrier(self, k: bytes, v: bytes) -> Tuple[Dict[str, Any], int]:
        """Fixed 754-mapped SELECT pins + needs_setup flag (not a spanning pin).

        Scalars is_event_fact/creation_kind live only in owner_kind temp until SETUP.
        send_state maps to next_chunk_index (non-checkpointed u32).
        """
        pins: Dict[str, Any] = {"carrier_key": k}
        needs_setup = 0
        if self.mode == 27:
            pins["focus_dig"] = o1a_dec_anchor_payload_dig(v)
            pins["tx16"] = o1a_body(v)[:16]
            # SELECT→SETUP: pin complete ANCHOR value dig for Mode27 cross-row
            # (expected_owner_pvd slot; no carrier_value / offline idx)
            pins["carrier_value_digest"] = d3s1.value_digest(v)
            # temp: owner_kind holds is_event_fact 0/1 until SELECT_SETUP consumes it
            self.owner_kind = 1 if o1a_anchor_is_event_fact(v) else 0
            needs_setup = 1
        elif self.mode == 28:
            tail = o1a_dec_ingress_tail(v)
            pins["view_a"] = tail["view_a"]
            pins["view_b"] = tail["view_b"]
            pins["semantic_stored"] = tail["semantic_stored"]
            body = o1a_body(v)
            msg_kind = struct.unpack(">I", body[20:24])[0] if len(body) >= 24 else -1
            if not o1a_mode28_view_pair_legal(msg_kind, tail["view_a"], tail["view_b"]):
                raise ValueError("mode28 illegal view pair for message_kind")
            needs_setup = 0
        elif self.mode == 29:
            dlv = o1a_dec_dlv(v)
            pins["focus_dig"] = dlv["payload_blob_key_digest"]
            pins["owner_raw"] = dlv["owner_raw"]
            # temp: owner_kind holds creation_kind (1 APP_FIRST / 2 CANCEL_FIRST)
            self.owner_kind = int(dlv["creation_kind"]) & 0xFF
            needs_setup = 1 if int(dlv["creation_kind"]) == 1 else 0
        elif self.mode == 30:
            rr = o1a_dec_rr(v)
            pins["focus_dig"] = rr["body_blob_key_digest"]
            pins["focus_raw80"] = rr["delivery_raw"]
            pins["transaction_id"] = rr["transaction_id"]
            pins["reply_kind"] = rr["reply_kind"]
            pins["semantic_digest"] = rr["semantic_digest"]
            pins["send_state"] = int(rr["send_state"])
            needs_setup = 0
        return product_pins_keep(pins), needs_setup

    def _select_lifecycle_no_setup(self, pins: Dict[str, Any]) -> Tuple[int, Optional[str]]:
        """Lifecycle from typed carrier pins + context temp scalars (no unmapped pins)."""
        if self.mode == 28:
            return LC_LIVE_REQUIRED, None
        if self.mode == 29:
            ck = int(self.owner_kind)  # creation_kind temp in owner_kind
            dig = pins.get("focus_dig") or O1A_ZERO32
            if ck == 2:
                if dig != O1A_ZERO32:
                    return LC_ILLEGAL, STAGE_SELECT_SETUP
                return LC_NONE, None
            if ck != 1:
                return LC_ILLEGAL, STAGE_SELECT_SETUP
            return LC_ILLEGAL, STAGE_SELECT_SETUP  # APP_FIRST must use setup G
        if self.mode == 30:
            rr_state = int(pins.get("send_state", self.next_chunk_index))
            dig = pins.get("focus_dig") or O1A_ZERO32
            if rr_state == 5:
                if dig == O1A_ZERO32:
                    return LC_ILLEGAL, STAGE_SELECT_SETUP
                return LC_HISTORICAL_ABSENT, None
            if rr_state not in (1, 2, 3, 4):
                return LC_ILLEGAL, STAGE_SELECT_SETUP
            if dig == O1A_ZERO32:
                return LC_ILLEGAL, STAGE_SELECT_SETUP
            return LC_LIVE_REQUIRED, None
        return LC_ILLEGAL, STAGE_SELECT_SETUP

    def _product_get_typed(
        self,
        request_key: bytes,
        *,
        expect_subtype: int,
        expect_flags: int,
        stage_absent: str = STAGE_SELECT_SETUP,
        provider_val: Optional[bytes] = None,
    ) -> Tuple[str, Optional[bytes]]:
        """Storage GET + returned-value typed CURRENT gate.

        provider_val overrides idx only as Storage response simulation (tests).
        Default: idx.get(request_key). Adjudication uses returned bytes only.
        """
        if provider_val is None:
            overrides = getattr(self, "_get_response_overrides", None) or {}
            provider_val = overrides.get(request_key)
            if provider_val is None:
                provider_val = self.idx.get(request_key)
        st = self._get(request_key, provider_val, peer=True)
        if st != "OK":
            return st, None
        val = provider_val
        err = o1a_value_typed_current(
            val, expect_subtype=expect_subtype, expect_flags=expect_flags
        )
        if err is not None:
            return "TYPED_FAIL", val
        return "OK", val

    def _select_key_after_frontier(self, k: bytes) -> bool:
        """Next carrier iff complete key strictly greater than last_carrier_key.

        Empty last_carrier_key (len 0) is −∞. No full-ID set / carrier_queue.
        """
        if not self.last_carrier_key:
            return True
        return k > self.last_carrier_key

    def _drive_select_w(self) -> bool:
        """SELECT pure W (§18.14.19.3 design B): GET 0; Port row + last_carrier frontier."""
        fr = self._reopen_if_needed()
        if self._fail_w_wg_entry(fr, row_budget=self.n_rows + 1):
            return False
        installed = None
        install_kind = None

        def on_row(k: bytes, v: bytes) -> None:
            nonlocal installed, install_kind
            if installed is not None:
                return
            # Port-only: current typed row + fixed last_carrier_key frontier.
            if not self._carrier_eligible_select(k, v):
                return
            if not self._select_key_after_frontier(k):
                return
            try:
                pins, needs_setup = self._select_pin_from_carrier(k, v)
            except Exception:
                installed = ("FAIL", STAGE_SELECT_SETUP, {"carrier_key": k})
                install_kind = "fail"
                return
            self.last_carrier_key = k  # sole frontier advance (754 last_carrier_key)
            pins_keep = product_pins_keep(pins)
            pins_keep["carrier_key"] = k
            self.active_pins = pins_keep
            self._sync_pin_to_context_754(pins_keep)
            if int(needs_setup) == 1:
                installed = pins_keep
                install_kind = "need_setup"
                return
            lc, fail = self._select_lifecycle_no_setup(pins_keep)
            self.lifecycle_class = lc
            if fail is not None or lc == LC_ILLEGAL:
                installed = ("FAIL", fail or STAGE_SELECT_SETUP, pins)
                install_kind = "fail"
                return
            if lc == LC_NONE:
                installed = pins
                install_kind = "none"
                return
            if lc == LC_HISTORICAL_ABSENT:
                installed = pins
                install_kind = "hist"
                return
            if self.mode == 28:
                self._reset_mode28_carrier_workspace()
                za, zb = self._mode28_za_zb(pins)
                if za == 1 and zb == 1:
                    installed = pins
                    install_kind = "m28_both0"
                elif za == 0:
                    installed = pins
                    install_kind = "m28_a"
                else:
                    installed = pins
                    install_kind = "m28_b0"
            else:
                installed = pins
                install_kind = "live"

        budget = self.n_rows + 1
        st = self._advance_w(budget, on_row=on_row)
        if st not in ("OK", "MIDWALK"):
            self._port_fail(st)
            self._drive_end(self.final_status, row_budget=budget)
            return False
        if st != "OK":
            self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
            self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False

        if install_kind == "fail":
            _, stage, _ = installed
            self._sticky_fail(OUT_CORRUPT, stage)
            self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False

        if installed is None:
            cvac = 0 if not self.any_carrier_completed else self.last_completed_count_mask
            self.bind_cb = cvac
            self._set_tuple(
                SS_EXHAUSTED, PHASE_BIND_MANIFEST, PASS_INTERNAL, 0, 0, 0x15, cvac, 0
            )
            if self.mode == 30:
                self._mode30_bind_entry_init()
            self._drive_end("OK", row_budget=budget)
            return True

        if install_kind == "need_setup":
            # Stay phase=2; sem=6 SELECT_SETUP G next. No NEED_REOPEN for G entry.
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 0, SEM_SELECT_SETUP, 0x01, 0, 0
            )
            self._drive_end("OK", row_budget=budget)
            return True

        if install_kind == "none":
            cm = 0x07 if self.mode == 30 else 0x03
            self.last_completed_count_mask = cm
            self.any_carrier_completed = 1
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 0, 0, 0x11, cm, 0
            )
            self._drive_end("OK", row_budget=budget)
            return True

        if install_kind == "m28_both0":
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SEMANTIC_PREFIX_REGET, PASS_INTERNAL, 1, 0, 0x03, 0x03, 0
            )
            self._drive_end("OK", row_budget=budget)
            return True

        if install_kind == "m28_b0":
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN_B, PASS_INTERNAL, 1, 0, 0x13, 0, 0
            )
            self._drive_end("OK", row_budget=budget)
            return True

        if install_kind in ("live", "hist", "m28_a"):
            fs = 0
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN, PASS_INTERNAL, fs, 0, 0x13, 0, 0
            )
            self._drive_end("OK", row_budget=budget)
            return True

        self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
        self._drive_end(OUT_CORRUPT, row_budget=budget)
        return False

    def _drive_select_setup_g(self) -> bool:
        """SELECT_SETUP pure G (phase2/sem6): Mode27 STATE[+SPOOL]; Mode29 APP RESULT_CACHE."""
        if not self._preflight_g_entry():
            self._drive_end(self.final_status, row_budget=0)
            return False
        pins = self.active_pins or {}
        if self.mode == 27:
            tx = pins.get("tx16") or self.focus_id16
            if not isinstance(tx, (bytes, bytearray)) or len(tx) != 16:
                self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(OUT_CORRUPT, row_budget=0)
                return False
            st_k = o1a_state_key(bytes(tx))
            st, st_v = self._product_get_typed(st_k, expect_subtype=0x22, expect_flags=0, stage_absent=STAGE_SELECT_SETUP)
            if st != "OK":
                if st in STORAGE_NATURAL:
                    self._port_fail(st, STAGE_PORT)
                elif st == "NOT_FOUND":
                    self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                else:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(self.final_status, row_budget=0)
                return False
            # copy-before-next-get: decode lifecycle fields drive-local (not spanning pins)
            try:
                stf = o1a_dec_state_fields(st_v)
            except Exception:
                self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(OUT_CORRUPT, row_budget=0)
                return False
            # is_event_fact was stored in owner_kind at SELECT (0/1)
            is_event_fact = int(self.owner_kind) & 0xFF
            dig = pins.get("focus_dig") or O1A_ZERO32
            spool_state = None
            sp_v = None
            if is_event_fact == 1:
                sp_k = o1a_spool_key(bytes(tx))
                st2, sp_v = self._product_get_typed(
                    sp_k, expect_subtype=0x50, expect_flags=0, stage_absent=STAGE_SELECT_SETUP
                )
                if st2 != "OK":
                    if st2 in STORAGE_NATURAL:
                        self._port_fail(st2, STAGE_PORT)
                    elif st2 == "NOT_FOUND":
                        self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                    else:
                        self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                    self._drive_end(self.final_status, row_budget=0)
                    return False
                try:
                    spool_state = o1a_dec_spool_state(sp_v)
                except Exception:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                    self._drive_end(OUT_CORRUPT, row_budget=0)
                    return False
            # R27-Sol: exact cross-row before lifecycle classification.
            # want_avd from SELECT pin carrier_value_digest (754 expected_owner_pvd slot).
            want_avd = pins.get("carrier_value_digest")
            if not isinstance(want_avd, (bytes, bytearray)) or len(want_avd) != 32:
                # context bank after SELECT sync (view_a slot for Mode27)
                want_avd = getattr(self, "view_a_key_digest", None)
            if not isinstance(want_avd, (bytes, bytearray)) or len(want_avd) != 32:
                self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(OUT_CORRUPT, row_budget=0)
                return False
            want_tx = pins.get("tx16") or self.focus_id16
            if not isinstance(want_tx, (bytes, bytearray)) or len(want_tx) != 16:
                self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(OUT_CORRUPT, row_budget=0)
                return False
            xerr = o1a_mode27_cross_row_ok(
                st_v, sp_v,
                is_ef=(is_event_fact == 1),
                want_avd=bytes(want_avd),
                want_tx=bytes(want_tx),
            )
            if xerr is not None:
                self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(OUT_CORRUPT, row_budget=0)
                return False
            # R26/R27 lifecycle exact matrix after cross-row
            if is_event_fact == 1:
                terminal_tx = stf["state"] == _D1_TXN_TERMINAL
                is_receipt = (
                    terminal_tx
                    and stf["outcome"] == _D1_OUT_SATISFIED
                    and stf["reason"] == _D1_R_REQUIRED_EVIDENCE_MET
                    and stf["discarded"] == 0
                )
                is_audited_discard = (
                    terminal_tx
                    and stf["outcome"] == _D1_OUT_FAILED
                    and stf["reason"] == _D1_R_OPERATOR_DISCARDED
                    and stf["discarded"] == 1
                )
                hist_ok = (
                    (is_receipt and spool_state == _D1_ES_RELEASED)
                    or (is_audited_discard and spool_state == _D1_ES_DISCARDED)
                )
                if not terminal_tx:
                    if stf["state"] == _D1_TXN_PARKED:
                        live_ok = spool_state == _D1_ES_PARKED and stf["discarded"] == 0
                    else:
                        live_ok = spool_state == _D1_ES_ACTIVE and stf["discarded"] == 0
                else:
                    live_ok = False
                if hist_ok:
                    if dig == O1A_ZERO32:
                        self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                        self._drive_end(OUT_CORRUPT, row_budget=0)
                        return False
                    self.lifecycle_class = LC_HISTORICAL_ABSENT
                    self._set_tuple(
                        SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN, PASS_INTERNAL, 0, 0, 0x13, 0, 0
                    )
                    self._drive_end("OK", row_budget=0)
                    return True
                if not live_ok:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                    self._drive_end(OUT_CORRUPT, row_budget=0)
                    return False
            else:
                if stf["discarded"] != 0:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                    self._drive_end(OUT_CORRUPT, row_budget=0)
                    return False
                if stf["state"] == _D1_TXN_TERMINAL:
                    if dig == O1A_ZERO32:
                        self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                        self._drive_end(OUT_CORRUPT, row_budget=0)
                        return False
                    self.lifecycle_class = LC_HISTORICAL_ABSENT
                    self._set_tuple(
                        SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN, PASS_INTERNAL, 0, 0, 0x13, 0, 0
                    )
                    self._drive_end("OK", row_budget=0)
                    return True
            if dig == O1A_ZERO32:
                self.lifecycle_class = LC_NONE
                cm = 0x03
                self.last_completed_count_mask = cm
                self.any_carrier_completed = 1
                self._set_tuple(
                    SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 0, 0, 0x11, cm, 0
                )
                self._drive_end("OK", row_budget=0)
                return True
            self.lifecycle_class = LC_LIVE_REQUIRED
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN, PASS_INTERNAL, 0, 0, 0x13, 0, 0
            )
            self._drive_end("OK", row_budget=0)
            return True

        if self.mode == 29:
            raw = pins.get("owner_raw") or b""
            if len(raw) != 80:
                self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(OUT_CORRUPT, row_budget=0)
                return False
            rc_k = o1a_rc_key(raw)
            st, rc_v = self._product_get_typed(rc_k, expect_subtype=0x41, expect_flags=0, stage_absent=STAGE_SELECT_SETUP)
            if st != "OK":
                if st in STORAGE_NATURAL:
                    self._port_fail(st, STAGE_PORT)
                elif st == "NOT_FOUND":
                    self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                else:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(self.final_status, row_budget=0)
                return False
            try:
                rc = o1a_dec_rc(rc_v)
            except Exception:
                self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(OUT_CORRUPT, row_budget=0)
                return False
            # delivery_state is drive-local; only lifecycle_class spans after setup
            dig = pins.get("focus_dig") or O1A_ZERO32
            if rc["delivery_state"] >= 4:
                if dig == O1A_ZERO32:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                    self._drive_end(OUT_CORRUPT, row_budget=0)
                    return False
                self.lifecycle_class = LC_HISTORICAL_ABSENT
                self._set_tuple(
                    SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN, PASS_INTERNAL, 0, 0, 0x13, 0, 0
                )
                self._drive_end("OK", row_budget=0)
                return True
            if dig == O1A_ZERO32:
                self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
                self._drive_end(OUT_CORRUPT, row_budget=0)
                return False
            self.lifecycle_class = LC_LIVE_REQUIRED
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN, PASS_INTERNAL, 0, 0, 0x13, 0, 0
            )
            self._drive_end("OK", row_budget=0)
            return True

        self._sticky_fail(OUT_CORRUPT, STAGE_SELECT_SETUP)
        self._drive_end(OUT_CORRUPT, row_budget=0)
        return False

    def _carrier_man_owner_identity_ok(self, man: Dict[str, Any], pins: Dict[str, Any]) -> bool:
        """True iff man.owner_raw equals SELECT carrier identity (before install).

        Mode27: ANCHOR.tx16; Mode29: DELIVERY raw80; Mode30: RR delivery raw80;
        Mode28: INGRESS ordered_sequence BE8 (optional legal check via focus_raw80 empty).
        """
        raw = man.get("owner_raw")
        if not isinstance(raw, (bytes, bytearray)):
            return False
        if self.mode == 27:
            want = pins.get("tx16") or self.focus_id16
            return isinstance(want, (bytes, bytearray)) and bytes(raw) == bytes(want)
        if self.mode == 29:
            want = pins.get("owner_raw")
            return isinstance(want, (bytes, bytearray)) and bytes(raw) == bytes(want)
        if self.mode == 30:
            want = pins.get("focus_raw80")
            return isinstance(want, (bytes, bytearray)) and bytes(raw) == bytes(want)
        if self.mode == 28:
            # legal INGRESS owner is ordered_sequence BE8; pin identity is view digests
            return len(raw) == 8
        return True

    def _focus_apply_live_match(self, *, which: str, man: Dict[str, Any], pins: Dict[str, Any]) -> None:
        """Install match into single man bank and sync all fields to 754 slots."""
        fixed = o1a_man_product_pins(man)
        self.active_man = fixed
        self._sync_man_to_context_754(fixed)
        if self.active_pins is not None and self.mode != 28:
            # focus_dig and man.key_digest share focus_key_digest (equal after match)
            self.active_pins["focus_dig"] = fixed["key_digest"]
            self._sync_pin_to_context_754(self.active_pins)
        if self.mode == 28:
            if which == "A":
                _a, b_half = self._mode28_read_pins()
                self._pin_mode28_totals(int(fixed["total_length"]), b_half)
            else:
                a_half, _b = self._mode28_read_pins()
                self._pin_mode28_totals(a_half, int(fixed["total_length"]))
        elif self.mode == 30:
            # transaction_id pin remains sole focus_id16 authority (not man.owner_raw)
            tid = pins.get("transaction_id") or self.focus_id16
            if isinstance(tid, (bytes, bytearray)) and len(tid) == 16:
                self.focus_id16 = bytes(tid)
        # Transient MATCH_INSTALLED; NEED_REOPEN already cleared by reopen.
        self.flags = (self.flags | FLAG_MATCH_INSTALLED) & 0xFF

    def _drive_focus_scan_w(self, *, which: str) -> bool:
        """FOCUS_SCAN / FOCUS_SCAN_B W with streaming dig-match (P1-2).

        After each successful iter_next, update match_count / man pins / Mode28
        totals / transient MATCH_* flags immediately so a later Port fault
        captures the exact state immediately before the failing event
        (§18.14.19.8 failure-point capture).
        """
        fr = self._reopen_if_needed()
        if self._fail_w_wg_entry(fr, row_budget=self.n_rows + 1):
            return False
        budget = self.n_rows + 1
        pins = self.active_pins or {}
        is_hist = self.lifecycle_class == LC_HISTORICAL_ABSENT
        if which == "A":
            if self.mode == 28:
                dig = pins.get("view_a") or O1A_ZERO32
            else:
                dig = pins.get("focus_dig") or O1A_ZERO32
        else:
            dig = pins.get("view_b") or O1A_ZERO32

        match_count = 0  # walk-local only (not call-spanning)
        installed_man: Optional[Dict[str, Any]] = None

        def on_row(k: bytes, v: bytes) -> None:
            nonlocal match_count, installed_man
            if dig == O1A_ZERO32:
                return
            if o1a_subtype(k) != 0x30 or o1a_flags(v) != 1:
                return
            if d3s1.key_digest(k) != dig:
                return
            if match_count == 0:
                try:
                    man = o1a_dec_man(k, v)
                except Exception:
                    # Un-decodable man key dig-match: count as observation without pin.
                    match_count = 1
                    self.flags = (self.flags | FLAG_MATCH_INSTALLED) & 0xFF
                    return
                match_count = 1
                # R12 P1-1: owner_raw≠carrier → sticky CORRUPT at this exact row,
                # abort walk via _walk_abort (not Port fault). No man install; no
                # residual iter_next / NOT_FOUND after the mismatch row.
                if not self._carrier_man_owner_identity_ok(man, pins):
                    installed_man = None
                    self._sticky_fail(OUT_CORRUPT, STAGE_FOCUS_SCAN)
                    self._walk_abort = "SEMANTIC"
                    return
                installed_man = man
                self._focus_apply_live_match(which=which, man=man, pins=pins)
            else:
                match_count = 2
                # Preserve MATCH_INSTALLED and set transient MATCH_DUPLICATE.
                self.flags = (
                    self.flags | FLAG_MATCH_INSTALLED | FLAG_MATCH_DUPLICATE
                ) & 0xFF

        st = self._advance_w(budget, on_row=on_row)
        # Semantic walk abort (owner_raw mismatch etc.): first sticky already set;
        # do not reclassify as Port fault (would overwrite CORRUPT with STORAGE).
        if self.has_sticky or self._failed:
            self._drive_end(self.final_status, row_budget=budget)
            return False
        if st != "OK":
            if st == "MIDWALK":
                self._sticky_fail(OUT_CORRUPT, STAGE_FOCUS_SCAN)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
                return False
            # NATURAL fault: flags/pins already updated by on_row for prior OK rows.
            self._port_fail(st)
            self._drive_end(self.final_status, row_budget=budget)
            return False

        # True exhaustion — normalize to OK exits (clear transient MATCH_DUPLICATE).
        if is_hist:
            if match_count != 0:
                self._sticky_fail(OUT_CORRUPT, STAGE_FOCUS_SCAN)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
                return False
            cm = 0x07 if self.mode == 30 else 0x03
            self.last_completed_count_mask = cm
            self.any_carrier_completed = 1
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 0, 0, 0x11, cm, 0
            )
            self._drive_end("OK", row_budget=budget)
            return True

        # LIVE: exact one match required
        if match_count == 0 or match_count >= 2 or installed_man is None:
            self._sticky_fail(OUT_CORRUPT, STAGE_FOCUS_SCAN)
            self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        man = installed_man
        if self.mode == 28:
            want_kind = 3 if which == "A" else 4
            if not o1a_mode_kind_ok(28, man) or man["blob_kind"] != want_kind:
                self._sticky_fail(OUT_CORRUPT, STAGE_FOCUS_SCAN)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
                return False
            if which == "A":
                # Pins already applied on first match; OK exit normal form 0x43.
                self._set_tuple(
                    SS_EXHAUSTED, PHASE_OWNER_PVD_PROOF, PASS_INTERNAL, 0, 0, 0x43, 0, 0
                )
            else:
                self._set_tuple(
                    SS_EXHAUSTED, PHASE_OWNER_PVD_PROOF_B, PASS_INTERNAL, 1, 0, 0x43, 0, 0
                )
        elif self.mode == 30:
            if o1a_mode30_h14(man, pins) is not None or o1a_mode30_h15(
                pins["reply_kind"], man
            ) is not None:
                self._sticky_fail(OUT_CORRUPT, STAGE_FOCUS_SCAN)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
                return False
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_CHUNKS, PASS_INTERNAL, 0, 0, 0x43, 0, 0
            )
        else:
            if not o1a_mode_kind_ok(self.mode, man):
                self._sticky_fail(OUT_CORRUPT, STAGE_FOCUS_SCAN)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
                return False
            self._set_tuple(
                SS_EXHAUSTED, PHASE_OWNER_PVD_PROOF, PASS_INTERNAL, 0, 0, 0x43, 0, 0
            )
        self._drive_end("OK", row_budget=budget)
        return True

    def _drive_owner_g(self, *, which: str) -> bool:
        if not self._preflight_g_entry():
            self._drive_end(self.final_status, row_budget=0)
            return False
        pins = self.active_pins or {}
        # R6: single active_man bank (Mode28 A/B overwrite; which only for tuple exit).
        man = self.active_man
        want_st = {27: 0x20, 28: 0x27, 29: 0x40, 30: 0x42}.get(self.mode, 0x20)
        st, owner_v = self._product_get_typed(
            pins["carrier_key"], expect_subtype=want_st, expect_flags=0,
            stage_absent=STAGE_OWNER_PVD,
        )
        if st != "OK":
            if st == "TYPED_FAIL":
                self._sticky_fail(OUT_CORRUPT, STAGE_OWNER_PVD)
            else:
                self._fail_get_status(st, stage_absent=STAGE_OWNER_PVD, stage_port=STAGE_PORT)
            self._drive_end(self.final_status)
            return False
        # Port-returned value only: VALUE_DIGEST == man pin expected_owner_pvd
        if man is None or d3s1.value_digest(owner_v) != man.get("expected_owner_pvd"):
            self._sticky_fail(OUT_CORRUPT, STAGE_OWNER_PVD)
            self._drive_end(OUT_CORRUPT)
            return False
        if which == "B":
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_CHUNKS_B, PASS_INTERNAL, 1, 0, 0x43, 0, 0
            )
        else:
            fs = 0 if self.mode != 28 else 0
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_CHUNKS, PASS_INTERNAL, fs, 0, 0x43, 0, 0
            )
        self._drive_end("OK")
        return True

    def _drive_chunks_g(self, *, which: str) -> bool:
        if not self._preflight_g_entry():
            self._drive_end(self.final_status, row_budget=0)
            return False
        # R6: single active_man bank only.
        man = self.active_man
        if man is None:
            self._sticky_fail(OUT_CORRUPT, STAGE_CHUNKS)
            self._drive_end(OUT_CORRUPT)
            return False
        for i in range(man["chunk_count"]):
            ck = o1a_chk_key_from_blob_index(man["blob_id"], i)
            st, cv = self._product_get_typed(
                ck, expect_subtype=0x30, expect_flags=2, stage_absent=STAGE_CHUNKS,
            )
            if st != "OK":
                if st in STORAGE_NATURAL:
                    self._port_fail(st, STAGE_PORT)
                elif st == "NOT_FOUND":
                    self.count_mask = MASK_COUNT_MAN
                    self._sticky_fail(OUT_CORRUPT, STAGE_CHUNKS)
                elif st == "TYPED_FAIL":
                    self.count_mask = MASK_COUNT_MAN
                    self._sticky_fail(OUT_CORRUPT, STAGE_CHUNKS)
                else:
                    raise ValueError(f"GET status outside closed set: {st!r}")
                self._drive_end(self.final_status)
                return False
            # returned chunk bytes only vs man pins
            try:
                ch = o1a_dec_chunk(ck, cv)
            except ValueError:
                self.count_mask = MASK_COUNT_MAN
                self._sticky_fail(OUT_CORRUPT, STAGE_CHUNKS)
                self._drive_end(OUT_CORRUPT)
                return False
            if (
                ch["blob_id"] != man["blob_id"]
                or ch["chunk_count"] != man["chunk_count"]
                or ch["total_length"] != man["total_length"]
                or ch["content_digest"] != man["content_digest"]
                or ch["manifest_key_digest"] != man["key_digest"]
                or ch["index"] != i
                or ch["primary_value_digest"] != man["expected_manifest_value_digest"]
            ):
                self.count_mask = MASK_COUNT_MAN
                self._sticky_fail(OUT_CORRUPT, STAGE_CHUNKS)
                self._drive_end(OUT_CORRUPT)
                return False

        if self.mode in (27, 29):
            self.last_completed_count_mask = 0x03
            self.any_carrier_completed = 1
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 0, 0, 0x11, 0x03, 0
            )
        elif self.mode == 30:
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SEMANTIC_PREFIX_REGET, PASS_INTERNAL, 0, 0, 0x03, 0x03, 0
            )
        elif self.mode == 28:
            pins = self.active_pins or {}
            za, zb = self._mode28_za_zb(pins)
            if which == "A":
                if zb == 0:
                    self._set_tuple(
                        SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN_B, PASS_INTERNAL, 1, 0, 0x13, 0, 0
                    )
                else:
                    self._set_tuple(
                        SS_EXHAUSTED, PHASE_SEMANTIC_PREFIX_REGET, PASS_INTERNAL, 1, 0, 0x03, 0x03, 0
                    )
            else:
                self._set_tuple(
                    SS_EXHAUSTED, PHASE_SEMANTIC_PREFIX_REGET, PASS_INTERNAL, 1, 0, 0x03, 0x03, 0
                )
        self._drive_end("OK")
        return True

    def _drive_mode28_prefix_g(self) -> bool:
        """Phase9 PREFIX G: SELECT pins are authority; hash msd_prefix then discard.

        Returned carrier semantic/view must exact-match SELECT pins (no overwrite).
        focus_id16 is sole totals authority; gate before any Port event.
        """
        if not self._preflight_g_entry():
            self._drive_end(self.final_status, row_budget=0)
            return False
        pins = self.active_pins or {}
        za, zb = self._mode28_za_zb(pins)
        # Unpack pins first — shadow fields must not affect gate/semantic.
        pin_a, pin_b = self._mode28_read_pins()
        # Gate before any Port event; no mask/saturation/low-32 selection.
        if pin_a > UINT32_MAX or pin_b > UINT32_MAX:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)  # zero Port events
            return False
        # checked convert to local u32 only (no call-spanning copy; focus_id16 is authority)
        pay_u = int(pin_a)
        evi_u = int(pin_b)
        # SELECT authority (never overwrite from returned carrier)
        select_va = pins.get("view_a")
        select_vb = pins.get("view_b")
        select_sem = pins.get("semantic_stored")
        if (
            not isinstance(select_va, (bytes, bytearray))
            or not isinstance(select_vb, (bytes, bytearray))
            or not isinstance(select_sem, (bytes, bytearray))
            or len(select_va) != 32
            or len(select_vb) != 32
            or len(select_sem) != 32
        ):
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False

        st, cv = self._product_get_typed(
            pins["carrier_key"], expect_subtype=0x27, expect_flags=0,
            stage_absent=STAGE_SEMANTIC,
        )
        if st != "OK":
            if st == "TYPED_FAIL":
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            else:
                self._fail_get_status(st, stage_absent=STAGE_SEMANTIC, stage_port=STAGE_PORT)
            self._drive_end(self.final_status)
            return False
        try:
            tail = o1a_dec_ingress_tail(cv)
        except ValueError:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        # Exact-match SELECT authority — do not replace expected pins with returned.
        if (
            tail["view_a"] != select_va
            or tail["view_b"] != select_vb
            or tail["semantic_stored"] != select_sem
        ):
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        # Start single product SHA: LABEL || msd_prefix || pay_len; discard prefix.
        if getattr(self, "_product_sha", None) is not None:
            self._product_sha.abandon()
            self._product_sha = None
        self._product_sha = FixedSha256Product()
        self._product_sha.update(O1A_MSD_LABEL)
        self._product_sha.update(tail["msd_prefix"])  # workspace only; not retained
        self._product_sha.update(struct.pack(">I", pay_u & 0xFFFFFFFF))
        # Preserve SELECT fixed pins only (allowlist); never store body/msd_prefix.
        self.active_pins = product_pins_keep(pins)
        self._sync_pin_to_context_754(self.active_pins)

        if za == 1 and zb == 1:
            # both views empty: pay bytes done; evi_len=0; finalize
            self._product_sha.update(struct.pack(">I", evi_u & 0xFFFFFFFF))
            dig = self._product_sha.digest_finalize()
            self._product_sha = None
            if dig != select_sem:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            self.last_completed_count_mask = 0x07
            self.any_carrier_completed = 1
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 1, 0, 0x11, 0x07, 0
            )
        elif za == 0:
            # need pay stream via view-A chunk GETs
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN, PASS_INTERNAL, 1, 1, 0x13, 0x03, 0
            )
        else:
            # pay empty already; commit evi_len and stream B later
            self._product_sha.update(struct.pack(">I", evi_u & 0xFFFFFFFF))
            self._set_tuple(
                SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN_B, PASS_INTERNAL, 1, 3, 0x13, 0x03, 0
            )
        self._drive_end("OK")
        return True

    def _drive_mode28_rescan_w(self, *, which: str) -> bool:
        """Mode28 semantic RESCAN W: dig exact-one reinstall into single man bank.

        Not a bare empty walk: re-match view digest, install fixed man pins, kind check.
        """
        fr = self._reopen_if_needed()
        if self._fail_w_wg_entry(fr, row_budget=self.n_rows + 1):
            return False
        budget = self.n_rows + 1
        pins = self.active_pins or {}
        if which == "A":
            dig = pins.get("view_a") or O1A_ZERO32
            want_kind = 3
        else:
            dig = pins.get("view_b") or O1A_ZERO32
            want_kind = 4
        match_count = 0
        installed_man: Optional[Dict[str, Any]] = None

        def on_row(k: bytes, v: bytes) -> None:
            nonlocal match_count, installed_man
            if dig == O1A_ZERO32:
                return
            if o1a_subtype(k) != 0x30 or o1a_flags(v) != 1:
                return
            if d3s1.key_digest(k) != dig:
                return
            if match_count == 0:
                try:
                    man = o1a_dec_man(k, v)
                except Exception:
                    match_count = 1
                    return
                match_count = 1
                installed_man = man
                # Immediate single-bank reinstall (overwrite any prior A/B bank).
                self._focus_apply_live_match(which=which, man=man, pins=pins)
            else:
                match_count = 2

        st = self._advance_w(budget, on_row=on_row)
        if st != "OK":
            if st != "MIDWALK":
                self._port_fail(st)
                self._drive_end(self.final_status, row_budget=budget)
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        if dig == O1A_ZERO32 or match_count != 1 or installed_man is None:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        man = installed_man
        if not o1a_mode_kind_ok(28, man) or man["blob_kind"] != want_kind:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        if which == "A":
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SEMANTIC_CHUNK_REWALK, PASS_INTERNAL, 1, 2, 0x03, 0x03, 0
            )
        else:
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SEMANTIC_CHUNK_REWALK, PASS_INTERNAL, 1, 4, 0x03, 0x03, 0
            )
        self._drive_end("OK", row_budget=budget)
        return True

    def _drive_mode28_view_chunks_g(self, *, which: str) -> bool:
        """Mode28 SEM view chunks: verify each returned chunk then sha_update data only.

        No whole-stream retention. Single FixedSha256Product bank from PREFIX.
        Uses current single active_man (reinstalled by RESCAN).
        """
        if not self._preflight_g_entry():
            self._drive_end(self.final_status, row_budget=0)
            return False
        pins = self.active_pins or {}
        man = self.active_man
        sha = getattr(self, "_product_sha", None)
        if sha is None:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        pa, pb = self._mode28_read_pins()
        if pa > UINT32_MAX or pb > UINT32_MAX:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        pay_u, evi_u = int(pa), int(pb)  # local per-drive decode of focus_id16
        streamed = 0  # G-drive local only (maps to length_sum workspace, not spanning attr)
        if man is not None:
            for i in range(man["chunk_count"]):
                ck = o1a_chk_key_from_blob_index(man["blob_id"], i)
                st, cv = self._product_get_typed(
                    ck, expect_subtype=0x30, expect_flags=2, stage_absent=STAGE_SEMANTIC,
                )
                if st != "OK":
                    if st in STORAGE_NATURAL:
                        self._port_fail(st, STAGE_PORT)
                    elif st in ("NOT_FOUND", "TYPED_FAIL"):
                        self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                    else:
                        raise ValueError(f"GET status outside closed set: {st!r}")
                    self._drive_end(self.final_status)
                    return False
                try:
                    ch = o1a_dec_chunk(ck, cv)
                except ValueError:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                    self._drive_end(OUT_CORRUPT)
                    return False
                # Full header identity vs man pins + index + PVD
                if (
                    ch["blob_id"] != man["blob_id"]
                    or ch["index"] != i
                    or ch["chunk_count"] != man["chunk_count"]
                    or ch["total_length"] != man["total_length"]
                    or ch["content_digest"] != man["content_digest"]
                    or ch["manifest_key_digest"] != man["key_digest"]
                    or ch["primary_value_digest"] != man["expected_manifest_value_digest"]
                ):
                    self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                    self._drive_end(OUT_CORRUPT)
                    return False
                # Incremental SHA: update with chunk data then discard (workspace overwrite)
                sha.update(ch["data"])
                streamed += len(ch["data"])
        # length check against pin
        if which == "A":
            if streamed != pay_u:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
        else:
            if streamed != evi_u:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
        za, zb = self._mode28_za_zb(pins)
        if which == "A":
            if zb == 0:
                # more B streaming later — commit evi_len now, keep SHA open
                sha.update(struct.pack(">I", evi_u & 0xFFFFFFFF))
                self._set_tuple(
                    SS_EXHAUSTED, PHASE_FOCUS_MANIFEST_SCAN_B, PASS_INTERNAL, 1, 3, 0x13, 0x03, 0
                )
            else:
                # B empty: evi_len then finalize
                sha.update(struct.pack(">I", evi_u & 0xFFFFFFFF))
                dig = sha.digest_finalize()
                self._product_sha = None
                if dig != pins.get("semantic_stored"):
                    self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                    self._drive_end(OUT_CORRUPT)
                    return False
                self.last_completed_count_mask = 0x07
                self.any_carrier_completed = 1
                self._set_tuple(
                    SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 1, 0, 0x11, 0x07, 0
                )
        else:
            dig = sha.digest_finalize()
            self._product_sha = None
            if dig != pins.get("semantic_stored"):
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            self.last_completed_count_mask = 0x07
            self.any_carrier_completed = 1
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 1, 0, 0x11, 0x07, 0
            )
        self._drive_end("OK")
        return True

    def _drive_mode30_prefix_g(self) -> bool:
        """Mode30 PREFIX G: RR verify→SHA start; DLV/RC/CELL/CS immediate SHA+discard.

        SELECT pins are authority: returned RR must exact-match delivery_raw/tx/
        reply_kind/semantic/body_blob/send_state. expected_semantic_digest is never
        overwritten. Call-spanning residual: SELECT fixed pins + RECEIPT 128 only.
        """
        if not self._preflight_g_entry():
            self._drive_end(self.final_status, row_budget=0)
            return False
        pins = self.active_pins or {}
        raw80 = pins.get("focus_raw80") or b""
        if len(raw80) != 80:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        select_tx = pins.get("transaction_id") or self.focus_id16
        select_rk = int(pins.get("reply_kind") or 0)
        select_sem = pins.get("semantic_digest")
        select_blob = pins.get("focus_dig")
        select_send = pins.get("send_state")
        if (
            not isinstance(select_tx, (bytes, bytearray))
            or len(select_tx) != 16
            or not isinstance(select_sem, (bytes, bytearray))
            or len(select_sem) != 32
            or not isinstance(select_blob, (bytes, bytearray))
            or len(select_blob) != 32
            or select_send is None
        ):
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        man = self.active_man
        if man is None:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        kind_map = {1: 2, 2: 3, 3: 5, 4: 6}
        if select_rk not in kind_map:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False

        # --- RR: verify vs SELECT authority, then start SHA immediately ---
        st, rr_v = self._product_get_typed(
            pins["carrier_key"], expect_subtype=0x42, expect_flags=0,
            stage_absent=STAGE_SEMANTIC,
        )
        if st != "OK":
            if st in STORAGE_NATURAL:
                self._port_fail(st, STAGE_PORT)
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(self.final_status)
            return False
        try:
            rr = o1a_dec_rr(rr_v)
        except ValueError:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        if (
            rr["delivery_raw"] != raw80
            or rr["transaction_id"] != select_tx
            or int(rr["reply_kind"]) != select_rk
            or rr["semantic_digest"] != select_sem
            or rr["body_blob_key_digest"] != select_blob
            or int(rr["send_state"]) != int(select_send)
            or rr["body_blob_key_digest"] != man["key_digest"]
        ):
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        # local workspace only (not call-spanning pins)
        attempt_id = rr["attempt_id"]
        rk = select_rk
        kind = kind_map[rk]
        if getattr(self, "_product_sha", None) is not None:
            self._product_sha.abandon()
            self._product_sha = None
        sha = FixedSha256Product()
        self._product_sha = sha
        sha.update(O1A_MSD_LABEL)
        sha.update(struct.pack(">I", kind & 0xFFFFFFFF))
        sha.update(struct.pack(">I", 0))  # flags
        sha.update(bytes(select_tx))
        sha.update(attempt_id)
        # discard rr / attempt after feed

        # --- DLV: verify, immediate SHA update, discard ---
        st, dlv_v = self._product_get_typed(
            o1a_dlv_key(raw80), expect_subtype=0x40, expect_flags=0,
            stage_absent=STAGE_SEMANTIC,
        )
        if st != "OK":
            if st in STORAGE_NATURAL:
                self._port_fail(st, STAGE_PORT)
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(self.final_status)
            return False
        try:
            d = o1a_dec_dlv(dlv_v)
        except ValueError:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        if d["owner_raw"] != raw80 or d["transaction_id"] != select_tx:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        if d3s1.value_digest(dlv_v) != man["expected_owner_pvd"]:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        sha.update(d["event_id"])
        sha.update(d["party"])
        sha.update(d["target"])
        sha.update(d["service"])  # max SERVICE_IDENTITY; not retained
        sha.update(d["content_digest"])
        sha.update(struct.pack(">Q", d["generation"] & 0xFFFFFFFFFFFFFFFF))
        sha.update(d["deadline_epoch"])
        sha.update(struct.pack(">Q", d["abs_deadline_ms"] & 0xFFFFFFFFFFFFFFFF))
        sha.update(struct.pack(">Q", d["evidence_grace_ms"] & 0xFFFFFFFFFFFFFFFF))
        sha.update(struct.pack(">I", d["required_evidence"] & 0xFFFFFFFF))
        del d  # discard DLV workspace

        # --- RC: verify gates, keep locals for SHA tail only ---
        st, rc_v = self._product_get_typed(
            o1a_rc_key(raw80), expect_subtype=0x41, expect_flags=0,
            stage_absent=STAGE_SEMANTIC,
        )
        if st != "OK":
            if st in STORAGE_NATURAL:
                self._port_fail(st, STAGE_PORT)
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(self.final_status)
            return False
        try:
            rc = o1a_dec_rc(rc_v)
        except ValueError:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        if rk == 1 and rc["app_kind"] != 1:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        if rk == 2 and rc["app_kind"] != 2:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        if rk == 3 and rc["app_kind"] == 2:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        rc_app = rc["app_kind"]
        rc_stage = rc["evidence_stage"]
        rc_disp = rc["disposition"]
        rc_effect = rc["effect_certainty"]
        rc_retry_g = rc["retry_guidance"]
        rc_retry_d = rc["retry_delay_ms"]
        rc_cancel = rc["cancel_result_kind"]
        del rc

        # optional CELL / CS — receipt 128 pin only for rk==1
        receipt_bytes = b""
        receipt_len = 0
        pinned_stage = 0
        cell_epoch = bytes(16)
        cell_at_ms = 0
        cell_trust = 0
        cancel_kind = 0
        if rk == 1:
            st, cell_v = self._product_get_typed(
                o1a_cell_key(raw80, 0), expect_subtype=0x32, expect_flags=0,
                stage_absent=STAGE_SEMANTIC,
            )
            if st != "OK":
                if st in STORAGE_NATURAL:
                    self._port_fail(st, STAGE_PORT)
                else:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(self.final_status)
                return False
            try:
                cm = o1a_dec_cell(cell_v)
            except ValueError:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            if cm["material_receipt_stage"] != rc_stage:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            if cm["evidence_length"] != man["total_length"] or cm["evidence_length"] > 128:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            if cm["evidence_digest"] != man["content_digest"]:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            evi = cm["evidence_bytes"]
            if len(evi) != cm["evidence_length"]:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            receipt_bytes = evi + bytes(128 - len(evi))
            receipt_len = cm["evidence_length"]
            pinned_stage = cm["material_receipt_stage"]
            cell_epoch = cm["evidence_epoch"]
            cell_at_ms = cm["evidence_at_ms"]
            cell_trust = cm["evidence_trust"]
            del cm
        elif rk == 4:
            st, cs_v = self._product_get_typed(
                o1a_cs_key(raw80), expect_subtype=0x33, expect_flags=0,
                stage_absent=STAGE_SEMANTIC,
            )
            if st != "OK":
                if st in STORAGE_NATURAL:
                    self._port_fail(st, STAGE_PORT)
                else:
                    self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(self.final_status)
                return False
            try:
                cancel_kind = o1a_dec_cancel_kind(cs_v)
            except (ValueError, struct.error):
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            if cancel_kind not in (1, 3) or rc_cancel != cancel_kind:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False

        # RC/CELL/CS tail into SHA; discard locals after update
        if rk == 1:
            sha.update(struct.pack(">I", rc_stage & 0xFFFFFFFF))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">Q", 0))
            sha.update(cell_epoch)
            sha.update(struct.pack(">Q", cell_at_ms & 0xFFFFFFFFFFFFFFFF))
            sha.update(struct.pack(">I", cell_trust & 0xFFFFFFFF))
            sha.update(struct.pack(">I", 0))  # payload len 0
            sha.update(struct.pack(">I", int(man["total_length"]) & 0xFFFFFFFF))
        elif rk == 2:
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", rc_disp & 0xFFFFFFFF))
            sha.update(struct.pack(">I", rc_effect & 0xFFFFFFFF))
            sha.update(struct.pack(">I", rc_retry_g & 0xFFFFFFFF))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">Q", rc_retry_d & 0xFFFFFFFFFFFFFFFF))
            sha.update(bytes(16))
            sha.update(struct.pack(">Q", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            dig = sha.digest_finalize()
            self._product_sha = None
            if dig != select_sem:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
        elif rk == 3:
            for _ in range(5):
                sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">Q", 0))
            sha.update(bytes(16))
            sha.update(struct.pack(">Q", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            dig = sha.digest_finalize()
            self._product_sha = None
            if dig != select_sem:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
        else:  # rk==4
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", cancel_kind & 0xFFFFFFFF))
            sha.update(struct.pack(">Q", 0))
            sha.update(bytes(16))
            sha.update(struct.pack(">Q", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            sha.update(struct.pack(">I", 0))
            dig = sha.digest_finalize()
            self._product_sha = None
            if dig != select_sem:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False

        # Call-spanning: SELECT authority + receipt 128 only (never overwrite semantic).
        keep = {
            "carrier_key": pins["carrier_key"],
            "focus_raw80": raw80,
            "transaction_id": bytes(select_tx),
            "reply_kind": select_rk,
            "semantic_digest": select_sem,
            "focus_dig": select_blob,
            "send_state": int(select_send),
        }
        if rk == 1:
            keep["receipt_evidence_bytes"] = receipt_bytes
            keep["receipt_evidence_len"] = receipt_len
            keep["pinned_receipt_stage"] = pinned_stage
        self.active_pins = product_pins_keep(keep)
        self._sync_pin_to_context_754(self.active_pins)
        self._set_tuple(
            SS_EXHAUSTED, PHASE_SEMANTIC_CHUNK_REWALK, PASS_INTERNAL, 0, 0, 0x03, 0x03, 0
        )
        self._drive_end("OK")
        return True

    def _drive_mode30_sem_chunk_g(self) -> bool:
        """Mode30 SEM_CHUNK: verify each returned chunk; incremental SHA + receipt pin compare."""
        if not self._preflight_g_entry():
            self._drive_end(self.final_status, row_budget=0)
            return False
        pins = self.active_pins or {}
        man = self.active_man
        if man is None:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        rk = int(pins.get("reply_kind") or 0)
        # non-receipt: must already be finalized at PREFIX; require empty man stream
        if rk != 1:
            if man["chunk_count"] != 0 or man["total_length"] != 0:
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            # no GETs; already compared digest at PREFIX
            self.last_completed_count_mask = 0x07
            self.any_carrier_completed = 1
            self._set_tuple(
                SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 0, 0, 0x11, 0x07, 0
            )
            self._drive_end("OK")
            return True
        # RECEIPT: stream chunks against fixed receipt pin + open SHA
        sha = getattr(self, "_product_sha", None)
        if sha is None:
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        evi_pin = pins.get("receipt_evidence_bytes") or bytes(128)
        evi_len = int(pins.get("receipt_evidence_len") or 0)
        off = 0
        for i in range(man["chunk_count"]):
            ck = o1a_chk_key_from_blob_index(man["blob_id"], i)
            st, cv = self._product_get_typed(
                ck, expect_subtype=0x30, expect_flags=2, stage_absent=STAGE_SEMANTIC,
            )
            if st != "OK":
                if st in STORAGE_NATURAL:
                    self._port_fail(st, STAGE_PORT)
                else:
                    self.count_mask = MASK_COUNT_MAN | MASK_COUNT_CH | MASK_COUNT_SEM
                    self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(self.final_status)
                return False
            try:
                ch = o1a_dec_chunk(ck, cv)
            except ValueError:
                self.count_mask = MASK_COUNT_MAN | MASK_COUNT_CH | MASK_COUNT_SEM
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            if (
                ch["blob_id"] != man["blob_id"]
                or ch["index"] != i
                or ch["chunk_count"] != man["chunk_count"]
                or ch["total_length"] != man["total_length"]
                or ch["content_digest"] != man["content_digest"]
                or ch["manifest_key_digest"] != man["key_digest"]
                or ch["primary_value_digest"] != man["expected_manifest_value_digest"]
            ):
                self.count_mask = MASK_COUNT_MAN | MASK_COUNT_CH | MASK_COUNT_SEM
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            data = ch["data"]
            # offset byte-compare to receipt pin (≤128)
            if off + len(data) > evi_len or evi_pin[off : off + len(data)] != data:
                self.count_mask = MASK_COUNT_MAN | MASK_COUNT_CH | MASK_COUNT_SEM
                self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
                self._drive_end(OUT_CORRUPT)
                return False
            sha.update(data)
            off += len(data)
        if off != evi_len or off != man["total_length"]:
            self.count_mask = MASK_COUNT_MAN | MASK_COUNT_CH | MASK_COUNT_SEM
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        dig = sha.digest_finalize()
        self._product_sha = None
        if dig != pins.get("semantic_digest"):
            self.count_mask = MASK_COUNT_MAN | MASK_COUNT_CH | MASK_COUNT_SEM
            self._sticky_fail(OUT_CORRUPT, STAGE_SEMANTIC)
            self._drive_end(OUT_CORRUPT)
            return False
        self.last_completed_count_mask = 0x07
        self.any_carrier_completed = 1
        self._set_tuple(
            SS_EXHAUSTED, PHASE_SELECT_CARRIER, PASS_INTERNAL, 0, 0, 0x11, 0x07, 0
        )
        self._drive_end("OK")
        return True

    def _mode30_bind_entry_init(self) -> None:
        """§18.14.9.3 BIND-entry exact clear (Mode30 SELECT→BIND once)."""
        self.last_carrier_key = b""
        self.peer_key = b""
        self.focus_key_digest = bytes(32)
        self.focus_raw80 = bytes(80)
        self.focus_raw_len = 0
        self.owner_kind = 0
        self.blob_kind = 0
        self.observed_live = 0
        self.semantic_pass = 0
        self._release_carrier_product_workspace()

    def _mode30_rr_success_clear(self) -> None:
        """§18.14.9.3 atomic success promotion clear set after frontier copy."""
        self.peer_key = b""
        self.focus_key_digest = bytes(32)
        self.focus_raw80 = bytes(80)
        self.focus_raw_len = 0
        self.owner_kind = 0
        self.blob_kind = 0
        self.observed_live = 0

    def _storage_get(self, request_key: bytes):
        """Storage Port GET: idx/override only as provider; returns (status, value)."""
        overrides = getattr(self, "_get_response_overrides", None) or {}
        provider_val = overrides.get(request_key)
        if provider_val is None:
            provider_val = self.idx.get(request_key)
        st = self._get(request_key, provider_val, peer=True)
        if st == "OK":
            return st, provider_val
        return st, None

    def _bind_wg_abort_get(self, st: str, *, stage_absent: str) -> None:
        """Natural GET fault or ABSENT → sticky; abort residual next via _walk_abort."""
        if st in STORAGE_NATURAL:
            self._port_fail(st, STAGE_PORT)
            self._walk_abort = st
            return
        if st == "NOT_FOUND":
            self._sticky_fail(OUT_CORRUPT, stage_absent)
            self._walk_abort = "SEMANTIC"
            return
        raise ValueError(f"BIND GET status outside closed set: {st!r}")

    def _bind_man_pin_and_prove(self, k: bytes, v: bytes) -> None:
        """§18.14.9.2 Modes27–29 BIND_MAN WG prove for one eligible man."""
        man = o1a_dec_man(k, v)
        self.last_carrier_key = k
        self.focus_key_digest = man["key_digest"]
        self.focus_raw80 = man["owner_raw"] + bytes(max(0, 80 - len(man["owner_raw"])))
        self.focus_raw_len = len(man["owner_raw"])
        self.owner_kind = int(man["owner_kind"])
        self.blob_kind = int(man["blob_kind"])
        self.owner_primary_key_digest = man["owner_primary_key_digest"]
        self.expected_owner_pvd = man["expected_owner_pvd"]
        try:
            peer = o1a_owner_complete_key(self.owner_kind, man["owner_raw"])
        except ValueError:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
            self._walk_abort = "SEMANTIC"
            return
        self.peer_key = peer
        if d3s1.key_digest(peer) != self.owner_primary_key_digest:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
            self._walk_abort = "SEMANTIC"
            return
        st, owner_v = self._storage_get(peer)
        if st != "OK" or owner_v is None:
            self._bind_wg_abort_get(st if st != "OK" else "NOT_FOUND", stage_absent=STAGE_BIND_M)
            return
        want_st = {27: 0x20, 28: 0x27, 29: 0x40}[self.mode]
        terr = o1a_value_typed_current(owner_v, expect_subtype=want_st, expect_flags=0)
        if terr is not None:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
            self._walk_abort = "SEMANTIC"
            return
        try:
            raw = o1a_owner_raw_identity(self.mode, owner_v)
            ref = o1a_owner_referrer_digest(self.mode, self.blob_kind, owner_v)
        except (ValueError, struct.error):
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
            self._walk_abort = "SEMANTIC"
            return
        if raw != man["owner_raw"]:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
            self._walk_abort = "SEMANTIC"
            return
        if ref != self.focus_key_digest:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
            self._walk_abort = "SEMANTIC"
            return
        if d3s1.value_digest(owner_v) != self.expected_owner_pvd:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
            self._walk_abort = "SEMANTIC"
            return

    def _bind_chunk_pin_and_prove(self, k: bytes, v: bytes) -> None:
        """§18.14.9.4 BIND_CHUNK WG prove for one eligible chunk row."""
        try:
            ch = o1a_dec_chunk(k, v)
        except ValueError:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        self.last_carrier_key = k
        self.blob_id_digest = ch["blob_id"]
        self.focus_key_digest = ch["manifest_key_digest"]
        self.next_chunk_index = int(ch["index"])
        self.chunk_count_pin = int(ch["chunk_count"])
        self.total_length_pin = int(ch["total_length"])
        self.content_digest_pin = ch["content_digest"]
        self.expected_manifest_value_digest = ch["primary_value_digest"]
        peer = o1a_man_key_from_blob_id(self.blob_id_digest)
        self.peer_key = peer
        if self.focus_key_digest != d3s1.key_digest(peer):
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        expect_ck = o1a_chk_key_from_blob_index(self.blob_id_digest, self.next_chunk_index)
        if k != expect_ck:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        st, man_v = self._storage_get(peer)
        if st != "OK" or man_v is None:
            self._bind_wg_abort_get(st if st != "OK" else "NOT_FOUND", stage_absent=STAGE_BIND_C)
            return
        terr = o1a_value_typed_current(man_v, expect_subtype=0x30, expect_flags=1)
        if terr is not None:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        try:
            man = o1a_dec_man(peer, man_v)
        except ValueError:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        if man["blob_id"] != self.blob_id_digest:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        if man["chunk_count"] != self.chunk_count_pin:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        if man["total_length"] != self.total_length_pin:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        if man["content_digest"] != self.content_digest_pin:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        if self.next_chunk_index >= man["chunk_count"]:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return
        if d3s1.value_digest(man_v) != self.expected_manifest_value_digest:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
            self._walk_abort = "SEMANTIC"
            return

    def _drive_bind_man_w(self) -> bool:
        """Modes27–29 BIND_MAN WG; Mode30 outer select pure W (§18.14.9.2–.3)."""
        fr = self._reopen_if_needed()
        if self._fail_w_wg_entry(fr, row_budget=self.n_rows + 1):
            return False
        budget = self.n_rows + 1
        if self.mode == 30:
            return self._drive_bind_man_outer_w(budget)

        def on_row(k: bytes, v: bytes) -> None:
            if not o1a_bind_man_eligible(self.mode, k, v):
                return
            self._bind_man_pin_and_prove(k, v)

        st = self._advance_w(budget, on_row=on_row)
        if self.has_sticky or self._failed:
            self._drive_end(self.final_status, row_budget=budget)
            return False
        if st != "OK":
            if st != "MIDWALK":
                self._port_fail(st)
                self._drive_end(self.final_status, row_budget=budget)
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        cb = self.bind_cb
        self.bind_mask = MASK_BIND_MANIFEST
        self._set_tuple(
            SS_EXHAUSTED, PHASE_BIND_CHUNK, PASS_INTERNAL, 0, 0, 0x15, cb, 0x08
        )
        self._drive_end("OK", row_budget=budget)
        return True

    def _drive_bind_man_outer_w(self, budget: int) -> bool:
        """Mode30 BIND_MAN outer pure W: select first man > proven frontier."""
        selected = {"mk": None, "man": None}

        def on_row(k: bytes, v: bytes) -> None:
            if selected["mk"] is not None:
                return
            if not o1a_bind_man_eligible(30, k, v):
                return
            if len(self.last_carrier_key) != 0 and not (k > self.last_carrier_key):
                return
            try:
                man = o1a_dec_man(k, v)
            except ValueError:
                return
            selected["mk"] = k
            selected["man"] = man

        st = self._advance_w(budget, on_row=on_row)
        if self.has_sticky or self._failed:
            self._drive_end(self.final_status, row_budget=budget)
            return False
        if st != "OK":
            if st != "MIDWALK":
                self._port_fail(st)
                self._drive_end(self.final_status, row_budget=budget)
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        cb = self.bind_cb
        if selected["mk"] is not None:
            man = selected["man"]
            mk = selected["mk"]
            self.peer_key = mk
            self.focus_key_digest = man["key_digest"]
            self.focus_raw80 = man["owner_raw"] + bytes(max(0, 80 - len(man["owner_raw"])))
            self.focus_raw_len = len(man["owner_raw"])
            self.owner_kind = int(man["owner_kind"])
            self.blob_kind = int(man["blob_kind"])
            self.observed_live = 0
            self._set_tuple(
                SS_EXHAUSTED, PHASE_BIND_MANIFEST, PASS_INTERNAL, 0, 5, 0x15, cb, 0
            )
        else:
            self.bind_mask = MASK_BIND_MANIFEST
            self._set_tuple(
                SS_EXHAUSTED, PHASE_BIND_CHUNK, PASS_INTERNAL, 0, 0, 0x15, cb, 0x08
            )
        self._drive_end("OK", row_budget=budget)
        return True

    def _drive_bind_rr_w(self) -> bool:
        """Mode30 BIND RR-band pure W (entry sem=5): boolean latch only."""
        fr = self._reopen_if_needed()
        if self._fail_w_wg_entry(fr, row_budget=self.n_rows + 1):
            return False
        budget = self.n_rows + 1
        self.observed_live = 0
        pin_dig = self.focus_key_digest
        pin_raw = self.focus_raw80[: self.focus_raw_len] if self.focus_raw_len else b""

        def on_row(k: bytes, v: bytes) -> None:
            if o1a_subtype(k) != 0x42:
                return
            # Port-returned walk value: strict CURRENT RR before field compares
            if o1a_value_typed_current(v, expect_subtype=0x42, expect_flags=0) is not None:
                return
            try:
                rr = o1a_dec_rr(v)
            except ValueError:
                return
            if rr["body_blob_key_digest"] != pin_dig:
                return
            if rr["delivery_raw"] != pin_raw:
                return
            if rr["send_state"] not in (1, 2, 3, 4):
                return
            self.observed_live = 1

        st = self._advance_w(budget, on_row=on_row)
        if self.has_sticky or self._failed:
            self._drive_end(self.final_status, row_budget=budget)
            return False
        if st != "OK":
            if st != "MIDWALK":
                self._port_fail(st)
                self._drive_end(self.final_status, row_budget=budget)
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        cb = self.bind_cb
        if self.observed_live == 0:
            self._sticky_fail(OUT_CORRUPT, STAGE_BIND_M)
            self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        self.last_carrier_key = self.peer_key
        self._mode30_rr_success_clear()
        self._set_tuple(
            SS_EXHAUSTED, PHASE_BIND_MANIFEST, PASS_INTERNAL, 0, 0, 0x15, cb, 0
        )
        self._drive_end("OK", row_budget=budget)
        return True

    def _drive_bind_chunk_w(self) -> bool:
        """Modes27–30 BIND_CHUNK WG (§18.14.9.4)."""
        fr = self._reopen_if_needed()
        if self._fail_w_wg_entry(fr, row_budget=self.n_rows + 1):
            return False
        budget = self.n_rows + 1

        def on_row(k: bytes, v: bytes) -> None:
            if o1a_subtype(k) != 0x30 or o1a_flags(v) != 2:
                return
            self._bind_chunk_pin_and_prove(k, v)

        st = self._advance_w(budget, on_row=on_row)
        if self.has_sticky or self._failed:
            self._drive_end(self.final_status, row_budget=budget)
            return False
        if st != "OK":
            if st != "MIDWALK":
                self._port_fail(st)
                self._drive_end(self.final_status, row_budget=budget)
            else:
                self._sticky_fail(OUT_CORRUPT, STAGE_BIND_C)
                self._drive_end(OUT_CORRUPT, row_budget=budget)
            return False
        cb = self.bind_cb
        self.bind_mask = MASK_BIND
        self._set_tuple(
            SS_EXHAUSTED, PHASE_COMPLETE, PASS_INTERNAL, 0, 0, 0x09, cb, 0x18
        )
        self.final_status = OUT_OK
        self.adopted = 1
        self.has_sticky = 0
        self.sticky = ""
        self.terminal_stage = STAGE_COMPLETE
        self._terminal = True
        self._drive_end("OK", row_budget=budget)
        return True


    def _finalize_pack(self) -> Dict[str, Any]:
        """§18.14.19.11 finalize cleanup + §18.14.19.10 sticky/cleanup precedence.

        Does not rewrite d3s3 phase/flags (last drive tuple retained).
        Rollback fault never creates/overwrites sticky.
        """
        if not any(c["op"] == "finalize" for c in self.calls):
            entry_fence = int(self.fence_pending)
            # Capture pre-finalize d3 snapshot phase for assertions (not rewritten)
            # 1) iterator cleanup
            if self.iter_live and self.txn_live:
                self._void_iter_close()
            elif self.iter_live and not self.txn_live:
                # drop without Port event
                self.iter_live = 0
                self.iter_handle_id = None

            rollback_status = "OK"
            if self.txn_live:
                f = self._fault_for("rollback")
                if f is not None:
                    rollback_status = self._storage_status_from_fault(f)
                    self._ev(
                        "rollback", rollback_status,
                        input_handle_id=self.txn_handle_id or "T1",
                        output_handle_id=None,
                        mode=None,
                    )
                    self.fault_used = 1
                    # never create/clear/overwrite sticky
                    self.cleanup_status = rollback_status
                else:
                    self._ev(
                        "rollback", "OK",
                        input_handle_id=self.txn_handle_id or "T1",
                        output_handle_id=None,
                        mode=None,
                    )
                    self.cleanup_status = None
                self.txn_live = 0
                self.txn_handle_id = None

            if rollback_status != "OK" or entry_fence != 0:
                if self.storage_handle_id is not None:
                    self._ev(
                        "close", None,
                        input_handle_id=self.storage_handle_id or "H1",
                        output_handle_id=None,
                        mode=None,
                    )
                    self.storage_handle_id = None
                self.reopen_required = 1
                # Fence completed: H1 closed once; final fence_pending clears (§18.14.19.11)
                self.fence_pending = 0

            # ensure liveness dead after finalize
            self.iter_live = 0
            self.iter_handle_id = None
            self.txn_live = 0
            self.txn_handle_id = None
            self.session_state = SS_DONE

            # status precedence: sticky wins; else rollback mapped; else COMPLETE OK
            if self.has_sticky:
                fin_status = self.sticky
            elif rollback_status != "OK":
                fin_status = STORAGE_TO_RUNTIME[rollback_status]
            elif self.phase == PHASE_COMPLETE:
                fin_status = OUT_OK
            else:
                # non-complete without sticky (should be rare); keep final_status if set
                fin_status = self.final_status if self.final_status else OUT_INVALID_STATE

            self.final_status = fin_status
            self.adopted = (
                1
                if (
                    self.phase == PHASE_COMPLETE
                    and not self.has_sticky
                    and rollback_status == "OK"
                    and entry_fence == 0
                    and int(self.reopen_required) == 0
                    and fin_status == OUT_OK
                )
                else 0
            )
            self._end_call("finalize", fin_status)

        # configured natural fault must be reachable and used exactly once
        # (ill-formed precheck vectors never reach Port; fault reachability N/A)
        if self.faults and int(self.fault_used) != 1 and not self._precheck_failed:
            raise ValueError(
                f"formal fault configured but not used exactly once "
                f"(used={self.fault_used}); unreachable or multi-hit"
            )

        positive = (
            self.final_status == OUT_OK
            and self.adopted == 1
            and not self.has_sticky
            and self.phase == PHASE_COMPLETE
        )
        return {
            "final_status": self.final_status,
            "adopted": self.adopted,
            "state_after": SS_DONE,
            "has_sticky_primary": int(self.has_sticky),
            "sticky_primary": "" if not self.has_sticky else self.sticky,
            "phase": self.phase,
            "count_complete_mask": self.count_mask,
            "binding_complete_mask": self.bind_mask,
            "flags": self.flags,
            "mutation_calls": 0,
            "d3_peer_get_count": self.peer,
            "iter_open_count": self.opens,
            "port_trace": list(self.port_trace),
            "profile_exact_active": int(self.profile_exact_active),
            "profile_mismatch": int(self.profile_mismatch),
            "future_profile_candidate": int(self.future_profile_candidate),
            "family14_row_count": int(self.family14_row_count),
            "family14_iter_seen_mask": int(self.family14_iter_seen_mask),
            "profile_get_present_mask": int(self.profile_get_present_mask),
            "recognizable_future_seen": int(self.recognizable_future_seen),
            "close_count": self.op_counts.get("close", 0),
            "reopen_required": int(self.reopen_required),
            "cleanup_status": self.cleanup_status,
            "faults_expected_used": int(self.fault_used if self.faults else 0),
            "o1b_row_budget_schedule": O1B_ROW_BUDGET_DOC,
            "_calls": list(self.calls),
            "_positive": 1 if positive else 0,
            "_terminal_stage": self.terminal_stage,
        }



### END O1A_INDEPENDENT_REFERENCE_SECTION ###


# ---- O1b-A mechanical validators (§18.14.19.7 / .9) ----

import re as _re_mod

_RE_HANDLE_I = _re_mod.compile(r"^I[1-9]\d*$")
_RE_HEX_LO = _re_mod.compile(r"^[0-9a-f]*$")


def _exact_keys(obj: Dict[str, Any], keys: Sequence[str]) -> Optional[str]:
    if not isinstance(obj, dict):
        return "not object"
    got = set(obj.keys())
    want = set(keys)
    missing = sorted(want - got)
    extra = sorted(got - want)
    if missing or extra:
        return f"missing={missing} extra={extra}"
    return None


def _is_u32(v: Any) -> bool:
    return type(v) is int and 0 <= v <= UINT32_MAX


def _is_u64(v: Any) -> bool:
    return type(v) is int and 0 <= v <= UINT64_MAX


def _is_u8(v: Any) -> bool:
    return type(v) is int and 0 <= v <= 255


def _is_bit01(v: Any) -> bool:
    return type(v) is int and v in (0, 1)


def _hex_ok(hx: Any, length: Any) -> Optional[str]:
    if not isinstance(hx, str):
        return "hex not str"
    if type(length) is bool or type(length) is not int:
        return "length not int"
    if length < 0 or length > UINT32_MAX:
        return "length u32"
    if len(hx) % 2 != 0:
        return "hex odd length"
    if not _RE_HEX_LO.fullmatch(hx):
        return "hex not lowercase [0-9a-f]"
    if len(hx) // 2 != length:
        return f"hex byte-len {len(hx)//2} != length {length}"
    return None


def _handle_ok(h: Any, *, kind: str) -> bool:
    if h is None:
        return kind in ("null", "H1|null", "T1|null", "I|null")
    if not isinstance(h, str):
        return False
    if kind == "H1":
        return h == HANDLE_H1
    if kind == "T1":
        return h == HANDLE_T1
    if kind == "I":
        return _RE_HANDLE_I.fullmatch(h) is not None
    if kind == "H1|null":
        return h == HANDLE_H1
    if kind == "T1|null":
        return h == HANDLE_T1
    if kind == "I|null":
        return _RE_HANDLE_I.fullmatch(h) is not None
    return False


def _na_zero(ev: Dict[str, Any]) -> Optional[str]:
    """All N/A request/key/value descriptor fields exact zero/empty."""
    if ev.get("prefix_hex") != "" or not _is_u32(ev.get("prefix_length")) or ev["prefix_length"] != 0:
        return "prefix N/A"
    if ev.get("request_key_hex") != "" or not _is_u32(ev.get("request_key_length")) or ev["request_key_length"] != 0:
        return "request N/A"
    if ev.get("key_hex") != "" or not _is_u32(ev.get("key_capacity")) or ev["key_capacity"] != 0:
        return "key_capacity N/A"
    if not _is_u32(ev.get("key_length")) or ev["key_length"] != 0:
        return "key_length N/A"
    if not _is_u32(ev.get("value_capacity")) or ev["value_capacity"] != 0:
        return "value_capacity N/A"
    if not _is_u32(ev.get("value_length")) or ev["value_length"] != 0:
        return "value_length N/A"
    return None


def validate_port_event(ev: Dict[str, Any], *, seq: int) -> Optional[str]:
    """Return error string if Port event fails exact §18.14.19.7 per-op values."""
    err = _exact_keys(ev, PORT_EVENT_KEYS)
    if err:
        return f"keys {err}"
    op = ev.get("op")
    if op not in PORT_EVENT_OPS:
        return f"bad op {op}"
    if not _is_u32(ev.get("seq")) or ev["seq"] != seq:
        return f"seq want {seq} got {ev.get('seq')}"
    if not _is_u32(ev.get("api_call_index")):
        return "api_call_index"
    if not _is_u32(ev.get("on_call")) or ev["on_call"] < 1:
        return "on_call"
    st = ev.get("storage_status")
    # prefix always ""/0 for formal product
    if ev.get("prefix_hex") != "" or not _is_u32(ev.get("prefix_length")) or ev["prefix_length"] != 0:
        return "prefix must be empty/0"

    if op == "begin":
        # product begin is success-only: H1→T1 READ_ONLY, all N/A zero
        if st != "OK":
            return "begin storage_status must be OK in product"
        if ev.get("input_handle_id") != HANDLE_H1:
            return "begin input H1"
        if ev.get("output_handle_id") != HANDLE_T1:
            return "begin output T1"
        if ev.get("mode") != "READ_ONLY":
            return "begin mode READ_ONLY"
        na = _na_zero(ev)
        if na:
            return f"begin {na}"
        return None

    if op == "get":
        if st not in PORT_STORAGE_OK_SET:
            return f"get bad storage_status {st}"
        if st not in ("OK", "NOT_FOUND") and st not in STORAGE_NATURAL:
            return f"get storage_status domain {st}"
        if ev.get("input_handle_id") != HANDLE_T1:
            return "get input T1"
        if ev.get("output_handle_id") is not None:
            return "get output null"
        if ev.get("mode") is not None:
            return "get mode null"
        hx, rl = ev.get("request_key_hex"), ev.get("request_key_length")
        he = _hex_ok(hx, rl)
        if he:
            return f"get request {he}"
        if not _is_u32(rl) or rl < 1:
            return "get request nonempty"
        if ev.get("key_hex") != "" or not _is_u32(ev.get("key_capacity")) or ev["key_capacity"] != 0:
            return "get output key empty/0"
        if not _is_u32(ev.get("key_length")) or ev["key_length"] != 0:
            return "get key_length 0"
        if not _is_u32(ev.get("value_capacity")) or ev["value_capacity"] != VALUE_CAPACITY:
            return "get value_capacity 4096"
        vl = ev.get("value_length")
        if not _is_u32(vl):
            return "get value_length"
        if st == "OK":
            if vl > VALUE_CAPACITY:
                return "get OK value_length > cap"
        else:
            # NOT_FOUND or natural fault: length 0, capacity retained
            if vl != 0:
                return "get NOT_FOUND/fault value_length 0"
        return None

    if op == "iter_open":
        if st not in (("OK",) + tuple(STORAGE_NATURAL)):
            return f"iter_open storage_status {st}"
        if ev.get("input_handle_id") != HANDLE_T1:
            return "iter_open input T1"
        if st == "OK":
            if not _handle_ok(ev.get("output_handle_id"), kind="I"):
                return "iter_open output I<n> on OK"
        else:
            if ev.get("output_handle_id") is not None:
                return "iter_open output null on fault"
        if ev.get("mode") is not None:
            return "iter_open mode null"
        na = _na_zero(ev)
        if na:
            return f"iter_open {na}"
        return None

    if op == "iter_next":
        if st not in (("OK", "NOT_FOUND") + tuple(STORAGE_NATURAL)):
            return f"iter_next storage_status {st}"
        if not _handle_ok(ev.get("input_handle_id"), kind="I"):
            return "iter_next input I<n>"
        if ev.get("output_handle_id") is not None:
            return "iter_next output null"
        if ev.get("mode") is not None:
            return "iter_next mode null"
        if ev.get("request_key_hex") != "" or not _is_u32(ev.get("request_key_length")) or ev["request_key_length"] != 0:
            return "iter_next request empty"
        if not _is_u32(ev.get("key_capacity")) or ev["key_capacity"] != KEY_CAPACITY:
            return "iter_next key_capacity 255"
        if not _is_u32(ev.get("value_capacity")) or ev["value_capacity"] != VALUE_CAPACITY:
            return "iter_next value_capacity 4096"
        kh, kl, vl = ev.get("key_hex"), ev.get("key_length"), ev.get("value_length")
        if not _is_u32(kl) or not _is_u32(vl):
            return "iter_next lengths"
        if st == "OK":
            he = _hex_ok(kh, kl)
            if he:
                return f"iter_next key {he}"
            if kl < 1:
                return "iter_next OK key nonempty"
            if kl > KEY_CAPACITY:
                return "iter_next key_length > cap"
            if vl > VALUE_CAPACITY:
                return "iter_next value_length > cap"
        else:
            if kh != "" or kl != 0 or vl != 0:
                return "iter_next NOT_FOUND/fault empty lengths"
        return None

    if op == "iter_close":
        if st is not None:
            return "iter_close storage_status null"
        if not _handle_ok(ev.get("input_handle_id"), kind="I"):
            return "iter_close input I<n>"
        if ev.get("output_handle_id") is not None:
            return "iter_close output null"
        if ev.get("mode") is not None:
            return "iter_close mode null"
        na = _na_zero(ev)
        if na:
            return f"iter_close {na}"
        return None

    if op == "rollback":
        if st not in (("OK",) + tuple(STORAGE_NATURAL)):
            return f"rollback storage_status {st}"
        if ev.get("input_handle_id") != HANDLE_T1:
            return "rollback input T1"
        if ev.get("output_handle_id") is not None:
            return "rollback output null"
        if ev.get("mode") is not None:
            return "rollback mode null"
        na = _na_zero(ev)
        if na:
            return f"rollback {na}"
        return None

    if op == "close":
        if st is not None:
            return "close storage_status null"
        if ev.get("input_handle_id") != HANDLE_H1:
            return "close input H1"
        if ev.get("output_handle_id") is not None:
            return "close output null"
        if ev.get("mode") is not None:
            return "close mode null"
        na = _na_zero(ev)
        if na:
            return f"close {na}"
        return None

    return f"unhandled op {op}"


def _validate_sticky_pair(has: Any, sticky: Any, *, where: str) -> Optional[str]:
    if not _is_bit01(has):
        return f"{where}.has_sticky_primary not 0/1"
    if not isinstance(sticky, str):
        return f"{where}.sticky_primary not str"
    if has == 0:
        if sticky != "":
            return f"{where}.sticky_primary must be empty when has=0"
    else:
        if sticky not in RUNTIME_STICKY:
            return f"{where}.sticky_primary domain {sticky}"
    return None


def _validate_cleanup(cs: Any, *, where: str) -> Optional[str]:
    if cs is None:
        return None
    if cs not in STORAGE_NATURAL:
        return f"{where}.cleanup_status domain {cs}"
    return None


def validate_checkpoint(
    cp: Dict[str, Any],
    *,
    finalize: bool,
    trace_len: int,
    after_successful_begin: bool = False,
) -> Optional[str]:
    """Return error string if checkpoint fails §18.14.19.9 closed domains/types."""
    err = _exact_keys(cp, CP_TOP_KEYS)
    if err:
        return f"top {err}"
    if "peer_key" in cp or "peer_key_len" in cp:
        return "forbidden peer_key scratch at top"
    sess = cp.get("session")
    d3 = cp.get("d3s3")
    port = cp.get("port")
    result = cp.get("result")
    err = _exact_keys(sess, CP_SESSION_KEYS)
    if err:
        return f"session {err}"
    if "peer_key" in sess or "peer_key_len" in sess:
        return "forbidden peer_key in session"
    err = _exact_keys(d3, CP_D3S3_KEYS)
    if err:
        return f"d3s3 {err}"
    if "peer_key" in d3 or "peer_key_len" in d3:
        return "forbidden peer_key scratch in d3s3"
    err = _exact_keys(port, CP_PORT_KEYS)
    if err:
        return f"port {err}"

    rs = cp.get("returned_status")
    if rs not in RUNTIME_RETURNED:
        return f"returned_status {rs}"
    if sess.get("state") not in SESSION_STATES:
        return f"session.state {sess.get('state')}"

    # session scalar domains
    for k in (
        "txn_live", "iter_live", "reopen_required", "fence_pending",
        "profile_exact_active", "profile_mismatch", "future_profile_candidate",
        "recognizable_future_seen", "has_previous",
    ):
        if not _is_bit01(sess.get(k)):
            return f"session.{k} not 0/1"
    err = _validate_sticky_pair(sess.get("has_sticky_primary"), sess.get("sticky_primary"), where="session")
    if err:
        return err
    err = _validate_cleanup(sess.get("cleanup_status"), where="session")
    if err:
        return err
    for k in ("family14_row_count", "family14_iter_seen_mask", "profile_get_present_mask", "previous_key_length"):
        if not _is_u32(sess.get(k)):
            return f"session.{k} u32"
    for k in ("ok_row_count", "current_domain_key_count"):
        if not _is_u64(sess.get(k)):
            return f"session.{k} u64"
    he = _hex_ok(sess.get("previous_key_hex"), sess.get("previous_key_length"))
    if he:
        return f"session.previous_key {he}"
    if sess["previous_key_length"] > KEY_CAPACITY:
        return "session.previous_key_length > 255"

    # d3s3 domains
    if not _is_u8(d3.get("phase")) or d3["phase"] > 14:
        return f"phase {d3.get('phase')}"
    if not _is_u8(d3.get("pass_kind")) or d3["pass_kind"] > 1:
        return f"pass_kind {d3.get('pass_kind')}"
    if not _is_u8(d3.get("semantic_pass")) or d3["semantic_pass"] > 6:
        return f"semantic_pass {d3.get('semantic_pass')}"
    for k in (
        "focus_mode", "focus_sub", "lifecycle_class", "expected_live",
        "observed_live", "reply_kind", "flags", "count_complete_mask",
        "binding_complete_mask", "last_carrier_key_len",
    ):
        if not _is_u8(d3.get(k)):
            return f"d3s3.{k} u8"
    if d3["last_carrier_key_len"] > 45:
        return "last_carrier_key_len > 45"
    he = _hex_ok(d3.get("last_carrier_key_hex"), d3.get("last_carrier_key_len"))
    if he:
        return f"last_carrier_key {he}"
    fid = d3.get("focus_id16_hex")
    if not isinstance(fid, str) or len(fid) != 32 or not _RE_HEX_LO.fullmatch(fid):
        return "focus_id16_hex must be 32 lowercase hex (16 bytes)"

    # port domains
    for k in (
        "event_start", "event_end", "trace_count",
        "begin_count", "get_count", "iter_open_count", "iter_next_count",
        "iter_close_count", "rollback_count", "close_count",
        "reopen_attempt_count", "reopen_success_count", "mutation_calls",
    ):
        if not _is_u32(port.get(k)):
            return f"port.{k} u32"
    if not _is_u64(port.get("d3_peer_get_count")):
        return "port.d3_peer_get_count u64"
    if not _is_u8(port.get("trace_overflow")) or port["trace_overflow"] != 0:
        return "trace_overflow must be 0"
    if port["mutation_calls"] != 0:
        return "mutation_calls must be 0"
    if not _handle_ok(port.get("storage_handle_id"), kind="H1|null"):
        return "port.storage_handle_id"
    if not _handle_ok(port.get("txn_handle_id"), kind="T1|null"):
        return "port.txn_handle_id"
    if not _handle_ok(port.get("iter_handle_id"), kind="I|null"):
        return "port.iter_handle_id"

    es, ee, tc = port["event_start"], port["event_end"], port["trace_count"]
    if not (0 <= es <= ee <= trace_len):
        return f"half-open window [{es},{ee}) vs trace_len={trace_len}"
    if tc != ee:
        return f"trace_count {tc} != event_end {ee}"

    gc = port["get_count"]
    peer = port["d3_peer_get_count"]
    if after_successful_begin or gc >= 17:
        if peer != gc - 17:
            return f"d3_peer_get_count {peer} != get_count-17 ({gc}-17)"
    else:
        if peer != 0:
            return f"d3_peer_get_count must be 0 before successful begin profile (got {peer})"

    if finalize:
        if result is None:
            return "result null on finalize"
        err = _exact_keys(result, CP_RESULT_KEYS)
        if err:
            return f"result {err}"
        if result.get("status") != rs:
            return "result.status != returned_status"
        if result.get("status") not in RUNTIME_RETURNED:
            return f"result.status domain {result.get('status')}"
        if result.get("state_after") != SS_DONE:
            return "result.state_after"
        if not _is_bit01(result.get("adopted")):
            return "result.adopted not 0/1"
        err = _validate_sticky_pair(
            result.get("has_sticky_primary"), result.get("sticky_primary"), where="result"
        )
        if err:
            return err
        err = _validate_cleanup(result.get("cleanup_status"), where="result")
        if err:
            return err
        for k in (
            "reopen_required", "profile_exact_active", "profile_mismatch",
            "future_profile_candidate", "recognizable_future_seen",
        ):
            if not _is_bit01(result.get(k)):
                return f"result.{k} not 0/1"
        if not _is_u32(result.get("mutation_calls")) or result["mutation_calls"] != 0:
            return "result.mutation_calls"
        for k in (
            "family14_row_count", "family14_iter_seen_mask", "profile_get_present_mask",
        ):
            if not _is_u32(result.get(k)):
                return f"result.{k} u32"
        for k in ("ok_row_count", "current_domain_key_count", "d3_peer_get_count"):
            if not _is_u64(result.get(k)):
                return f"result.{k} u64"
        # mirrored session/result fields (adoption/rollback precedence remains O1b-C)
        for k in (
            "has_sticky_primary", "sticky_primary", "reopen_required", "cleanup_status",
            "profile_exact_active", "profile_mismatch", "future_profile_candidate",
            "recognizable_future_seen", "family14_row_count", "family14_iter_seen_mask",
            "profile_get_present_mask", "ok_row_count", "current_domain_key_count",
        ):
            if result.get(k) != sess.get(k):
                return f"result.{k} != session.{k}"
        if result.get("d3_peer_get_count") != port.get("d3_peer_get_count"):
            return "result.d3_peer_get_count != port.d3_peer_get_count"
    else:
        if result is not None:
            return "result must be null before finalize"
    return None


def validate_b5_formal_vector(v: Dict[str, Any]) -> Optional[str]:
    """Independent B5 formal-class checks (§18.14.19.8 B5).

    Requires formal_class=b5_baseline, N>=1, first two drives budgets [N, N+1],
    first checkpoint OPEN/BASELINE, second EXHAUSTED/SELECT (B1).
    """
    if v.get("formal_class") != FORMAL_CLASS_B5_BASELINE:
        return "formal_class is not b5_baseline"
    rows = v.get("rows") or []
    n = len(rows)
    if n < 1:
        return "B5 requires N>=1 rows"
    calls = v.get("calls") or []
    drives = [c for c in calls if c.get("op") == "d3s3_drive"]
    if len(drives) < 2:
        return "B5 needs midwalk+resume drives"
    if int(drives[0].get("row_budget", -1)) != n:
        return f"B5 first budget want N={n} got {drives[0].get('row_budget')}"
    if int(drives[1].get("row_budget", -1)) != n + 1:
        return f"B5 resume budget want N+1={n + 1} got {drives[1].get('row_budget')}"
    cp0 = drives[0].get("checkpoint") or {}
    sess0 = cp0.get("session") or {}
    d3_0 = cp0.get("d3s3") or {}
    if sess0.get("state") != SS_OPEN or int(d3_0.get("phase", -1)) != PHASE_BASELINE:
        return "B5 first drive must be OPEN/BASELINE"
    if int(d3_0.get("flags", -1)) != 0x00:
        return "B5 midwalk flags must be 0x00"
    cp1 = drives[1].get("checkpoint") or {}
    sess1 = cp1.get("session") or {}
    d3_1 = cp1.get("d3s3") or {}
    if sess1.get("state") != SS_EXHAUSTED or int(d3_1.get("phase", -1)) != PHASE_SELECT_CARRIER:
        return "B5 resume must be EXHAUSTED/SELECT (B1)"
    if int(d3_1.get("flags", -1)) != 0x11:
        return "B5 resume flags must be 0x11"
    # Non-BASELINE W must not use row_budget=N midwalk under this class after B1.
    for di, c in enumerate(drives[2:], start=2):
        rb = int(c.get("row_budget", 0))
        d3 = (c.get("checkpoint") or {}).get("d3s3") or {}
        if int(d3.get("pass_kind", -1)) != PASS_BASELINE and rb == n:
            # residual W budgets are N+1 (true exhaust); N alone after B1 is illegal B5
            sess = (c.get("checkpoint") or {}).get("session") or {}
            if sess.get("state") == SS_OPEN and int(d3.get("phase", -1)) != PHASE_BASELINE:
                return f"B5 midwalk on non-BASELINE drive[{di}]"
    return None


def is_zero_port_precheck_failed(exp: Dict[str, Any]) -> bool:
    """Legacy expected-only zero-Port CORRUPT shape (pre-R18 synthetic Runtime).

    R18 product formal_precheck uses ``execution_scope`` on the **vector**
    (see ``is_formal_precheck_vector``) — not this sticky/phase14 expected.
    R16: does not coerce falsy non-list port_trace (e.g. {} / \"\") to [].
    """
    if not isinstance(exp, dict):
        return False
    # Explicit default only when key missing — never `or []` (would swallow {} / "").
    ptrace = exp.get("port_trace", [])
    return (
        type(ptrace) is list
        and len(ptrace) == 0
        and exp.get("final_status") == OUT_CORRUPT
        and int(exp.get("phase", -1)) == PHASE_FAILED
        and int(exp.get("has_sticky_primary", 0)) == 1
        and int(exp.get("adopted", 1)) == 0
    )


def map_precheck_error(reason: str) -> Optional[str]:
    """Map pure ``rep1_precheck_formal_inputs`` reason → closed precheck_error."""
    if type(reason) is not str:
        return None
    return PRECHECK_REASON_TO_ERROR.get(reason)


def is_formal_precheck_vector(v: Dict[str, Any]) -> bool:
    """R18: product vector is formal_precheck (validator-only; no production API)."""
    return isinstance(v, dict) and v.get("execution_scope") == EXEC_SCOPE_FORMAL_PRECHECK


def is_rep1_l2_vector(v: Dict[str, Any]) -> bool:
    return isinstance(v, dict) and v.get("execution_scope") == EXEC_SCOPE_REP1_L2


def validate_execution_scope_vector(v: Dict[str, Any]) -> Optional[str]:
    """R18: every suffix vector must carry closed execution_scope (+ precheck rules)."""
    if not isinstance(v, dict):
        return "vector not object"
    scope = v.get("execution_scope")
    if scope is None:
        return "missing execution_scope"
    if scope not in EXECUTION_SCOPES:
        return f"unknown execution_scope {scope!r}; closed {sorted(EXECUTION_SCOPES)}"
    if scope == EXEC_SCOPE_FORMAL_PRECHECK:
        return validate_formal_precheck_vector(v)
    # rep1_l2
    if "precheck_error" in v:
        return "rep1_l2 forbids precheck_error"
    calls = v.get("calls")
    if type(calls) is not list or len(calls) == 0:
        return "rep1_l2 requires non-empty calls"
    return None


def validate_formal_precheck_vector(v: Dict[str, Any]) -> Optional[str]:
    """R18 formal_precheck: no production calls/checkpoints/result; Port empty.

    Zero Port because production is **not** invoked — not a synthesized Runtime
    CORRUPT transcript. Independent pure precheck must reject the rows.
    """
    if v.get("execution_scope") != EXEC_SCOPE_FORMAL_PRECHECK:
        return "not formal_precheck scope"
    pe = v.get("precheck_error")
    if pe is None:
        return "formal_precheck missing precheck_error"
    if pe not in PRECHECK_ERRORS:
        return f"precheck_error not in closed set; got {pe!r}"
    calls = v.get("calls")
    if type(calls) is not list or len(calls) != 0:
        return "formal_precheck calls must be empty list (no production API)"
    if "faults" not in v:
        faults: Any = []
    else:
        faults = v.get("faults")
    if type(faults) is not list or len(faults) != 0:
        return "formal_precheck faults must be empty list"
    exp = v.get("expected")
    if type(exp) is not dict:
        return "formal_precheck expected must be object"
    # No Runtime sticky/phase/result/checkpoint fields — Port empty only.
    allowed_exp = frozenset({"port_trace"})
    surplus = sorted(set(exp.keys()) - allowed_exp)
    if surplus:
        return f"formal_precheck expected surplus keys {surplus}"
    # R16: type before emptiness — {} / "" must not coerce to [] green.
    if "port_trace" not in exp:
        return "formal_precheck missing port_trace"
    ptrace = exp.get("port_trace")
    if type(ptrace) is not list:
        return "port_trace not list"
    if len(ptrace) != 0:
        return "formal_precheck port_trace must be []"
    if "result" in v:
        return "formal_precheck forbids top-level result"
    # Independent pure gate must reject; error code must match reason map.
    reason = rep1_precheck_formal_inputs(
        v.get("mode"),
        v.get("rows"),
        formal_class=v.get("formal_class", FORMAL_CLASS_ORDINARY),
        faults=faults if type(faults) is list else [],
    )
    if reason is None:
        return "formal_precheck rows must fail pure precheck"
    mapped = map_precheck_error(reason)
    if mapped is None:
        return f"formal_precheck unmapped pure reason {reason!r}"
    if mapped != pe:
        return (
            f"precheck_error mismatch pure_reason={reason!r} "
            f"mapped={mapped!r} got={pe!r}"
        )
    return None


# §18.14.19.4 closed non-terminal matrix: (phase, mode, semantic_pass) → unit kind.
# Each triple maps to exactly one unit; absence ⇒ INVALID_STATE.
_REP1_MODES = frozenset({27, 28, 29, 30})
REP1_NONTERM_MATRIX: Dict[Tuple[int, int, int], str] = {}
for _ph, _modes, _sem, _unit in (
    (1, _REP1_MODES, 0, "W"),
    (2, _REP1_MODES, 0, "W"),
    (2, frozenset({27, 29}), 6, "G"),
    (3, frozenset({27, 29, 30}), 0, "W"),
    (3, frozenset({28}), 0, "W"),
    (3, frozenset({28}), 1, "W"),
    (4, frozenset({27, 29}), 0, "G"),
    (4, frozenset({28}), 0, "G"),
    (5, _REP1_MODES, 0, "G"),
    (6, frozenset({28}), 0, "W"),
    (6, frozenset({28}), 3, "W"),
    (7, frozenset({28}), 0, "G"),
    (8, frozenset({28}), 0, "G"),
    (9, frozenset({28, 30}), 0, "G"),
    (10, frozenset({30}), 0, "G"),
    (10, frozenset({28}), 2, "G"),
    (10, frozenset({28}), 4, "G"),
    (11, frozenset({27, 28, 29}), 0, "WG"),
    (11, frozenset({30}), 0, "W"),
    (11, frozenset({30}), 5, "W"),
    (12, _REP1_MODES, 0, "WG"),
):
    for _m in _modes:
        REP1_NONTERM_MATRIX[(_ph, _m, _sem)] = _unit

# Terminal checkpoint table: (phase, mode, pass_kind, semantic_pass)
REP1_TERMINAL_TABLE: frozenset = frozenset()
_term: List[Tuple[int, int, int, int]] = []
for _m in (27, 28, 29, 30):
    _term.append((13, _m, 1, 0))  # COMPLETE
for _m in (27, 29):
    _term.append((14, _m, 0, 0))
    _term.append((14, _m, 1, 0))
    _term.append((14, _m, 1, 6))
_term.append((14, 28, 0, 0))
for _sem in (0, 1, 2, 3, 4):
    _term.append((14, 28, 1, _sem))
_term.append((14, 30, 0, 0))
for _sem in (0, 5):
    _term.append((14, 30, 1, _sem))
REP1_TERMINAL_TABLE = frozenset(_term)


def rep1_matrix_unit(phase: int, mode: int, semantic_pass: int) -> Optional[str]:
    """Return unit kind for non-terminal triple, or None if absent."""
    return REP1_NONTERM_MATRIX.get((int(phase), int(mode), int(semantic_pass)))


def validate_rep1_checkpoint_matrix(
    cp: Dict[str, Any],
    *,
    mode: int,
    finalize: bool = False,
) -> Optional[str]:
    """Validate closed non-terminal matrix / terminal table + pass_kind legality.

    Drive exit checkpoints with phase 1..12 must be matrix members (next-unit entry).
    Phase 13/14 must match the terminal table. G entry liveness is checked separately
    against the entry snapshot when available.
    """
    d3 = cp.get("d3s3") or {}
    sess = cp.get("session") or {}
    phase = int(d3.get("phase", -1))
    pk = int(d3.get("pass_kind", -1))
    sem = int(d3.get("semantic_pass", -1))
    fm = int(d3.get("focus_mode", -1))
    if fm not in _REP1_MODES:
        # Pre-begin / zero-port may leave focus unset; only enforce after begin product.
        if phase >= 1 and not finalize:
            return f"focus_mode {fm} not in {{27..30}}"
    if fm in _REP1_MODES and int(mode) in _REP1_MODES and fm != int(mode):
        return f"focus_mode {fm} != bound mode {mode}"
    if phase == 13 or phase == 14:
        if (phase, int(mode), pk, sem) not in REP1_TERMINAL_TABLE:
            return (
                f"terminal tuple illegal phase={phase} mode={mode} "
                f"pass_kind={pk} semantic_pass={sem}"
            )
        return None
    if phase < 1 or phase > 12:
        if phase == 0 and finalize:
            return None
        return f"phase {phase} outside 1..14 product range"
    # Non-terminal pass_kind legality
    if phase == 1:
        if pk != PASS_BASELINE:
            return f"phase1 pass_kind want 0 got {pk}"
    else:
        if pk != PASS_INTERNAL:
            return f"phase{phase} pass_kind want 1 got {pk}"
    unit = rep1_matrix_unit(phase, mode, sem)
    if unit is None:
        return (
            f"non-terminal matrix miss phase={phase} mode={mode} semantic_pass={sem}"
        )
    # Successful true-exhaust W/WG leave EXHAUSTED (B5 midwalk OPEN/BASELINE only).
    st = sess.get("state")
    if unit in ("W", "WG") and phase != 1:
        if st not in (SS_EXHAUSTED, SS_FAILED):
            # failure-point may already be FAILED
            if st != SS_FAILED:
                return f"W/WG exit state want EXHAUSTED/FAILED got {st}"
    return None


def validate_rep1_drive_dispatch(v: Dict[str, Any]) -> Optional[str]:
    """Validate each drive exit against matrix/terminal + G/W/WG liveness windows."""
    mode = int(v.get("mode", -1))
    if mode not in _REP1_MODES:
        return f"mode {mode}"
    calls = v.get("calls") or []
    exp = v.get("expected") or {}
    if is_zero_port_precheck_failed(exp):
        return None
    # Entry state for first drive is after successful begin: OPEN/BASELINE/pk0/sem0.
    entry_phase, entry_pk, entry_sem = 1, PASS_BASELINE, 0
    entry_state, entry_txn, entry_iter = SS_OPEN, 1, 1
    entry_flags = 0
    for ci, c in enumerate(calls):
        op = c.get("op")
        if op == "begin_profiled_d3s3":
            cp = c.get("checkpoint") or {}
            err = validate_rep1_checkpoint_matrix(cp, mode=mode, finalize=False)
            # begin may be FAILED zero-port or OPEN/BASELINE
            d3 = (cp.get("d3s3") or {})
            if int(d3.get("phase", -1)) == PHASE_BASELINE:
                entry_phase, entry_pk, entry_sem = 1, PASS_BASELINE, 0
                sess = cp.get("session") or {}
                entry_state = sess.get("state", SS_OPEN)
                entry_txn = int(sess.get("txn_live", 0))
                entry_iter = int(sess.get("iter_live", 0))
                entry_flags = int(d3.get("flags", 0))
            continue
        if op != "d3s3_drive":
            if op == "finalize":
                cp = c.get("checkpoint") or {}
                # Terminal snapshot lives in last drive; finalize keeps phase.
                err = validate_rep1_checkpoint_matrix(cp, mode=mode, finalize=True)
                if err is not None:
                    # finalize after COMPLETE/FAILED is ok if terminal table holds
                    d3 = cp.get("d3s3") or {}
                    ph = int(d3.get("phase", -1))
                    if ph in (13, 14):
                        err2 = validate_rep1_checkpoint_matrix(cp, mode=mode, finalize=False)
                        if err2 is not None:
                            return f"calls[{ci}] finalize terminal: {err2}"
                    elif err is not None and ph not in (0, 13, 14):
                        return f"calls[{ci}] finalize matrix: {err}"
            continue
        # Validate entry triple is in matrix (drive was dispatched on it).
        unit = rep1_matrix_unit(entry_phase, mode, entry_sem)
        if entry_phase not in (13, 14) and unit is None:
            return (
                f"calls[{ci}] drive entry matrix miss "
                f"phase={entry_phase} mode={mode} sem={entry_sem}"
            )
        if entry_phase == 1 and entry_pk != PASS_BASELINE:
            return f"calls[{ci}] BASELINE entry pass_kind"
        if 2 <= entry_phase <= 12 and entry_pk != PASS_INTERNAL:
            return f"calls[{ci}] INTERNAL entry pass_kind"
        # G liveness exact
        if unit == "G":
            if entry_state != SS_EXHAUSTED or entry_txn != 1 or entry_iter != 1:
                return (
                    f"calls[{ci}] G entry liveness want EXHAUSTED+txn1+iter1 "
                    f"got state={entry_state} txn={entry_txn} iter={entry_iter}"
                )
        # W/WG reopen/liveness exact (entry flags NEED_REOPEN + iter_live)
        if unit in ("W", "WG") and entry_phase != 1:
            need = (entry_flags & FLAG_NEED_REOPEN) != 0
            if entry_iter != 1:
                # formal product must not enter W/WG with iter_live=0
                # (INVALID_STATE before Port); only allow if call already failed
                # with no Port events — checked via window empty + INVALID_STATE.
                window_empty = int((c.get("checkpoint") or {}).get("port", {}).get(
                    "event_end", 0
                )) == int((c.get("checkpoint") or {}).get("port", {}).get(
                    "event_start", 0
                ))
                if not window_empty:
                    return (
                        f"calls[{ci}] W/WG entry iter_live=0 with Port events "
                        f"(need_reopen={int(need)})"
                    )
        cp = c.get("checkpoint") or {}
        err = validate_rep1_checkpoint_matrix(cp, mode=mode, finalize=False)
        if err is not None:
            return f"calls[{ci}] drive exit: {err}"
        # Next entry = this exit
        d3 = cp.get("d3s3") or {}
        sess = cp.get("session") or {}
        entry_phase = int(d3.get("phase", -1))
        entry_pk = int(d3.get("pass_kind", -1))
        entry_sem = int(d3.get("semantic_pass", -1))
        entry_state = sess.get("state")
        entry_txn = int(sess.get("txn_live", 0))
        entry_iter = int(sess.get("iter_live", 0))
        entry_flags = int(d3.get("flags", 0))
    return None


def validate_vector_port_mechanics(v: Dict[str, Any]) -> Optional[str]:
    """Mechanical Port/checkpoint validation + trace replay for one suffix vector."""
    # R18: formal_precheck has no Port mechanics (production not invoked).
    if is_formal_precheck_vector(v):
        # Binding/type first (R16), then formal_precheck schema.
        fb = validate_formal_fault_trace_binding(v)
        if fb is not None:
            return fb
        err = validate_formal_precheck_vector(v)
        if err is not None:
            return err
        return None
    exp = v.get("expected") or {}
    # R16: never normalize falsy non-list ({} / "") to [] via `or []`.
    ptrace = exp.get("port_trace", [])
    if type(ptrace) is not list:
        return "port_trace not list"
    if not ptrace:
        # Legacy synthetic zero-Port expected (pre-R18) still allowed for tests.
        if is_zero_port_precheck_failed(exp):
            # R15: still enforce fault binding (no configured/unobserved fault).
            fb = validate_formal_fault_trace_binding(v)
            if fb is not None:
                return fb
            ug = validate_rep1_unit_grammar(v)
            if ug is not None:
                return f"rep1 unit grammar: {ug}"
            return None
        return "empty port_trace"
    ntrace = len(ptrace)
    size_err = port_trace_size_error(ntrace, TRACE_CAPACITY)
    if size_err is not None:
        return size_err

    for ti, ev in enumerate(ptrace):
        err = validate_port_event(ev, seq=ti)
        if err:
            return f"port_trace[{ti}]: {err}"

    # exactly one begin and it must be first; no later begin
    if ptrace[0].get("op") != "begin":
        return "trace must start with begin"
    begin_idxs = [i for i, ev in enumerate(ptrace) if ev.get("op") == "begin"]
    if begin_idxs != [0]:
        return f"begin must be exactly once at index 0 (got {begin_idxs})"

    # per-op on_call sequence 1..N
    op_seen: Dict[str, int] = {}
    for ti, ev in enumerate(ptrace):
        op = ev["op"]
        want = op_seen.get(op, 0) + 1
        if ev["on_call"] != want:
            return f"port_trace[{ti}]: on_call want {want} got {ev['on_call']} for {op}"
        op_seen[op] = want

    # logical handle lineage replay (mechanical; scheduling still O1b-A)
    h1_live = True
    t1_live = False
    iter_live: Optional[str] = None
    next_i = 1
    h1_closed = False
    for ti, ev in enumerate(ptrace):
        if h1_closed:
            return f"port_trace[{ti}]: event after close"
        op, st = ev["op"], ev["storage_status"]
        if op == "begin":
            if not h1_live:
                return f"port_trace[{ti}]: begin without H1"
            if t1_live:
                return f"port_trace[{ti}]: begin while T1 live"
            if iter_live is not None:
                return f"port_trace[{ti}]: begin while iterator live"
            if st == "OK":
                t1_live = True
        elif op == "get":
            if not t1_live:
                return f"port_trace[{ti}]: get without T1"
        elif op == "iter_open":
            if not t1_live:
                return f"port_trace[{ti}]: iter_open without T1"
            if iter_live is not None:
                return f"port_trace[{ti}]: iter_open while iterator live"
            if st == "OK":
                want_i = f"I{next_i}"
                if ev["output_handle_id"] != want_i:
                    return f"port_trace[{ti}]: iter_open want {want_i} got {ev['output_handle_id']}"
                iter_live = want_i
                next_i += 1
            # fault: attempt with T1 live, no live iterator; does not install Ik
        elif op == "iter_next":
            if iter_live is None or ev["input_handle_id"] != iter_live:
                return f"port_trace[{ti}]: iter_next handle want {iter_live} got {ev['input_handle_id']}"
        elif op == "iter_close":
            if iter_live is None or ev["input_handle_id"] != iter_live:
                return f"port_trace[{ti}]: iter_close handle want {iter_live} got {ev['input_handle_id']}"
            iter_live = None
        elif op == "rollback":
            if not t1_live:
                return f"port_trace[{ti}]: rollback without T1"
            if iter_live is not None:
                return f"port_trace[{ti}]: rollback while iterator live"
            t1_live = False
        elif op == "close":
            if not h1_live:
                return f"port_trace[{ti}]: close without H1"
            if t1_live:
                return f"port_trace[{ti}]: close while T1 live"
            if iter_live is not None:
                return f"port_trace[{ti}]: close while iterator live"
            h1_live = False
            h1_closed = True

    calls = v.get("calls") or []
    if not calls:
        return "empty calls"
    for ci, c in enumerate(calls):
        cop = c.get("op")
        if cop not in FORMAL_CALL_OPS:
            return f"calls[{ci}] op not in formal set: {cop}"
    if calls[0].get("op") != "begin_profiled_d3s3":
        return "calls must start begin_profiled_d3s3"
    if calls[-1].get("op") != "finalize":
        return "calls must end finalize"
    n_begin_calls = sum(1 for c in calls if c.get("op") == "begin_profiled_d3s3")
    n_fin_calls = sum(1 for c in calls if c.get("op") == "finalize")
    if n_begin_calls != 1:
        return f"exactly one begin_profiled_d3s3 call (got {n_begin_calls})"
    if n_fin_calls != 1:
        return f"exactly one finalize call (got {n_fin_calls})"

    # windows partition: authority is checkpoint port.event_start/end
    cursor = 0
    begin_ok = False
    for ci, c in enumerate(calls):
        cp = c.get("checkpoint")
        if not isinstance(cp, dict):
            return f"calls[{ci}] missing checkpoint"
        port = cp.get("port") or {}
        if not isinstance(port, dict):
            return f"calls[{ci}] port missing"
        es, ee = port.get("event_start"), port.get("event_end")
        if not _is_u32(es) or not _is_u32(ee):
            return f"calls[{ci}] port window types"
        if es != cursor:
            return f"calls[{ci}] window gap/overlap: start {es} want {cursor}"
        if ee < es or ee > ntrace:
            return f"calls[{ci}] bad event_end {ee}"
        # every event in window must carry this call's api_call_index
        for ti in range(es, ee):
            if ptrace[ti]["api_call_index"] != ci:
                return (
                    f"port_trace[{ti}]: api_call_index {ptrace[ti]['api_call_index']} "
                    f"!= call index {ci}"
                )
        # legacy trace_begin/end must equal port window
        tb, te = c.get("trace_begin"), c.get("trace_end")
        if not _is_u32(tb) or not _is_u32(te) or tb != es or te != ee:
            return f"calls[{ci}] trace_begin/end must equal port event_start/end"

        fin = c.get("op") == "finalize"
        # successful begin detected after first call with 17 profile gets
        if ci == 0:
            window = ptrace[es:ee]
            if len(window) < 1 or window[0].get("op") != "begin":
                return "begin window must start with begin"
            n_base = 0
            for ev in window[1:]:
                if ev.get("op") != "get":
                    break
                n_base += 1
            # O1b-B: successful begin window is begin + exactly 17 GETs + iter_open→I1
            if c.get("expected_status") in ("OK", OUT_OK) and window[0].get("storage_status") == "OK":
                if n_base != 17:
                    return (
                        f"successful begin window must be begin+17 GETs+I1 "
                        f"(got gets={n_base})"
                    )
                if len(window) != 19 or window[-1].get("op") != "iter_open":
                    return (
                        f"successful begin window must end with iter_open I1 "
                        f"(window={len(window)} last={window[-1].get('op') if window else None})"
                    )
                if window[-1].get("output_handle_id") != "I1":
                    return f"begin I1 handle want I1 got {window[-1].get('output_handle_id')}"
                begin_ok = True
            after_begin = False
        else:
            after_begin = begin_ok

        err = validate_checkpoint(
            cp, finalize=fin, trace_len=ntrace, after_successful_begin=after_begin or begin_ok,
        )
        if err:
            return f"calls[{ci}] checkpoint: {err}"

        # cumulative op counters vs trace prefix [0, ee)
        counts = {
            "begin": 0, "get": 0, "iter_open": 0, "iter_next": 0,
            "iter_close": 0, "rollback": 0, "close": 0,
        }
        h1 = True
        t1 = False
        ilive: Optional[str] = None
        for ev in ptrace[:ee]:
            counts[ev["op"]] = counts.get(ev["op"], 0) + 1
            if ev["op"] == "begin" and ev["storage_status"] == "OK":
                t1 = True
            elif ev["op"] == "iter_open" and ev["storage_status"] == "OK":
                ilive = ev["output_handle_id"]
            elif ev["op"] == "iter_close":
                ilive = None
            elif ev["op"] == "rollback":
                t1 = False
            elif ev["op"] == "close":
                h1 = False
        for name, field in (
            ("begin", "begin_count"), ("get", "get_count"),
            ("iter_open", "iter_open_count"), ("iter_next", "iter_next_count"),
            ("iter_close", "iter_close_count"), ("rollback", "rollback_count"),
            ("close", "close_count"),
        ):
            if port[field] != counts.get(name, 0):
                return (
                    f"calls[{ci}] {field}={port[field]} != trace prefix count "
                    f"{counts.get(name, 0)}"
                )
        if port["trace_count"] != ee:
            return f"calls[{ci}] trace_count != event_end"
        # exposed live handle IDs match replay at end of window
        want_h = HANDLE_H1 if h1 else None
        want_t = HANDLE_T1 if t1 else None
        if port.get("storage_handle_id") != want_h:
            return f"calls[{ci}] storage_handle_id want {want_h} got {port.get('storage_handle_id')}"
        if port.get("txn_handle_id") != want_t:
            return f"calls[{ci}] txn_handle_id want {want_t} got {port.get('txn_handle_id')}"
        if port.get("iter_handle_id") != ilive:
            return f"calls[{ci}] iter_handle_id want {ilive} got {port.get('iter_handle_id')}"
        if port.get("mutation_calls") != 0:
            return f"calls[{ci}] mutation_calls"
        # session liveness flags vs replay (best-effort mechanical)
        sess = cp["session"]
        if _is_bit01(sess.get("txn_live")) and sess["txn_live"] != (1 if t1 else 0):
            return f"calls[{ci}] session.txn_live vs replay"
        if _is_bit01(sess.get("iter_live")) and sess["iter_live"] != (1 if ilive else 0):
            return f"calls[{ci}] session.iter_live vs replay"

        cursor = ee

    if cursor != ntrace:
        return f"windows do not cover full trace: end={cursor} len={ntrace}"
    # after final formal call: T1 and iterator dead; H1 may remain or be closed
    if t1_live:
        return "after final call T1 still live"
    if iter_live is not None:
        return f"after final call iterator still live ({iter_live})"
    # §18.14.19.4 closed matrix + terminal table + G/W/WG entry liveness
    mx = validate_rep1_drive_dispatch(v)
    if mx is not None:
        return f"rep1 matrix/dispatch: {mx}"
    ug = validate_rep1_unit_grammar(v)
    if ug is not None:
        return f"rep1 unit grammar: {ug}"
    return None




def _rep1_g_entry_context(
    mode: int,
    entry_phase: int,
    entry_sem: int,
    rows: List[Dict[str, str]],
    entry_d3: Dict[str, Any],
) -> Optional[Dict[str, Any]]:
    """Shared fixture+entry context for G key planning and semantic-stop simulation."""
    idx = o1a_index(rows)
    lck_hex = entry_d3.get("last_carrier_key_hex") or ""
    try:
        carrier_k = bytes.fromhex(lck_hex) if lck_hex else b""
    except ValueError:
        carrier_k = b""
    fid_hex = entry_d3.get("focus_id16_hex") or ("00" * 16)
    try:
        focus_id16 = bytes.fromhex(fid_hex)
    except ValueError:
        focus_id16 = bytes(16)
    reply_kind = int(entry_d3.get("reply_kind") or 0)

    def _man_for_dig(dig: bytes) -> Optional[Dict[str, Any]]:
        for r in rows:
            k, v = o1a_row_key(r), o1a_row_val(r)
            if o1a_subtype(k) == 0x30 and o1a_flags(v) == 1 and d3s1.key_digest(k) == dig:
                try:
                    return o1a_dec_man(k, v)
                except ValueError:
                    return None
        return None

    return {
        "idx": idx,
        "carrier_k": carrier_k,
        "focus_id16": focus_id16,
        "reply_kind": reply_kind,
        "man_for_dig": _man_for_dig,
        "rows": rows,
        "mode": mode,
        "entry_phase": entry_phase,
        "entry_sem": entry_sem,
    }


def rep1_expected_g_request_keys(
    mode: int,
    entry_phase: int,
    entry_sem: int,
    rows: List[Dict[str, str]],
    entry_d3: Dict[str, Any],
) -> Optional[List[bytes]]:
    """Derive successful-G full planned request keys from fixture rows + entry only.

    Independent of port_trace (anti-circular). Returns None if unit is not a
    product G with a closed request schedule under REP1-v1. This is the *full*
    plan; use rep1_expected_g_realized_keys for semantic-stop / ABSENT length.
    """
    ctx = _rep1_g_entry_context(mode, entry_phase, entry_sem, rows, entry_d3)
    if ctx is None:
        return None
    idx = ctx["idx"]
    carrier_k = ctx["carrier_k"]
    focus_id16 = ctx["focus_id16"]
    _man_for_dig = ctx["man_for_dig"]

    # SELECT_SETUP G
    if entry_phase == PHASE_SELECT_CARRIER and entry_sem == SEM_SELECT_SETUP:
        if mode == 27:
            keys = [o1a_state_key(focus_id16)]
            if carrier_k in idx and o1a_anchor_is_event_fact(idx[carrier_k]):
                keys.append(o1a_spool_key(focus_id16))
            return keys
        if mode == 29:
            if carrier_k not in idx:
                return []
            raw = o1a_dec_dlv(idx[carrier_k])["owner_raw"]
            return [o1a_rc_key(raw)]
        return []

    # OWNER_PVD G
    if entry_phase in (PHASE_OWNER_PVD_PROOF, PHASE_OWNER_PVD_PROOF_B):
        if not carrier_k:
            return []
        return [carrier_k]

    # FOCUS_CHUNKS G (A/B)
    if entry_phase in (PHASE_FOCUS_CHUNKS, PHASE_FOCUS_CHUNKS_B):
        if not carrier_k or carrier_k not in idx:
            return []
        cv = idx[carrier_k]
        if mode == 27:
            dig = o1a_dec_anchor_payload_dig(cv)
        elif mode == 28:
            tail = o1a_dec_ingress_tail(cv)
            dig = tail["view_a"] if entry_phase == PHASE_FOCUS_CHUNKS else tail["view_b"]
            if dig == O1A_ZERO32:
                return []
        elif mode == 29:
            dig = o1a_dec_dlv(cv)["payload_blob_key_digest"]
        elif mode == 30:
            dig = o1a_dec_rr(cv)["body_blob_key_digest"]
        else:
            return []
        man = _man_for_dig(dig)
        if man is None:
            return []
        return [o1a_chk_key_from_blob_index(man["blob_id"], i) for i in range(int(man["chunk_count"]))]

    # PREFIX G
    if entry_phase == PHASE_SEMANTIC_PREFIX_REGET and entry_sem == 0:
        if mode == 28:
            return [carrier_k] if carrier_k else []
        if mode == 30:
            if not carrier_k or carrier_k not in idx:
                return []
            rr = o1a_dec_rr(idx[carrier_k])
            raw = rr["delivery_raw"]
            keys = [carrier_k, o1a_dlv_key(raw), o1a_rc_key(raw)]
            rk = int(rr["reply_kind"])
            if rk == 1:
                keys.append(o1a_cell_key(raw, 0))
            elif rk == 4:
                keys.append(o1a_cs_key(raw))
            return keys
        return []

    # SEM_CHUNK / view chunks G
    if entry_phase == PHASE_SEMANTIC_CHUNK_REWALK:
        if mode == 30:
            if not carrier_k or carrier_k not in idx:
                return []
            rr = o1a_dec_rr(idx[carrier_k])
            if int(rr["reply_kind"]) != 1:
                return []
            dig = rr["body_blob_key_digest"]
            man = _man_for_dig(dig)
            if man is None:
                return []
            return [o1a_chk_key_from_blob_index(man["blob_id"], i) for i in range(int(man["chunk_count"]))]
        if mode == 28:
            if not carrier_k or carrier_k not in idx:
                return []
            tail = o1a_dec_ingress_tail(idx[carrier_k])
            dig = tail["view_a"] if entry_sem == 2 else tail["view_b"] if entry_sem == 4 else O1A_ZERO32
            if dig == O1A_ZERO32:
                return []
            man = _man_for_dig(dig)
            if man is None:
                return []
            return [o1a_chk_key_from_blob_index(man["blob_id"], i) for i in range(int(man["chunk_count"]))]
        return []
    return None


def rep1_expected_g_realized_keys(
    mode: int,
    entry_phase: int,
    entry_sem: int,
    rows: List[Dict[str, str]],
    entry_d3: Dict[str, Any],
) -> Optional[List[bytes]]:
    """Exact G request-key sequence including fixture semantic-stop / ABSENT.

    Walks the full planned keys against fixture storage and stops at the first
    of: missing key (NOT_FOUND attempt included), typed-current fail after OK
    get, or product semantic reject after inspecting the returned value.
    Independent of port_trace. Does not model formal NATURAL Port faults
    (those are status-aware prefixes of the full plan; see grammar).
    """
    planned = rep1_expected_g_request_keys(
        mode, entry_phase, entry_sem, rows, entry_d3
    )
    if planned is None:
        return None
    if not planned:
        return []

    ctx = _rep1_g_entry_context(mode, entry_phase, entry_sem, rows, entry_d3)
    assert ctx is not None
    idx: Dict[bytes, bytes] = ctx["idx"]
    carrier_k: bytes = ctx["carrier_k"]
    focus_id16: bytes = ctx["focus_id16"]
    reply_kind = int(ctx["reply_kind"])
    _man_for_dig = ctx["man_for_dig"]

    def _present(k: bytes) -> Optional[bytes]:
        return idx.get(k)

    def _typed_ok(val: bytes, subtype: int, flags: int) -> bool:
        return o1a_value_typed_current(val, expect_subtype=subtype, expect_flags=flags) is None

    out: List[bytes] = []

    # ---- SELECT_SETUP (mirror _drive_select_setup_g stop boundaries) ----
    if entry_phase == PHASE_SELECT_CARRIER and entry_sem == SEM_SELECT_SETUP:
        if mode == 27:
            # planned: STATE [+ SPOOL if EventFact]. Stop after STATE if typed/decode fails.
            for i, k in enumerate(planned):
                out.append(k)
                val = _present(k)
                if val is None:
                    return out
                if i == 0:
                    # TRANSACTION_STATE: subtype 0x22 flags 0 + discarded decode
                    if not _typed_ok(val, 0x22, 0):
                        return out
                    try:
                        o1a_dec_state_discarded(val)
                    except Exception:
                        return out
                else:
                    # EVENT_SPOOL: subtype 0x50 flags 0 (typed current only)
                    if not _typed_ok(val, 0x50, 0):
                        return out
            return out
        if mode == 29:
            for k in planned:
                out.append(k)
                val = _present(k)
                if val is None:
                    return out
                if not _typed_ok(val, 0x41, 0):
                    return out
                try:
                    o1a_dec_rc(val)
                except Exception:
                    return out
            return out
        # other modes: empty plan
        return out

    # ---- OWNER_PVD ----
    if entry_phase in (PHASE_OWNER_PVD_PROOF, PHASE_OWNER_PVD_PROOF_B):
        want_st = {27: 0x20, 28: 0x27, 29: 0x40, 30: 0x42}.get(mode, 0x20)
        # man expected_owner_pvd from dig-matching man (focus_key_digest path)
        man = None
        # recover man via carrier payload dig (same as FOCUS path)
        if carrier_k and carrier_k in idx:
            cv = idx[carrier_k]
            try:
                if mode == 27:
                    dig = o1a_dec_anchor_payload_dig(cv)
                elif mode == 28:
                    dig = o1a_dec_ingress_tail(cv)["view_a"]
                elif mode == 29:
                    dig = o1a_dec_dlv(cv)["payload_blob_key_digest"]
                elif mode == 30:
                    dig = o1a_dec_rr(cv)["body_blob_key_digest"]
                else:
                    dig = O1A_ZERO32
                man = _man_for_dig(dig)
            except (ValueError, KeyError, struct.error, TypeError):
                man = None
        for k in planned:
            out.append(k)
            val = _present(k)
            if val is None:
                return out
            if not _typed_ok(val, want_st, 0):
                return out  # TYPED_FAIL after OK get
            if man is None or d3s1.value_digest(val) != man.get("expected_owner_pvd"):
                return out  # semantic stop after this GET
        return out

    # ---- FOCUS_CHUNKS / SEM_CHUNK ----
    if entry_phase in (
        PHASE_FOCUS_CHUNKS, PHASE_FOCUS_CHUNKS_B, PHASE_SEMANTIC_CHUNK_REWALK
    ):
        man = None
        if carrier_k and carrier_k in idx:
            cv = idx[carrier_k]
            try:
                if mode == 27:
                    dig = o1a_dec_anchor_payload_dig(cv)
                elif mode == 28:
                    tail = o1a_dec_ingress_tail(cv)
                    if entry_phase == PHASE_SEMANTIC_CHUNK_REWALK:
                        dig = tail["view_a"] if entry_sem == 2 else tail["view_b"] if entry_sem == 4 else O1A_ZERO32
                    else:
                        dig = tail["view_a"] if entry_phase == PHASE_FOCUS_CHUNKS else tail["view_b"]
                elif mode == 29:
                    dig = o1a_dec_dlv(cv)["payload_blob_key_digest"]
                elif mode == 30:
                    dig = o1a_dec_rr(cv)["body_blob_key_digest"]
                else:
                    dig = O1A_ZERO32
                man = _man_for_dig(dig)
            except (ValueError, KeyError, struct.error, TypeError):
                man = None
        if man is None:
            # no man: empty plan already handled; if plan non-empty, first get fails typed/absent
            for k in planned:
                out.append(k)
                return out
        for i, k in enumerate(planned):
            out.append(k)
            val = _present(k)
            if val is None:
                return out
            if not _typed_ok(val, 0x30, 2):
                return out
            try:
                ch = o1a_dec_chunk(k, val)
            except ValueError:
                return out
            if (
                ch["blob_id"] != man["blob_id"]
                or ch["chunk_count"] != man["chunk_count"]
                or ch["total_length"] != man["total_length"]
                or ch["content_digest"] != man["content_digest"]
                or ch["manifest_key_digest"] != man["key_digest"]
                or ch["index"] != i
                or ch["primary_value_digest"] != man["expected_manifest_value_digest"]
            ):
                return out
        return out

    # ---- PREFIX Mode28: single carrier reget ----
    if entry_phase == PHASE_SEMANTIC_PREFIX_REGET and entry_sem == 0 and mode == 28:
        for k in planned:
            out.append(k)
            val = _present(k)
            if val is None:
                return out
            if not _typed_ok(val, 0x27, 0):
                return out
        return out

    # ---- PREFIX Mode30: RR → DLV → RC → CELL/CS ----
    if entry_phase == PHASE_SEMANTIC_PREFIX_REGET and entry_sem == 0 and mode == 30:
        if not carrier_k or carrier_k not in idx:
            return []
        try:
            rr0 = o1a_dec_rr(idx[carrier_k])
        except (ValueError, KeyError, struct.error):
            # still attempt first planned get then stop
            if planned:
                out.append(planned[0])
            return out
        raw80 = rr0["delivery_raw"]
        select_tx = focus_id16
        select_rk = int(reply_kind) if reply_kind else int(rr0["reply_kind"])
        select_sem = rr0["semantic_digest"]
        select_blob = rr0["body_blob_key_digest"]
        select_send = int(rr0["send_state"])
        man = _man_for_dig(select_blob)
        kind_map = {1: 2, 2: 3, 3: 5, 4: 6}
        # step helpers mirror _drive_mode30_prefix_g
        # 1) RR
        k = planned[0]
        out.append(k)
        val = _present(k)
        if val is None:
            return out
        if not _typed_ok(val, 0x42, 0):
            return out
        try:
            rr = o1a_dec_rr(val)
        except (ValueError, struct.error):
            return out
        if (
            rr["delivery_raw"] != raw80
            or rr["transaction_id"] != select_tx
            or int(rr["reply_kind"]) != select_rk
            or rr["semantic_digest"] != select_sem
            or rr["body_blob_key_digest"] != select_blob
            or int(rr["send_state"]) != select_send
            or (man is not None and rr["body_blob_key_digest"] != man["key_digest"])
            or man is None
        ):
            return out
        if select_rk not in kind_map:
            return out
        rk = select_rk
        # 2) DLV
        if len(planned) < 2:
            return out
        k = planned[1]
        out.append(k)
        val = _present(k)
        if val is None:
            return out
        if not _typed_ok(val, 0x40, 0):
            return out
        try:
            d = o1a_dec_dlv(val)
        except (ValueError, struct.error):
            return out
        if d["owner_raw"] != raw80 or d["transaction_id"] != select_tx:
            return out
        if d3s1.value_digest(val) != man["expected_owner_pvd"]:
            return out
        # 3) RC
        if len(planned) < 3:
            return out
        k = planned[2]
        out.append(k)
        val = _present(k)
        if val is None:
            return out
        if not _typed_ok(val, 0x41, 0):
            return out
        try:
            rc = o1a_dec_rc(val)
        except (ValueError, struct.error):
            return out
        if rk == 1 and rc["app_kind"] != 1:
            return out
        if rk == 2 and rc["app_kind"] != 2:
            return out
        if rk == 3 and rc["app_kind"] == 2:
            return out
        rc_stage = rc["evidence_stage"]
        rc_cancel = rc["cancel_result_kind"]
        # 4) CELL / CS optional
        if len(planned) < 4:
            return out
        if rk == 1:
            k = planned[3]
            out.append(k)
            val = _present(k)
            if val is None:
                return out
            if not _typed_ok(val, 0x32, 0):
                return out
            try:
                cm = o1a_dec_cell(val)
            except (ValueError, struct.error):
                return out
            if cm["material_receipt_stage"] != rc_stage:
                return out
            if cm["evidence_length"] != man["total_length"] or cm["evidence_length"] > 128:
                return out
            if cm["evidence_digest"] != man["content_digest"]:
                return out
            evi = cm["evidence_bytes"]
            if len(evi) != cm["evidence_length"]:
                return out
            return out
        if rk == 4:
            k = planned[3]
            out.append(k)
            val = _present(k)
            if val is None:
                return out
            if not _typed_ok(val, 0x33, 0):
                return out
            try:
                cancel_kind = o1a_dec_cancel_kind(val)
            except (ValueError, struct.error):
                return out
            if cancel_kind not in (1, 3) or rc_cancel != cancel_kind:
                return out
            return out
        return out

    # default: no early semantic model → full planned (presence only)
    for k in planned:
        out.append(k)
        if _present(k) is None:
            return out
    return out


def rep1_g_fixture_get_status(rows: List[Dict[str, str]], key: bytes) -> str:
    """Independent fixture result for a G request key: present→OK, absent→NOT_FOUND.

    Does not consult port_trace. Semantic/typed failure after an OK GET still
    records Storage status OK; only key presence drives this column.
    """
    idx = o1a_index(rows)
    return "OK" if key in idx else "NOT_FOUND"


def validate_formal_fault_trace_binding(v: Dict[str, Any]) -> Optional[str]:
    """R14/R15/R18: formal faults[] exactly binds the single natural Port event.

    Independent of rebuild equality. Closed faults length 0|1; shape=natural;
    natural Storage statuses appear exactly once in port_trace when a fault is
    configured, and that event's op/on_call/status match faults[0] exactly.
    No natural event without a configured fault; configured fault must be observed.
    R15/R18: formal_precheck / legacy zero-Port forbids configured faults / used=1.
    """
    exp = v.get("expected") or {}
    # R16: missing faults key → []; present falsy non-list ({} / "") → type RED.
    if "faults" not in v:
        faults: Any = []
    else:
        faults = v.get("faults")
    if type(faults) is not list:
        return "formal fault binding: faults not list"
    if len(faults) > 1:
        return "formal fault binding: faults length must be 0|1"
    # R16: never `or []` — {} / "" must not become empty-list green.
    ptrace = exp.get("port_trace", [])
    if type(ptrace) is not list:
        return "formal fault binding: port_trace not list"
    natural_idxs = [
        i
        for i, ev in enumerate(ptrace)
        if isinstance(ev, dict) and ev.get("storage_status") in STORAGE_NATURAL
    ]
    used = int(exp.get("faults_expected_used", 0) or 0)
    # R18 formal_precheck: no production Port; faults must be clean empty.
    if is_formal_precheck_vector(v) or is_zero_port_precheck_failed(exp):
        if len(faults) != 0:
            return "formal fault binding: zero-Port forbids configured fault"
        if used != 0:
            return "formal fault binding: zero-Port faults_expected_used want 0"
        if natural_idxs:
            return "formal fault binding: zero-Port natural event forbidden"
        if ptrace:
            return "formal fault binding: zero-Port port_trace must be empty"
        return None
    if len(faults) == 0:
        if natural_idxs:
            return "formal fault binding: natural event without configured fault"
        if used != 0:
            return "formal fault binding: faults_expected_used want 0"
        return None
    # length 1
    f = faults[0]
    if not isinstance(f, dict):
        return "formal fault binding: fault not object"
    if f.get("shape") != "natural":
        return "formal fault binding: shape must be natural"
    want_keys = frozenset({"op", "on_call", "status", "shape"})
    if frozenset(f.keys()) != want_keys:
        return "formal fault binding: fault keys closed {op,on_call,status,shape}"
    if f.get("op") not in ("get", "iter_open", "iter_next", "rollback"):
        return "formal fault binding: fault op"
    if f.get("status") not in STORAGE_NATURAL:
        return "formal fault binding: fault status not NATURAL"
    if not _is_u32(f.get("on_call")) or int(f["on_call"]) < 1:
        return "formal fault binding: fault on_call"
    if len(natural_idxs) == 0:
        return "formal fault binding: configured fault unobserved"
    if len(natural_idxs) != 1:
        return "formal fault binding: want exactly one natural event"
    ev = ptrace[natural_idxs[0]]
    if (
        ev.get("op") != f.get("op")
        or int(ev.get("on_call", -1)) != int(f["on_call"])
        or ev.get("storage_status") != f.get("status")
    ):
        return (
            "formal fault binding: mismatch op/on_call/status "
            f"fault=({f.get('op')},{f.get('on_call')},{f.get('status')}) "
            f"event=({ev.get('op')},{ev.get('on_call')},{ev.get('storage_status')})"
        )
    if used != 1:
        return "formal fault binding: faults_expected_used want 1"
    return None


def validate_rep1_unit_grammar(v: Dict[str, Any]) -> Optional[str]:
    """Independent per-drive unit grammar: W GET ban, G no iter, WG shape, budgets, fault-tail.

    Re-derives W/G/WG from entry triple (prior drive exit / begin). Does not trust notes.
    """
    mode = int(v.get("mode", -1))
    if mode not in _REP1_MODES:
        return f"mode {mode}"
    exp = v.get("expected") or {}
    # R15/R18: formal_precheck / zero-Port still runs fault binding.
    fb = validate_formal_fault_trace_binding(v)
    if fb is not None:
        return fb
    # Call grammar applies only to rep1_l2 (R18).
    if is_formal_precheck_vector(v) or is_zero_port_precheck_failed(exp):
        return None
    rows = v.get("rows") or []
    n = len(rows)
    # R16: explicit type; no falsy non-list coercion.
    ptrace = exp.get("port_trace", [])
    if type(ptrace) is not list:
        return "port_trace not list"
    calls = v.get("calls") or []
    formal_class = v.get("formal_class") or FORMAL_CLASS_ORDINARY
    # entry after successful begin
    entry_phase, entry_pk, entry_sem = 1, PASS_BASELINE, 0
    entry_state, entry_txn, entry_iter = SS_OPEN, 1, 1
    entry_flags = 0
    entry_d3_prev: Dict[str, Any] = {}
    b5_midwalk_done = False
    for ci, c in enumerate(calls):
        op = c.get("op")
        if op == "begin_profiled_d3s3":
            cp = c.get("checkpoint") or {}
            d3 = cp.get("d3s3") or {}
            sess = cp.get("session") or {}
            if int(d3.get("phase", -1)) == PHASE_BASELINE:
                entry_phase, entry_pk, entry_sem = 1, PASS_BASELINE, 0
                entry_state = sess.get("state", SS_OPEN)
                entry_txn = int(sess.get("txn_live", 0))
                entry_iter = int(sess.get("iter_live", 0))
                entry_flags = int(d3.get("flags", 0))
            continue
        if op != "d3s3_drive":
            if op == "finalize":
                continue
            continue
        unit = rep1_matrix_unit(entry_phase, mode, entry_sem)
        if entry_phase not in (13, 14) and unit is None:
            return f"calls[{ci}] entry matrix miss p={entry_phase} m={mode} sem={entry_sem}"
        rb = int(c.get("row_budget", -1))
        # budgets
        if unit == "G":
            if rb != 0:
                return f"calls[{ci}] G row_budget want 0 got {rb}"
        elif unit in ("W", "WG"):
            if formal_class == FORMAL_CLASS_B5_BASELINE and entry_phase == 1 and not b5_midwalk_done:
                if rb != n:
                    # first B5 may be N; allow only when exit stays BASELINE OPEN
                    pass
            elif unit in ("W", "WG") and entry_phase != 1:
                if rb != n + 1:
                    return f"calls[{ci}] ordinary {unit} row_budget want N+1={n+1} got {rb}"
            elif entry_phase == 1:
                if formal_class == FORMAL_CLASS_B5_BASELINE and not b5_midwalk_done:
                    if rb not in (n, n + 1):
                        return f"calls[{ci}] B5 BASELINE budget {rb}"
                else:
                    if rb != n + 1:
                        return f"calls[{ci}] BASELINE W budget want N+1 got {rb}"
        cp = c.get("checkpoint") or {}
        port = cp.get("port") or {}
        es, ee = int(port.get("event_start", 0)), int(port.get("event_end", 0))
        window = ptrace[es:ee]
        # liveness entry
        if unit == "G":
            if entry_state != SS_EXHAUSTED or entry_txn != 1 or entry_iter != 1:
                if window:
                    return (
                        f"calls[{ci}] G entry liveness with Port events "
                        f"state={entry_state} txn={entry_txn} iter={entry_iter}"
                    )
        if unit in ("W", "WG"):
            need = (entry_flags & FLAG_NEED_REOPEN) != 0
            if entry_iter != 1 and window:
                return f"calls[{ci}] {unit} entry iter_live=0 with Port"
            # reopen prefix exact
            wi = 0
            if entry_phase != 1 and need and entry_iter == 1:
                if len(window) < 2:
                    # may be INVALID_STATE zero port already handled
                    if window:
                        return f"calls[{ci}] NEED_REOPEN prefix short"
                else:
                    if window[0].get("op") != "iter_close":
                        return f"calls[{ci}] NEED_REOPEN want close first"
                    if window[1].get("op") != "iter_open":
                        return f"calls[{ci}] NEED_REOPEN want open second"
                    wi = 2
            elif entry_phase != 1 and not need:
                # neither close nor open at start
                if window and window[0].get("op") in ("iter_close", "iter_open"):
                    return f"calls[{ci}] NEED=0 must not close/open first"
        # unit body grammar
        d3 = cp.get("d3s3") or {}
        sess = cp.get("session") or {}
        call_ok = c.get("expected_status") in ("OK", OUT_OK)
        sticky = int(sess.get("has_sticky_primary", 0) or 0) == 1
        if unit == "W":
            for ev in window:
                if ev.get("op") == "get":
                    return f"calls[{ci}] W window must not contain get"
            body = window
            if entry_phase != 1 and (entry_flags & FLAG_NEED_REOPEN) and entry_iter == 1 and len(window) >= 2:
                body = window[2:]
            for ev in body:
                if ev.get("op") not in ("iter_next",):
                    if ev.get("op") in ("iter_close", "iter_open", "get", "begin", "rollback"):
                        return f"calls[{ci}] W illegal op {ev.get('op')}"
            # Successful non-B5 W (and B5 resume/true-exhaust W) must end iter_next NOT_FOUND.
            # B5 first midwalk OPEN BASELINE is the only success exception.
            b5_open = (
                formal_class == FORMAL_CLASS_B5_BASELINE
                and entry_phase == 1
                and not b5_midwalk_done
                and sess.get("state") == SS_OPEN
                and int(d3.get("phase", -1)) == PHASE_BASELINE
            )
            if call_ok and not sticky and not b5_open:
                if not body or body[-1].get("op") != "iter_next" or body[-1].get("storage_status") != "NOT_FOUND":
                    return f"calls[{ci}] successful non-B5 W must end iter_next NOT_FOUND"
        elif unit == "G":
            for ev in window:
                if ev.get("op") in ("iter_next", "iter_open", "iter_close"):
                    return f"calls[{ci}] G must not {ev.get('op')}"
                if ev.get("op") not in ("get",):
                    if ev.get("op") in ("begin", "rollback", "close"):
                        return f"calls[{ci}] G illegal op {ev.get('op')}"
            # Independent G schedule (R13): fixture rows + entry checkpoint only.
            # planned = full success plan; realized = exact keys through ABSENT/semantic stop.
            # - success: got == planned (== realized when fixture OK)
            # - natural Port fault: got == planned[:n], last NATURAL; prior keys must be a
            #   proper prefix of realized (fixture would not have stopped earlier)
            # - fixture ABSENT / early semantic: got == realized exactly (no short/long)
            entry_d3_for_g = entry_d3_prev if entry_d3_prev else d3
            planned_keys = rep1_expected_g_request_keys(
                mode, entry_phase, entry_sem, rows, entry_d3_for_g
            )
            if planned_keys is not None:
                got_evs = [ev for ev in window if ev.get("op") == "get"]
                try:
                    got = [bytes.fromhex(ev["request_key_hex"]) for ev in got_evs]
                except (KeyError, ValueError, TypeError):
                    return f"calls[{ci}] G GET request_key_hex unreadable"
                preflight_zero = (
                    not window
                    and c.get("expected_status") in (OUT_INVALID_STATE, "NINLIL_E_INVALID_STATE")
                )
                if preflight_zero:
                    pass
                elif len(planned_keys) == 0:
                    if got:
                        return f"calls[{ci}] G GET schedule mismatch want=0 got={len(got)}"
                else:
                    realized = rep1_expected_g_realized_keys(
                        mode, entry_phase, entry_sem, rows, entry_d3_for_g
                    )
                    if realized is None:
                        return f"calls[{ci}] G realized schedule underivable"
                    last_st = got_evs[-1].get("storage_status") if got_evs else None
                    natural_tail = last_st in STORAGE_NATURAL
                    if natural_tail:
                        # Exact planned prefix through fault attempt; fixture would not stop sooner.
                        if (
                            len(got) < 1
                            or len(got) > len(planned_keys)
                            or got != planned_keys[: len(got)]
                        ):
                            return (
                                f"calls[{ci}] G GET schedule mismatch "
                                f"want={len(planned_keys)} got={len(got)}"
                            )
                        # R14: prior OK GETs must be a *proper* prefix of realized
                        # (prior_n < len(realized)). Equality would allow a natural
                        # GET after the semantic-stop row (off-by-one). Fault may
                        # land on the semantic-failing GET itself (prior_n == len-1).
                        prior_n = len(got) - 1
                        if prior_n >= len(realized):
                            return (
                                f"calls[{ci}] G GET natural after fixture stop "
                                f"realized={len(realized)} got={len(got)}"
                            )
                        if got[:prior_n] != realized[:prior_n]:
                            return (
                                f"calls[{ci}] G GET schedule mismatch "
                                f"want={len(realized)} got={len(got)}"
                            )
                        # R15: prior GET statuses = fixture presence (OK/NOT_FOUND);
                        # tail alone may be configured NATURAL.
                        for i in range(prior_n):
                            want_st = rep1_g_fixture_get_status(rows, got[i])
                            got_st = got_evs[i].get("storage_status")
                            if got_st != want_st:
                                return (
                                    f"calls[{ci}] G GET status mismatch "
                                    f"i={i} want={want_st} got={got_st}"
                                )
                    else:
                        # Success / ABSENT / semantic: exact realized sequence (full or stop).
                        if got != realized:
                            return (
                                f"calls[{ci}] G GET schedule mismatch "
                                f"want={len(realized)} got={len(got)}"
                            )
                        if call_ok and not sticky and got != planned_keys:
                            return (
                                f"calls[{ci}] G GET schedule mismatch "
                                f"want={len(planned_keys)} got={len(got)}"
                            )
                        # R15: each GET storage_status exact fixture column (no port_trace copy).
                        for i, k in enumerate(got):
                            want_st = rep1_g_fixture_get_status(rows, k)
                            got_st = got_evs[i].get("storage_status")
                            if got_st != want_st:
                                return (
                                    f"calls[{ci}] G GET status mismatch "
                                    f"i={i} want={want_st} got={got_st}"
                                )
        elif unit == "WG":
            body = window
            if entry_phase != 1 and (entry_flags & FLAG_NEED_REOPEN) and entry_iter == 1:
                if len(window) >= 2 and window[0].get("op") == "iter_close" and window[1].get("op") == "iter_open":
                    body = window[2:]
            for ei, ev in enumerate(body):
                op = ev.get("op")
                st = ev.get("storage_status")
                if op not in ("iter_next", "get"):
                    return f"calls[{ci}] WG illegal op {op}"
                # GET NOT_FOUND or any NATURAL GET is always last operational event
                if op == "get" and st == "NOT_FOUND" and ei != len(body) - 1:
                    return f"calls[{ci}] WG GET NOT_FOUND must be last operational event"
                if st in STORAGE_NATURAL and ei != len(body) - 1:
                    return f"calls[{ci}] natural fault must be last operational event"
            if call_ok and not sticky:
                if not body or body[-1].get("op") != "iter_next" or body[-1].get("storage_status") != "NOT_FOUND":
                    return f"calls[{ci}] successful WG must end iter_next NOT_FOUND"
            for ei, ev in enumerate(body):
                if ev.get("op") == "get":
                    if ei == 0 or body[ei - 1].get("op") != "iter_next" or body[ei - 1].get("storage_status") != "OK":
                        return f"calls[{ci}] WG get must immediately follow iter_next OK"

        # fault last-event for any unit with natural fault in window
        for ei, ev in enumerate(window):
            if ev.get("storage_status") in STORAGE_NATURAL:
                if ei != len(window) - 1:
                    return f"calls[{ci}] natural fault not last event"
                break

        # B5 track (d3/sess already bound in unit body)
        if formal_class == FORMAL_CLASS_B5_BASELINE and entry_phase == 1:
            if sess.get("state") == SS_OPEN and int(d3.get("phase", -1)) == PHASE_BASELINE:
                b5_midwalk_done = True
        # advance entry from this drive's exit checkpoint
        entry_d3_prev = dict(d3)
        entry_phase = int(d3.get("phase", -1))
        entry_pk = int(d3.get("pass_kind", -1))
        entry_sem = int(d3.get("semantic_pass", -1))
        entry_state = sess.get("state")
        entry_txn = int(sess.get("txn_live", 0))
        entry_iter = int(sess.get("iter_live", 0))
        entry_flags = int(d3.get("flags", 0))
    return None



def vec(
    vid: str,
    kind: str,
    mode: int,
    rows: List[Dict[str, str]],
    cases: List[int],
    notes: str,
    faults: Optional[List] = None,
    *,
    formal_class: str = FORMAL_CLASS_ORDINARY,
    **top_meta: Any,
) -> Dict[str, Any]:
    """Build one vector: fixture rows/faults only; independent evaluator inside.

    No expected / outcome / fail_at / stage / positive injection parameters.
    Formal vector field ``faults`` is always a built-in list of length 0 or 1
    (never JSON null). API omission ``None`` is canonicalized once to ``[]``.
    ``formal_class`` is a closed keyword argument (§18.14.19.2); default ordinary.
    """
    if formal_class not in FORMAL_VECTOR_CLASSES:
        raise ValueError(
            f"{vid}: unknown formal_class {formal_class!r}; "
            f"closed set {sorted(FORMAL_VECTOR_CLASSES)}"
        )
    # R19: every fixture row must be locally D1-legal (constructible-fixture rule).
    # formal_precheck may duplicate complete keys; each row still passes this gate.
    d1_err = d1_rows_legality_gate(rows)
    if d1_err is not None:
        raise SystemExit(f"{vid}: D1-illegal fixture: {d1_err}")
    # Canonicalize once for serialization + oracle input. Do not destroy caller's list:
    # None → new []; explicit list reused as-is; non-list rejected by RefSession.
    if faults is None:
        faults_canon: List = []
    else:
        faults_canon = faults
    packed = RefSession(mode, rows).run(
        faults=faults_canon, formal_class=formal_class,
    )
    calls = packed.get("_calls")
    if calls is None:
        raise SystemExit(f"{vid}: missing exact calls from reference multipass")
    pos = int(packed.get("_positive", 0))
    # R18: formal precheck → validator-only product (no production call column).
    if packed.get("_precheck_failed"):
        reason = str(packed.get("_precheck_reason") or "")
        pe = map_precheck_error(reason)
        if pe is None:
            raise SystemExit(
                f"{vid}: formal precheck reason not product-mappable: {reason!r}"
            )
        if faults_canon:
            raise SystemExit(f"{vid}: formal_precheck forbids configured faults")
        out = {
            "id": vid,
            "kind": kind,
            "mode": mode,
            "formal_class": formal_class,
            "execution_scope": EXEC_SCOPE_FORMAL_PRECHECK,
            "precheck_error": pe,
            "candidate_binding": d3s1.default_binding_fields(),
            "rows": rows,
            "alt_rows": {},
            "faults": [],
            "calls": [],
            "expected": {"port_trace": []},
            "anti_false_pass_cases": cases,
            "notes": notes,
            "ownership": OWNERSHIP,
            "positive": False,
        }
    else:
        exp = {k: v for k, v in packed.items() if not k.startswith("_")}
        out = {
            "id": vid,
            "kind": kind,
            "mode": mode,
            "formal_class": formal_class,
            "execution_scope": EXEC_SCOPE_REP1_L2,
            "candidate_binding": d3s1.default_binding_fields(),
            "rows": rows,
            "alt_rows": {},
            "faults": faults_canon,
            "calls": calls,
            "expected": exp,
            "anti_false_pass_cases": cases,
            "notes": notes,
            "ownership": OWNERSHIP,
            "positive": bool(pos),
        }
    # Non-outcome metadata only (e.g. SCAN locate description) — never expected override
    for k, val in top_meta.items():
        if k.startswith("expected") or k in (
            "outcome", "fail_at", "positive", "final_status", "sticky_primary",
            "error_stage", "stage", "adopted", "formal_class",
            "execution_scope", "precheck_error",
        ):
            raise SystemExit(f"{vid}: forbidden expected-answer top_meta {k}")
        out[k] = val
    return out


