    V.append(vec("D3S3_M27_LIVE_ANCHOR_MULTI_CHUNK_OK", "mode27_live_multi_chunk_ok", 27, r,
        [2, 17],
        "Mode27 live multi-chunk (count=2) content_digest over concatenated stream"))
    r = mat27_zero()
    V.append(vec("D3S3_M27_LIVE_ANCHOR_MAN_ZERO_OK", "mode27_live_zero_ok", 27, r,
        [17],
        "Mode27 live zero-length manifest (count0 content SHA empty)"))
    r = mat27_hist()
    V.append(vec("D3S3_M27_HISTORICAL_ABSENT_OK", "mode27_historical_absent_ok", 27, r,
        [17],
        "Mode27 historical: DS TERMINAL/EXPIRED man absent + non-zero dig OK"))
    r = mat27_zero()
