def _validate_known_json_ints(obj: Any, *, path: str = "$") -> Optional[str]:
    """Closed nested schema: every known always-int key is strict JSON int + range."""
    if isinstance(obj, dict):
        for k, v in obj.items():
            rng = _KNOWN_JSON_INT_RANGES.get(k)
            if rng is None and (
                k.endswith("_prefix_count") or k.endswith("_suffix_count")
            ):
                rng = (0, UINT32_MAX)
            if rng is not None and v is not None:
                e = _strict_json_int(
                    v, name=f"{path}.{k}", min_v=rng[0], max_v=rng[1],
                )
                if e is not None:
                    return e
            if k == "anti_false_pass_cases":
                if not isinstance(v, list):
                    return f"{path}.{k} must be array"
                for i, x in enumerate(v):
                    e = _strict_json_int(
                        x, name=f"{path}.{k}[{i}]", min_v=1, max_v=17,
                    )
                    if e is not None:
                        return e
                continue
            err = _validate_known_json_ints(v, path=f"{path}.{k}")
            if err is not None:
                return err
        return None
    if isinstance(obj, list):
        for i, v in enumerate(obj):
            err = _validate_known_json_ints(v, path=f"{path}[{i}]")
            if err is not None:
                return err
        return None
    return None


# R28 r3 P2-1: complete closed nested schema for the checkpoint subtree. Every key
# present at any depth must be a known key of the expected type; bool/float/unknown
# keys are rejected at any depth (bool is type 'bool', not 'int', so a bool in an
# integer position fails). previous_key_length / last_carrier_key_len etc. are now
# covered. Leaf type sets: int / str / nullable-str.
_CP_INT = frozenset({"int"})
_CP_STR = frozenset({"str"})
_CP_NULL_STR = frozenset({"NoneType", "str"})

