def _validate_closed_schema(obj: Any, schema: Dict[str, Any], path: str) -> Optional[str]:
    """Closed nested schema: reject unknown keys + bool/float at any depth."""
    if not isinstance(obj, dict):
        return f"{path} must be object (got {type(obj).__name__})"
    for k, v in obj.items():
        if k not in schema:
            return f"{path}.{k}: unknown key (closed checkpoint schema)"
        spec = schema[k]
        if isinstance(spec, dict):
            if not isinstance(v, dict):
                return f"{path}.{k} must be object (got {type(v).__name__})"
            err = _validate_closed_schema(v, spec, f"{path}.{k}")
            if err is not None:
                return err
        elif spec is None:
            if v is None:
                continue
            if not isinstance(v, dict):
                return f"{path}.{k} must be null or object (got {type(v).__name__})"
            err = _validate_closed_schema(v, _CHECKPOINT_RESULT_SCHEMA, f"{path}.{k}")
            if err is not None:
                return err
        else:
            tname = type(v).__name__
            if tname not in spec:
                return f"{path}.{k} must be {'/'.join(sorted(spec))} (got {tname})"
    return None


def _validate_vector_row_shapes(vectors: Any, *, where: str) -> Optional[str]:
    """Validate vectors list element/row nested shapes (generate+check shared)."""
    if not isinstance(vectors, list):
        return f"{where}: vectors must be array"
    for i, v in enumerate(vectors):
        if not isinstance(v, dict):
            return f"{where}: vectors[{i}] must be object"
        err = _walk_reject_bad_numbers(v, path=f"{where}.vectors[{i}]")
        if err is not None:
            return err
        rows = v.get("rows")
        # rows must be array when present; {} / null / string are input-shape RED
        if "rows" in v and not isinstance(rows, list):
            return f"{where}: vectors[{i}].rows must be array"
        if isinstance(rows, list):
            for j, r in enumerate(rows):
                if not isinstance(r, dict):
                    return f"{where}: vectors[{i}].rows[{j}] must be object"
                # R28 P2-1: key_hex/value_hex are required (row={} RED), not
                # type-checked only when present.
                if not isinstance(r.get("key_hex"), str):
                    return f"{where}: vectors[{i}].rows[{j}].key_hex must be string"
                if not isinstance(r.get("value_hex"), str):
                    return f"{where}: vectors[{i}].rows[{j}].value_hex must be string"
        if "mode" in v and v["mode"] is not None:
            e = _strict_json_int(
                v["mode"], name=f"{where}.vectors[{i}].mode", min_v=0, max_v=255,
            )
            if e is not None:
                return e
        # expected object shape when present
        exp = v.get("expected")
        if exp is not None and not isinstance(exp, dict):
            return f"{where}: vectors[{i}].expected must be object"
        if "faults" in v and v["faults"] is not None and not isinstance(v["faults"], list):
            return f"{where}: vectors[{i}].faults must be array"
        if "calls" in v and v["calls"] is not None and not isinstance(v["calls"], list):
            return f"{where}: vectors[{i}].calls must be array"
        # R28 r3 P2-1: closed checkpoint schema (reject bool/float/unknown any depth).
        calls = v.get("calls")
        if isinstance(calls, list):
            for ci, c in enumerate(calls):
                if isinstance(c, dict) and c.get("checkpoint") is not None:
                    err = _validate_closed_schema(
                        c["checkpoint"], _CHECKPOINT_SCHEMA,
                        f"{where}.vectors[{i}].calls[{ci}].checkpoint",
                    )
                    if err is not None:
                        return err
    return None


def _validate_document_shape(probe: Any, *, where: str) -> Optional[str]:
    """Full document shape + closed nested integer schema (adopt / check shared)."""
    if not isinstance(probe, dict):
        return f"{where}: top-level must be object (got {type(probe).__name__})"
    err = _walk_reject_bad_numbers(probe, path=where)
    if err is not None:
        return err
    err = _validate_known_json_ints(probe, path=where)
    if err is not None:
        return err
    if "vectors" not in probe:
        return f"{where}: missing vectors"
    vectors = probe.get("vectors")
    if not isinstance(vectors, list):
        return f"{where}: vectors must be array"
    shape = _validate_vector_row_shapes(vectors, where=where)
    if shape is not None:
        return shape
    # top-level required typed fields when present
    if "vector_count" in probe:
        e = _strict_json_int(
            probe["vector_count"], name=f"{where}.vector_count",
            min_v=0, max_v=UINT32_MAX,
        )
        if e is not None:
            return e
    if "format" in probe and not isinstance(probe.get("format"), str):
        return f"{where}: format must be string"
    return None


def _canonical_first144() -> List[Dict[str, Any]]:
    """Frozen first144 objects from DEFAULT_JSON authority (exact object equality)."""
    if not DEFAULT_JSON.is_file():
        raise SystemExit(f"missing canonical authority {DEFAULT_JSON}")
    try:
        live = json.loads(DEFAULT_JSON.read_text(encoding="utf-8"))
    except (OSError, UnicodeDecodeError, json.JSONDecodeError) as e:
        raise SystemExit(f"unreadable canonical authority: {e}") from e
    if not isinstance(live, dict) or not isinstance(live.get("vectors"), list):
        raise SystemExit("canonical authority vectors missing")
    if len(live["vectors"]) < D3S2_PREFIX:
        raise SystemExit("canonical authority shorter than 144")
    return copy.deepcopy(live["vectors"][:D3S2_PREFIX])


def _validate_prefix_source_document(probe: Any, *, where: str) -> Optional[str]:
    """R26/R27-Sol: fail-closed full-document validation before adopting existing path.

    Validates entire document shape + closed nested integer schema (all vectors
    including suffix rows must be arrays — rows={} RED), then first144 authority.
    Never adopt unvalidated first144 or unvalidated suffix/top-level shape.
    """
    err = _validate_document_shape(probe, where=where)
    if err is not None:
        return err
    vectors = probe["vectors"]
    if len(vectors) < D3S2_PREFIX:
        return f"{where}: vectors shorter than first144 authority"
    # exact first144 vs canonical authority
    try:
        canon = _canonical_first144()
    except SystemExit as e:
        return str(e) if e.args else "canonical authority unavailable"
    for i in range(D3S2_PREFIX):
        if vectors[i] != canon[i]:
            return f"{where}: first144 authority mismatch at index {i}"
    # optional authority block when present must match pins
    auth = probe.get("d3s2_prefix_authority")
    if auth is not None:
        if not isinstance(auth, dict):
            return f"{where}: d3s2_prefix_authority must be object"
        if auth.get("format") != D3S2_FORMAT:
            return f"{where}: d3s2_prefix_authority format"
        e = _strict_json_int(
            auth.get("vector_count"), name=f"{where}.d3s2_prefix_authority.vector_count",
            min_v=0, max_v=UINT32_MAX,
        )
        if e is not None:
            return e
        if auth.get("vector_count") != D3S2_PREFIX:
            return f"{where}: d3s2_prefix_authority vector_count"
        if auth.get("content_sha256") != D3S2_CONTENT:
            return f"{where}: d3s2_prefix_authority content_sha256"
        if auth.get("raw_sha256") != D3S2_RAW:
            return f"{where}: d3s2_prefix_authority raw_sha256"
    return None


def build_document(source: Path) -> Dict[str, Any]:
    try:
        raw = source.read_text(encoding="utf-8")
        src = json.loads(raw)
    except (OSError, UnicodeDecodeError, json.JSONDecodeError) as e:
        raise SystemExit(f"unreadable prefix source: {e}") from e
    verr = _validate_prefix_source_document(src, where="prefix source")
    if verr is not None:
        raise SystemExit(verr)
    prefix = copy.deepcopy(src["vectors"][:D3S2_PREFIX])
    # pin prefix ids against frozen d3s2 content when source is d3s2 or d3s3
    suffix = build_suffix()
    vectors = prefix + suffix
    doc: Dict[str, Any] = {
        "version": VERSION,
        "format": FORMAT,
        "scope": "D3-S3 constructible BLOB lifecycle append-only on d3s1+d3s2 prefix",
        "vector_count": len(vectors),
        "d3s1_prefix_count": 94,
        "d3s2_prefix_count": D3S2_PREFIX,
        "d3s3_suffix_count": len(suffix),
        "d3s3_production_count": sum(
            1 for v in suffix if v.get("execution_scope") == EXEC_SCOPE_REP1_L2
        ),
        "d3s3_formal_precheck_count": sum(
            1 for v in suffix if v.get("execution_scope") == EXEC_SCOPE_FORMAL_PRECHECK
        ),
        "required_kinds": sorted({v["kind"] for v in suffix}),
        "workspace": copy.deepcopy(src.get("workspace", {})),
        "d3s2_prefix_authority": {
            "format": D3S2_FORMAT,
            "vector_count": D3S2_PREFIX,
            "content_sha256": D3S2_CONTENT,
            "raw_sha256": D3S2_RAW,
        },
        "sha256_procedure": (
            "content_sha256=SHA-256(utf8(canonical JSON without content_sha256; "
            "sort_keys; separators=(',', ':')))"
        ),
        "vectors": vectors,
    }
    # retain prior authorities
    for k, v in src.items():
        if k.endswith("_authority") or k.endswith("_prefix_count") or k.startswith("d3s2_"):
            if k not in doc:
                doc[k] = copy.deepcopy(v)
    body = {k: v for k, v in doc.items() if k != "content_sha256"}
    doc["content_sha256"] = hashlib.sha256(
        json.dumps(body, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode()
    ).hexdigest()
    return doc

def _content_sha(doc):
    body = {k: v for k, v in doc.items() if k != "content_sha256"}
    return hashlib.sha256(
        json.dumps(body, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode()
    ).hexdigest()

def generate(path: Path) -> None:
    """Write d3s3 oracle JSON to path.

    Prefix source is DEFAULT_JSON (or path only when it already holds a valid
    ≥144-vector crossrow document with exact first144 authority). Empty/new
    output paths must not be read as JSON sources.

    R25/R26: existing path with scalar/non-object, non-list vectors, non-object
    elements, malformed rows/nested fields, bool/float/nonfinite numbers, or wrong
    first144 authority → SystemExit(2) one short error; never AttributeError;
    never adopt unvalidated first144.
    """
    def _gen_err(msg: str) -> None:
        # CLI contract: one short stderr line starting with error: (exit via SystemExit).
        text = msg if str(msg).startswith("error:") else f"error: {msg}"
        raise SystemExit(text)

    src = DEFAULT_JSON
    if path.is_file() and path.stat().st_size > 0 and path.resolve() != DEFAULT_JSON.resolve():
        try:
            raw = path.read_text(encoding="utf-8")
            probe = json.loads(raw)
        except (json.JSONDecodeError, OSError, UnicodeDecodeError) as e:
            # Documented contract: malformed existing path → exit2 (not silent fallback).
            _gen_err(f"generate output path not a usable object document: {e}")
        verr = _validate_prefix_source_document(probe, where="generate output path")
        if verr is not None:
            _gen_err(verr)
        # only after full validation may we reuse path as prefix source
        src = path
    if not src.is_file():
        _gen_err(f"missing prefix source {src}")
    try:
        doc = build_document(src)
    except SystemExit as e:
        # build_document may raise without error: prefix
        msg = str(e) if e.args else "build_document failed"
        _gen_err(msg)
    path.write_text(json.dumps(doc, indent=2, ensure_ascii=False) + "\n", encoding="utf-8")
    print(f"wrote {path} format={doc['format']} count={doc['vector_count']} "
          f"suffix={doc['d3s3_suffix_count']} content={doc['content_sha256'][:16]}")

def check(path: Path, *, quiet: bool = False) -> int:
    def _err(*parts, code: int = 1) -> int:
        if not quiet:
            print(" ".join(str(p) for p in parts), file=sys.stderr)
        return code

    try:
        doc = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, UnicodeDecodeError, json.JSONDecodeError) as e:
        # Input errors → exit 2 (usage/input class), not authority RED (1).
        return _err(f"error: unreadable/malformed input {path}: {e}", code=2)

    # R24/R26/R27-Sol: closed document shape + nested known-integer schema before
    # any coerce / authority rebuild. Malformed input → exit 2, one line, no traceback.
    # Authority pin failures remain exit 1.
    shape_err = _validate_document_shape(doc, where="check")
    if shape_err is not None:
        return _err(f"error: {shape_err}", code=2)
    if "format" not in doc or "vectors" not in doc or "vector_count" not in doc:
        return _err("error: missing required fields format/vectors/vector_count", code=2)
    vectors = doc["vectors"]
    vector_count = doc["vector_count"]

    if doc.get("format") != FORMAT:
        return _err("format mismatch")
    if vector_count != len(vectors):
        return _err("count mismatch")
    if doc.get("d3s2_prefix_count") != D3S2_PREFIX:
        return _err("d3s2 prefix pin")
    if doc.get("d3s3_suffix_count") != D3S3_SUFFIX_COUNT:
        return _err(f"d3s3 suffix must be {D3S3_SUFFIX_COUNT}")
    if len(vectors) != D3S2_PREFIX + D3S3_SUFFIX_COUNT:
        return _err(
            f"total vectors must be {D3S2_PREFIX + D3S3_SUFFIX_COUNT}"
        )
    if _content_sha(doc) != doc.get("content_sha256"):
        return _err("content_sha mismatch")
    auth = doc.get("d3s2_prefix_authority")
    if auth is None or not isinstance(auth, dict):
        return _err("error: d3s2_prefix_authority must be object", code=2)
    if auth.get("format") != D3S2_FORMAT:
        return _err("d3s2_prefix_authority format")
    if auth.get("vector_count") != D3S2_PREFIX:
        return _err("d3s2_prefix_authority vector_count")
    if auth.get("content_sha256") != D3S2_CONTENT:
        return _err("d3s2_prefix_authority content_sha256")
    if auth.get("raw_sha256") != D3S2_RAW:
        return _err("d3s2_prefix_authority raw_sha256")

    # R19: D1-legality on disk suffix rows before rebuild equality (fail-closed).
    # formal_precheck may duplicate complete keys; each row still must be local-D1.
    for v in vectors[D3S2_PREFIX:]:
        rows = v.get("rows") or []
        if not rows:
            return _err(v.get("id", "?"), "empty rows")
        d1_err = d1_rows_legality_gate(rows)
        if d1_err is not None:
            return _err(v.get("id", "?"), "D1-illegal fixture:", d1_err)

    rebuilt = build_document(DEFAULT_JSON)
    if len(rebuilt["vectors"]) != len(doc["vectors"]):
        return _err("rebuild length drift")
    # first144 full-object equality vs rebuilt authority prefix
    for i in range(D3S2_PREFIX):
        if doc["vectors"][i] != rebuilt["vectors"][i]:
            return _err(f"first144 full-object mismatch at {i}")
    # suffix exact rebuild equality (independent reference)
    for i in range(D3S2_PREFIX, len(doc["vectors"])):
        if doc["vectors"][i] != rebuilt["vectors"][i]:
            return _err(
                f"suffix rebuild drift at {i} id={doc['vectors'][i].get('id')}"
            )

    # AFP fixed anchor table
    if not _check_afp_anchor_table(doc):
        return 1

    CALL_ST = frozenset(CALL_EXPECTED_STATUS)

    covered = set()
    n_prod = 0
    n_formal = 0
    for v in doc["vectors"][D3S2_PREFIX:]:
        for c in v.get("anti_false_pass_cases", []):
            covered.add(int(c))
        rows = v.get("rows") or []
        if not rows:
            return _err(v["id"], "empty rows")
        # R18/R19: execution_scope closed; formal vs production schema split.
        sc_err = validate_execution_scope_vector(v)
        if sc_err is not None:
            return _err(v["id"], "execution_scope:", sc_err)
        if is_formal_precheck_vector(v):
            n_formal += 1
            mech = validate_vector_port_mechanics(v)
            if mech is not None:
                return _err(v["id"], "o1b-a mechanics:", mech)
            ug = validate_rep1_unit_grammar(v)
            if ug is not None:
                return _err(v["id"], "unit grammar:", ug)
            continue
        n_prod += 1
        exp = v.get("expected") or {}
        for req in (
            "final_status", "adopted", "phase", "flags", "count_complete_mask",
            "binding_complete_mask", "has_sticky_primary", "sticky_primary",
            "d3_peer_get_count", "iter_open_count", "port_trace",
            "mutation_calls", "profile_exact_active", "faults_expected_used",
        ):
            if req not in exp:
                return _err(v["id"], "missing expected", req)
        # R16: no `or []` coercion of falsy non-list port_trace.
        ptrace = exp.get("port_trace", [])
        if type(ptrace) is not list:
            return _err(v["id"], "port_trace not list")
        if not ptrace:
            return _err(v["id"], "port_trace empty")
        # O1b-A mechanical Port event + nested checkpoint schema
        mech = validate_vector_port_mechanics(v)
        if mech is not None:
            return _err(v["id"], "o1b-a mechanics:", mech)
        # exact calls: begin, N drives, finalize; no soft statuses
        calls = v.get("calls") or []
        if not calls or calls[0].get("op") != "begin_profiled_d3s3":
            return _err(v["id"], "calls must start begin_profiled_d3s3")
        if calls[-1].get("op") != "finalize":
            return _err(v["id"], "calls must end finalize")
        seen_terminal = False
        for ci, c in enumerate(calls):
            st = c.get("expected_status") or ""
            if st in ("OK_OR_STICKY", "STICKY_OR_OK", "FINAL_NEG"):
                return _err(v["id"], "soft call status", st)
            if st not in CALL_ST:
                return _err(v["id"], "unknown call status", st)
            if c.get("op") == "d3s3_drive":
                if seen_terminal:
                    return _err(v["id"], "drive after terminal")
                if st not in ("OK", OUT_OK):
                    seen_terminal = True
            if c.get("op") == "finalize" and st not in ("OK", OUT_OK):
                seen_terminal = True
        # fault expected usage (already strict-int via closed schema; no bool coerce)
        fl = v.get("faults") or []
        used = exp.get("faults_expected_used", 0)
        if type(used) is not int or type(used) is bool:
            return _err(f"error: {v['id']}: faults_expected_used must be JSON integer", code=2)
        if fl and used != 1:
            return _err(v["id"], "fault configured but faults_expected_used!=1")

        if not fl and used != 0:
            return _err(v["id"], "no fault but faults_expected_used!=0")
    if n_prod != D3S3_PRODUCTION_COUNT:
        return _err(
            f"production rep1_l2 count want {D3S3_PRODUCTION_COUNT} got {n_prod}"
        )
    if n_formal != D3S3_FORMAL_PRECHECK_COUNT:
        return _err(
            f"formal_precheck count want {D3S3_FORMAL_PRECHECK_COUNT} got {n_formal}"
        )
    if n_prod + n_formal != D3S3_SUFFIX_COUNT:
        return _err("suffix count != production+formal")
    if int(doc.get("d3s3_production_count", -1)) != D3S3_PRODUCTION_COUNT:
        return _err("d3s3_production_count pin")
    if int(doc.get("d3s3_formal_precheck_count", -1)) != D3S3_FORMAL_PRECHECK_COUNT:
        return _err("d3s3_formal_precheck_count pin")
    # P1-B: formal setup/PREFIX GET natural-fault vectors — byte-exact key + full tuple
    setup_fault_err = validate_all_formal_setup_get_faults(
        [v for v in doc["vectors"][D3S2_PREFIX:] if is_rep1_l2_vector(v)]
    )
    if setup_fault_err is not None:
        return _err(setup_fault_err)

    # O1b-R2: exact 24-pair NATURAL fault Cartesian authority on suffix
    cart_err = validate_formal_fault_cartesian_authority(doc["vectors"][D3S2_PREFIX:])
    if cart_err is not None:
        return _err("formal fault Cartesian authority:", cart_err)

    bind_neg_err = validate_all_formal_bind_negatives(doc["vectors"][D3S2_PREFIX:])
    if bind_neg_err is not None:
        return _err("formal BIND negative unit proof:", bind_neg_err)

    blob_vecs = 0
    for v in doc["vectors"][D3S2_PREFIX:]:
        for r in v["rows"]:
            k = d3s1.from_hex(r["key_hex"])
            if len(k) >= 10 and k[9] == 0x30:
                blob_vecs += 1
                break
    if blob_vecs < 8:
        return _err(f"too few vectors with BLOB rows: {blob_vecs}")
    missing = [c for c in range(1, 18) if c not in covered]
    if missing:
        return _err("missing afp", missing)
    print(
        f"check ok vectors={len(doc['vectors'])} suffix={len(doc['vectors'])-D3S2_PREFIX} "
        f"production={n_prod} formal_precheck={n_formal} "
        f"blob_vecs={blob_vecs} afp={sorted(covered)}"
    )
    return 0


# §18.14.15 AFP 1..17 fixed anchors (ID/mode/positive/case membership/blob shape)
AFP_ANCHOR_TABLE = [
    # (case, id, mode, positive, require_blob)
    (1, "D3S3_M27_SCAN_NOT_REVERSE_OK", 27, True, True),
    (2, "D3S3_M27_LIVE_ANCHOR_MAN_CHUNK_OK", 27, True, True),
    (3, "D3S3_M30_RECEIPT_EMPTY_BLOB_OK", 30, True, True),
    (4, "D3S3_M30_CROSS_DELIVERY_DIGEST_CORRUPT", 30, False, True),
    (5, "D3S3_M30_DISP_NONEMPTY_BLOB_CORRUPT", 30, False, True),
    (6, "D3S3_M30_CELL_BYTE_MISMATCH_CORRUPT", 30, False, True),
    (7, "D3S3_M30_ORPHAN_MANIFEST_0RR_CORRUPT", 30, False, True),
    (8, "D3S3_M30_SAME_DELIVERY_2RR_OK", 30, True, True),
    (9, "D3S3_M27_ORPHAN_CHUNK_CORRUPT", 27, False, True),
    (10, "D3S3_M30_MISSING_CANCEL_CORRUPT", 30, False, True),
    (11, "D3S3_M27_DUPLICATE_DIGEST_MATCH_CORRUPT", 27, False, True),
    (12, "D3S3_M28_SEMANTIC_DIGEST_MISMATCH_CORRUPT", 28, False, True),
    (13, "D3S3_M27_OWNER_PVD_MISMATCH_CORRUPT", 27, False, True),
    (14, "D3S3_M28_DUAL_VIEW_PAYLOAD_NONEMPTY_OK", 28, True, True),
    (15, "D3S3_M29_RESULT_CACHE_MISSING_CORRUPT", 29, False, False),
    (16, "D3S3_M27_EMPTY_PROFILE_PRODUCT_OK", 27, True, False),
    (17, "D3S3_M27_MISSING_CHUNK_CORRUPT", 27, False, True),
]


def _check_afp_anchor_table(doc: Dict[str, Any]) -> bool:
    by_id = {v["id"]: v for v in doc["vectors"][D3S2_PREFIX:]}
    for case, vid, mode, positive, require_blob in AFP_ANCHOR_TABLE:
        if vid not in by_id:
            print(f"AFP {case} missing id {vid}", file=sys.stderr)
            return False
        v = by_id[vid]
        if int(v.get("mode", -1)) != mode:
            print(f"AFP {case} mode", file=sys.stderr); return False
        if bool(v.get("positive")) != bool(positive):
            print(f"AFP {case} positive", file=sys.stderr); return False
        if case not in [int(c) for c in (v.get("anti_false_pass_cases") or [])]:
            print(f"AFP {case} not in anti_false_pass_cases of {vid}", file=sys.stderr)
            return False
        if require_blob:
            ok = False
            for r in v.get("rows") or []:
                k = d3s1.from_hex(r["key_hex"])
                if len(k) >= 10 and k[9] == 0x30:
                    ok = True
                    break
            if not ok:
                print(f"AFP {case} missing blob row", file=sys.stderr); return False
    return True


def emit_c_fixture(json_path: Path, header_path: Path) -> None:
    # Shared document authority gate: never emit a C fixture from invalid JSON.
    # In particular rep1_l2 with calls=[] / port_trace=[] must fail closed here.
    rc = check(json_path, quiet=True)
    if rc != 0:
        raise SystemExit(rc)
    doc = json.loads(json_path.read_text(encoding="utf-8"))
    suffix = doc["vectors"][D3S2_PREFIX:]
    lines: List[str] = []
    lines.append("/* Generated by domain_scan_crossrow_d3s3_vector_gen.py — do not edit. */")
    lines.append("#ifndef NINLIL_DOMAIN_SCAN_CROSSROW_D3S3_FIXTURE_H")
    lines.append("#define NINLIL_DOMAIN_SCAN_CROSSROW_D3S3_FIXTURE_H")
    lines.append("#include <stddef.h>")
    lines.append("#include <stdint.h>")
    n_prod = sum(1 for v in suffix if v.get("execution_scope") == EXEC_SCOPE_REP1_L2)
    n_formal = sum(
        1 for v in suffix if v.get("execution_scope") == EXEC_SCOPE_FORMAL_PRECHECK
    )
    lines.append(f"#define NINLIL_D3S2_PREFIX_COUNT ((size_t){D3S2_PREFIX}u)")
    lines.append(f"#define NINLIL_D3S3_SUFFIX_COUNT ((size_t){len(suffix)}u)")
    lines.append(f"#define NINLIL_D3S3_VECTOR_COUNT ((size_t){len(suffix)}u)")
    lines.append(f"#define NINLIL_D3S3_PRODUCTION_COUNT ((size_t){n_prod}u)")
    lines.append(f"#define NINLIL_D3S3_FORMAL_PRECHECK_COUNT ((size_t){n_formal}u)")
    lines.append(f'#define NINLIL_D3S3_FORMAT "{FORMAT}"')
    lines.append(f'#define NINLIL_D3S3_CONTENT_SHA256 "{doc.get("content_sha256","")}"')
    lines.append("#define NINLIL_D3S3_MAX_TRACE ((size_t)1024u)")
    lines.append("#define NINLIL_D3S3_MAX_KEY ((size_t)64u)")
    lines.append(
        "typedef enum ninlil_d3s3_execution_scope { "
        "NINLIL_D3S3_SCOPE_REP1_L2, NINLIL_D3S3_SCOPE_FORMAL_PRECHECK "
        "} ninlil_d3s3_execution_scope_t;"
    )
    lines.append(
        "typedef enum ninlil_d3s3_precheck_error { "
        "NINLIL_D3S3_PRECHECK_NONE, NINLIL_D3S3_PRECHECK_DUPLICATE_COMPLETE_KEY "
        "} ninlil_d3s3_precheck_error_t;"
    )
    lines.append("typedef struct ninlil_d3s3_binding {")
    lines.append("  uint32_t storage_schema; uint32_t role; uint32_t environment;")
    lines.append("  uint8_t runtime_id[16];")
    lines.append("  uint32_t max_services; uint32_t max_nonterminal_transactions;")
    lines.append("  uint32_t max_targets_per_transaction; uint32_t max_logical_payload_bytes;")
    lines.append("  uint64_t max_durable_outbox_payload_bytes;")
    lines.append("  uint32_t max_attempts_per_target_per_cycle;")
    lines.append("  uint32_t max_cancel_attempts_per_transaction;")
    lines.append("  uint32_t max_evidence_per_target;")
    lines.append("  uint32_t max_retained_terminal_transactions;")
    lines.append("  uint32_t max_nonterminal_deliveries; uint32_t max_event_spool_count;")
    lines.append("  uint64_t max_event_spool_bytes; uint32_t max_result_cache_entries;")
    lines.append("  uint32_t max_retained_dispositions; uint32_t max_ingress_per_step;")
    lines.append("  uint32_t max_callbacks_per_step; uint32_t max_state_transitions_per_step;")
    lines.append("  uint32_t max_bearer_sends_per_step; uint32_t max_deferred_tokens;")
    lines.append("  uint64_t terminal_retention_ms; uint64_t result_cache_retention_ms;")
    lines.append("  uint64_t observation_retention_ms;")
    lines.append("} ninlil_d3s3_binding_t;")
    lines.append("typedef struct ninlil_d3s3_row {")
    lines.append("  uint8_t key[64]; uint32_t key_length; const uint8_t *value; uint32_t value_length;")
    lines.append("} ninlil_d3s3_row_t;")
    lines.append("typedef struct ninlil_d3s3_fault {")
