    lines.append("  uint32_t key_length; uint32_t value_length;")
    lines.append("} ninlil_d3s3_fault_t;")
    lines.append("/* O1c: lossless typed authority fields.  Names are closed enums; JSON is")
    lines.append(" * deliberately not parsed by the production bridge. */")
    lines.append("typedef struct ninlil_d3s3_bytes { const uint8_t *data; uint32_t length; } ninlil_d3s3_bytes_t;")
    lines.append("typedef enum ninlil_d3s3_runtime_status { NINLIL_D3S3_RS_OK, NINLIL_D3S3_RS_STORAGE_CORRUPT, NINLIL_D3S3_RS_STORAGE, NINLIL_D3S3_RS_COMMIT_UNKNOWN, NINLIL_D3S3_RS_CAPACITY, NINLIL_D3S3_RS_WOULD_BLOCK, NINLIL_D3S3_RS_UNSUPPORTED, NINLIL_D3S3_RS_INVALID_STATE, NINLIL_D3S3_RS_INVALID_ARGUMENT } ninlil_d3s3_runtime_status_t;")
