    lines.append("typedef enum ninlil_d3s3_handle { NINLIL_D3S3_HANDLE_NONE, NINLIL_D3S3_HANDLE_H1, NINLIL_D3S3_HANDLE_T1, NINLIL_D3S3_HANDLE_I1, NINLIL_D3S3_HANDLE_I2, NINLIL_D3S3_HANDLE_I3, NINLIL_D3S3_HANDLE_I4, NINLIL_D3S3_HANDLE_I5, NINLIL_D3S3_HANDLE_I6, NINLIL_D3S3_HANDLE_I7, NINLIL_D3S3_HANDLE_I8, NINLIL_D3S3_HANDLE_I9, NINLIL_D3S3_HANDLE_I10 } ninlil_d3s3_handle_t;")
    lines.append("typedef enum ninlil_d3s3_mode { NINLIL_D3S3_MODE_NONE, NINLIL_D3S3_MODE_READ_ONLY } ninlil_d3s3_mode_t;")
    lines.append("typedef enum ninlil_d3s3_state { NINLIL_D3S3_STATE_IDLE, NINLIL_D3S3_STATE_OPEN, NINLIL_D3S3_STATE_EXHAUSTED, NINLIL_D3S3_STATE_FAILED, NINLIL_D3S3_STATE_DONE } ninlil_d3s3_state_t;")
    lines.append("typedef struct ninlil_d3s3_optional_runtime_status { uint8_t present; ninlil_d3s3_runtime_status_t value; } ninlil_d3s3_optional_runtime_status_t;")
    lines.append("typedef struct ninlil_d3s3_optional_storage_status { uint8_t present; ninlil_d3s3_storage_status_t value; } ninlil_d3s3_optional_storage_status_t;")
    lines.append("typedef struct ninlil_d3s3_port_event { uint32_t seq; uint32_t api_call_index; ninlil_d3s3_op_t op; uint32_t on_call; ninlil_d3s3_optional_storage_status_t storage_status; ninlil_d3s3_handle_t input_handle_id; ninlil_d3s3_handle_t output_handle_id; ninlil_d3s3_mode_t mode; ninlil_d3s3_bytes_t prefix; ninlil_d3s3_bytes_t request_key; ninlil_d3s3_bytes_t key; uint32_t key_capacity; uint32_t key_length; uint32_t value_capacity; uint32_t value_length; } ninlil_d3s3_port_event_t;")
    lines.append("typedef struct ninlil_d3s3_checkpoint_session { ninlil_d3s3_state_t state; uint8_t txn_live; uint8_t iter_live; uint8_t has_sticky_primary; ninlil_d3s3_optional_runtime_status_t sticky_primary; ninlil_d3s3_optional_storage_status_t cleanup_status; uint32_t reopen_required; uint8_t fence_pending; uint8_t profile_exact_active; uint8_t profile_mismatch; uint8_t future_profile_candidate; uint8_t recognizable_future_seen; uint64_t family14_row_count; uint32_t family14_iter_seen_mask; uint32_t profile_get_present_mask; uint64_t ok_row_count; uint64_t current_domain_key_count; uint8_t has_previous; ninlil_d3s3_bytes_t previous_key; } ninlil_d3s3_checkpoint_session_t;")
