def validate_formal_bind_negative_vector(v: Dict[str, Any]) -> Optional[str]:
    """Assert failing drive entered the named BIND unit; GET last; no early fail."""
    specs = {s["id"]: s for s in _FORMAL_BIND_NEGATIVE_SPECS}
    vid = v.get("id")
    if vid not in specs:
        return None
    sp = specs[vid]
    calls = v.get("calls") or []
    ptrace = (v.get("expected") or {}).get("port_trace") or []
    prev = None
    fail_call = None
    for c in calls:
        if c.get("op") != "d3s3_drive":
            continue
        d3 = (c.get("checkpoint") or {}).get("d3s3") or {}
        if int(d3.get("phase", -1)) == PHASE_FAILED:
            fail_call = c
            break
        prev = (
            int(d3.get("phase", -1)),
            int(d3.get("semantic_pass", -1)),
            int(d3.get("flags", -1)),
        )
    if fail_call is None or prev is None:
        return f"{vid}: missing FAIL drive or entry snapshot"
    if prev[0] != int(sp["entry_phase"]) or prev[1] != int(sp["entry_sem"]):
        return (
            f"{vid}: failing entry phase/sem want "
            f"({sp['entry_phase']},{sp['entry_sem']}) got {prev[0:2]}"
        )
    # no prior FAIL
    for c in calls:
        if c is fail_call:
            break
        if c.get("op") == "d3s3_drive":
            st = c.get("expected_status")
            if st not in ("OK", OUT_OK):
                return f"{vid}: preceding drive non-OK {st}"
    port = (fail_call.get("checkpoint") or {}).get("port") or {}
    es, ee = int(port.get("event_start", 0)), int(port.get("event_end", 0))
    win = ptrace[es:ee]
    if not win:
        return f"{vid}: empty failing drive window"
    last = win[-1]
    if last.get("op") != sp["last_op"] or last.get("storage_status") != sp["last_status"]:
        return (
            f"{vid}: last event want {sp['last_op']}/{sp['last_status']} "
            f"got {last.get('op')}/{last.get('storage_status')}"
        )
    if sp["last_op"] == "get" and sp["last_status"] == "OK":
        # successful GET then semantic sticky: no residual next
        if any(e.get("op") == "iter_next" for e in win[win.index(last) + 1 :] if False):
            pass
    exp = v.get("expected") or {}
    if exp.get("final_status") not in (OUT_CORRUPT, "NINLIL_E_STORAGE_CORRUPT"):
        # natural mapped statuses also possible for absent
        if sp["last_status"] == "NOT_FOUND" and exp.get("final_status") == OUT_CORRUPT:
            pass
        elif exp.get("final_status") != OUT_CORRUPT:
            return f"{vid}: final_status {exp.get('final_status')}"
    return None


def validate_all_formal_bind_negatives(vectors: List[Dict[str, Any]]) -> Optional[str]:
    by_id = {v.get("id"): v for v in vectors}
    for s in _FORMAL_BIND_NEGATIVE_SPECS:
        if s["id"] not in by_id:
            return f"formal BIND negative missing: {s['id']}"
        err = validate_formal_bind_negative_vector(by_id[s["id"]])
        if err is not None:
            return err
    return None


def _o1b_select_prefix_transcript_tests() -> int:
    """P1-1: every SELECT/PREFIX setup GET position exact transcript + faults."""

    def fl(op, on, status):
        return [{"op": op, "on_call": on, "status": status, "shape": "natural"}]

    def drives_of(p):
        return [c for c in p["_calls"] if c["op"] == "d3s3_drive"]

    def peer_ok(p, label):
        for c in p["_calls"]:
            port = (c.get("checkpoint") or {}).get("port") or {}
            gc = int(port.get("get_count", 0))
            peer = int(port.get("d3_peer_get_count", 0))
            if gc >= 17 and peer != gc - 17:
                print(f"P1-1 {label} peer formula {c['op']}", peer, gc, file=sys.stderr)
                return 1
        return 0

    def assert_last_get_fail(
        p, *, expected_key: bytes, status: str, label: str, want_tuple: Dict[str, int],
    ) -> int:
        return _assert_failure_get_drive(
            p,
            expected_key=expected_key,
            status=status,
            want_tuple=want_tuple,
            label=label,
        )

    def select_drive_live(p):
        """SELECT W that installs LIVE/HIST and exits to FOCUS (phase 3, 0x13)."""
        for c in drives_of(p):
            d3 = c["checkpoint"]["d3s3"]
            if int(d3["phase"]) == PHASE_FOCUS_MANIFEST_SCAN and int(d3["flags"]) == 0x13:
                return c
        return None

    def prefix_drive(p):
        for c in drives_of(p):
            d3 = c["checkpoint"]["d3s3"]
            if int(d3["phase"]) == PHASE_SEMANTIC_CHUNK_REWALK and int(d3["flags"]) == 0x03:
                return c
        return None

    # ---- Mode27 DesiredState: STATE only ----
    p = RefSession(27, mat27_chunked()).run()
    if p.get("final_status") != OUT_OK or peer_ok(p, "m27") != 0:
        print("P1-1 m27 positive/peer", file=sys.stderr)
        return 1
    # DesiredState: SELECT STATE + OWNER + CHUNKS + BIND_MAN owner + BIND_CHUNK man = 5
    if int(p["d3_peer_get_count"]) != 5:
        print("P1-1 m27 peer total", p["d3_peer_get_count"], file=sys.stderr)
        return 1
    sel = select_drive_live(p)
    if sel is None:
        print("P1-1 m27 SELECT drive", file=sys.stderr)
        return 1
    tr = p["port_trace"][sel["trace_begin"] : sel["trace_end"]]
    gets = [e for e in tr if e["op"] == "get"]
    if len(gets) != 1 or o1a_subtype(bytes.fromhex(gets[0]["request_key_hex"])) != 0x22:
        print("P1-1 m27 STATE get", file=sys.stderr)
        return 1
    anc_k = next(
        o1a_row_key(r) for r in mat27_chunked()
        if o1a_subtype(o1a_row_key(r)) == 0x20
    )
    anc_v = next(
        o1a_row_val(r) for r in mat27_chunked()
        if o1a_subtype(o1a_row_key(r)) == 0x20
    )
    want_st = o1a_state_key(o1a_body(anc_v)[:16])
    if bytes.fromhex(gets[0]["request_key_hex"]) != want_st:
        print("P1-1 m27 STATE key exact", file=sys.stderr)
        return 1

    # ---- Mode27 EventFact: STATE → EVENT_SPOOL exact order ----
    r_ef = mat27_eventfact_chunked()
    pef = RefSession(27, r_ef).run()
    if pef.get("final_status") != OUT_OK:
        print("P1-1 m27 EF positive", pef.get("final_status"), file=sys.stderr)
        return 1
    # EventFact: STATE+SPOOL + OWNER + CHUNKS + BIND_MAN + BIND_CHUNK = 6
    if int(pef["d3_peer_get_count"]) != 6:
        print("P1-1 m27 EF peer", pef["d3_peer_get_count"], file=sys.stderr)
        return 1
    sel_ef = select_drive_live(pef)
    tr_ef = pef["port_trace"][sel_ef["trace_begin"] : sel_ef["trace_end"]]
    gets_ef = [e for e in tr_ef if e["op"] == "get"]
    if len(gets_ef) != 2:
        print("P1-1 m27 EF want 2 setup gets", len(gets_ef), file=sys.stderr)
        return 1
    anc_ef_v = next(
        o1a_row_val(r) for r in r_ef if o1a_subtype(o1a_row_key(r)) == 0x20
    )
    tx = o1a_body(anc_ef_v)[:16]
    if bytes.fromhex(gets_ef[0]["request_key_hex"]) != o1a_state_key(tx):
        print("P1-1 m27 EF STATE key", file=sys.stderr)
        return 1
    if bytes.fromhex(gets_ef[1]["request_key_hex"]) != o1a_spool_key(tx):
        print("P1-1 m27 EF SPOOL key", file=sys.stderr)
        return 1
    if o1a_subtype(bytes.fromhex(gets_ef[0]["request_key_hex"])) != 0x22:
        print("P1-1 m27 EF order STATE", file=sys.stderr)
        return 1
    if o1a_subtype(bytes.fromhex(gets_ef[1]["request_key_hex"])) != 0x50:
        print("P1-1 m27 EF order SPOOL", file=sys.stderr)
        return 1

    # missing STATE / SPOOL → NOT_FOUND last of SELECT W; full pre-fail tuple
    for lab, rows, key_b in (
        ("ef_miss_state", mat27_ef_missing_state(), o1a_state_key(tx)),
        ("ef_miss_spool", mat27_ef_missing_spool(), o1a_spool_key(tx)),
    ):
        pm = RefSession(27, rows).run()
        if pm.get("final_status") != OUT_CORRUPT:
            print(f"P1-1 {lab} status", file=sys.stderr)
            return 1
        if assert_last_get_fail(
            pm, expected_key=key_b, status="NOT_FOUND", label=lab,
            want_tuple=_SELECT_SETUP_FAIL_TUPLE,
        ) != 0:
            return 1

    # natural fault at STATE@18 and SPOOL@19 for EF
    for lab, on, key_b in (
        ("ef_fault_state", 18, o1a_state_key(tx)),
        ("ef_fault_spool", 19, o1a_spool_key(tx)),
    ):
        pf = RefSession(27, r_ef).run(faults=fl("get", on, "IO_ERROR"))
        if pf.get("sticky_primary") != OUT_STORAGE:
            print(f"P1-1 {lab} sticky", file=sys.stderr)
            return 1
        if assert_last_get_fail(
            pf, expected_key=key_b, status="IO_ERROR", label=lab,
            want_tuple=_SELECT_SETUP_FAIL_TUPLE,
        ) != 0:
            return 1

    # DS natural fault STATE@18
    p_f = RefSession(27, mat27_chunked()).run(faults=fl("get", 18, "IO_ERROR"))
    if assert_last_get_fail(
        p_f, expected_key=want_st, status="IO_ERROR", label="ds_fault_state",
        want_tuple=_SELECT_SETUP_FAIL_TUPLE,
    ) != 0:
        return 1

    # ---- Mode29 APP_FIRST RESULT exact; CANCEL_FIRST SELECT is drives[1] ----
    r29 = mat29_app()
    p29 = RefSession(29, r29).run()
    if p29.get("final_status") != OUT_OK:
        print("P1-1 m29 positive", file=sys.stderr)
        return 1
    sel29 = select_drive_live(p29)
    tr29 = p29["port_trace"][sel29["trace_begin"] : sel29["trace_end"]]
    gets29 = [e for e in tr29 if e["op"] == "get"]
    if len(gets29) != 1:
        print("P1-1 m29 RESULT count", file=sys.stderr)
        return 1
    want_rc = o1a_rc_key(_carrier_dlv_raw(r29)[1])
    if bytes.fromhex(gets29[0]["request_key_hex"]) != want_rc:
        print("P1-1 m29 RESULT key exact", file=sys.stderr)
        return 1
    p29m = RefSession(29, mat29_rc_missing()).run()
    if assert_last_get_fail(
        p29m, expected_key=want_rc, status="NOT_FOUND", label="m29_miss_rc",
        want_tuple=_SELECT_SETUP_FAIL_TUPLE,
    ) != 0:
        return 1
    p29f = RefSession(29, r29).run(faults=fl("get", 18, "BUSY"))
    if assert_last_get_fail(
        p29f, expected_key=want_rc, status="BUSY", label="m29_fault_rc",
        want_tuple=_SELECT_SETUP_FAIL_TUPLE,
    ) != 0:
        return 1
    # CANCEL_FIRST: drive[0]=B1, drive[1]=SELECT with nexts and zero gets
    p29c = RefSession(29, mat29_cancel()).run()
    d29c = drives_of(p29c)
    if len(d29c) < 2:
        print("P1-1 m29 cancel drives", file=sys.stderr)
        return 1
    # B1: exit SELECT phase 2 flags 0x11
    b1 = d29c[0]
    if int(b1["checkpoint"]["d3s3"]["phase"]) != PHASE_SELECT_CARRIER:
        print("P1-1 m29 cancel B1 phase", file=sys.stderr)
        return 1
    sel_c = d29c[1]
    tr_c = p29c["port_trace"][sel_c["trace_begin"] : sel_c["trace_end"]]
    if not any(e["op"] == "iter_next" for e in tr_c):
        print("P1-1 m29 cancel SELECT has no next", file=sys.stderr)
        return 1
    if any(e["op"] == "get" for e in tr_c):
        print("P1-1 m29 cancel SELECT must have 0 setup GET", file=sys.stderr)
        return 1

    # ---- Mode30 PREFIX by reply_kind: exact keys, no extra get/next ----
    def check_prefix(rows, expect_subtypes, label):
        p0 = RefSession(30, rows).run()
        if p0.get("final_status") != OUT_OK:
            print(f"P1-1 {label} positive", p0.get("final_status"), file=sys.stderr)
            return 1
        pref = prefix_drive(p0)
        if pref is None:
            print(f"P1-1 {label} PREFIX drive", file=sys.stderr)
            return 1
        tr0 = p0["port_trace"][pref["trace_begin"] : pref["trace_end"]]
        if any(e["op"] == "iter_next" for e in tr0):
            print(f"P1-1 {label} PREFIX has iter_next", file=sys.stderr)
            return 1
        gets0 = [e for e in tr0 if e["op"] == "get"]
        if len(gets0) != len(expect_subtypes):
            print(f"P1-1 {label} nget", len(gets0), file=sys.stderr)
            return 1
        # reconstruct expected keys from carrier RR
        rr_v = None
        raw80 = None
        for r in rows:
            k = o1a_row_key(r)
            if o1a_subtype(k) == 0x42:
                rr_v = o1a_row_val(r)
                raw80 = o1a_dec_rr(rr_v)["delivery_raw"]
                rr_k = k
                break
        want_keys = [rr_k, o1a_dlv_key(raw80), o1a_rc_key(raw80)]
        if expect_subtypes[-1] == 0x32:
            want_keys.append(o1a_cell_key(raw80, 0))
        elif expect_subtypes[-1] == 0x33:
            want_keys.append(o1a_cs_key(raw80))
        for e, wk, st in zip(gets0, want_keys, expect_subtypes):
            got = bytes.fromhex(e["request_key_hex"])
            if got != wk or o1a_subtype(got) != st:
                print(f"P1-1 {label} key mismatch", st, file=sys.stderr)
                return 1
            if e["storage_status"] != "OK":
                print(f"P1-1 {label} get not OK", file=sys.stderr)
                return 1
        if peer_ok(p0, label) != 0:
            return 1
        return 0

    if check_prefix(mat30_receipt_empty(), [0x42, 0x40, 0x41, 0x32], "receipt") != 0:
        return 1
    if check_prefix(mat30_cancel_empty(), [0x42, 0x40, 0x41, 0x33], "cancel") != 0:
        return 1
    if check_prefix(mat30_disposition_empty(), [0x42, 0x40, 0x41], "disp") != 0:
        return 1
    if check_prefix(mat30_custody_empty(), [0x42, 0x40, 0x41], "cust") != 0:
        return 1

    # missing companions → NOT_FOUND last of PREFIX G; count_mask stays 0x03 (P1-A)
    def miss_key(rows_fn, which: str) -> bytes:
        rows = rows_fn()
        _rrk, raw, _rk = _carrier_rr(rows)
        if which == "dlv":
            return o1a_dlv_key(raw)
        if which == "rc":
            return o1a_rc_key(raw)
        if which == "cell":
            return o1a_cell_key(raw, 0)
        if which == "cs":
            return o1a_cs_key(raw)
        raise ValueError(which)

    for lab, rows_fn, which in (
        ("miss_dlv", mat30_missing_dlv, "dlv"),
        ("miss_rc", mat30_missing_rc, "rc"),
        ("miss_cell", mat30_missing_cell, "cell"),
        ("miss_cancel", mat30_missing_cancel, "cs"),
    ):
        rows_m = rows_fn()
        pm = RefSession(30, rows_m).run()
        if pm.get("final_status") != OUT_CORRUPT:
            print(f"P1-1 {lab} status", file=sys.stderr)
            return 1
        _rrk, raw_m, rk_m = _carrier_rr(rows_m)
        if assert_last_get_fail(
            pm,
            expected_key=miss_key(rows_fn, which),
            status="NOT_FOUND",
            label=lab,
            want_tuple=_prefix_fail_tuple(rk_m),
        ) != 0:
            return 1
        # Explicit P1-A: count must not advance to 0x07
        d3m = drives_of(pm)[-1]["checkpoint"]["d3s3"]
        if int(d3m["count_complete_mask"]) != 0x03:
            print(f"P1-1 {lab} count_mask want 0x03 got {d3m['count_complete_mask']}", file=sys.stderr)
            return 1

    # natural fault every PREFIX position by kind (byte exact + full tuple)
    def fault_key(rows, on: int) -> bytes:
        rrk, raw, rk = _carrier_rr(rows)
        # on_call relative product: 18 RR, 19 DLV, 20 RESULT, 21 CELL/CANCEL
        idx = on - 18
        keys = [rrk, o1a_dlv_key(raw), o1a_rc_key(raw)]
        if rk == 1:
            keys.append(o1a_cell_key(raw, 0))
        elif rk == 4:
            keys.append(o1a_cs_key(raw))
        return keys[idx]

    for lab, rows_fn, on in (
        ("rcpt_rr", mat30_receipt_empty, 18),
        ("rcpt_dlv", mat30_receipt_empty, 19),
        ("rcpt_rc", mat30_receipt_empty, 20),
        ("rcpt_cell", mat30_receipt_empty, 21),
        ("can_rr", mat30_cancel_empty, 18),
        ("can_dlv", mat30_cancel_empty, 19),
        ("can_rc", mat30_cancel_empty, 20),
        ("can_cs", mat30_cancel_empty, 21),
        ("disp_rr", mat30_disposition_empty, 18),
        ("disp_dlv", mat30_disposition_empty, 19),
        ("disp_rc", mat30_disposition_empty, 20),
        ("cust_rr", mat30_custody_empty, 18),
        ("cust_dlv", mat30_custody_empty, 19),
        ("cust_rc", mat30_custody_empty, 20),
    ):
        rows_f = rows_fn()
        pf = RefSession(30, rows_f).run(faults=fl("get", on, "IO_ERROR"))
        if pf.get("sticky_primary") != OUT_STORAGE:
            print(f"P1-1 {lab} sticky", file=sys.stderr)
            return 1
        rk_f = _carrier_rr(rows_f)[2]
        if assert_last_get_fail(
            pf,
            expected_key=fault_key(rows_f, on),
            status="IO_ERROR",
            label=lab,
            want_tuple=_prefix_fail_tuple(rk_f),
        ) != 0:
            return 1

    # Formal suffix independent validator for all setup/PREFIX natural-fault vectors
    suf = build_suffix()
    ferr = validate_all_formal_setup_get_faults(suf)
    if ferr is not None:
        print("P1-1 formal setup-fault validator:", ferr, file=sys.stderr)
        return 1
    return 0


def _o1b_focus_failure_capture_tests() -> int:
    """P1-2: FOCUS W streaming match + iter_next fault failure-point capture.

    Mode27/28 keep the live RefSession so single active_man install is
    asserted directly (Sol core), not flags alone. The MATCH_DUPLICATE case is an
    internal streaming-callback unit test: it mutates sorted_rows after formal
    precheck and is not a formal REP1 input/vector.
    """

    def fl(op, on, status):
        return [{"op": op, "on_call": on, "status": status, "shape": "natural"}]

    def prep_session(mode: int, rows: List[Dict[str, str]]) -> "RefSession":
        rs = RefSession(mode, rows)
        rs.faults = []
        rs.formal_class = FORMAL_CLASS_ORDINARY
        rs.b5 = False
        rs.b5_done = False
        rs._call_events_start = 0
        rs.api_call_index = 0
        rs._product_gets = False
        rs.peer = 0
        rs.iter_pos = 0
        rs.bind_cb = 0
        rs.last_completed_count_mask = 0
        rs.any_carrier_completed = 0
        rs.active_man = None
        return rs

    rows = mat27_chunked()
    sorted_rows = sorted(rows, key=lambda r: o1a_row_key(r))
    man_i = None
    man_row = None
    want_man: Optional[Dict[str, Any]] = None
    for i, r in enumerate(sorted_rows):
        k, v = o1a_row_key(r), o1a_row_val(r)
        if o1a_subtype(k) == 0x30 and o1a_flags(v) == 1:
            man_i = i
            man_row = r
            want_man = o1a_dec_man(k, v)
            break
    if man_i is None or man_row is None or want_man is None:
        print("P1-2 man row missing in mat27_chunked", file=sys.stderr)
        return 1

    # ---- Mode27: keep session; assert active_man install before fault ----
    rs27 = prep_session(27, rows)
    if not rs27._do_begin() or not rs27._drive_baseline() or not rs27._drive_select_w():
        print("P1-2 Mode27 setup failed", file=sys.stderr)
        return 1
    # O1b-R1: Mode27 SELECT pure W → SELECT_SETUP G → FOCUS
    if rs27.phase == PHASE_SELECT_CARRIER and int(rs27.semantic_pass) == SEM_SELECT_SETUP:
        if not rs27._drive_select_setup_g():
            print("P1-2 Mode27 SELECT_SETUP failed", file=sys.stderr)
            return 1
    if rs27.phase != PHASE_FOCUS_MANIFEST_SCAN:
        print("P1-2 Mode27 expected FOCUS entry", rs27.phase, file=sys.stderr)
        return 1
    next_so_far = int(rs27.op_counts.get("iter_next", 0))
    # FOCUS reopen does not emit iter_next; first OK next is next_so_far+1 at index 0.
    man_on_call = next_so_far + 1 + man_i
    fault_after_match = man_on_call + 1
    rs27.faults = fl("iter_next", fault_after_match, "IO_ERROR")
    rs27.fault_used = 0
    rs27._call_events_start = len(rs27.port_trace)
    ok27 = rs27._drive_focus_scan_w(which="A")
    if ok27 or rs27.phase != PHASE_FAILED:
        print("P1-2 Mode27 post-match fault should fail", ok27, rs27.phase, file=sys.stderr)
        return 1
    if int(rs27.flags) != 0x43:
        print(f"P1-2 Mode27 flags want 0x43 got {rs27.flags:#x}", file=sys.stderr)
        return 1
    # R10: sticky releases pin/man; install evidence is Normative context slots.
    if rs27.active_pins is not None or rs27.active_man is not None:
        print("P1-2 Mode27 FAILED must release pins/man", file=sys.stderr)
        return 1
    if rs27.focus_key_digest != want_man["key_digest"]:
        print("P1-2 Mode27 focus_key_digest mismatch after install+fault", file=sys.stderr)
        return 1
    if int(rs27.total_length_pin) != int(want_man["total_length"]):
        print("P1-2 Mode27 total_length_pin mismatch", file=sys.stderr)
        return 1
    if rs27.owner_primary_key_digest != want_man["owner_primary_key_digest"]:
        print("P1-2 Mode27 owner_primary_key_digest mismatch", file=sys.stderr)
        return 1
    if rs27.focus_id16 != want_man["owner_raw"]:
        print("P1-2 Mode27 focus_id16/owner_raw mismatch", file=sys.stderr)
        return 1
    if not rs27.port_trace or rs27.port_trace[-1]["op"] != "iter_next":
        print("P1-2 Mode27 last event not iter_next", file=sys.stderr)
        return 1
    if rs27.port_trace[-1]["storage_status"] != "IO_ERROR":
        print("P1-2 Mode27 last status", file=sys.stderr)
        return 1
    pack27 = rs27._finalize_pack()
    drives27 = [c for c in pack27["_calls"] if c["op"] == "d3s3_drive"]
    tr27 = pack27["port_trace"][drives27[-1]["trace_begin"] : drives27[-1]["trace_end"]]
    if any(e["op"] in ("rollback", "close") for e in tr27):
        print("P1-2 Mode27 cleanup inside failing drive", file=sys.stderr)
        return 1
    fcall27 = pack27["_calls"][-1]
    if fcall27["op"] != "finalize":
        print("P1-2 Mode27 missing finalize", file=sys.stderr)
        return 1
    ftr27 = pack27["port_trace"][fcall27["trace_begin"] : fcall27["trace_end"]]
    if not any(e["op"] == "rollback" for e in ftr27):
        print("P1-2 Mode27 finalize missing rollback", file=sys.stderr)
        return 1
    if int(drives27[-1]["checkpoint"]["d3s3"]["flags"]) != 0x43:
        print("P1-2 Mode27 checkpoint flags", file=sys.stderr)
        return 1

    # ---- Mode28: single active_man + focus_id16 A total before fault ----
    rows28 = mat28_payload_only()
    s28 = sorted(rows28, key=lambda r: o1a_row_key(r))
    man28_i = None
    want_man28: Optional[Dict[str, Any]] = None
    for i, r in enumerate(s28):
        k, v = o1a_row_key(r), o1a_row_val(r)
        if o1a_subtype(k) == 0x30 and o1a_flags(v) == 1:
            man28_i = i
            want_man28 = o1a_dec_man(k, v)
            break
    if man28_i is None or want_man28 is None:
        print("P1-2 Mode28 man missing", file=sys.stderr)
        return 1
    rs28 = prep_session(28, rows28)
    if not rs28._do_begin() or not rs28._drive_baseline() or not rs28._drive_select_w():
        print("P1-2 Mode28 setup failed", file=sys.stderr)
        return 1
    if rs28.phase != PHASE_FOCUS_MANIFEST_SCAN:
        print("P1-2 Mode28 expected FOCUS A entry", rs28.phase, file=sys.stderr)
        return 1
    next28 = int(rs28.op_counts.get("iter_next", 0))
    fault28 = next28 + 1 + man28_i + 1
    rs28.faults = fl("iter_next", fault28, "IO_ERROR")
    rs28.fault_used = 0
    rs28._call_events_start = len(rs28.port_trace)
    ok28 = rs28._drive_focus_scan_w(which="A")
    if ok28 or rs28.phase != PHASE_FAILED:
        print("P1-2 Mode28 post-match fault should fail", ok28, rs28.phase, file=sys.stderr)
        return 1
    if int(rs28.flags) != 0x43:
        print(f"P1-2 Mode28 flags want 0x43 got {rs28.flags:#x}", file=sys.stderr)
        return 1
    # R10: sticky releases pin/man; install evidence in Normative context slots.
    if rs28.active_pins is not None or rs28.active_man is not None:
        print("P1-2 Mode28 FAILED must release pins/man", file=sys.stderr)
        return 1
    if rs28.focus_key_digest != want_man28["key_digest"]:
        print("P1-2 Mode28 focus_key_digest mismatch after install+fault", file=sys.stderr)
        return 1
    if int(rs28.total_length_pin) != int(want_man28["total_length"]):
        print("P1-2 Mode28 total_length_pin mismatch", file=sys.stderr)
        return 1
    if rs28.owner_primary_key_digest != want_man28["owner_primary_key_digest"]:
        print("P1-2 Mode28 owner_primary_key_digest mismatch", file=sys.stderr)
        return 1
    pin_a, pin_b = rs28._mode28_read_pins()
    if pin_a != int(want_man28["total_length"]):
        print(
            f"P1-2 Mode28 pin_a want {want_man28['total_length']} got {pin_a}",
            file=sys.stderr,
        )
        return 1
    pack28 = rs28._finalize_pack()
    drives28 = [c for c in pack28["_calls"] if c["op"] == "d3s3_drive"]
    tr28 = pack28["port_trace"][drives28[-1]["trace_begin"] : drives28[-1]["trace_end"]]
    if any(e["op"] in ("rollback", "close") for e in tr28):
        print("P1-2 Mode28 cleanup inside failing drive", file=sys.stderr)
        return 1
    ftr28 = pack28["port_trace"][
        pack28["_calls"][-1]["trace_begin"] : pack28["_calls"][-1]["trace_end"]
    ]
    if not any(e["op"] == "rollback" for e in ftr28):
        print("P1-2 Mode28 finalize missing rollback", file=sys.stderr)
        return 1
    fid_hex = drives28[-1]["checkpoint"]["d3s3"].get("focus_id16_hex") or ""
    if len(fid_hex) != 32:
        print("P1-2 Mode28 focus_id16 missing at failure checkpoint", file=sys.stderr)
        return 1
    cpa, cpb = struct.unpack(">QQ", bytes.fromhex(fid_hex))
    if cpa != int(want_man28["total_length"]):
        print("P1-2 Mode28 checkpoint pin_a mismatch", file=sys.stderr)
        return 1

    # ---- Internal unit test (not formal REP1 input): MATCH_DUPLICATE streaming ----
    # Formal precheck forbids multiset complete keys; this mutates sorted_rows after
    # a successful formal begin/baseline/SELECT only to exercise the on_row callback.
    rs = prep_session(27, rows)
    if not rs._do_begin() or not rs._drive_baseline() or not rs._drive_select_w():
        print("P1-2 dup unit setup failed", file=sys.stderr)
        return 1
    if rs.phase == PHASE_SELECT_CARRIER and int(rs.semantic_pass) == SEM_SELECT_SETUP:
        if not rs._drive_select_setup_g():
            print("P1-2 dup unit SELECT_SETUP failed", file=sys.stderr)
            return 1
    if rs.phase != PHASE_FOCUS_MANIFEST_SCAN:
        print("P1-2 dup unit expected FOCUS entry", rs.phase, file=sys.stderr)
        return 1
    dup_rows = list(rs.sorted_rows)
    insert_at = man_i + 1
    dup_rows = dup_rows[:insert_at] + [man_row] + dup_rows[insert_at:]
    rs.sorted_rows = dup_rows
    rs.n_rows = len(dup_rows)
    rs.row_budget = rs.n_rows + 1
    next_so_far = int(rs.op_counts.get("iter_next", 0))
    # Second man is at index man_i+1 after insert.
    fault_after_dup = next_so_far + 1 + man_i + 1 + 1
    rs.faults = fl("iter_next", fault_after_dup, "BUSY")
    rs.fault_used = 0
    rs._call_events_start = len(rs.port_trace)
    ok = rs._drive_focus_scan_w(which="A")
    if ok or rs.phase != PHASE_FAILED:
        print("P1-2 dup unit fault should fail FOCUS", ok, rs.phase, file=sys.stderr)
        return 1
    want_dup_flags = (
        FLAG_BASELINE_DONE | FLAG_FOCUS_LIVE | FLAG_MATCH_INSTALLED | FLAG_MATCH_DUPLICATE
    )
    if int(rs.flags) != want_dup_flags:
        print(f"P1-2 dup unit flags want {want_dup_flags:#x} got {rs.flags:#x}", file=sys.stderr)
        return 1
    # Normative evidence is FLAG_MATCH_DUPLICATE (no private match_count attr)
    if (int(rs.flags) & FLAG_MATCH_DUPLICATE) == 0:
        print("P1-2 dup unit missing MATCH_DUPLICATE flag", file=sys.stderr)
        return 1
    # R10: projections released on sticky; first-match install is focus_key_digest + flags.
    if rs.active_pins is not None or rs.active_man is not None:
        print("P1-2 dup unit FAILED must release pins/man", file=sys.stderr)
        return 1
    if rs.focus_key_digest != want_man["key_digest"]:
        print("P1-2 dup unit focus_key_digest not first match", file=sys.stderr)
        return 1
    if not rs.port_trace or rs.port_trace[-1]["op"] != "iter_next":
        print("P1-2 dup unit last op", file=sys.stderr)
        return 1
    if rs.port_trace[-1]["storage_status"] != "BUSY":
        print("P1-2 dup unit last status", rs.port_trace[-1]["storage_status"], file=sys.stderr)
        return 1
    pack = rs._finalize_pack()
    drives_d = [c for c in pack["_calls"] if c["op"] == "d3s3_drive"]
    tr_d = pack["port_trace"][drives_d[-1]["trace_begin"] : drives_d[-1]["trace_end"]]
    if any(e["op"] in ("rollback", "close") for e in tr_d):
        print("P1-2 dup unit cleanup in failing drive", file=sys.stderr)
        return 1
    ftr = pack["port_trace"][pack["_calls"][-1]["trace_begin"] : pack["_calls"][-1]["trace_end"]]
    if not any(e["op"] == "rollback" for e in ftr):
        print("P1-2 dup unit finalize missing rollback", file=sys.stderr)
        return 1
    if int(drives_d[-1]["checkpoint"]["d3s3"]["flags"]) != want_dup_flags:
        print(
            f"P1-2 dup unit checkpoint flags "
            f"{drives_d[-1]['checkpoint']['d3s3']['flags']:#x}",
            file=sys.stderr,
        )
        return 1
    return 0


def _o1bc_fault_finalize_tests() -> int:
    """O1b-C formal fault matrix, failure-point capture, finalize precedence."""
    STATUSES = (
        "NO_SPACE", "IO_ERROR", "CORRUPT", "COMMIT_UNKNOWN", "BUSY", "UNSUPPORTED_SCHEMA",
    )

    def fl(op, on, status):
        return [{"op": op, "on_call": on, "status": status, "shape": "natural"}]

    def last_drive(p):
        drives = [c for c in p["_calls"] if c["op"] == "d3s3_drive"]
        return drives[-1] if drives else None

    def fin(p):
        return p["_calls"][-1]

    # ---- 4 ops × 6 statuses mapping / exact-use / last-event ----
    for st in STATUSES:
        want = STORAGE_TO_RUNTIME[st]
        # get call 19 Mode27 chunked (OWNER after SELECT setup STATE get@18)
        p = RefSession(27, mat27_chunked()).run(faults=fl("get", 19, st))
        if p["sticky_primary"] != want or int(p["has_sticky_primary"]) != 1:
            print(f"O1b-C get map {st}->{want} got {p['sticky_primary']}", file=sys.stderr)
            return 1
        if int(p["faults_expected_used"]) != 1:
            print(f"O1b-C get {st} not used once", file=sys.stderr)
            return 1
        d = last_drive(p)
        tr = p["port_trace"][d["trace_begin"]:d["trace_end"]]
        if not tr or tr[-1]["op"] != "get" or tr[-1]["storage_status"] != st:
            print(f"O1b-C get {st} last event", file=sys.stderr)
            return 1
        # cleanup only in finalize after failing drive
        if any(e["op"] in ("rollback", "close") for e in tr):
            print(f"O1b-C get {st} cleanup inside drive", file=sys.stderr)
            return 1
        fcall = fin(p)
        ftr = p["port_trace"][fcall["trace_begin"]:fcall["trace_end"]]
        if not any(e["op"] == "rollback" for e in ftr):
            print(f"O1b-C get {st} finalize missing rollback", file=sys.stderr)
            return 1
        # failure-point: flags preserved (OWNER entry 0x43) not BASELINE_DONE-only
        if int(d["checkpoint"]["d3s3"]["flags"]) != 0x43:
            print(
                f"O1b-C get {st} flags capture want 0x43 got "
                f"{d['checkpoint']['d3s3']['flags']:#x}",
                file=sys.stderr,
            )
            return 1
        if int(d["checkpoint"]["session"]["txn_live"]) != 1:
            print(f"O1b-C get {st} txn_live", file=sys.stderr)
            return 1
        # peer counts faulted GET
        if int(p["d3_peer_get_count"]) != int(
            fcall["checkpoint"]["port"]["get_count"]
        ) - 17:
            print(f"O1b-C get {st} peer formula", file=sys.stderr)
            return 1
        if p["final_status"] != want or fcall["expected_status"] != want:
            print(f"O1b-C get {st} final_status", file=sys.stderr)
            return 1

        # iter_open call 2 first reopen (SELECT after B1)
        p = RefSession(27, mat27_chunked()).run(faults=fl("iter_open", 2, st))
        if p["sticky_primary"] != want:
            print(f"O1b-C iter_open map {st}", file=sys.stderr)
            return 1
        d = last_drive(p)
        tr = p["port_trace"][d["trace_begin"]:d["trace_end"]]
        if tr[-1]["op"] != "iter_open" or tr[-1]["storage_status"] != st:
            print(f"O1b-C iter_open {st} last", file=sys.stderr)
            return 1
        # void close then failed open
        if not any(e["op"] == "iter_close" for e in tr):
            print(f"O1b-C iter_open {st} missing prior close", file=sys.stderr)
            return 1
        if int(d["checkpoint"]["session"]["txn_live"]) != 1:
            print(f"O1b-C iter_open {st} txn", file=sys.stderr)
            return 1
        if int(d["checkpoint"]["session"]["iter_live"]) != 0:
            print(f"O1b-C iter_open {st} iter_live0", file=sys.stderr)
            return 1
        if int(d["checkpoint"]["port"]["reopen_attempt_count"]) < 1:
            print(f"O1b-C iter_open {st} attempt", file=sys.stderr)
            return 1
        # success unchanged (0 post-I1 success if open failed)
        if int(d["checkpoint"]["port"]["reopen_success_count"]) != 0:
            print(f"O1b-C iter_open {st} success must stay 0", file=sys.stderr)
            return 1
        # NEED_REOPEN cleared
        if int(d["checkpoint"]["d3s3"]["flags"]) & FLAG_NEED_REOPEN:
            print(f"O1b-C iter_open {st} NEED still set", file=sys.stderr)
            return 1

        # iter_next call 1 baseline first next
        p = RefSession(27, mat27_chunked()).run(faults=fl("iter_next", 1, st))
        if p["sticky_primary"] != want:
            print(f"O1b-C iter_next map {st}", file=sys.stderr)
            return 1
        d = last_drive(p)
        tr = p["port_trace"][d["trace_begin"]:d["trace_end"]]
        if tr[-1]["op"] != "iter_next" or tr[-1]["storage_status"] != st:
            print(f"O1b-C iter_next {st} last", file=sys.stderr)
            return 1
        if int(d["checkpoint"]["session"]["txn_live"]) != 1:
            print(f"O1b-C iter_next {st} txn", file=sys.stderr)
            return 1
        if int(d["checkpoint"]["session"]["iter_live"]) != 1:
            print(f"O1b-C iter_next {st} iter_live1", file=sys.stderr)
            return 1

        # rollback call 1 on complete positive
        p = RefSession(27, mat27_chunked()).run(faults=fl("rollback", 1, st))
        if int(p["has_sticky_primary"]) != 0:
            print(f"O1b-C rollback {st} must not create sticky", file=sys.stderr)
            return 1
        if p["cleanup_status"] != st:
            print(f"O1b-C rollback {st} cleanup", file=sys.stderr)
            return 1
        if p["final_status"] != want:
            print(f"O1b-C rollback {st} status {p['final_status']}", file=sys.stderr)
            return 1
        if int(p["adopted"]) != 0:
            print(f"O1b-C rollback {st} adopted", file=sys.stderr)
            return 1
        if int(p["reopen_required"]) != 1:
            print(f"O1b-C rollback {st} reopen", file=sys.stderr)
            return 1
        # phase stays COMPLETE (13), not rewritten to 14
        if int(p["phase"]) != PHASE_COMPLETE:
            print(f"O1b-C rollback {st} phase keep COMPLETE got {p['phase']}", file=sys.stderr)
            return 1
        fcall = fin(p)
        ftr = p["port_trace"][fcall["trace_begin"]:fcall["trace_end"]]
        ops = [e["op"] for e in ftr]
        if "rollback" not in ops or "close" not in ops:
            print(f"O1b-C rollback {st} finalize ops {ops}", file=sys.stderr)
            return 1
        if fcall["checkpoint"]["result"]["status"] != want:
            print(f"O1b-C rollback {st} result.status", file=sys.stderr)
            return 1
        if fcall["checkpoint"]["result"]["status"] != fcall["checkpoint"]["returned_status"]:
            print(f"O1b-C rollback {st} result!=returned", file=sys.stderr)
            return 1

    # sticky wins over rollback cleanup
    bad_rows = mat27_owner_pvd_bad()
    p = RefSession(27, bad_rows).run(faults=fl("rollback", 1, "BUSY"))
    if p["sticky_primary"] != OUT_CORRUPT:
        print("O1b-C sticky wins over rollback", p["sticky_primary"], file=sys.stderr)
        return 1
    if p["cleanup_status"] != "BUSY":
        print("O1b-C cleanup still records rollback", file=sys.stderr)
        return 1
    if p["final_status"] != OUT_CORRUPT:
        print("O1b-C sticky final_status", file=sys.stderr)
        return 1
    if int(p["phase"]) != PHASE_FAILED:
        print("O1b-C drive failure phase14", file=sys.stderr)
        return 1
    if int(p["adopted"]) != 0:
        print("O1b-C sticky+rollback adopted0", file=sys.stderr)
        return 1

    # preexisting fence + rollback OK → close/reopen1/adopted0
    rs = RefSession(27, mat27_chunked())
    # run to complete but inject fence before finalize by patching after drives
    # simpler: complete run with no fault, manually not available — use internal steps
    p = RefSession(27, mat27_chunked()).run()
    if int(p["adopted"]) != 1 or p["final_status"] != OUT_OK:
        print("O1b-C baseline complete for fence test", file=sys.stderr)
        return 1
    # re-run with fence_pending set via custom session after schedule
    rs = RefSession(27, mat27_chunked())
    rs.faults = []
    rs.fault_used = 0
    rs._call_events_start = 0
    rs.api_call_index = 0
    rs._product_gets = False
    rs.peer = 0
    rs.formal_class = FORMAL_CLASS_ORDINARY
    rs.b5 = False
    rs.b5_done = False
    rs.iter_pos = 0
    rs.focus_id16 = bytes(16)
    rs.last_completed_count_mask = 0
    rs.any_carrier_completed = 0
    rs.active_pins = None
    rs.active_man = None
    rs.bind_cb = 0
    if not rs._do_begin() or not rs._drive_baseline():
        print("O1b-C fence setup begin/base", file=sys.stderr)
        return 1
    # drive rest by full loop
    while not rs._terminal and rs.phase not in (PHASE_COMPLETE, PHASE_FAILED):
        # reuse run body single step via calling public drives is hard; use full run then
        break
    p = RefSession(27, mat27_chunked()).run()
    # monkey: reconstruct finalize with fence by calling finalize path only
    # Build complete session then set fence and re-finalize once:
    rs2 = RefSession(27, mat27_chunked())
    pack = rs2.run()
    # create a session at COMPLETE with fence by replaying finalize logic unit:
    rs3 = RefSession(27, mat27_chunked())
    pack3 = rs3.run()
    # direct unit on a completed machine state:
    rs4 = RefSession(27, mat27_chunked())
    out = rs4.run()
    # Take a finished RefSession is hard after run() already finalized.
    # Unit-test finalize path by constructing minimal state:
    rs5 = RefSession(27, sort_rows(profile_rows()))
    rs5.faults = []
    rs5.fault_used = 0
    rs5._call_events_start = 0
    rs5.api_call_index = 0
    rs5.txn_live = 1
    rs5.txn_handle_id = "T1"
    rs5.iter_live = 0
    rs5.iter_handle_id = None
    rs5.storage_handle_id = "H1"
    rs5.session_state = SS_EXHAUSTED
    rs5.phase = PHASE_COMPLETE
    rs5.pass_kind = PASS_INTERNAL
    rs5.flags = 0x09
    rs5.count_mask = 0
    rs5.bind_mask = 0x18
    rs5.has_sticky = 0
    rs5.sticky = ""
    rs5.final_status = OUT_OK
    rs5.fence_pending = 1
    rs5.reopen_required = 0
    rs5.cleanup_status = None
    rs5.profile_exact_active = 1
    rs5.calls = [{"op": "begin_profiled_d3s3"}]  # non-empty so finalize not skipped oddly
    # clear fake begin so finalize can run once
    rs5.calls = []
    rs5.port_trace = []
    rs5.op_counts = {k: 0 for k in rs5.op_counts}
    pack5 = rs5._finalize_pack()
    if int(pack5["reopen_required"]) != 1 or int(pack5["adopted"]) != 0:
        print("O1b-C fence+OK rollback reopen/adopted", pack5, file=sys.stderr)
        return 1
    if pack5["cleanup_status"] is not None:
        print("O1b-C fence+OK cleanup null", file=sys.stderr)
        return 1
    if any(e["op"] == "close" for e in pack5["port_trace"]):
        pass  # expected
    else:
        print("O1b-C fence+OK must close H1", file=sys.stderr)
        return 1

    # iter_live1 txn_live0: drop without iter_close
    rs6 = RefSession(27, sort_rows(profile_rows()))
    rs6.faults = []
    rs6.fault_used = 0
    rs6.calls = []
    rs6.port_trace = []
    rs6.op_counts = {k: 0 for k in rs6.op_counts}
    rs6.txn_live = 0
    rs6.txn_handle_id = None
    rs6.iter_live = 1
    rs6.iter_handle_id = "I3"
    rs6.storage_handle_id = "H1"
    rs6.phase = PHASE_COMPLETE
    rs6.flags = 0x09
    rs6.bind_mask = 0x18
    rs6.has_sticky = 0
    rs6.sticky = ""
    rs6.final_status = OUT_OK
    rs6.fence_pending = 0
    rs6.reopen_required = 0
    rs6.cleanup_status = None
    rs6.profile_exact_active = 1
    pack6 = rs6._finalize_pack()
    if any(e["op"] == "iter_close" for e in pack6["port_trace"]):
        print("O1b-C iter drop without Port close", file=sys.stderr)
        return 1
    if int(pack6.get("reopen_required", 0)) != 0 and pack6["phase"] == PHASE_COMPLETE:
        # no fence, no rollback (txn dead) — reopen stays 0; no rollback event either
        pass
    # no txn → no rollback event
    if any(e["op"] == "rollback" for e in pack6["port_trace"]):
        print("O1b-C no txn must skip rollback", file=sys.stderr)
        return 1

    # malformed rejects (closed array/schema)
    bad_schedules = [
        [{"op": "get", "on_call": 18, "status": "IO_ERROR", "shape": "natural", "x": 1}],
        [{"op": "get", "on_call": True, "status": "IO_ERROR", "shape": "natural"}],
        [{"op": "get", "on_call": 17, "status": "IO_ERROR", "shape": "natural"}],
        [{"op": "iter_open", "on_call": 1, "status": "IO_ERROR", "shape": "natural"}],
        [{"op": "rollback", "on_call": 2, "status": "IO_ERROR", "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": "OK", "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": "NOT_FOUND", "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": "BUFFER_TOO_SMALL", "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": "WEIRD", "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": "IO_ERROR", "shape": "shaped"}],
        [{"op": "begin", "on_call": 1, "status": "IO_ERROR", "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": "IO_ERROR", "shape": "natural"},
         {"op": "get", "on_call": 19, "status": "IO_ERROR", "shape": "natural"}],
        # non-str op/status/shape (incl. unhashable)
        [{"op": [], "on_call": 18, "status": "IO_ERROR", "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": [], "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": "IO_ERROR", "shape": 1}],
        [{"op": b"get", "on_call": 18, "status": "IO_ERROR", "shape": "natural"}],
        [{"op": "get", "on_call": 18, "status": b"IO_ERROR", "shape": "natural"}],
    ]
    for bad in bad_schedules:
        try:
            RefSession(27, mat27_chunked()).run(faults=bad)
            print(f"O1b-C malformed accepted {bad}", file=sys.stderr)
            return 1
        except ValueError:
            pass

    # explicit non-list faults must reject (no coerce to [])
    def _gen():
        if False:
            yield None
        return
        yield  # pragma: no cover

    non_list_faults = [
        {},
        (),
        "",
        0,
        False,
        (fl("get", 18, "IO_ERROR")[0],),  # tuple of one fault
        iter([fl("get", 18, "IO_ERROR")[0]]),
        (x for x in fl("get", 18, "IO_ERROR")),
    ]
    for bad in non_list_faults:
        try:
            RefSession(27, mat27_chunked()).run(faults=bad)  # type: ignore[arg-type]
            print(f"O1b-C non-list faults accepted {type(bad).__name__}={bad!r}", file=sys.stderr)
            return 1
        except ValueError:
            pass
    # [] and None only accept (RefSession direct)
    p_empty = RefSession(27, mat27_chunked()).run(faults=[])
    if int(p_empty["faults_expected_used"]) != 0 or p_empty["final_status"] != OUT_OK:
        print("O1b-C faults=[] must accept", file=sys.stderr)
        return 1
    p_none = RefSession(27, mat27_chunked()).run(faults=None)
    if int(p_none["faults_expected_used"]) != 0 or p_none["final_status"] != OUT_OK:
        print("O1b-C faults=None omit must accept", file=sys.stderr)
        return 1

    # vec() serializes faults as array length 0|1 (never null)
    v_omit = vec("T_OMIT", "t", 27, mat27_chunked(), [], "omit faults")
    if type(v_omit["faults"]) is not list or v_omit["faults"] != []:
        print(f"O1b-C vec omit faults want [] got {v_omit['faults']!r}", file=sys.stderr)
        return 1
    one = [{"op": "get", "on_call": 18, "status": "IO_ERROR", "shape": "natural"}]
    v_one = vec("T_ONE", "t", 27, mat27_chunked(), [], "one fault", faults=one)
    if type(v_one["faults"]) is not list or len(v_one["faults"]) != 1:
        print(f"O1b-C vec one fault length", file=sys.stderr)
        return 1
    if v_one["faults"] is not one:
        print("O1b-C vec must reuse caller list (no destroy/replace)", file=sys.stderr)
        return 1
    if v_one["faults"][0] != one[0]:
        print("O1b-C vec one fault content", file=sys.stderr)
        return 1

    # _port_fail / _fail_get_status: validate before mutation
    rs = RefSession(27, mat27_chunked())
    rs.has_sticky = 0
    rs.sticky = ""
    rs.phase = PHASE_OWNER_PVD_PROOF
    rs.flags = 0x43
    rs.session_state = SS_EXHAUSTED
    snap = (rs.has_sticky, rs.sticky, rs.phase, rs.flags, rs.session_state)
    try:
        rs._port_fail("WEIRD")
        print("O1b-C _port_fail(WEIRD) must raise", file=sys.stderr)
        return 1
    except ValueError:
        pass
    if (rs.has_sticky, rs.sticky, rs.phase, rs.flags, rs.session_state) != snap:
        print("O1b-C _port_fail(WEIRD) mutated state", file=sys.stderr)
        return 1
    try:
        rs._fail_get_status("WEIRD", stage_absent=STAGE_OWNER_PVD)
        print("O1b-C _fail_get_status(WEIRD) must raise", file=sys.stderr)
        return 1
    except ValueError:
        pass
    if (rs.has_sticky, rs.sticky, rs.phase, rs.flags, rs.session_state) != snap:
        print("O1b-C _fail_get_status(WEIRD) mutated state", file=sys.stderr)
        return 1

    # unreachable fault (get on_call huge)
    try:
        RefSession(27, mat27_chunked()).run(
            faults=fl("get", 99999, "IO_ERROR")
        )
        print("O1b-C unreachable fault must raise", file=sys.stderr)
        return 1
    except ValueError as e:
        if "exactly once" not in str(e) and "used" not in str(e):
            # still OK if message differs slightly
            pass

    # peer counts NOT_FOUND product get: force missing key path counts via peer formula
    p = RefSession(27, mat27_chunked()).run()
    fcp = fin(p)["checkpoint"]["port"]
    if int(p["d3_peer_get_count"]) != int(fcp["get_count"]) - 17:
        print("O1b-C peer formula success path", file=sys.stderr)
        return 1

    return 0


def _o1ba_append_unit_tests() -> int:
    """Direct unit tests for _append_port_event key/type/capacity gates."""
    global TRACE_CAPACITY
    rs = RefSession(27, sort_rows(profile_rows()))
    rs.api_call_index = 0
    base = {
        "op": "begin",
        "on_call": 1,
        "storage_status": "OK",
        "input_handle_id": "H1",
        "output_handle_id": "T1",
        "mode": "READ_ONLY",
        "prefix_hex": "",
        "prefix_length": 0,
        "request_key_hex": "",
        "request_key_length": 0,
        "key_hex": "",
        "key_capacity": 0,
        "key_length": 0,
        "value_capacity": 0,
        "value_length": 0,
    }
    # happy path
    try:
        rs._append_port_event(dict(base))
    except Exception as e:
        print("append happy failed", e, file=sys.stderr)
        return 1
    # unknown key
    try:
        rs._append_port_event({**base, "on_call": 2, "extra": 1})
        print("append unknown key did not raise", file=sys.stderr)
        return 1
    except ValueError as e:
        if "unknown" not in str(e):
            print("append unknown msg", e, file=sys.stderr)
            return 1
    # missing key
    try:
        bad = dict(base)
        bad["on_call"] = 2
        del bad["mode"]
        rs._append_port_event(bad)
        print("append missing key did not raise", file=sys.stderr)
        return 1
    except ValueError as e:
        if "missing" not in str(e):
            print("append missing msg", e, file=sys.stderr)
            return 1
    # bool as u32
    try:
        rs._append_port_event({**base, "on_call": True})
        print("append bool did not raise", file=sys.stderr)
        return 1
    except TypeError:
        pass
    # negative u32
    try:
        rs._append_port_event({**base, "on_call": -1})
        print("append neg u32 did not raise", file=sys.stderr)
        return 1
    except ValueError:
        pass
    # seq/api_call_index forbidden in input
    try:
        rs._append_port_event({**base, "on_call": 3, "seq": 9})
        print("append seq input did not raise", file=sys.stderr)
        return 1
    except ValueError:
        pass
    # TRACE_CAPACITY boundary without 1M alloc
    old = TRACE_CAPACITY
    try:
        TRACE_CAPACITY = 1
        rs2 = RefSession(27, sort_rows(profile_rows()))
        rs2.api_call_index = 0
        rs2._append_port_event(dict(base))  # length becomes 1 — at capacity
        try:
            rs2._append_port_event({**base, "on_call": 2})
            print("append over capacity did not raise", file=sys.stderr)
            return 1
        except RuntimeError as e:
            if "TRACE_CAPACITY" not in str(e):
                print("append capacity msg", e, file=sys.stderr)
                return 1
        # validator shares pure helper
        if port_trace_size_error(2, 1) is None:
            print("size helper over capacity", file=sys.stderr)
            return 1
    finally:
        TRACE_CAPACITY = old
    return 0


def _o1b_bind_wg_tests() -> int:
    """Stage O1b BIND-WG: INTERNAL freeze, Port-only proof, Mode30 frontier/latch, matrix."""
    # (1) INTERNAL public counters freeze after BASELINE; lex still advances.
    p = RefSession(27, mat27_chunked()).run()
    if p.get("final_status") != OUT_OK:
        print("BIND-WG M27 positive fail", p.get("final_status"), file=sys.stderr)
        return 1
    base_ok = None
    for c in p["_calls"]:
        if c["op"] != "d3s3_drive":
            continue
        d3 = c["checkpoint"]["d3s3"]
        sess = c["checkpoint"]["session"]
        if int(d3["phase"]) == PHASE_SELECT_CARRIER and int(d3["pass_kind"]) == PASS_INTERNAL:
            base_ok = int(sess["ok_row_count"])
            break
    if base_ok is None or base_ok < 1:
        print("BIND-WG missing baseline ok_row_count", file=sys.stderr)
        return 1
    for c in p["_calls"]:
        if c["op"] != "d3s3_drive":
            continue
        d3 = c["checkpoint"]["d3s3"]
        sess = c["checkpoint"]["session"]
        if int(d3["pass_kind"]) != PASS_INTERNAL:
            continue
        if int(sess["ok_row_count"]) != base_ok:
            print(
                f"BIND-WG INTERNAL ok_row_count mutated {sess['ok_row_count']}!={base_ok}",
                file=sys.stderr,
            )
            return 1
        if int(sess["current_domain_key_count"]) != base_ok:
            print("BIND-WG INTERNAL current_domain_key_count mutated", file=sys.stderr)
            return 1

    # (2) BIND_MAN / BIND_CHUNK emit peer GETs (WG); peer count includes them.
    peer = int(p["d3_peer_get_count"])
    if peer < 1:
        print("BIND-WG M27 peer_get_count expected GETs", peer, file=sys.stderr)
        return 1
    bind_gets = 0
    for c in p["_calls"]:
        if c["op"] != "d3s3_drive":
            continue
        d3 = c["checkpoint"]["d3s3"]
        # count gets in BIND phase drives via window
        if int(d3["phase"]) in (PHASE_BIND_CHUNK, PHASE_COMPLETE) or (
            int(d3["phase"]) == PHASE_BIND_MANIFEST
        ):
            pass
    # Direct: scan port_trace for get after first BIND_MAN entry
    in_bind = False
    for c in p["_calls"]:
        if c["op"] != "d3s3_drive":
            continue
        # detect entry to BIND by exit phase of prior — use flags BIND_ACTIVE on exit
        d3 = c["checkpoint"]["d3s3"]
        port = c["checkpoint"]["port"]
        es, ee = int(port["event_start"]), int(port["event_end"])
        # After SELECT-empty exit phase=11; subsequent drives with WG get
        if int(d3["phase"]) in (PHASE_BIND_CHUNK, PHASE_COMPLETE, PHASE_BIND_MANIFEST, PHASE_FAILED):
            for ev in (p["port_trace"] or [])[es:ee]:
                if ev.get("op") == "get":
                    bind_gets += 1
    if bind_gets < 2:  # at least 1 man owner get + 1 chunk man-presence get
        print(f"BIND-WG expected man+chunk GETs got {bind_gets}", file=sys.stderr)
        return 1

    # (3) Multi-chunk positive: two chunk GETs in BIND_CHUNK
    p2 = RefSession(27, mat27_multi()).run()
    if p2.get("final_status") != OUT_OK:
        print("BIND-WG multi-chunk positive", p2.get("final_status"), file=sys.stderr)
        return 1
    chunk_gets = 0
    for c in p2["_calls"]:
        if c["op"] != "d3s3_drive":
            continue
        d3 = c["checkpoint"]["d3s3"]
        if int(d3["phase"]) != PHASE_COMPLETE:
            continue
        port = c["checkpoint"]["port"]
        es, ee = int(port["event_start"]), int(port["event_end"])
        for ev in (p2["port_trace"] or [])[es:ee]:
            if ev.get("op") == "get":
                chunk_gets += 1
    if chunk_gets < 2:
        print(f"BIND-WG multi-chunk BIND_CHUNK gets {chunk_gets}", file=sys.stderr)
        return 1

    # (4) Owner absent CORRUPT via Port GET NOT_FOUND (not offline)
    p3 = RefSession(27, sort_rows(
        mat27_chunked() + []  # use existing corrupt vector materializer path
    )).run()
    # build owner-absent like build_suffix
    r = mat27_chunked()
    foreign_tx = bytes([0xA1]) + bytes(15)
    extra_k, extra_v = rebuild_manifest(
        1, foreign_tx, 1, b"\x01", foreign_tx[:16], bytes(32), bytes(32)
    )
    r_abs = sort_rows(r + [mkrow(extra_k, extra_v)])
    p_abs = RefSession(27, r_abs).run()
    if p_abs.get("final_status") != OUT_CORRUPT:
        print("BIND-WG owner absent must CORRUPT", p_abs.get("final_status"), file=sys.stderr)
        return 1
    # offline helper still true/false independent — formal used Port
    scoped = o1a_mode_scoped_mans(27, r_abs)
    offline = o1a_bind_manifest_ok(27, scoped, o1a_index(r_abs))
    if offline:
        print("BIND-WG owner-absent offline should also fail", file=sys.stderr)
        return 1

    # (5) Mode30 BIND-entry clears last_carrier_key (empty frontier)
    p30 = RefSession(30, mat30_receipt_empty()).run()
    if p30.get("final_status") != OUT_OK:
        print("BIND-WG M30 positive", p30.get("final_status"), file=sys.stderr)
        return 1
    # first BIND_MAN outer exit with selection should have non-empty last_carrier only after RR
    saw_rr = False
    for c in p30["_calls"]:
        if c["op"] != "d3s3_drive":
            continue
        d3 = c["checkpoint"]["d3s3"]
        if int(d3["phase"]) == PHASE_BIND_MANIFEST and int(d3["semantic_pass"]) == 5:
            # exit of outer select: last_carrier must still be empty frontier (not advanced)
            if int(d3["last_carrier_key_len"]) != 0:
                print("BIND-WG M30 outer must not advance frontier", file=sys.stderr)
                return 1
            saw_rr = True
            break
    if not saw_rr:
        print("BIND-WG M30 missing RR pending exit", file=sys.stderr)
        return 1

    # (6) Mode30 orphan REPLY man (0 RR) → latch0 CORRUPT
    p_or = RefSession(30, mat30_orphan_man_0rr()).run()
    if p_or.get("final_status") != OUT_CORRUPT:
        print("BIND-WG M30 0rr orphan must CORRUPT", p_or.get("final_status"), file=sys.stderr)
        return 1

    # (7) Multi-RR latch stays boolean 0/1 (same delivery 2 RR)
    p_rr = RefSession(30, mat30_two_rr_shared()).run()
    if p_rr.get("final_status") != OUT_OK:
        print("BIND-WG M30 2RR", p_rr.get("final_status"), file=sys.stderr)
        return 1
    for c in p_rr["_calls"]:
        if c["op"] != "d3s3_drive":
            continue
        d3 = c["checkpoint"]["d3s3"]
        if int(d3.get("observed_live", 0)) not in (0, 1):
            print("BIND-WG observed_live not boolean", d3.get("observed_live"), file=sys.stderr)
            return 1

    # (8) Orphan chunk → BIND_CHUNK GET ABSENT CORRUPT
    p_oc = RefSession(30, mat30_orphan_chunk()).run()
    if p_oc.get("final_status") != OUT_CORRUPT:
        print("BIND-WG orphan chunk", p_oc.get("final_status"), file=sys.stderr)
        return 1

    # (9) Matrix validator accepts positive M27 and rejects illegal triple
    v27 = {
        "mode": 27,
        "calls": p["_calls"],
        "expected": {k: p[k] for k in p if not k.startswith("_")},
    }
    # reconstruct minimal vector-like for dispatch — use real vec path later via check
    err = validate_rep1_drive_dispatch({
        "mode": 27,
        "calls": p["_calls"],
        "expected": {
            "final_status": p["final_status"],
            "phase": p["phase"],
            "has_sticky_primary": p.get("has_sticky_primary", 0),
            "adopted": p.get("adopted", 0),
            "port_trace": p.get("port_trace") or [],
        },
    })
    if err is not None:
        print("BIND-WG matrix dispatch M27", err, file=sys.stderr)
        return 1
    if rep1_matrix_unit(11, 30, 5) != "W":
        print("BIND-WG matrix M30 RR unit", file=sys.stderr)
        return 1
    if rep1_matrix_unit(11, 27, 0) != "WG":
        print("BIND-WG matrix M27 BIND_MAN unit", file=sys.stderr)
        return 1
    if rep1_matrix_unit(11, 30, 1) is not None:
        print("BIND-WG illegal M30 sem=1 must miss", file=sys.stderr)
        return 1
    if (13, 27, 1, 0) not in REP1_TERMINAL_TABLE:
        print("BIND-WG COMPLETE terminal missing", file=sys.stderr)
        return 1

    # (10) Mode28 positive still green with BIND owner GET
    p28 = RefSession(28, mat28_payload_only()).run()
    if p28.get("final_status") != OUT_OK:
        print("BIND-WG M28 positive", p28.get("final_status"), file=sys.stderr)
        return 1

    # (11) Source formal path must not call offline o1a_bind_*_ok
    src = Path(__file__).read_text(encoding="utf-8")
    # Restrict to RefSession methods region
    i0 = src.index("class RefSession:")
    i1 = src.index("def validate_checkpoint(")
    body = src[i0:i1]
    if "o1a_bind_manifest_ok(" in body or "o1a_bind_chunk_ok(" in body:
        print("BIND-WG formal RefSession still calls offline o1a_bind_*_ok", file=sys.stderr)
        return 1
    if "m30_bound_mans" in body:
        print("BIND-WG formal still uses m30_bound_mans set", file=sys.stderr)
        return 1

    # (12) Lex commit retained after mid-BIND semantic fail (owner absent)
    # after failure has_previous must be 1 with some previous_key
    fin_sess = None
    for c in reversed(p_abs["_calls"]):
        if c["op"] == "d3s3_drive":
            fin_sess = c["checkpoint"]["session"]
            break
    if fin_sess is None or int(fin_sess.get("has_previous", 0)) != 1:
        print("BIND-WG fault retains lex has_previous", file=sys.stderr)
        return 1
    if int(fin_sess.get("ok_row_count", -1)) != base_ok:
        # base_ok from clean fixture; abs has more rows so baseline count differs
        pass  # skip exact equality across fixtures

    # (13) Independent unit-grammar RED mutations must RED
    v_ok = {
        "mode": 27,
        "formal_class": FORMAL_CLASS_ORDINARY,
        "rows": mat27_chunked(),
        "calls": p["_calls"],
        "expected": {k: p[k] for k in p if not str(k).startswith("_")},
    }
    # rebuild a formal-like vector via vec for full mechanics
    v_full = vec("TMP_OK", "tmp", 27, mat27_chunked(), [2], "tmp")
    if validate_vector_port_mechanics(v_full) is not None:
        print("BIND-WG baseline mechanics should pass", file=sys.stderr)
        return 1

    def mut_red(label, mutator) -> int:
        bad = json.loads(json.dumps(v_full))
        mutator(bad)
        err = validate_vector_port_mechanics(bad)
        if err is None:
            print(f"grammar RED {label} did not RED", file=sys.stderr)
            return 1
        return 0

    # W window smuggled get
    def add_get_to_w(d):
        for c in d["calls"]:
            if c.get("op") != "d3s3_drive":
                continue
            port = c["checkpoint"]["port"]
            es, ee = port["event_start"], port["event_end"]
            win = d["expected"]["port_trace"][es:ee]
            if any(e["op"] == "iter_next" for e in win) and not any(e["op"] == "get" for e in win):
                # inject fake get into window by expanding event_end and inserting event
                fake = dict(win[0])
                fake["op"] = "get"
                fake["storage_status"] = "OK"
                fake["on_call"] = 99
                d["expected"]["port_trace"].insert(ee, fake)
                # shift subsequent windows
                for c2 in d["calls"]:
                    p2 = c2["checkpoint"]["port"]
                    if p2["event_start"] >= ee:
                        p2["event_start"] += 1
                        p2["event_end"] += 1
                        p2["trace_count"] = p2["event_end"]
                    elif p2["event_end"] >= ee and c2 is c:
                        p2["event_end"] += 1
                        p2["trace_count"] = p2["event_end"]
                        p2["get_count"] = int(p2.get("get_count", 0)) + 1
                c["trace_end"] = c.get("trace_end", ee) + 1
                break
    if mut_red("W_has_get", add_get_to_w) != 0:
        return 1

    # G with iter_next smuggled
    def add_next_to_g(d):
        for c in d["calls"]:
            if c.get("op") != "d3s3_drive":
                continue
            if int(c.get("row_budget", -1)) != 0:
                continue
            port = c["checkpoint"]["port"]
            es, ee = port["event_start"], port["event_end"]
            win = d["expected"]["port_trace"][es:ee]
            if any(e["op"] == "get" for e in win) and not any(e["op"] == "iter_next" for e in win):
                fake = dict(win[0])
                fake["op"] = "iter_next"
                fake["storage_status"] = "OK"
                d["expected"]["port_trace"].insert(ee, fake)
                for c2 in d["calls"]:
                    p2 = c2["checkpoint"]["port"]
                    if p2["event_start"] >= ee:
                        p2["event_start"] += 1
                        p2["event_end"] += 1
                        p2["trace_count"] = p2["event_end"]
                    elif c2 is c:
                        p2["event_end"] += 1
                        p2["trace_count"] = p2["event_end"]
                break
    if mut_red("G_has_iter_next", add_next_to_g) != 0:
        return 1

    # wrong G budget
    def bad_g_budget(d):
        for c in d["calls"]:
            if c.get("op") == "d3s3_drive" and int(c.get("row_budget", -1)) == 0:
                c["row_budget"] = 3
                break
    if mut_red("G_budget", bad_g_budget) != 0:
        return 1

    # fault not last: duplicate trailing next after natural fault window is hard;
    # use wrong ordinary W budget
    def bad_w_budget(d):
        n = len(d.get("rows") or [])
        for c in d["calls"]:
            if c.get("op") == "d3s3_drive" and int(c.get("row_budget", 0)) == n + 1:
                c["row_budget"] = n
                # only non-BASELINE
                d3 = c["checkpoint"]["d3s3"]
                if int(d3.get("pass_kind", 0)) == PASS_INTERNAL:
                    break
    if mut_red("W_budget", bad_w_budget) != 0:
        return 1

    print("BIND-WG self-tests ok")
    return 0



def _o1b_r3_preflight_and_typed_red_tests() -> int:
    """O1b-R3: G preflight fail-closed + returned-value typed gate RED overrides."""
    # --- G preflight Mode30 PREFIX (executable, not docstring) ---
    rows = mat30_receipt_empty()
    rs = RefSession(30, rows)
    rs.faults = []
    rs.formal_class = FORMAL_CLASS_ORDINARY
    rs.b5 = False
    rs.b5_done = False
    rs.api_call_index = 0
    rs.peer = 0
    rs._product_gets = False
    rs.bind_cb = 0
    rs._get_response_overrides = {}
    if not rs._do_begin() or not rs._drive_baseline():
        print("R3 preflight begin/baseline failed", file=sys.stderr)
        return 1
    # Drive to PREFIX G entry by multipass product until phase 9
    guard = 0
    while (
        not rs._terminal
        and rs.phase not in (PHASE_COMPLETE, PHASE_FAILED, PHASE_SEMANTIC_PREFIX_REGET)
        and guard < 40
    ):
        guard += 1
        # one step of run loop
        if rs.phase == PHASE_SELECT_CARRIER and rs.semantic_pass == 0:
            if not rs._drive_select_w():
                break
        elif rs.phase == PHASE_SELECT_CARRIER and rs.semantic_pass == SEM_SELECT_SETUP:
            if not rs._drive_select_setup_g():
                break
        elif rs.phase == PHASE_FOCUS_MANIFEST_SCAN and rs.semantic_pass == 0:
            if not rs._drive_focus_scan_w(which="A"):
                break
        elif rs.phase == PHASE_OWNER_PVD_PROOF:
            if not rs._drive_owner_g(which="A"):
                break
        elif rs.phase == PHASE_FOCUS_CHUNKS:
            if not rs._drive_chunks_g(which="A"):
                break
        else:
            break
    if rs.phase != PHASE_SEMANTIC_PREFIX_REGET:
        # Mode30 may go SELECT→FOCUS→CHUNKS→PREFIX without OWNER
        # rematerialize via full run intermediate is hard; call prefix with forced bad liveness
        rs2 = RefSession(30, rows)
        rs2.faults = []
        rs2.formal_class = FORMAL_CLASS_ORDINARY
        rs2.b5 = False
        rs2.b5_done = False
        rs2.api_call_index = 0
        rs2.peer = 0
        rs2._product_gets = True
        rs2.session_state = SS_EXHAUSTED
        rs2.txn_live = 1
        rs2.iter_live = 0  # bad
        rs2.phase = PHASE_SEMANTIC_PREFIX_REGET
        rs2.pass_kind = PASS_INTERNAL
        # Preflight fails before pin use — leave pin/man released (754-coherent).
        rs2.active_pins = None
        rs2.active_man = None
        n_before = len(rs2.port_trace)
        ok = rs2._drive_mode30_prefix_g()
        if ok or rs2.final_status != OUT_INVALID_STATE or len(rs2.port_trace) != n_before:
            print(
                "R3 Mode30 G preflight dead-iter must INVALID_STATE zero-Port",
                ok, rs2.final_status, len(rs2.port_trace) - n_before,
                file=sys.stderr,
            )
            return 1
        rs2.iter_live = 1
        rs2.txn_live = 0
        rs2.has_sticky = 0
        rs2._failed = False
        rs2._terminal = False
        rs2.phase = PHASE_SEMANTIC_PREFIX_REGET
        rs2.active_pins = None
        rs2.active_man = None
        n_before = len(rs2.port_trace)
        ok = rs2._drive_mode30_prefix_g()
        if ok or rs2.final_status != OUT_INVALID_STATE or len(rs2.port_trace) != n_before:
            print("R3 Mode30 G preflight txn0 must INVALID_STATE", file=sys.stderr)
            return 1
    else:
        n_before = len(rs.port_trace)
        rs.iter_live = 0
        ok = rs._drive_mode30_prefix_g()
        if ok or rs.final_status != OUT_INVALID_STATE or len(rs.port_trace) != n_before:
            print("R3 Mode30 G preflight at PREFIX entry", file=sys.stderr)
            return 1

    # OWNER G preflight
    rs3 = RefSession(27, mat27_chunked())
    rs3.faults = []
    rs3.formal_class = FORMAL_CLASS_ORDINARY
    rs3.b5 = False
    rs3.b5_done = False
    rs3.session_state = SS_EXHAUSTED
    rs3.txn_live = 1
    rs3.iter_live = 0
    rs3.phase = PHASE_OWNER_PVD_PROOF
    rs3.pass_kind = PASS_INTERNAL
    rs3.active_pins = None
    rs3.active_man = None
    rs3._get_response_overrides = {}
    n_before = len(rs3.port_trace)
    if rs3._drive_owner_g(which="A") or rs3.final_status != OUT_INVALID_STATE:
        print("R3 OWNER G preflight", file=sys.stderr)
        return 1
    if len(rs3.port_trace) != n_before:
        print("R3 OWNER G preflight must be zero-Port", file=sys.stderr)
        return 1

    # --- Response override: valid key path, bad returned family/subtype/flags/CRC ---
    def _mk_override_value(*, subtype: int, flags: int, family: int = 6, version: int = 1, flip_crc: bool = False) -> bytes:
        body = bytes(32)
        v = d3s1.enc_env_full(family if family == 6 else 6, subtype, flags, 1, bytes(16), bytes(32), bytes(32), body)
        if family != 6:
            b = bytearray(v)
            b[4:6] = struct.pack(">H", family)
            b[-4:] = struct.pack(">I", d3s1.crc32c(bytes(b[:-4])))
            v = bytes(b)
        if version != 1:
            b = bytearray(v)
            b[6:8] = struct.pack(">H", version)
            b[-4:] = struct.pack(">I", d3s1.crc32c(bytes(b[:-4])))
            v = bytes(b)
        if flip_crc:
            b = bytearray(v)
            b[-1] ^= 0xFF
            v = bytes(b)
        return v

    # SELECT_SETUP STATE returned wrong subtype
    rs = RefSession(27, mat27_chunked())
    p = rs.run()  # warm
    # rebuild session to SELECT_SETUP entry
    rs = RefSession(27, mat27_chunked())
    rs.faults = []; rs.formal_class = FORMAL_CLASS_ORDINARY; rs.b5 = False; rs.b5_done = False
    rs.api_call_index = 0; rs.peer = 0; rs._product_gets = False
    if not rs._do_begin() or not rs._drive_baseline() or not rs._drive_select_w():
        print("R3 typed RED select setup path", file=sys.stderr); return 1
    if rs.semantic_pass != SEM_SELECT_SETUP:
        print("R3 expected SELECT_SETUP entry", rs.phase, rs.semantic_pass, file=sys.stderr); return 1
    tx = rs.active_pins.get("tx16") if rs.active_pins else None
    st_k = o1a_state_key(tx)
    bad = _mk_override_value(subtype=0x20, flags=0)  # wrong subtype (ANCHOR not STATE)
    rs._get_response_overrides[st_k] = bad
    n_before = len(rs.port_trace)
    ok = rs._drive_select_setup_g()
    if ok or rs.phase != PHASE_FAILED:
        print("R3 STATE wrong subtype must fail SELECT_SETUP", ok, rs.phase, file=sys.stderr); return 1
    # last event get OK (typed fail after successful get)
    win = rs.port_trace[n_before:]
    if not win or win[-1].get("op") != "get" or win[-1].get("storage_status") != "OK":
        print("R3 typed RED last event", win[-1] if win else None, file=sys.stderr); return 1
    if any(e.get("op") == "iter_next" for e in win):
        print("R3 typed RED residual next", file=sys.stderr); return 1

    # BIND_CHUNK man returned wrong flags (CHUNK flags on man key)
    # Use response override during BIND on a full OK path session is heavy; unit call:
    rs = RefSession(27, mat27_chunked())
    rs.faults = []; rs.formal_class = FORMAL_CLASS_ORDINARY; rs.b5 = False; rs.b5_done = False
    rs._get_response_overrides = {}
    # craft fake chunk walk prove
    man_k = man_v = None
    for r in mat27_chunked():
        k, v = o1a_row_key(r), o1a_row_val(r)
        if o1a_subtype(k) == 0x30 and o1a_flags(v) == 1:
            man_k, man_v = k, v
            break
    chk_k = chk_v = None
    for r in mat27_chunked():
        k, v = o1a_row_key(r), o1a_row_val(r)
        if o1a_subtype(k) == 0x30 and o1a_flags(v) == 2:
            chk_k, chk_v = k, v
            break
    if not man_k or not chk_k:
        print("R3 missing man/chunk", file=sys.stderr); return 1
    # override man response with flags=2 (chunk flags) same subtype BLOB
    bad_man = bytearray(man_v)
    bad_man[15] = 2
    bad_man[-4:] = struct.pack(">I", d3s1.crc32c(bytes(bad_man[:-4])))
    rs.idx = o1a_index(mat27_chunked())
    rs._get_response_overrides[man_k] = bytes(bad_man)
    rs.mode = 27
    rs.pass_kind = PASS_INTERNAL
    rs.txn_live = 1
    rs.iter_live = 1
    rs.session_state = SS_EXHAUSTED
    rs._product_gets = True
    rs._walk_abort = None
    n_before = len(rs.port_trace)
    rs._bind_chunk_pin_and_prove(chk_k, chk_v)
    if rs._walk_abort is None and not rs.has_sticky:
        print("R3 BIND_CHUNK wrong man flags must fail", file=sys.stderr); return 1
    # last get should be OK then semantic fail
    win = rs.port_trace[n_before:]
    if not win or win[-1].get("op") != "get":
        print("R3 BIND_CHUNK typed RED last", win, file=sys.stderr); return 1

    # CRC flip on OWNER carrier get
    rs = RefSession(27, mat27_chunked())
    rs.faults = []; rs.formal_class = FORMAL_CLASS_ORDINARY; rs.b5 = False; rs.b5_done = False
    rs.api_call_index = 0; rs.peer = 0; rs._product_gets = False
    if not rs._do_begin() or not rs._drive_baseline():
        print("R3 CRC path setup", file=sys.stderr); return 1
    # advance to OWNER
    guard = 0
    while rs.phase != PHASE_OWNER_PVD_PROOF and not rs._terminal and guard < 20:
        guard += 1
        if rs.phase == PHASE_SELECT_CARRIER and rs.semantic_pass == 0:
            rs._drive_select_w()
        elif rs.phase == PHASE_SELECT_CARRIER and rs.semantic_pass == SEM_SELECT_SETUP:
            rs._drive_select_setup_g()
        elif rs.phase == PHASE_FOCUS_MANIFEST_SCAN:
            rs._drive_focus_scan_w(which="A")
        else:
            break
    if rs.phase != PHASE_OWNER_PVD_PROOF:
        print("R3 did not reach OWNER", rs.phase, file=sys.stderr); return 1
    ck = rs.active_pins["carrier_key"]
    good = rs.idx.get(ck)
    bad = bytearray(good); bad[-1] ^= 0xFF
    rs._get_response_overrides[ck] = bytes(bad)
    n_before = len(rs.port_trace)
    ok = rs._drive_owner_g(which="A")
    if ok or rs.phase != PHASE_FAILED:
        print("R3 OWNER CRC must fail", file=sys.stderr); return 1
    win = rs.port_trace[n_before:]
    if not win or win[-1].get("op") != "get" or win[-1].get("storage_status") != "OK":
        print("R3 OWNER CRC last get", file=sys.stderr); return 1


    # --- P1-A strict framing RED (short/valid-CRC must fail) ---
    def _forge_short_ok_crc(subtype: int, flags: int) -> bytes:
        # plen=4 forged envelope that old gate accepted
        payload = bytes([0, 1, subtype & 0xFF, flags & 0xFF])
        body = b"NLR1" + struct.pack(">HH", 6, 1) + struct.pack(">I", 4) + payload
        return body + struct.pack(">I", d3s1.crc32c(body))

    short = _forge_short_ok_crc(0x22, 0)
    if o1a_value_typed_current(short, expect_subtype=0x22, expect_flags=0) is None:
        print("R3 short-valid-CRC must not pass CURRENT gate", file=sys.stderr)
        return 1
    real = gval("DSB2_STATE_TYPED")
    bad_df = bytearray(real)
    bad_df[12:14] = struct.pack(">H", 2)
    bad_df[-4:] = struct.pack(">I", d3s1.crc32c(bytes(bad_df[:-4])))
    if o1a_value_typed_current(bytes(bad_df), expect_subtype=0x22, expect_flags=0) is None:
        print("R3 wrong domain_format must fail", file=sys.stderr)
        return 1
    bad_bl = bytearray(real)
    bl = int.from_bytes(real[104:108], "big") ^ 1
    bad_bl[104:108] = struct.pack(">I", bl)
    bad_bl[-4:] = struct.pack(">I", d3s1.crc32c(bytes(bad_bl[:-4])))
    if o1a_value_typed_current(bytes(bad_bl), expect_subtype=0x22, expect_flags=0) is None:
        print("R3 body_len mismatch must fail", file=sys.stderr)
        return 1

    # --- P1-B Mode28: alter returned chunk data (valid CRC) must fail offline-free ---
    rows28 = mat28_payload_only()
    rs = RefSession(28, rows28)
    rs.faults = []
    rs.formal_class = FORMAL_CLASS_ORDINARY
    rs.b5 = False
    rs.b5_done = False
    rs.api_call_index = 0
    rs.peer = 0
    rs._product_gets = False
    rs.bind_cb = 0
    rs._get_response_overrides = {}
    # drive to view-A chunks G (sem=2) after PREFIX
    guard = 0
    while not rs._terminal and guard < 40:
        guard += 1
        if rs.phase == PHASE_SELECT_CARRIER and rs.semantic_pass == 0:
            if not rs._drive_select_w():
                break
        elif rs.phase == PHASE_FOCUS_MANIFEST_SCAN and rs.semantic_pass == 0:
            if not rs._drive_focus_scan_w(which="A"):
                break
        elif rs.phase == PHASE_OWNER_PVD_PROOF:
            if not rs._drive_owner_g(which="A"):
                break
        elif rs.phase == PHASE_FOCUS_CHUNKS:
            if not rs._drive_chunks_g(which="A"):
                break
        elif rs.phase == PHASE_SEMANTIC_PREFIX_REGET and rs.semantic_pass == 0:
            if not rs._drive_mode28_prefix_g():
                break
        elif rs.phase == PHASE_FOCUS_MANIFEST_SCAN and rs.semantic_pass == 1:
            if not rs._drive_mode28_rescan_w(which="A"):
                break
        elif rs.phase == PHASE_SEMANTIC_CHUNK_REWALK and rs.semantic_pass == 2:
            # inject bad chunk payload before view chunks G
            man = rs.active_man
            if man is None or man["chunk_count"] < 1:
                print("R3 m28 no man for chunk override", file=sys.stderr)
                return 1
            ck = o1a_chk_key_from_blob_index(man["blob_id"], 0)
            good = rs.idx.get(ck)
            # flip one data byte and recompute CRC; keep typed subtype/flags
            b = bytearray(good)
            # data starts after body header; flip last body byte before CRC
            if len(b) > 120:
                b[-5] ^= 0x5A
            b[-4:] = struct.pack(">I", d3s1.crc32c(bytes(b[:-4])))
            rs._get_response_overrides[ck] = bytes(b)
            n_before = len(rs.port_trace)
            ok = rs._drive_mode28_view_chunks_g(which="A")
            if ok or rs.phase != PHASE_FAILED:
                print("R3 m28 altered chunk response must fail", ok, rs.phase, file=sys.stderr)
                return 1
            win = rs.port_trace[n_before:]
            if not win or win[-1].get("op") != "get":
                print("R3 m28 chunk RED last event", file=sys.stderr)
                return 1
            break
        else:
            break
    else:
        print("R3 m28 did not reach view-chunks G", rs.phase, rs.semantic_pass, file=sys.stderr)
        return 1

    # --- P1-B Mode30: alter returned DLV body (valid CRC) after PREFIX pin path ---
    rows30 = mat30_receipt_empty()
    rs = RefSession(30, rows30)
    rs.faults = []
    rs.formal_class = FORMAL_CLASS_ORDINARY
    rs.b5 = False
    rs.b5_done = False
    rs.api_call_index = 0
    rs.peer = 0
    rs._product_gets = False
    rs.bind_cb = 0
    rs._get_response_overrides = {}
    guard = 0
    while not rs._terminal and guard < 40:
        guard += 1
        if rs.phase == PHASE_SELECT_CARRIER and rs.semantic_pass == 0:
            if not rs._drive_select_w():
                break
        elif rs.phase == PHASE_FOCUS_MANIFEST_SCAN and rs.semantic_pass == 0:
            if not rs._drive_focus_scan_w(which="A"):
                break
        elif rs.phase == PHASE_FOCUS_CHUNKS:
            if not rs._drive_chunks_g(which="A"):
                break
        elif rs.phase == PHASE_SEMANTIC_PREFIX_REGET and rs.semantic_pass == 0:
            # override DLV response to flip a non-identity body byte after raw
            raw80 = (rs.active_pins or {}).get("focus_raw80") or b""
            if len(raw80) != 80:
                print("R3 m30 raw80 missing", file=sys.stderr)
                return 1
            dk = o1a_dlv_key(raw80)
            good = rs.idx.get(dk)
            b = bytearray(good)
            # flip near end of body before CRC without breaking outer envelope lengths
            if len(b) > 120:
                b[-8] ^= 0x33
            b[-4:] = struct.pack(">I", d3s1.crc32c(bytes(b[:-4])))
            # keep typed CURRENT (subtype/flags/domain_format) but semantic fields change
            rs._get_response_overrides[dk] = bytes(b)
            n_before = len(rs.port_trace)
            ok = rs._drive_mode30_prefix_g()
            # PREFIX only types/pins; fail may be later at SEM_CHUNK if pin accepts.
            # Force semantic path: if PREFIX succeeded, continue to SEM_CHUNK with bad pin.
            if not ok:
                # typed fail or port fail is also acceptable for corrupt body if framing broke
                if rs.phase == PHASE_FAILED and rs.port_trace[n_before:]:
                    break
                print("R3 m30 prefix unexpected", ok, rs.phase, file=sys.stderr)
                return 1
            # PREFIX OK with altered DLV pin — SEM_CHUNK must fail using returned pin
            if rs.phase != PHASE_SEMANTIC_CHUNK_REWALK:
                print("R3 m30 expected SEM_CHUNK after PREFIX", rs.phase, file=sys.stderr)
                return 1
            n_before2 = len(rs.port_trace)
            ok2 = rs._drive_mode30_sem_chunk_g()
            if ok2 or rs.phase != PHASE_FAILED:
                print("R3 m30 altered DLV must fail SEM_CHUNK", ok2, rs.phase, file=sys.stderr)
                return 1
            break
        else:
            break
    else:
        print("R3 m30 path not reached", rs.phase, file=sys.stderr)
        return 1

    # Mode29: alter returned DELIVERY value at OWNER G (valid CRC) must fail PVD
    rows29 = mat29_app()
    rs = RefSession(29, rows29)
    rs.faults = []
    rs.formal_class = FORMAL_CLASS_ORDINARY
    rs.b5 = False
    rs.b5_done = False
    rs.api_call_index = 0
    rs.peer = 0
    rs._product_gets = False
    rs.bind_cb = 0
    rs._get_response_overrides = {}
    guard = 0
    while not rs._terminal and guard < 30:
        guard += 1
        if rs.phase == PHASE_SELECT_CARRIER and rs.semantic_pass == 0:
            if not rs._drive_select_w():
                break
        elif rs.phase == PHASE_SELECT_CARRIER and rs.semantic_pass == SEM_SELECT_SETUP:
            if not rs._drive_select_setup_g():
                break
        elif rs.phase == PHASE_FOCUS_MANIFEST_SCAN and rs.semantic_pass == 0:
            if not rs._drive_focus_scan_w(which="A"):
                break
        elif rs.phase == PHASE_OWNER_PVD_PROOF:
            ck = (rs.active_pins or {}).get("carrier_key")
            good = rs.idx.get(ck) if ck else None
            if not good:
                print("R3 m29 owner key missing", file=sys.stderr)
                return 1
            b = bytearray(good)
            if len(b) > 120:
                b[-8] ^= 0x55
            b[-4:] = struct.pack(">I", d3s1.crc32c(bytes(b[:-4])))
            rs._get_response_overrides[ck] = bytes(b)
            n_before = len(rs.port_trace)
            ok = rs._drive_owner_g(which="A")
            if ok or rs.phase != PHASE_FAILED:
                print("R3 m29 altered owner response must fail OWNER", ok, rs.phase, file=sys.stderr)
                return 1
            win = rs.port_trace[n_before:]
            if not win or win[-1].get("op") != "get" or win[-1].get("storage_status") != "OK":
                print("R3 m29 owner RED last get", file=sys.stderr)
                return 1
            break
        else:
            break
    else:
        print("R3 m29 OWNER not reached", rs.phase, file=sys.stderr)
        return 1


    # --- R7: structural allowlist + AST + max-occupancy product audit ---
    import ast as _ast

    src_text = Path(__file__).read_text(encoding="utf-8")
    if not PRODUCT_PATH_PIN_ALLOWLIST or "msd_prefix" in PRODUCT_PATH_PIN_ALLOWLIST:
        print("R7 pin allowlist invalid", file=sys.stderr)
        return 1
    if "key" in PRODUCT_PATH_MAN_ALLOWLIST or "value" in PRODUCT_PATH_MAN_ALLOWLIST:
        print("R7 man allowlist must exclude key/value", file=sys.stderr)
        return 1
    if _PRODUCT_SHA_MAX != 1:
        print("R7 SHA max must be 1", file=sys.stderr)
        return 1
    if _PRODUCT_SHA_LIVE != 0:
        print("R7 SHA live leak after tests", _PRODUCT_SHA_LIVE, file=sys.stderr)
        return 1

    # AST: product drive methods must not reference carrier_queue/carriers_seen/idx as authority
    tree = _ast.parse(src_text)
    drive_names = {
        "_drive_select_w", "_drive_select_setup_g", "_drive_focus_scan_w",
        "_drive_owner_g", "_drive_chunks_g", "_drive_mode28_prefix_g",
        "_drive_mode28_rescan_w", "_drive_mode28_view_chunks_g",
        "_drive_mode30_prefix_g", "_drive_mode30_sem_chunk_g",
        "_drive_bind_man_w", "_drive_bind_chunk_w", "_select_pin_from_carrier",
        "_focus_apply_live_match",
    }
    banned_attrs = {"carrier_queue", "carriers_seen"}
    for node in tree.body:
        if not isinstance(node, _ast.ClassDef) or node.name != "RefSession":
            continue
        for item in node.body:
            if not isinstance(item, (_ast.FunctionDef, _ast.AsyncFunctionDef)):
                continue
            if item.name not in drive_names and not item.name.startswith("_drive_"):
                continue
            for sub in _ast.walk(item):
                if isinstance(sub, _ast.Attribute) and sub.attr in banned_attrs:
                    print(f"R7 AST product uses full-ID set: {item.name}.{sub.attr}", file=sys.stderr)
                    return 1
                # self.idx in drive (except product_get provider helpers) is adjudication offline
                if (
                    isinstance(sub, _ast.Attribute)
                    and sub.attr == "idx"
                    and item.name not in ("_product_get_typed", "_storage_get", "_get")
                    and item.name.startswith("_drive_")
                ):
                    # allow only as part of comments — AST sees real loads
                    print(f"R7 AST product drive uses offline idx: {item.name}", file=sys.stderr)
                    return 1

    def _audit_run(mode: int, rows: List[Dict[str, str]], label: str) -> int:
        p = RefSession(mode, rows).run()
        if p.get("final_status") != OUT_OK or int(p.get("adopted", 0)) != 1:
            print(f"R7 audit {label} final", p.get("final_status"), file=sys.stderr)
            return 1
        if _PRODUCT_SHA_LIVE != 0:
            print(f"R7 audit {label} SHA live", file=sys.stderr)
            return 1
        return 0

    # Mode28 legal arms A/B + zero; both-nonzero reject (D1 mix)
    if _audit_run(28, mat28_payload_only(), "m28_armA") != 0:
        return 1
    if _audit_run(28, mat28_evidence_only(), "m28_armB") != 0:
        return 1
    if _audit_run(28, mat28_zero_both(), "m28_zero") != 0:
        return 1
    # both-nonzero APPLICATION is D1-illegal → exact CORRUPT / no-adopt at SELECT
    rows_bn = mat28_both_nonzero_illegal()
    rs_bn = RefSession(28, rows_bn)
    rs_bn.faults = []
    rs_bn.formal_class = FORMAL_CLASS_ORDINARY
    rs_bn.b5 = False
    rs_bn.b5_done = False
    if not rs_bn._do_begin() or not rs_bn._drive_baseline():
        print("R8 both-nonzero setup", file=sys.stderr)
        return 1
    ok_bn = rs_bn._drive_select_w()
    if ok_bn or rs_bn.phase != PHASE_FAILED:
        print(
            "R8 both-nonzero must FAILED at SELECT",
            ok_bn, rs_bn.phase, rs_bn.final_status,
            file=sys.stderr,
        )
        return 1
    if rs_bn.final_status != OUT_CORRUPT:
        print("R8 both-nonzero sticky must CORRUPT", rs_bn.final_status, file=sys.stderr)
        return 1
    if int(rs_bn.adopted) != 0:
        print("R8 both-nonzero must no-adopt", file=sys.stderr)
        return 1

    # Max SERVICE_IDENTITY exact 240 linked fixtures (self-test only; not formal count)
    if len(o1a_service_identity_max240()) != 240:
        print("R7 SERVICE_IDENTITY max not 240", file=sys.stderr)
        return 1
    if _audit_run(29, mat29_app_max_service(), "m29_max_svc") != 0:
        return 1
    if _audit_run(30, mat30_receipt_max_service(), "m30_max_svc") != 0:
        return 1
    if _audit_run(30, mat30_receipt_128(), "m30_receipt128") != 0:
        return 1

    # Mid-drive max occupancy: SELECT + FOCUS leave single man bank, no full-ID set
    rs = RefSession(28, mat28_payload_only())
    rs.faults = []
    rs.formal_class = FORMAL_CLASS_ORDINARY
    rs.b5 = False
    rs.b5_done = False
    rs.api_call_index = 0
    rs.peer = 0
    rs._product_gets = False
    rs.bind_cb = 0
    rs._get_response_overrides = {}
    if not rs._do_begin() or not rs._drive_baseline() or not rs._drive_select_w():
        print("R7 m28 SELECT audit setup", file=sys.stderr)
        return 1
    # drive_end already asserted; explicit checks
    if hasattr(rs, "carrier_queue") or hasattr(rs, "carriers_seen"):
        print("R7 SELECT session has full-ID set attrs", file=sys.stderr)
        return 1
    pins = rs.active_pins or {}
    if "body" in pins or "msd_prefix" in pins:
        print("R7 m28 SELECT retained body/msd_prefix", file=sys.stderr)
        return 1
    if "view_a" not in pins or "semantic_stored" not in pins:
        print("R7 m28 SELECT missing fixed digests", file=sys.stderr)
        return 1
    if not rs._drive_focus_scan_w(which="A"):
        print("R7 m28 FOCUS audit", file=sys.stderr)
        return 1
    if rs.active_man is None or "key" in (rs.active_man or {}):
        print("R7 m28 mid FOCUS man bank invalid", file=sys.stderr)
        return 1

    rs29 = RefSession(29, mat29_app_max_service())
    rs29.faults = []
    rs29.formal_class = FORMAL_CLASS_ORDINARY
    rs29.b5 = False
    rs29.b5_done = False
    if not rs29._do_begin() or not rs29._drive_baseline() or not rs29._drive_select_w():
        print("R7 m29 SELECT audit setup", file=sys.stderr)
        return 1
    if "dlv" in (rs29.active_pins or {}) or "service" in (rs29.active_pins or {}):
        print("R7 m29 SELECT retained dlv/service", file=sys.stderr)
        return 1

    # R8: successful Modes27–30 final instances must have released pin/man banks
    for label, mode, rows in (
        ("m27", 27, mat27_chunked()),
        ("m28a", 28, mat28_payload_only()),
        ("m28b", 28, mat28_evidence_only()),
        ("m29", 29, mat29_app_max_service()),
        ("m30", 30, mat30_receipt_max_service()),
    ):
        rs_f = RefSession(mode, rows)
        pack = rs_f.run()
        if pack.get("final_status") != OUT_OK or int(pack.get("adopted", 0)) != 1:
            print(f"R8 final {label} not OK", pack.get("final_status"), file=sys.stderr)
            return 1
        if rs_f.active_pins is not None or rs_f.active_man is not None:
            print(
                f"R8 final {label} must release pins/man",
                rs_f.active_pins is not None, rs_f.active_man is not None,
                file=sys.stderr,
            )
            return 1
        if rs_f.phase != PHASE_COMPLETE:
            print(f"R8 final {label} phase", rs_f.phase, file=sys.stderr)
            return 1

    # --- R9: exhaustive slot coverage + RED mutation of each alias class ---
    try:
        _layout_754_validate_static()
    except AssertionError as e:
        print("R9 layout static", e, file=sys.stderr)
        return 1
    # Every allowed pin/man key maps to a slot inside 0..753
    for k, slot in PRODUCT_PATH_PIN_SLOT.items():
        a, b = layout_754_range(slot)
        if not (0 <= a < b <= 754):
            print("R9 pin slot OOB", k, slot, a, b, file=sys.stderr)
            return 1
    for k, slot in PRODUCT_PATH_MAN_SLOT.items():
        a, b = layout_754_range(slot)
        if not (0 <= a < b <= 754):
            print("R9 man slot OOB", k, slot, a, b, file=sys.stderr)
            return 1
    if set(PRODUCT_PATH_PIN_ALLOWLIST) != set(PRODUCT_PATH_PIN_SLOT):
        print("R9 pin allowlist != slot map keys", file=sys.stderr)
        return 1
    if set(PRODUCT_PATH_MAN_ALLOWLIST) != set(PRODUCT_PATH_MAN_SLOT):
        print("R9 man allowlist != slot map keys", file=sys.stderr)
        return 1

    def _red_assert(label: str, mut) -> int:
        rs = RefSession(30, mat30_receipt_empty())
        rs.faults = []
        rs.formal_class = FORMAL_CLASS_ORDINARY
        rs.b5 = False
        rs.b5_done = False
        if not rs._do_begin() or not rs._drive_baseline() or not rs._drive_select_w():
            print(f"R9 RED {label} setup", file=sys.stderr)
            return 1
        if rs.phase != PHASE_FOCUS_MANIFEST_SCAN or rs.active_pins is None:
            print(f"R9 RED {label} expected FOCUS+pins", file=sys.stderr)
            return 1
        mut(rs)
        try:
            rs._product_state_assert_r8()
            print(f"R9 RED {label} must reject", file=sys.stderr)
            return 1
        except AssertionError:
            return 0

    # carrier_key != last_carrier_key
    if _red_assert("carrier_key", lambda rs: rs.active_pins.__setitem__(
        "carrier_key", b"\xff" * 20
    )) != 0:
        return 1
    # Mode30 transaction_id != focus_id16
    if _red_assert("tx_focus", lambda rs: (
        rs.active_pins.__setitem__("transaction_id", b"\x11" * 16)
    )) != 0:
        return 1
    # focus_raw80 pin != context
    if _red_assert("raw80", lambda rs: rs.active_pins.__setitem__(
        "focus_raw80", bytes(80)
    ) if rs.active_pins.get("focus_raw80") != bytes(80) else rs.active_pins.__setitem__(
        "focus_raw80", b"\xaa" * 80
    )) != 0:
        return 1
    # focus_dig != focus_key_digest
    if _red_assert("focus_dig", lambda rs: rs.active_pins.__setitem__(
        "focus_dig", b"\x22" * 32
    )) != 0:
        return 1
    # send_state != next_chunk_index
    if _red_assert("send_state", lambda rs: rs.active_pins.__setitem__(
        "send_state", (int(rs.next_chunk_index) ^ 3) or 3
    )) != 0:
        return 1
    # unmapped pin key
    if _red_assert("unmapped_pin", lambda rs: rs.active_pins.__setitem__(
        "needs_setup", 1
    )) != 0:
        return 1
    # man key_digest != focus_key_digest after FOCUS
    rs_m = RefSession(30, mat30_receipt_empty())
    rs_m.faults = []
    rs_m.formal_class = FORMAL_CLASS_ORDINARY
    rs_m.b5 = False
    rs_m.b5_done = False
    if not rs_m._do_begin() or not rs_m._drive_baseline() or not rs_m._drive_select_w():
        print("R9 RED man setup", file=sys.stderr)
        return 1
    if not rs_m._drive_focus_scan_w(which="A"):
        print("R9 RED man FOCUS", file=sys.stderr)
        return 1
    if rs_m.active_man is None:
        print("R9 RED man missing", file=sys.stderr)
        return 1
    rs_m.active_man = dict(rs_m.active_man)
    rs_m.active_man["key_digest"] = b"\x33" * 32
    try:
        rs_m._product_state_assert_r8()
        print("R9 RED man.key_digest must reject", file=sys.stderr)
        return 1
    except AssertionError:
        pass
    # Mode28 man.key_digest not equal either view
    rs28 = RefSession(28, mat28_payload_only())
    rs28.faults = []
    rs28.formal_class = FORMAL_CLASS_ORDINARY
    rs28.b5 = False
    rs28.b5_done = False
    if not rs28._do_begin() or not rs28._drive_baseline() or not rs28._drive_select_w():
        print("R9 RED m28 setup", file=sys.stderr)
        return 1
    if not rs28._drive_focus_scan_w(which="A"):
        print("R9 RED m28 FOCUS", file=sys.stderr)
        return 1
    rs28.active_man = dict(rs28.active_man)
    rs28.active_man["key_digest"] = b"\x44" * 32
    # keep context in sync would pass man.slot check if we only change man — desync
    try:
        rs28._product_state_assert_r8()
        print("R9 RED m28 man.key_digest must reject", file=sys.stderr)
        return 1
    except AssertionError:
        pass
    # semantic_digest pin != expected_semantic_digest context
    if _red_assert("semantic", lambda rs: (
        rs.active_pins.__setitem__("semantic_digest", b"\x55" * 32)
    )) != 0:
        return 1

    # --- R10: FAILED releases pin/man/SHA; no mismatch-continue false-pass ---
    # Cross-delivery Mode30 ends FAILED with projections released + SHA dead
    rs_cd = RefSession(30, mat30_cross_delivery())
    pack_cd = rs_cd.run()
    if pack_cd.get("final_status") == OUT_OK or int(pack_cd.get("adopted", 0)) != 0:
        print("R10 cross-delivery must not adopt", pack_cd.get("final_status"), file=sys.stderr)
        return 1
    if rs_cd.phase != PHASE_FAILED:
        print("R10 cross-delivery phase", rs_cd.phase, file=sys.stderr)
        return 1
    if rs_cd.active_pins is not None or rs_cd.active_man is not None:
        print("R10 cross-delivery must release pins/man", file=sys.stderr)
        return 1
    if getattr(rs_cd, "_product_sha", None) is not None or _PRODUCT_SHA_LIVE != 0:
        print("R10 cross-delivery SHA must be dead", _PRODUCT_SHA_LIVE, file=sys.stderr)
        return 1
    # Representative mid-phase natural fault (Mode28 FOCUS after match)
    rows_f = mat28_payload_only()
    s_f = sorted(rows_f, key=lambda r: o1a_row_key(r))
    man_i_f = next(
        i for i, r in enumerate(s_f)
        if o1a_subtype(o1a_row_key(r)) == 0x30 and o1a_flags(o1a_row_val(r)) == 1
    )
    rs_f = RefSession(28, rows_f)
    rs_f.faults = []
    rs_f.formal_class = FORMAL_CLASS_ORDINARY
    rs_f.b5 = False
    rs_f.b5_done = False
    if not rs_f._do_begin() or not rs_f._drive_baseline() or not rs_f._drive_select_w():
        print("R10 mid-fault setup", file=sys.stderr)
        return 1
    n0 = int(rs_f.op_counts.get("iter_next", 0))
    rs_f.faults = [{"op": "iter_next", "on_call": n0 + 1 + man_i_f + 1, "status": "IO_ERROR", "shape": "natural"}]
    rs_f.fault_used = 0
    rs_f._call_events_start = len(rs_f.port_trace)
    if rs_f._drive_focus_scan_w(which="A") or rs_f.phase != PHASE_FAILED:
        print("R10 mid-fault must FAILED", file=sys.stderr)
        return 1
    if rs_f.active_pins is not None or rs_f.active_man is not None:
        print("R10 mid-fault must release pins/man", file=sys.stderr)
        return 1
    if getattr(rs_f, "_product_sha", None) is not None or _PRODUCT_SHA_LIVE != 0:
        print("R10 mid-fault SHA must be dead", file=sys.stderr)
        return 1
    # Deliberately retained unequal owner_raw while pins live must be rejected
    rs_u = RefSession(30, mat30_receipt_empty())
    rs_u.faults = []
    rs_u.formal_class = FORMAL_CLASS_ORDINARY
    rs_u.b5 = False
    rs_u.b5_done = False
    if not rs_u._do_begin() or not rs_u._drive_baseline() or not rs_u._drive_select_w():
        print("R10 unequal setup", file=sys.stderr)
        return 1
    if not rs_u._drive_focus_scan_w(which="A"):
        print("R10 unequal FOCUS", file=sys.stderr)
        return 1
    if rs_u.active_man is None or rs_u.active_pins is None:
        print("R10 unequal expected live pin/man", file=sys.stderr)
        return 1
    rs_u.active_man = dict(rs_u.active_man)
    rs_u.active_man["owner_raw"] = b"\xee" * 80  # unequal to pin focus_raw80
    try:
        rs_u._product_state_assert_r8()
        print("R10 unequal man.owner_raw must reject (no continue escape)", file=sys.stderr)
        return 1
    except AssertionError:
        pass

    print("O1b-R3/R10 preflight/typed RED + 754 slot audit ok")
    return 0


def self_test() -> int:
    import contextlib
    import io
    import subprocess

    @contextlib.contextmanager
    def _silence_stderr():
        buf = io.StringIO()
        old = sys.stderr
        sys.stderr = buf
        try:
            yield buf
        finally:
            sys.stderr = old

    with tempfile.TemporaryDirectory() as td:
        td = Path(td)
        d1 = build_document(DEFAULT_JSON)
        d2 = build_document(DEFAULT_JSON)
        b1 = json.dumps(d1, indent=2, ensure_ascii=False) + "\n"
        b2 = json.dumps(d2, indent=2, ensure_ascii=False) + "\n"
        if b1 != b2:
            print("non-deterministic generate", file=sys.stderr); return 1
        if d1.get("content_sha256") != d2.get("content_sha256"):
            print("content_sha non-deterministic", file=sys.stderr); return 1
        p = td / "out.json"
        p.write_text(b1, encoding="utf-8")
        if check(p) != 0:
            return 1
        # first144 full-object vs live file prefix
        live = json.loads(DEFAULT_JSON.read_text(encoding="utf-8"))
        if len(live.get("vectors", [])) < D3S2_PREFIX:
            print("live shorter than 144", file=sys.stderr); return 1
        for i in range(D3S2_PREFIX):
            if live["vectors"][i] != d1["vectors"][i]:
                print(f"first144 full-object mismatch at {i}", file=sys.stderr)
                return 1
        if len(d1["vectors"]) - D3S2_PREFIX != D3S3_SUFFIX_COUNT:
            print(f"suffix not {D3S3_SUFFIX_COUNT}", file=sys.stderr); return 1
        b5_ids = [
            v for v in d1["vectors"][D3S2_PREFIX:]
            if v.get("formal_class") == FORMAL_CLASS_B5_BASELINE
        ]
        if len(b5_ids) < 1:
            print("temp suffix missing B5 formal vector", file=sys.stderr); return 1
        b5_err = validate_b5_formal_vector(b5_ids[0])
        if b5_err is not None:
            print("B5 formal vector invalid:", b5_err, file=sys.stderr); return 1

        def must_red(label: str, mutator) -> int:
            bad = json.loads(b1)
            mutator(bad)
            bad["content_sha256"] = _content_sha(bad)
            bp = td / f"mut_{label}.json"
            bp.write_text(json.dumps(bad, indent=2) + "\n", encoding="utf-8")
            with _silence_stderr():
                rc = check(bp, quiet=True)
            if rc == 0:
                print(f"mutation {label} did not RED", file=sys.stderr)
                return 1
            return 0

        # pick a positive suffix with non-empty port_trace and calls
        pos_i = None
        neg_i = None
        for i, v in enumerate(d1["vectors"]):
            if i < D3S2_PREFIX:
                continue
            if v.get("positive") and (v["expected"].get("port_trace") or []):
                pos_i = i
            if not v.get("positive") and neg_i is None:
                neg_i = i
        if pos_i is None or neg_i is None:
            print("missing pos/neg vectors for mutation", file=sys.stderr); return 1

        # Document-level authority / AFP / expected-summary mutations only
        # (O1b-A mechanics RED is direct-validator, not rebuild-drift).
        doc_mutations = [
            ("call_status", lambda d: d["vectors"][pos_i]["calls"][1].__setitem__(
                "expected_status", "STORAGE_CORRUPT")),
            ("final_status", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "final_status", "STORAGE_CORRUPT")),
            ("phase", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "phase", PHASE_FAILED)),
            ("flags", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "flags", 0)),
            ("count_mask", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "count_complete_mask", 0x7F)),
            ("binding_mask", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "binding_complete_mask", 0)),
            ("sticky", lambda d: (
                d["vectors"][neg_i]["expected"].__setitem__("sticky_primary", "OK"),
                d["vectors"][neg_i]["expected"].__setitem__("has_sticky_primary", 0),
            )),
            ("adopted", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "adopted", 0)),
            ("fault_used", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "faults_expected_used", 1 if not d["vectors"][pos_i].get("faults") else 0)),
            ("get_count", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "d3_peer_get_count",
                int(d["vectors"][pos_i]["expected"]["d3_peer_get_count"]) + 99)),
            ("open_count", lambda d: d["vectors"][pos_i]["expected"].__setitem__(
                "iter_open_count",
                int(d["vectors"][pos_i]["expected"]["iter_open_count"]) + 99)),
            ("afp_mapping", lambda d: d["vectors"][pos_i].__setitem__(
                "anti_false_pass_cases", [])),
            ("prefix_authority_content", lambda d: d["d3s2_prefix_authority"].__setitem__(
                "content_sha256", "0" * 64)),
            ("prefix_authority_raw", lambda d: d["d3s2_prefix_authority"].__setitem__(
                "raw_sha256", "1" * 64)),
            ("prefix_authority_format", lambda d: d["d3s2_prefix_authority"].__setitem__(
                "format", "tampered-format")),
            ("prefix_object", lambda d: d["vectors"][0].__setitem__(
                "id", "TAMPERED_PREFIX_ID")),
        ]
        for lab, fn in doc_mutations:
            if must_red(lab, fn) != 0:
                return 1

        # ---- O1b-A direct mechanics + append unit tests ----
        if _o1ba_direct_mechanics_red(d1["vectors"][pos_i], d1["vectors"][neg_i]) != 0:
            return 1
        if _o1ba_append_unit_tests() != 0:
            return 1
        # ---- O1b-B control-tuple / schedule tests ----
        if _o1bb_control_tuple_tests() != 0:
            return 1
        # ---- P1-5 formal pre-generation gate + schedule plan ----
        if _o1b_precheck_tests() != 0:
            return 1
        # ---- P1-1 SELECT setup + Mode30 PREFIX transcript ----
        if _o1b_select_prefix_transcript_tests() != 0:
            return 1
        # ---- P1-2 FOCUS streaming match / failure-point capture ----
        if _o1b_focus_failure_capture_tests() != 0:
            return 1
        # ---- O1b-C fault / finalize / sticky precedence ----
        if _o1bc_fault_finalize_tests() != 0:
            return 1
        # ---- O1b BIND-WG Port-only / Mode30 frontier / matrix ----
        if _o1b_bind_wg_tests() != 0:
            return 1
        # ---- O1b-R3 G preflight + returned-value typed RED ----
        if _o1b_r3_preflight_and_typed_red_tests() != 0:
            return 1
        # ---- R11/R12 P1-1 owner_raw mismatch E2E + post-fault CORRUPT (Mode27 + Mode29) ----
        if _o1b_r11_owner_raw_mismatch_e2e() != 0:
            return 1
        # ---- R12 P1-2 G schedule on semantic failure RED ----
        if _o1b_r12_g_schedule_semantic_failure_red() != 0:
            return 1
        # ---- R12 P2 check() total-count diagnostic f-string ----
        if _o1b_r12_check_count_diagnostic() != 0:
            return 1
        # ---- R19 independent D1-legality gate permanent RED matrix ----
        if _o1b_r19_d1_legality_gate_tests() != 0:
            return 1
        if _o1b_r20_d1_legality_gate_tests() != 0:
            return 1
        if _o1b_r21_d1_legality_gate_tests() != 0:
            return 1
        if _o1b_r22_d1_legality_gate_tests() != 0:
            return 1
        if _o1b_r23_d1_legality_gate_tests() != 0:
            return 1
        if _o1b_r24_d1_legality_gate_tests() != 0:
            return 1
        # ---- R25 COMMIT_UNKNOWN fence + Mode27 lifecycle pins ----
        if _o1b_r25_commit_unknown_fence_tests() != 0:
            return 1
        # ---- R11 P2-1 CLI exact arity matrix ----
        if _o1b_r11_cli_arity_matrix() != 0:
            return 1
        # ---- R24/R25 CLI closed failure contract matrix (check + generate) ----
        if _o1b_r24_cli_failure_matrix() != 0:
            return 1

        # Port event key insertion order must match PORT_EVENT_KEYS (stable serialization)
        pos_trace = d1["vectors"][pos_i]["expected"].get("port_trace") or []
        if not pos_trace:
            print("port event key-order: empty trace", file=sys.stderr); return 1
        got_keys = list(pos_trace[0].keys())
        if got_keys != list(PORT_EVENT_KEYS):
            print(
                f"port event key-order mismatch:\n  got {got_keys}\n  want {list(PORT_EVENT_KEYS)}",
                file=sys.stderr,
            )
            return 1

        # Cross-process PYTHONHASHSEED determinism: two generate subprocesses, exact bytes
        import os as _os
        gen_script = str(Path(__file__).resolve())
        seed_paths = []
        for seed in ("1", "2"):
            outp = td / f"hashseed_{seed}.json"
            env = _os.environ.copy()
            env["PYTHONHASHSEED"] = seed
            r = subprocess.run(
                [sys.executable, gen_script, "generate", str(outp)],
                capture_output=True,
                text=True,
                env=env,
            )
            if r.returncode != 0:
                print(
                    f"generate PYTHONHASHSEED={seed} failed rc={r.returncode}\n"
                    f"stdout:\n{r.stdout}\nstderr:\n{r.stderr}",
                    file=sys.stderr,
                )
                return 1
            seed_paths.append(outp)
        b_s1 = seed_paths[0].read_bytes()
        b_s2 = seed_paths[1].read_bytes()
        if b_s1 != b_s2:
            print(
                "PYTHONHASHSEED generate byte inequality "
                f"(seed1={len(b_s1)} seed2={len(b_s2)} bytes)",
                file=sys.stderr,
            )
            return 1

        # d3s2 check fail-closed on content + prefix
        mut = json.loads(b1)
        mut["d3s2_prefix_authority"]["content_sha256"] = "0" * 64
        (td / "d3s2_soft.json").write_text(json.dumps(mut, indent=2) + "\n")
        r = subprocess.run(
            [sys.executable, str(REPO / "tools" / "domain_scan_crossrow_d3s2_vector_gen.py"),
             "check", str(td / "d3s2_soft.json")],
            capture_output=True, text=True,
        )
        if r.returncode == 0:
            print("d3s2 check soft-passed content_sha", file=sys.stderr); return 1

        ha, hb = td / "a.h", td / "b.h"
        emit_c_fixture(p, ha)
        emit_c_fixture(p, hb)
        if ha.read_bytes() != hb.read_bytes():
            print("emit nondeterministic", file=sys.stderr); return 1
        # P1-3: faults_expected_used must appear before port_trace pointer in initializer
        hdr = ha.read_text(encoding="utf-8")
        if "uint32_t faults_expected_used;" not in hdr:
            print("emit-c missing faults_expected_used field", file=sys.stderr); return 1
        # Every emitted placeholder must reference the exact checkpoint symbol.  Keep
        # this guard explicit because an extra C integer suffix (for example
        # ``6u_checkpoints``) is valid generator text but an invalid C identifier.
        if "u_checkpoints" in hdr:
            print("emit-c malformed checkpoint symbol reference", file=sys.stderr); return 1
        # Find production expected initializer: ..., reopen_required, faults_used, trace, count
        # Structural: every "ninlil_d3s3_N_trace," line must be preceded by a uint used value
        import re as _re_emit
        # Match expected-block tail: <u32>u, ninlil_d3s3_<i>_trace, <count>u
        pat = _re_emit.compile(
            r"(\d+)u,\s*ninlil_d3s3_(\d+)_trace,\s*(\d+)u"
        )
        hits = pat.findall(hdr)
        if len(hits) != D3S3_PRODUCTION_COUNT:
            print(
                f"emit-c faults_expected_used column hits={len(hits)} "
                f"want {D3S3_PRODUCTION_COUNT}",
                file=sys.stderr,
            )
            return 1
        for used_s, vi_s, cnt_s in hits:
            used = int(used_s)
            if used not in (0, 1):
                print(
                    f"emit-c faults_expected_used out of range for vi={vi_s}: {used}",
                    file=sys.stderr,
                )
                return 1
            if int(cnt_s) == 0:
                print(
                    f"emit-c production port_trace_count=0 for vi={vi_s}",
                    file=sys.stderr,
                )
                return 1
            # Identifier reference must match the production vi (no mangled suffix).
            if f"ninlil_d3s3_{vi_s}_checkpoints" not in hdr:
                print(
                    f"emit-c missing checkpoint symbol for vi={vi_s}",
                    file=sys.stderr,
                )
                return 1
            if f"&ninlil_d3s3_{vi_s}_checkpoints[" not in hdr:
                print(
                    f"emit-c call checkpoint pointer wrong for vi={vi_s}",
                    file=sys.stderr,
                )
                return 1

        # formal_precheck: no empty-call / RS_OK-IDLE checkpoint / dummy port sentinels
        # and no Runtime expected object.  Its vector owns only NULL columns.
        formal_vi = next(
            (
                i
                for i, v in enumerate(d1["vectors"][D3S2_PREFIX:])
                if is_formal_precheck_vector(v)
            ),
            None,
        )
        if formal_vi is None:
            print("emit-c formal_precheck vector missing", file=sys.stderr)
            return 1
        if f"ninlil_d3s3_{formal_vi}_checkpoints" in hdr:
            print("emit-c formal has checkpoint array sentinel", file=sys.stderr)
            return 1
        if f"ninlil_d3s3_{formal_vi}_calls" in hdr:
            print("emit-c formal has calls array sentinel", file=sys.stderr)
            return 1
        if f"ninlil_d3s3_{formal_vi}_trace" in hdr:
            print("emit-c formal has port_trace array sentinel", file=sys.stderr)
            return 1
        if f"ninlil_d3s3_{formal_vi}_expected" in hdr:
            print("emit-c formal has Runtime expected sentinel", file=sys.stderr)
            return 1
        if '{ "", 0u, 0u, "", 0u, 0u,' in hdr:
            print("emit-c empty call sentinel present", file=sys.stderr)
            return 1
        production_expected = _re_emit.findall(
            r"static const ninlil_d3s3_expected_t ninlil_d3s3_(\d+)_expected =",
            hdr,
        )
        if len(production_expected) != D3S3_PRODUCTION_COUNT:
            print(
                f"emit-c production expected objects={len(production_expected)} "
                f"want {D3S3_PRODUCTION_COUNT}",
                file=sys.stderr,
            )
            return 1
        # formal calls column line: NULL, 0u,
        pat_null_calls = _re_emit.compile(r"^\s+NULL, 0u,\s*$", _re_emit.M)
        null_calls_hits = pat_null_calls.findall(hdr)
        if len(null_calls_hits) != D3S3_FORMAL_PRECHECK_COUNT:
            print(
                f"emit-c formal calls NULL,0 hits={len(null_calls_hits)} "
                f"want {D3S3_FORMAL_PRECHECK_COUNT}",
                file=sys.stderr,
            )
            return 1
        formal_id = d1["vectors"][D3S2_PREFIX + formal_vi]["id"]
        formal_start = hdr.find(f'    "{formal_id}",')
        formal_end = hdr.find("\n  },", formal_start)
        if formal_start < 0 or formal_end < 0:
            print("emit-c formal vector initializer missing", file=sys.stderr)
            return 1
        formal_block = hdr[formal_start:formal_end]
        if "\n    NULL, 0u,\n    NULL," not in formal_block:
            print("emit-c formal calls/expected NULL columns missing", file=sys.stderr)
            return 1

        # Invalid production calls=[] / port_trace=[] must not emit a header (RED).
        bad_doc = json.loads(b1)
        prod_i = next(
            (
                i
                for i, v in enumerate(bad_doc["vectors"])
                if i >= D3S2_PREFIX and is_rep1_l2_vector(v)
            ),
            None,
        )
        if prod_i is None:
            print("emit-c invalid-prod test: no rep1_l2", file=sys.stderr)
            return 1
        bad_doc["vectors"][prod_i]["calls"] = []
        bad_doc["vectors"][prod_i].setdefault("expected", {})["port_trace"] = []
        bad_doc["content_sha256"] = _content_sha(bad_doc)
        bad_p = td / "bad_empty_prod.json"
        bad_h = td / "bad_empty_prod.h"
        bad_p.write_text(
            json.dumps(bad_doc, indent=2, ensure_ascii=False) + "\n",
            encoding="utf-8",
        )
        try:
            with _silence_stderr():
                emit_c_fixture(bad_p, bad_h)
            print(
                "emit invalid production calls=[]/port_trace=[] did not RED",
                file=sys.stderr,
            )
            return 1
        except SystemExit as e:
            code = e.code if isinstance(e.code, int) else 1
            if code == 0:
                print(
                    "emit invalid production SystemExit(0)",
                    file=sys.stderr,
                )
                return 1
        if bad_h.exists():
            print(
                "emit wrote header for invalid production empty calls/port_trace",
                file=sys.stderr,
            )
            return 1

        # ---- O1a source gates: no expected-answer builder API; no fixture helpers in REF ----
        if _o1a_source_gates() != 0:
            return 1

        # ---- Direct RefSession mutations (semantic families) ----
        if _o1a_direct_refsession_mutations() != 0:
            return 1

        print("self-test ok")
        return 0


def _o1a_source_gates() -> int:
    """Reject expected-answer builder args and fixture-helper calls in O1A_REF."""
    import re as _re

    src = Path(__file__).read_text(encoding="utf-8")
    # Builder API: vec signature must not accept expected/outcome/fail_at
    if "def vec(" not in src:
        print("source gate: vec missing", file=sys.stderr); return 1
    i = src.index("def vec(")
    j = src.index(") -> Dict[str, Any]:", i)
    header = src[i:j]
    for banned in (
        "expected",
        "outcome",
        "fail_at",
        "error_stage",
        "expected_ok",
        "sticky",
        "positive",
    ):
        if _re.search(rf"\b{banned}\b\s*[:=,)]", header):
            print(f"source gate: vec still accepts {banned}", file=sys.stderr)
            return 1
    bs = src[src.index("def build_suffix") : src.index("def build_document")]
    for banned_call in (
        "ref_" + "expected(",
        "ok_" + "expected(",
        "corrupt_" + "expected(",
        "out" + "come=",
        "fail" + "_at=",
        "expec" + "ted=",
    ):
        if banned_call in bs:
            print(f"source gate: build_suffix contains {banned_call}", file=sys.stderr)
            return 1

    # Unique exact-line markers; require exactly one begin and one end, end after begin
    begin_line = "### BEGIN O1A_INDEPENDENT_REFERENCE_SECTION ###"
    end_line = "### END O1A_INDEPENDENT_REFERENCE_SECTION ###"
    begins = [n for n, ln in enumerate(src.splitlines()) if ln.strip() == begin_line]
    ends = [n for n, ln in enumerate(src.splitlines()) if ln.strip() == end_line]
    if len(begins) != 1 or len(ends) != 1:
        print(
            f"source gate: marker count begin={len(begins)} end={len(ends)} (want 1/1)",
            file=sys.stderr,
        )
        return 1
    if ends[0] <= begins[0]:
        print("source gate: end marker before begin", file=sys.stderr); return 1
    # Extract by exact line positions (not index of substring in comments)
    lines = src.splitlines(keepends=True)
    ref = "".join(lines[begins[0] : ends[0] + 1])
    if len(ref) < 8000:
        print(f"source gate: ref slice too short ({len(ref)} bytes)", file=sys.stderr)
        return 1
    # Must include late reference symbols (proves slice is not empty/truncated)
    for must in ("def o1a_bind_chunk_ok", "class RefSession", "def o1a_semantic_mode30"):
        if must not in ref:
            print(f"source gate: ref missing {must}", file=sys.stderr); return 1
    import re as _re2
    # Ban fixture-helper call sites; do not trip on o1a_* independent names
    # (e.g. o1a_msd_ingress contains the token msd_ingress).
    for call in (
        r"(?<![A-Za-z0-9_])msd_ingress\(",
        r"(?<![A-Za-z0-9_])msd_parts\(",
        r"(?<![A-Za-z0-9_])dlv_msd_fields\(",
        r"(?<![A-Za-z0-9_])_cs_cancel_kind\(",
        r"(?<![A-Za-z0-9_])man_owner_raw\(",
        r"(?<![A-Za-z0-9_])rc_evidence_stage\(",
        r"(?<![A-Za-z0-9_])rebuild_manifest\(",
        r"(?<![A-Za-z0-9_])rebuild_chunk\(",
        r"(?<![A-Za-z0-9_])set_payload_blob_dig\(",
        r"(?<![A-Za-z0-9_])set_dlv_payload_blob_dig\(",
        r"(?<![A-Za-z0-9_])set_ingress_blob_digs\(",
        r"(?<![A-Za-z0-9_])body_of\(",
        r"(?<![A-Za-z0-9_])man_body_offsets\(",
        r"(?<![A-Za-z0-9_])rr_attempt_and_semantic_off\(",
    ):
        if _re2.search(call, ref):
            print(f"source gate: O1A_REF calls fixture helper /{call}/", file=sys.stderr)
            return 1
    return 0


def _o1a_flip_man_content_bit(rows: List[Dict[str, str]]) -> List[Dict[str, str]]:
    out = []
    flipped = False
    for r in rows:
        k = d3s1.from_hex(r["key_hex"])
        v = d3s1.from_hex(r["value_hex"])
        if (
            not flipped
            and len(k) >= 10
            and k[9] == 0x30
            and len(v) > 15
            and v[15] == 1
        ):
            body = bytearray(o1a_body(v))
            # content_digest starts at base+12 after owner_raw+opkd
            rl = struct.unpack(">H", body[36:38])[0]
            base = 38 + rl + 32
            body[base + 12] ^= 0x01
            v = d3s1.enc_env_full(
                6, 0x30, 1, 1, v[24:40], v[40:72], v[72:104], bytes(body)
            )
            flipped = True
        out.append(mkrow(k, v))
    if not flipped:
        raise RuntimeError("no man content_digest to flip")
    return sort_rows(out)


def _o1a_patch_subtype_body(
    rows: List[Dict[str, str]], subtype: int, mutator
) -> List[Dict[str, str]]:
    out = []
    for r in rows:
        k = d3s1.from_hex(r["key_hex"])
        v = d3s1.from_hex(r["value_hex"])
        if len(k) >= 10 and k[9] == subtype:
            body = bytearray(o1a_body(v))
            body = mutator(body, v)
            flags = v[15]
            rec_type = 1 if subtype == 0x30 else 0
            # re-encode with same common fields; subtype-specific flags for blob
            if subtype == 0x30:
                v = d3s1.enc_env_full(
                    6, 0x30, flags, 1, v[24:40], v[40:72], v[72:104], bytes(body)
                )
            else:
                v = d3s1.enc_env_full(
                    6, subtype, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body)
                )
        out.append(mkrow(k, v))
    return sort_rows(out)


def _o1a_must_flip(
    label: str,
    mode: int,
    base_rows: List[Dict[str, str]],
    mut_rows: List[Dict[str, str]],
    *,
    want_status: str,
    want_stage: str,
) -> int:
    """Baseline must be exact OK/positive/complete; mutation exact status+stage."""
    base = RefSession(mode, base_rows).run()
    if (
        base.get("final_status") != OUT_OK
        or int(base.get("_positive", 0)) != 1
        or base.get("_terminal_stage") != STAGE_COMPLETE
    ):
        print(
            f"direct mutation {label}: baseline not OK/positive/complete "
            f"got {base.get('final_status')}/{base.get('_positive')}/{base.get('_terminal_stage')}",
            file=sys.stderr,
        )
        return 1
    mut = RefSession(mode, mut_rows).run()
    if mut.get("final_status") != want_status or mut.get("_terminal_stage") != want_stage:
        print(
            f"direct mutation {label}: want {want_status}/{want_stage} "
            f"got {mut.get('final_status')}/{mut.get('_terminal_stage')}",
            file=sys.stderr,
        )
        return 1
    if int(mut.get("_positive", 1)) != 0:
        print(f"direct mutation {label}: mutated still positive", file=sys.stderr)
        return 1
    return 0



def _o1a_direct_refsession_mutations() -> int:
    """Direct RefSession mutations across semantic families (§18.14)."""
    W = OUT_CORRUPT

    def flip(label, mode, base, mut, stage):
        return _o1a_must_flip(label, mode, base, mut, want_status=W, want_stage=stage)

    # ---- M27 owner PVD / referrer / content digest ----
    r = mat27_chunked()
    out = []
    for row in r:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            v = d3s1.patch_pvd(v, bytes([0x11]) * 32)
        out.append(mkrow(k, v))
    if flip("m27_owner_pvd", 27, r, sort_rows(out), STAGE_OWNER_PVD) != 0:
        return 1

    out = []
    anc_mut = None
    for row in r:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x20:
            body = bytearray(o1a_body(v))
            body[-32:] = bytes([0xFF]) * 32
            v = d3s1.enc_env_full(6, 0x20, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
            anc_mut = v
        out.append(mkrow(k, v))
    # Keep STATE avd/pvd synced so fail is FOCUS referrer (not SELECT_SETUP cross-row)
    if anc_mut is not None:
        out2 = []
        for row in out:
            k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
            if len(k) >= 10 and k[9] == 0x22:
                v = _sync_state_avd_pvd_to_anchor(anc_mut, v)
            out2.append(mkrow(k, v))
        out = out2
    if flip("m27_referrer", 27, r, sort_rows(out), STAGE_FOCUS_SCAN) != 0:
        return 1

    if flip("m27_chunk_cd", 27, r, _o1a_flip_man_content_bit(r), STAGE_CHUNKS) != 0:
        return 1

    # ---- M27 unrelated STATE substitution ----
    out = []
    for row in r:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x22:
            body = bytearray(o1a_body(v))
            body[0:16] = bytes([0xEE]) * 16  # foreign tx
            # rebuild STATE key for foreign tx so it is present but not matching anchor
            v = d3s1.enc_env_full(6, 0x22, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
            k = o1a_state_key(bytes([0xEE]) * 16)
        out.append(mkrow(k, v))
    if flip("m27_unrelated_state", 27, r, sort_rows(out), STAGE_SELECT_SETUP) != 0:
        return 1

    # ---- M28 semantic / views ----
    r28 = mat28_payload_only()
    out = []
    for row in r28:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x27:
            body = bytearray(o1a_body(v))
            body[-132] ^= 0x01
            v = d3s1.enc_env_full(6, 0x27, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    fixed = []
    ing_vdig = None
    for row in out:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x27:
            ing_vdig = d3s1.value_digest(v)
    for row in out:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if ing_vdig and len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            v = d3s1.patch_pvd(v, ing_vdig)
        fixed.append(mkrow(k, v))
    man_vdig = None
    for row in fixed:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_vdig = d3s1.value_digest(v)
    fixed2 = []
    for row in fixed:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if man_vdig and len(k) >= 10 and k[9] == 0x30 and v[15] == 2:
            v = d3s1.patch_pvd(v, man_vdig)
        fixed2.append(mkrow(k, v))
    if flip("m28_semantic", 28, r28, sort_rows(fixed2), STAGE_SEMANTIC) != 0:
        return 1

    out = []
    for row in r28:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x27:
            body = bytearray(o1a_body(v))
            body[-100] ^= 0x01
            v = d3s1.enc_env_full(6, 0x27, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    if flip("m28_view_a", 28, r28, sort_rows(out), STAGE_FOCUS_SCAN) != 0:
        return 1

    out = []
    for row in r28:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x27:
            body = bytearray(o1a_body(v))
            body[-68:-36] = bytes([0xAB]) * 32
            v = d3s1.enc_env_full(6, 0x27, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    # re-pin man/chunk PVD after ingress body mutate so FOCUS reaches view_b SCAN
    ing_vdig = None
    for row in out:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x27:
            ing_vdig = d3s1.value_digest(v)
    tmp = []
    for row in out:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if ing_vdig and len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            v = d3s1.patch_pvd(v, ing_vdig)
        tmp.append(mkrow(k, v))
    man_vdig = None
    for row in tmp:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_vdig = d3s1.value_digest(v)
    out2 = []
    for row in tmp:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if man_vdig and len(k) >= 10 and k[9] == 0x30 and v[15] == 2:
            v = d3s1.patch_pvd(v, man_vdig)
        out2.append(mkrow(k, v))
    # APPLICATION + non-zero evidence digest is D1-illegal → SELECT reject (not FOCUS).
    if flip("m28_view_b", 28, r28, sort_rows(out2), STAGE_SELECT_SETUP) != 0:
        return 1

    # ---- M29 lifecycle RC drop + unrelated RC substitution ----
    r29 = mat29_app()
    r29_miss = [
        row for row in r29
        if not (len(d3s1.from_hex(row["key_hex"])) >= 10 and d3s1.from_hex(row["key_hex"])[9] == 0x41)
    ]
    if flip("m29_lifecycle_rc", 29, r29, sort_rows(r29_miss), STAGE_SELECT_SETUP) != 0:
        return 1

    # Unrelated RESULT_CACHE: rekey RC to foreign delivery raw
    foreign_raw = bytes([0xCD]) + bytes(79)
    foreign_rc_k = o1a_rc_key(foreign_raw)
    out = []
    for row in r29:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x41:
            body = bytearray(o1a_body(v))
            # replace delivery raw in RC body
            body[0:2] = struct.pack(">H", 80)
            body[2:82] = foreign_raw
            v = d3s1.enc_env_full(6, 0x41, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
            k = foreign_rc_k
        out.append(mkrow(k, v))
    if flip("m29_unrelated_rc", 29, r29, sort_rows(out), STAGE_SELECT_SETUP) != 0:
        return 1

    # ---- M30 companions ----
    r30 = mat30_receipt_empty()
    # unrelated RESULT: foreign raw on RC while DELIVERY/RR stay
    out = []
    for row in r30:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x41:
            body = bytearray(o1a_body(v))
            body[0:2] = struct.pack(">H", 80)
            body[2:82] = foreign_raw
            v = d3s1.enc_env_full(6, 0x41, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
            k = foreign_rc_k
        out.append(mkrow(k, v))
    if flip("m30_unrelated_rc", 30, r30, sort_rows(out), STAGE_SEMANTIC) != 0:
        return 1

    # unrelated CELL: rekey slot0 cell to foreign raw
    foreign_cell_k = o1a_cell_key(foreign_raw, 0)
    out = []
    for row in r30:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x32:
            body = bytearray(o1a_body(v))
            # owner_kind already DELIVERY; replace raw contents
            # layout: okind2 + cell_kind2 + rl2 + raw...
            body[4:6] = struct.pack(">H", 80)
            body[6:86] = foreign_raw
            v = d3s1.enc_env_full(6, 0x32, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
            k = foreign_cell_k
        out.append(mkrow(k, v))
    if flip("m30_unrelated_cell", 30, r30, sort_rows(out), STAGE_SEMANTIC) != 0:
        return 1

    # M30 #14 raw / #15 / #16 / matrix (exact stages)
    out = []
    for row in r30:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            body = bytearray(o1a_body(v))
            body[38] ^= 0x01
            v = d3s1.enc_env_full(6, 0x30, 1, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    if flip("m30_h14_raw", 30, r30, sort_rows(out), STAGE_FOCUS_SCAN) != 0:
        return 1

    r30d = mat30_disposition_empty()
    out = []
    for row in r30d:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            body = bytearray(o1a_body(v))
            rl = struct.unpack(">H", body[36:38])[0]
            base = 38 + rl + 32
            body[base : base + 8] = struct.pack(">Q", 1)
            body[base + 8 : base + 12] = struct.pack(">I", 1)
            v = d3s1.enc_env_full(6, 0x30, 1, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    if flip("m30_h15", 30, r30d, sort_rows(out), STAGE_FOCUS_SCAN) != 0:
        return 1

    r30r = mat30_receipt_1byte()
    out = []
    for row in r30r:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x32:
            body = bytearray(o1a_body(v))
            st_off = 6 + 80 + 64 + 4 + 2 + 2
            body[st_off + 8 : st_off + 12] = struct.pack(">I", 9)
            v = d3s1.enc_env_full(6, 0x32, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    if flip("m30_h16_stage", 30, r30r, sort_rows(out), STAGE_SEMANTIC) != 0:
        return 1

    out = []
    for row in r30:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x41:
            body = bytearray(o1a_body(v))
            o = 2 + 80 + 32 + 16 + 8 + 4 + 4 + 4 + 4 + 16 + 8 + 16 + 8 + 16 + 8 + 8 + 8 + 8 + 8 + 16 + 8
            body[o : o + 4] = struct.pack(">I", 2)
            v = d3s1.enc_env_full(6, 0x41, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    if flip("m30_matrix_appkind", 30, r30, sort_rows(out), STAGE_SEMANTIC) != 0:
        return 1

    # M30 CANCEL unrelated (CANCEL_RESULT baseline)
    r30c = mat30_cancel_empty()
    foreign_cs_k = o1a_cs_key(foreign_raw)
    out = []
    for row in r30c:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x33:
            body = bytearray(o1a_body(v))
            body[4:6] = struct.pack(">H", 80)
            body[6:86] = foreign_raw
            v = d3s1.enc_env_full(6, 0x33, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
            k = foreign_cs_k
        out.append(mkrow(k, v))
    if flip("m30_unrelated_cancel", 30, r30c, sort_rows(out), STAGE_SEMANTIC) != 0:
        return 1

    # ---- scoped extra TX man ----
    r27 = mat27_chunked()
    foreign_tx = bytes([0xB2]) + bytes(15)
    ek, ev = rebuild_manifest(1, foreign_tx, 1, b"\x01", foreign_tx[:16], bytes(32), bytes(32))
    if flip("m27_scoped_extra_man", 27, r27, sort_rows(r27 + [mkrow(ek, ev)]), STAGE_BIND_M) != 0:
        return 1

    # foreign INGRESS man ignored by Mode27
    base = RefSession(27, r27).run()
    if base.get("final_status") != OUT_OK or base.get("_terminal_stage") != STAGE_COMPLETE:
        print("m27 baseline not OK", file=sys.stderr); return 1
    ing_man_k, ing_man_v = rebuild_manifest(
        2, struct.pack(">Q", 99), 3, b"", bytes(16), bytes(32), bytes(32)
    )
    mix_ok = RefSession(27, sort_rows(r27 + [mkrow(ing_man_k, ing_man_v)])).run()
    if mix_ok.get("final_status") != OUT_OK:
        print("mode-scoped foreign INGRESS man must be ignored", file=sys.stderr); return 1

    # ---- zero historical digests -> select_setup ----
    # M27 hist with dig wiped to zero
    r_hist = mat27_hist()
    out = []
    for row in r_hist:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x20:
            body = bytearray(o1a_body(v))
            body[-32:] = O1A_ZERO32
            v = d3s1.enc_env_full(6, 0x20, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    if flip("m27_hist_zero_dig", 27, r_hist, sort_rows(out), STAGE_SELECT_SETUP) != 0:
        return 1

    # M29 terminal hist with dig wiped
    r29h = mat29_terminal_hist()
    out = []
    for row in r29h:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x40:
            body = bytearray(o1a_body(v))
            body[-96:-64] = O1A_ZERO32
            v = d3s1.enc_env_full(6, 0x40, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    if flip("m29_hist_zero_dig", 29, r29h, sort_rows(out), STAGE_SELECT_SETUP) != 0:
        return 1

    # M30 state5 with zero body dig: construct from receipt RR by setting send_state=5 and dig0
    r30live = mat30_receipt_empty()
    out = []
    for row in r30live:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x42:
            body = bytearray(o1a_body(v))
            rl = struct.unpack(">H", body[0:2])[0]
            o = 2 + rl
            dl = struct.unpack(">H", body[o : o + 2])[0]
            o = o + 2 + dl + 16 + 4 + 32  # at body_blob
            body[o : o + 32] = O1A_ZERO32
            o += 32
            body[o : o + 4] = struct.pack(">I", 5)  # send_state=5
            v = d3s1.enc_env_full(6, 0x42, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out.append(mkrow(k, v))
    # baseline for this case is not the live receipt OK path with state5+zero;
    # construct positive historical first then mutate dig to zero.
    # Positive hist: state5 + nonzero dig + no man
    out_hist = []
    man_k_dig = None
    for row in r30live:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x30:
            continue  # drop man/chunks for historical
        if len(k) >= 10 and k[9] == 0x42:
            body = bytearray(o1a_body(v))
            rl = struct.unpack(">H", body[0:2])[0]
            o = 2 + rl
            dl = struct.unpack(">H", body[o : o + 2])[0]
            o = o + 2 + dl + 16 + 4 + 32
            # keep body_blob dig nonzero; set send_state=5
            o2 = o + 32
            body[o2 : o2 + 4] = struct.pack(">I", 5)
            v = d3s1.enc_env_full(6, 0x42, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out_hist.append(mkrow(k, v))
    r30h = sort_rows(out_hist)
    base_h = RefSession(30, r30h).run()
    if base_h.get("final_status") != OUT_OK:
        print(f"m30 hist baseline not OK: {base_h.get('final_status')}/{base_h.get('_terminal_stage')}",
              file=sys.stderr)
        return 1
    out_z = []
    for row in r30h:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x42:
            body = bytearray(o1a_body(v))
            rl = struct.unpack(">H", body[0:2])[0]
            o = 2 + rl
            dl = struct.unpack(">H", body[o : o + 2])[0]
            o = o + 2 + dl + 16 + 4 + 32
            body[o : o + 32] = O1A_ZERO32
            v = d3s1.enc_env_full(6, 0x42, 0, 1, v[24:40], v[40:72], v[72:104], bytes(body))
        out_z.append(mkrow(k, v))
    if flip("m30_hist_zero_dig", 30, r30h, sort_rows(out_z), STAGE_SELECT_SETUP) != 0:
        return 1

    # ---- lingering historical man -> focus_scan ----
    man_k = gkey("DSB3_BLOB_MAN_ZERO_TYPED")
    man_v = gval("DSB3_BLOB_MAN_ZERO_TYPED")
    r_ling = sort_rows(r_hist + [mkrow(man_k, man_v)])
    if flip("m27_hist_lingering_man", 27, r_hist, r_ling, STAGE_FOCUS_SCAN) != 0:
        return 1

    # M29 terminal + add payload man matching dig
    # mat29_terminal_hist dig points at DSB3_BLOB_MAN_DLV_CMD_TYPED key dig
    man_k29 = gkey("DSB3_BLOB_MAN_DLV_CMD_TYPED")
    man_v29 = gval("DSB3_BLOB_MAN_DLV_CMD_TYPED")
    # re-pin man PVD to delivery for constructibility not required for match_count
    r29_ling = sort_rows(r29h + [mkrow(man_k29, man_v29)])
    if flip("m29_hist_lingering_man", 29, r29h, r29_ling, STAGE_FOCUS_SCAN) != 0:
        return 1

    # M30 hist + re-add REPLY man matching dig
    # recover dig from r30h RR body_blob
    man_from_receipt = None
    for row in mat30_receipt_empty():
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            man_from_receipt = (k, v)
            break
    if man_from_receipt is None:
        print("no receipt man", file=sys.stderr); return 1
    r30_ling = sort_rows(r30h + [mkrow(*man_from_receipt)])
    if flip("m30_hist_lingering_man", 30, r30h, r30_ling, STAGE_FOCUS_SCAN) != 0:
        return 1

    # ---- M27 EventFact exact EVENT_SPOOL setup ----
    # Promote DesiredState anchor to EventFact (derived event_map dig) + legal ES
    r_ef = mat27_zero()
    tx = None
    anc_ef = None
    st_tmpl = None
    out = []
    for row in r_ef:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x20:
            v = _promote_anchor_to_eventfact(v)
            tx = o1a_body(v)[:16]
            anc_ef = v
        elif len(k) >= 10 and k[9] == 0x22:
            st_tmpl = v
            continue  # rebuild below as EF STATE
        out.append(mkrow(k, v))
    if tx is None or anc_ef is None or st_tmpl is None:
        print("ef: no anchor/state", file=sys.stderr); return 1
    # EF STATE + matching avd/pvd/es_rev for Mode27 cross-row
    st_k, st_v = _rebuild_state_for_anchor(
        anc_ef, st_tmpl,
        state=_D1_TXN_READY, outcome=0, reason=0, park=0,
        ddl=_D1_DDL_NA, latest=0, retry=1, attempt=0, cumul=0, es_rev=1,
        has_late=0, discarded=0,
    )
    out.append(mkrow(st_k, st_v))
    es_k, es_v = _rebuild_spool_for_anchor(
        anc_ef, gval("DSB3_ES_ACTIVE_TYPED"),
        spool_state=_D1_ES_ACTIVE, park_cause=0, rev=1, retry=1, discard_flag=0,
    )
    es_body = bytearray(o1a_body(es_v))  # for foreign-spool mutations below
    # re-pin man PVD after anchor mutate
    ing_vdig = d3s1.value_digest(anc_ef)
    tmp = []
    for row in out:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if ing_vdig and len(k) >= 10 and k[9] == 0x30 and v[15] == 1:
            v = d3s1.patch_pvd(v, ing_vdig)
        tmp.append(mkrow(k, v))
    r_ef_ok = sort_rows(tmp + [mkrow(es_k, es_v)])
    base_ef = RefSession(27, r_ef_ok).run()
    if (
        base_ef.get("final_status") != OUT_OK
        or int(base_ef.get("_positive", 0)) != 1
        or base_ef.get("_terminal_stage") != STAGE_COMPLETE
    ):
        print(
            f"EventFact baseline not OK: {base_ef.get('final_status')}/"
            f"{base_ef.get('_positive')}/{base_ef.get('_terminal_stage')}",
            file=sys.stderr,
        )
        return 1
    # missing spool
    if flip("m27_ef_missing_spool", 27, r_ef_ok, sort_rows(tmp), STAGE_SELECT_SETUP) != 0:
        return 1
    # unrelated spool (body tx foreign, correct ID128 key for foreign)
    foreign_tx = bytes([0xAA]) + bytes(15)
    es_k_f = o1a_spool_key(foreign_tx)
    es_body_f = bytearray(es_body)
    es_body_f[0:16] = foreign_tx
    es_v_f = d3s1.enc_env_full(
        6, 0x50, 0, 1, es_v[24:40], es_v[40:72], es_v[72:104], bytes(es_body_f)
    )
    r_ef_unrel = sort_rows(tmp + [mkrow(es_k_f, es_v_f)])
    if flip("m27_ef_unrelated_spool", 27, r_ef_ok, r_ef_unrel, STAGE_SELECT_SETUP) != 0:
        return 1
    # key-mismatched spool: body tx matches but complete key wrong
    es_k_wrong = o1a_spool_key(foreign_tx)  # wrong key, body still anchor tx
    es_body_m = bytearray(es_body)
    es_body_m[0:16] = tx
    es_v_m = d3s1.enc_env_full(
        6, 0x50, 0, 1, es_v[24:40], es_v[40:72], es_v[72:104], bytes(es_body_m)
    )
    r_ef_km = sort_rows(tmp + [mkrow(es_k_wrong, es_v_m)])
    if flip("m27_ef_spool_key_mismatch", 27, r_ef_ok, r_ef_km, STAGE_SELECT_SETUP) != 0:
        return 1
    # duplicate body-matching spools (multiset complete key):
    # R18: pre-generation gate rejects before any Port/call column (not mid-SELECT,
    # not product formal_precheck packaging — pure reason only here).
    r_ef_dup = sort_rows(tmp + [mkrow(es_k, es_v), mkrow(es_k, es_v)])
    base_ef = RefSession(27, r_ef_ok).run()
    if (
        base_ef.get("final_status") != OUT_OK
        or int(base_ef.get("_positive", 0)) != 1
        or base_ef.get("_terminal_stage") != STAGE_COMPLETE
    ):
        print(
            "direct mutation m27_ef_spool_duplicate: baseline not OK/positive/complete",
            file=sys.stderr,
        )
        return 1
    pure_dup = rep1_precheck_formal_inputs(27, r_ef_dup)
    if pure_dup != "duplicate complete key":
        print(
            f"direct mutation m27_ef_spool_duplicate: pure reason {pure_dup!r}",
            file=sys.stderr,
        )
        return 1
    rs_dup = RefSession(27, r_ef_dup)
    mut_dup = rs_dup.run()
    if not getattr(rs_dup, "_precheck_failed", False):
        print(
            "direct mutation m27_ef_spool_duplicate: must precheck-fail",
            file=sys.stderr,
        )
        return 1
    if getattr(rs_dup, "_precheck_reason", None) != pure_dup:
        print(
            "direct mutation m27_ef_spool_duplicate: reason drift",
            file=sys.stderr,
        )
        return 1
    if mut_dup.get("port_trace") or mut_dup.get("_calls"):
        print(
            "direct mutation m27_ef_spool_duplicate: must be Port/call empty",
            file=sys.stderr,
        )
        return 1
    if int(mut_dup.get("_positive", 1)) != 0:
        print(
            "direct mutation m27_ef_spool_duplicate: mutated still positive",
            file=sys.stderr,
        )
        return 1

    # ---- BIND_CHUNK: isolated empty-carrier + foreign-mode legal man/chunk ----
    # Mode28 empty: no ingress carriers; TX-owned man+chunk is out of BIND_MANIFEST scope
    # but still adjudicated by untyped BIND_CHUNK.
    r_empty = sort_rows(profile_rows())
    base_e = RefSession(28, r_empty).run()
    if (
        base_e.get("final_status") != OUT_OK
        or int(base_e.get("_positive", 0)) != 1
        or base_e.get("_terminal_stage") != STAGE_COMPLETE
    ):
        print("empty m28 baseline not OK", file=sys.stderr); return 1
    # legal foreign TX man+chunk (Mode27 kinds) rebuilt under exact forward keys
    stream = b"\x2a"
    man_k, man_v = rebuild_manifest(
        1, bytes([0x71]) + bytes(15), 1, stream, bytes([0x71]) + bytes(15),
        D1_NONZERO_PVD, D1_NONZERO_HEAD,
    )
    # ensure keys match reconstructors
    bid = o1a_dec_man(man_k, man_v)["blob_id"]
    man_k = o1a_man_key_from_blob_id(bid)
    # re-encode man under exact key identity (rebuild_manifest already does)
    man_k, man_v = rebuild_manifest(
        1, bytes([0x71]) + bytes(15), 1, stream, bytes([0x71]) + bytes(15),
        D1_NONZERO_PVD, D1_NONZERO_HEAD,
    )
    ck, cv = rebuild_chunk(man_k, man_v, stream, 0)
    if man_k != o1a_man_key_from_blob_id(o1a_dec_man(man_k, man_v)["blob_id"]):
        print("legal man key rebuild mismatch", file=sys.stderr); return 1
    if ck != o1a_chk_key_from_blob_index(o1a_dec_chunk(ck, cv)["blob_id"], 0):
        print("legal chunk key rebuild mismatch", file=sys.stderr); return 1
    r_iso = sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(ck, cv)])
    base_iso = RefSession(28, r_iso).run()
    if (
        base_iso.get("final_status") != OUT_OK
        or int(base_iso.get("_positive", 0)) != 1
        or base_iso.get("_terminal_stage") != STAGE_COMPLETE
    ):
        print(
            f"isolated foreign man/chunk baseline not OK: "
            f"{base_iso.get('final_status')}/{base_iso.get('_terminal_stage')}",
            file=sys.stderr,
        )
        return 1

    def bind_c(label, mut_rows):
        return flip(label, 28, r_iso, mut_rows, STAGE_BIND_C)

    # orphan chunk: drop man
    if bind_c("bind_c_orphan_chunk", sort_rows(r_empty + [mkrow(ck, cv)])) != 0:
        return 1

    # wrong manifest complete key (body same bid, key != reconstruct)
    wrong_mk = o1a_man_key_from_blob_id(bytes([0xFF]) * 32)
    if bind_c("bind_c_wrong_man_key", sort_rows(r_empty + [mkrow(wrong_mk, man_v), mkrow(ck, cv)])) != 0:
        return 1

    # wrong chunk complete key
    wrong_ck = o1a_chk_key_from_blob_index(bytes([0xFF]) * 32, 0)
    if bind_c("bind_c_wrong_chk_key", sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(wrong_ck, cv)])) != 0:
        return 1

    # manifest_key_digest mismatch on chunk body
    body = bytearray(o1a_body(cv))
    body[32:64] = bytes([0x11]) * 32
    cv_mkd = d3s1.enc_env_full(6, 0x30, 2, 1, cv[24:40], cv[40:72], cv[72:104], bytes(body))
    if bind_c("bind_c_mkd_mismatch", sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(ck, cv_mkd)])) != 0:
        return 1

    # chunk_count mismatch
    body = bytearray(o1a_body(cv))
    body[68:72] = struct.pack(">I", 9)
    cv_cnt = d3s1.enc_env_full(6, 0x30, 2, 1, cv[24:40], cv[40:72], cv[72:104], bytes(body))
    if bind_c("bind_c_count_mismatch", sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(ck, cv_cnt)])) != 0:
        return 1

    # total_length mismatch
    body = bytearray(o1a_body(cv))
    body[72:80] = struct.pack(">Q", 999)
    cv_tot = d3s1.enc_env_full(6, 0x30, 2, 1, cv[24:40], cv[40:72], cv[72:104], bytes(body))
    if bind_c("bind_c_total_mismatch", sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(ck, cv_tot)])) != 0:
        return 1

    # content_digest mismatch
    body = bytearray(o1a_body(cv))
    body[80] ^= 0x01
    cv_cd = d3s1.enc_env_full(6, 0x30, 2, 1, cv[24:40], cv[40:72], cv[72:104], bytes(body))
    if bind_c("bind_c_cd_mismatch", sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(ck, cv_cd)])) != 0:
        return 1

    # chunk PVD != man value digest
    cv_pvd = d3s1.patch_pvd(cv, bytes([0x22]) * 32)
    if bind_c("bind_c_pvd_mismatch", sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(ck, cv_pvd)])) != 0:
        return 1

    # out-of-range index (index=1 while count=1)
    ck1, cv1 = rebuild_chunk(man_k, man_v, b"\x00", 1)
    # force index 1 under correct reconstruct key for index 1
    if bind_c(
        "bind_c_oor_index",
        sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(ck, cv), mkrow(ck1, cv1)]),
    ) != 0:
        return 1

    # duplicate index: same chunk complete key twice → R18 pre-generation invalid
    # (Port/call empty; not mid-BIND stage, not product formal_precheck packaging).
    r_dup_idx = sort_rows(r_empty + [mkrow(man_k, man_v), mkrow(ck, cv), mkrow(ck, cv)])
    pure_idx = rep1_precheck_formal_inputs(28, r_dup_idx)
    if pure_idx != "duplicate complete key":
        print(
            f"direct mutation bind_c_dup_index: pure reason {pure_idx!r}",
            file=sys.stderr,
        )
        return 1
    rs_idx = RefSession(28, r_dup_idx)
    mut_idx = rs_idx.run()
    if (
        not getattr(rs_idx, "_precheck_failed", False)
        or getattr(rs_idx, "_precheck_reason", None) != pure_idx
        or mut_idx.get("port_trace")
        or mut_idx.get("_calls")
        or int(mut_idx.get("_positive", 1)) != 0
    ):
        print(
            "direct mutation bind_c_dup_index: must precheck-fail Port/call empty",
            file=sys.stderr,
        )
        return 1

    # live-path FOCUS chunk PVD still exact STAGE_CHUNKS (not counted as bind_c)
    out = []
    for row in r:
        k = d3s1.from_hex(row["key_hex"]); v = d3s1.from_hex(row["value_hex"])
        if len(k) >= 10 and k[9] == 0x30 and v[15] == 2:
            v = d3s1.patch_pvd(v, bytes([0x22]) * 32)
        out.append(mkrow(k, v))
    if flip("m27_chunk_pvd_focus", 27, r, sort_rows(out), STAGE_CHUNKS) != 0:
        return 1

    # source marker extraction regression: slice must contain late symbols
    if _o1a_source_gates() != 0:
        print("marker regression: source gates failed", file=sys.stderr)
        return 1
    src = Path(__file__).read_text(encoding="utf-8")
    begin_line = "### BEGIN O1A_INDEPENDENT_REFERENCE_SECTION ###"
    end_line = "### END O1A_INDEPENDENT_REFERENCE_SECTION ###"
    lines = src.splitlines()
    bi = [i for i, ln in enumerate(lines) if ln.strip() == begin_line]
    ei = [i for i, ln in enumerate(lines) if ln.strip() == end_line]
    if len(bi) != 1 or len(ei) != 1 or ei[0] <= bi[0]:
        print("marker regression positions", file=sys.stderr); return 1
    ref = "\n".join(lines[bi[0] : ei[0] + 1])
    if "def o1a_bind_chunk_ok" not in ref or "class RefSession" not in ref:
        print("marker regression content missing", file=sys.stderr); return 1
    if len(ref) < 8000:
        print("marker regression too short", file=sys.stderr); return 1

    return 0



def main(argv: List[str]) -> int:
    """CLI: generate|check|emit-c-fixture|self-test.

    Exact arity (surplus → exit 2, no side effects, no traceback):
      generate [out.json]          → len 2|3
      check [in.json]              → len 2|3
      emit-c-fixture <in> <out.h>  → len 4
      self-test                    → len 2
      --help / -h / help           → len 2
    Usage / missing / unreadable / malformed input → exit 2, short message, no traceback.
    """
    usage = (
        "Usage:\n"
        f"  {argv[0]} generate [out.json]     # default: {DEFAULT_JSON}\n"
        f"  {argv[0]} check [in.json]         # default: {DEFAULT_JSON}\n"
        f"  {argv[0]} emit-c-fixture <in.json> <out.h>\n"
        f"  {argv[0]} self-test\n"
        "REP1-v1 oracle: units W / G / WG; SELECT pure W; SELECT_SETUP G (sem=6)."
    )
    if len(argv) < 2:
        print(usage, file=sys.stderr)
        return 2
    cmd = argv[1]
    if cmd in ("-h", "--help", "help"):
        if len(argv) != 2:
            print(usage, file=sys.stderr)
            print("error: surplus args for --help", file=sys.stderr)
            return 2
        print(usage)
        return 0
    try:
        if cmd == "generate":
            if len(argv) > 3:
                print(usage, file=sys.stderr)
                print("error: surplus args for generate", file=sys.stderr)
                return 2
            generate(Path(argv[2]) if len(argv) == 3 else DEFAULT_JSON)
            return 0
        if cmd == "check":
            if len(argv) > 3:
                print(usage, file=sys.stderr)
                print("error: surplus args for check", file=sys.stderr)
                return 2
            p = Path(argv[2]) if len(argv) == 3 else DEFAULT_JSON
            if not p.is_file():
                print(f"error: unreadable input {p}", file=sys.stderr)
                return 2
            return check(p)
        if cmd == "emit-c-fixture":
            if len(argv) != 4:
                print(usage, file=sys.stderr)
                print("error: emit-c-fixture requires exact <in.json> <out.h>", file=sys.stderr)
                return 2
            inp, outp = Path(argv[2]), Path(argv[3])
            if not inp.is_file():
                print(f"error: unreadable input {inp}", file=sys.stderr)
                return 2
            emit_c_fixture(inp, outp)
            return 0
        if cmd == "self-test":
            if len(argv) != 2:
                print(usage, file=sys.stderr)
                print("error: surplus args for self-test", file=sys.stderr)
                return 2
            return self_test()
        print(usage, file=sys.stderr)
        print(f"error: unknown command {cmd!r}", file=sys.stderr)
        return 2
    except SystemExit as e:
        # generate/build may raise SystemExit on short source
        code = e.code if isinstance(e.code, int) else 2
        if code not in (0, 1, 2):
            code = 2
        if code == 2 or code != 0:
            msg = str(e) if e.args and not isinstance(e.code, int) else None
            if msg:
                # avoid "error: error: ..." when raise site already prefixed
                if not str(msg).startswith("error:"):
                    msg = f"error: {msg}"
                print(msg, file=sys.stderr)
            elif code == 2:
                print("error: input/usage failure", file=sys.stderr)
        return 2 if code not in (0, 1) else code
    except (OSError, json.JSONDecodeError, UnicodeDecodeError, ValueError, TypeError, KeyError) as e:
        print(f"error: {e}", file=sys.stderr)
        return 2

if __name__ == "__main__":
    sys.exit(main(sys.argv))
